// anon キー: apikey ヘッダー（プロジェクト識別）に常に使用。データ行の閲覧可否は
// ログインユーザーのJWT(_authToken)＋RLSで制御する（Phase1: テナント分離）。
const SUPABASE_KEY =
  (typeof import.meta !== "undefined" && import.meta.env && import.meta.env.VITE_SUPABASE_ANON_KEY) ||
  "eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6Impqb3V3dHNqeWt4bm12dWFxaGJjIiwicm9sZSI6ImFub24iLCJpYXQiOjE3NzUyMTg1OTgsImV4cCI6MjA5MDc5NDU5OH0.pLWwbpsVTtS5-6iyJXjcUhrX_vXutd7dhRKjqHR4Knc";

// ==================== SUPABASE AUTH（Phase1）====================
// フロントは supabase-js 非依存のため Auth REST を直接叩く。
// ログイン成功後、以降の REST リクエストは anon キーではなく
// ユーザーの access_token(JWT) を Authorization に載せる → RLS が app_metadata を参照。
const GG_AUTH_EMAIL_DOMAIN = "go-group-sys.app";
const GG_SESSION_KEY = "gogroup_sb_session";

// ログイン中ユーザーのアクセストークン（未ログイン時は anon キー）
let _authToken = SUPABASE_KEY;

function _saveSession(s) {
  try { localStorage.setItem(GG_SESSION_KEY, JSON.stringify(s)); } catch (e) {}
}
function _loadSession() {
  try { const s = localStorage.getItem(GG_SESSION_KEY); return s ? JSON.parse(s) : null; } catch (e) { return null; }
}
function _clearSession() {
  try { localStorage.removeItem(GG_SESSION_KEY); } catch (e) {}
}

// 起動時: 保存済みセッションがあればトークンを復元（期限切れでも復元し、後述のrefreshで更新）
(function restoreAuthToken() {
  const s = _loadSession();
  if (s && s.access_token) _authToken = s.access_token;
})();

// username → email 変換（ログインフォームはID入力のままでUI不変）
function _ggEmail(username) {
  return String(username || "").includes("@") ? username : `${username}@${GG_AUTH_EMAIL_DOMAIN}`;
}

// app_metadata からアプリ内 user オブジェクト（既存のshape）を組み立てる
function ggUserFromAuth(authUser, fallbackFacility) {
  const m = (authUser && authUser.app_metadata) || {};
  const facilityId = m.facility_id || null;
  return {
    id: authUser?.id,
    username: m.username || (authUser?.email || "").split("@")[0],
    role: m.role || "staff",
    staffId: m.staff_id || null,
    childId: m.child_id || null,
    facilityId,
    displayName: m.display_name || m.username || "ユーザー",
    selectedFacilityId: facilityId || fallbackFacility || "f1",
  };
}

// サインイン（成功: {ok:true,user} / 失敗: {ok:false,status,error}）
async function ggAuthSignIn(username, password) {
  try {
    const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=password`, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
      body: JSON.stringify({ email: _ggEmail(username), password }),
    });
    const j = await r.json().catch(() => ({}));
    if (!r.ok || !j.access_token) {
      return { ok: false, status: r.status, error: j.error_description || j.msg || "認証に失敗しました" };
    }
    _authToken = j.access_token;
    _saveSession({ access_token: j.access_token, refresh_token: j.refresh_token, expires_at: j.expires_at });
    return { ok: true, user: j.user };
  } catch (e) {
    return { ok: false, status: 0, error: "通信に失敗しました" };
  }
}

// リフレッシュ（access_token を更新）。成功で true。
async function ggAuthRefresh() {
  const s = _loadSession();
  if (!s || !s.refresh_token) return false;
  try {
    const r = await fetch(`${SUPABASE_URL}/auth/v1/token?grant_type=refresh_token`, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, "Content-Type": "application/json" },
      body: JSON.stringify({ refresh_token: s.refresh_token }),
    });
    const j = await r.json().catch(() => ({}));
    if (!r.ok || !j.access_token) return false;
    _authToken = j.access_token;
    _saveSession({ access_token: j.access_token, refresh_token: j.refresh_token, expires_at: j.expires_at });
    return true;
  } catch (e) { return false; }
}

// サインアウト（トークン破棄・anonへ戻す）
async function ggAuthSignOut() {
  const tok = _authToken;
  _authToken = SUPABASE_KEY;
  _clearSession();
  try {
    await fetch(`${SUPABASE_URL}/auth/v1/logout`, {
      method: "POST",
      headers: { apikey: SUPABASE_KEY, Authorization: "Bearer " + tok },
    });
  } catch (e) {}
}

// 現在のトークンでヘッダーを組み立てる（毎リクエスト時に最新の _authToken を反映）
function _authHeaders(extra) {
  return {
    apikey: SUPABASE_KEY,
    Authorization: "Bearer " + _authToken,
    "Content-Type": "application/json",
    "Prefer": "return=minimal",
    ...(extra || {}),
  };
}

// /api/* （自ドメインのサーバーレス関数）呼び出しに、ログインユーザーの
// JWT を自動付与する。全AI/OCR/LINE等のAPIを「認証済みのみ実行可」にするための
// フロント側の一括対応（19箇所の個別改修を避け、将来の呼び出しも自動保護）。
// Supabase REST / Auth は絶対URL(https://…)のため対象外＝影響なし。
if (typeof window !== "undefined" && window.fetch && !window.__ggApiFetchPatched) {
  const _origFetch = window.fetch.bind(window);
  window.fetch = function (input, init) {
    try {
      const url = typeof input === "string" ? input : (input && input.url) || "";
      if (typeof url === "string" && url.startsWith("/api/") && _authToken && _authToken !== SUPABASE_KEY) {
        const h = new Headers((init && init.headers) || (typeof input !== "string" && input.headers) || {});
        if (!h.has("Authorization")) h.set("Authorization", "Bearer " + _authToken);
        init = { ...(init || {}), headers: h };
      }
    } catch (e) { /* 付与失敗時は素通し */ }
    return _origFetch(input, init);
  };
  window.__ggApiFetchPatched = true;
}

// ==================== OCR共通ユーティリティ ====================
// 実装と単体テストは lib/ocr-utils.js（本番障害「The string did not match the
// expected pattern.」の根本原因と対策の解説も同モジュール冒頭に記載）。
// 既存の呼び出し名(_ocr*)を維持するためエイリアスでインポートする。
import {
  OCR_DEV          as _OCR_DEV,
  ocrCompressImage as _ocrCompressImage,
  ocrError         as _ocrErr,
  ocrPrepareUpload as _ocrPrepare,
  ocrReadJson      as _ocrReadJson,
  ocrTime          as _ocrTime,
  ocrDate          as _ocrDate,
  ocrText          as _ocrText,
  ocrFlag          as _ocrFlag,
} from "./lib/ocr-utils.js";

// 401（トークン失効）なら一度だけリフレッシュして再試行する共通fetch
async function _sbFetch(url, opts) {
  let r = await fetch(url, opts);
  if (r.status === 401 && _authToken !== SUPABASE_KEY) {
    const ok = await ggAuthRefresh();
    if (ok) {
      const h = { ...(opts.headers || {}), Authorization: "Bearer " + _authToken };
      r = await fetch(url, { ...opts, headers: h });
    }
  }
  return r;
}

const sb = {
  from: function(table) {
    const base = SUPABASE_URL + "/rest/v1/" + table;
    return {
      select: async function(cols) {
        cols = cols || "*";
        const r = await _sbFetch(base + "?select=" + cols, {headers: _authHeaders()});
        return r.json();
      },
      insert: async function(data) {
        const r = await _sbFetch(base, {method:"POST", headers: _authHeaders(), body: JSON.stringify(data)});
        if(!r.ok) { const e = await r.text(); console.error("SB insert error:", e); }
        return r;
      },
      upsert: async function(data) {
        const r = await _sbFetch(base, {method:"POST", headers: _authHeaders({"Prefer": "resolution=merge-duplicates,return=minimal"}), body: JSON.stringify(data)});
        // ⚠️ ここでは r.text() を読まない（sbSave側で読むため body を消費しない）
        return r;
      },
      delete: async function(id) {
        const r = await _sbFetch(base + "?id=eq." + id, {method:"DELETE", headers: _authHeaders()});
        return r;
      },
      eq: function(col, val) {
        return {
          select: async function(cols) {
            cols = cols || "*";
            const r = await _sbFetch(base + "?select=" + cols + "&" + col + "=eq." + encodeURIComponent(val), {headers: _authHeaders()});
            return r.json();
          }
        };
      }
    };
  }
};

// ==================== 安定化ユーティリティ ====================

// ネットワークエラー通知コールバック（App起動後に登録される）
let _sbErrCb = null;

// ── オフライン検知 ──
// navigator.onLine を初期値に、online/offline イベントで同期
let _isOnline = typeof navigator !== "undefined" ? navigator.onLine : true;
if (typeof window !== "undefined") {
  window.addEventListener("online",  () => {
    _isOnline = true;
    _sbErrCb?.("通信が回復しました ✅ 未保存のデータを再保存してください。", "success");
  });
  window.addEventListener("offline", () => {
    _isOnline = false;
    _sbErrCb?.("📡 オフラインです。通信環境を確認してください。", "error");
  });
}

// ── 二重保存防止セット ──
// 同じ table+id の保存が進行中なら重複実行をスキップする
const _savingIds = new Set();

// ── Supabaseエラーの日本語マッピング ──
function _sbErrMsg(status, message, body) {
  if (!_isOnline)               return "📡 オフラインです。通信環境を確認してください。";
  if (status === 401)           return "🔒 認証エラーです。再ログインしてください。";
  if (status === 403)           return "🔒 保存権限がありません（RLS/GRANT設定を確認）。管理者にお問い合わせください。";
  if (status === 404)           return "⚠️ 保存先テーブルが見つかりません。管理者に連絡してください。";
  if (status === 409)           return "⚠️ データが競合しています。ページを再読み込みして再試行してください。";
  if (status === 422)           return "⚠️ 入力データの形式が正しくありません。内容を確認してください。";
  if (status >= 500)            return "🔧 サーバーエラーです。しばらく待ってから再試行してください。";
  if (message?.includes("Failed to fetch")) return "📡 通信に失敗しました。ネットワーク接続を確認してください。";
  // PGRST204: スキーマキャッシュにカラムが見つからない（DB項目設定エラー）
  const bodyStr = body || message || "";
  if (bodyStr.includes("PGRST204") || bodyStr.includes("schema cache"))
    return "🔧 DB項目設定エラー（PGRST204）: テーブルのカラムが見つかりません。管理者にお問い合わせください。";
  return "保存に失敗しました。通信状況を確認してもう一度お試しください。";
}

// Supabaseへの保存ヘルパー（成功:true / 失敗:false）
// retry: 最大リトライ回数（デフォルト3回、指数バックオフ 1s→2s→4s）
async function sbSave(table, data, { retry = 3 } = {}) {
  // ① オフライン時は即座に失敗
  if (!_isOnline) {
    _sbErrCb?.(_sbErrMsg(0, "offline"), "error");
    return false;
  }

  // ② 二重保存防止（同一 table+id が保存中ならスキップ）
  const saveKey = `${table}_${data?.id || ""}`;
  if (saveKey !== `${table}_` && _savingIds.has(saveKey)) {
    console.warn(`sbSave: 二重保存スキップ [${saveKey}]`);
    return true; // すでに保存中 → OK扱い
  }
  if (saveKey !== `${table}_`) _savingIds.add(saveKey);

  // ③ 保存ペイロードをコンソールに記録（デバッグ用）
  console.log(`[SB SAVE] table=${table} id=${data?.id||"(none)"} keys=${Object.keys(data||{}).join(",")}`);

  let lastErr = null;
  let lastStatus = 0;
  let lastErrBody = "";

  for (let attempt = 0; attempt < retry; attempt++) {
    // 指数バックオフ（1回目はすぐ、2回目は1秒後、3回目は2秒後）
    if (attempt > 0) {
      await new Promise(r => setTimeout(r, 1000 * Math.pow(2, attempt - 1)));
      if (!_isOnline) { lastErr = new Error("offline"); break; }
    }
    try {
      const r = await sb.from(table).upsert(data);
      if (r && typeof r.ok !== "undefined" && !r.ok) {
        // ★ body をここで読む（upsert側では読まない設計に変更済み）
        const errText = await r.text().catch(() => "（body読み取り失敗）");
        lastStatus = r.status;
        lastErrBody = errText;
        // ★ 実エラー内容をコンソールに出力
        console.error(`[SB SAVE ERROR] table=${table} status=${r.status} body=${errText}`, data);
        // 4xx はリトライ不要（権限エラー・スキーマ不一致）
        if (r.status >= 400 && r.status < 500) {
          lastErr = new Error(`HTTP ${r.status}: ${errText}`);
          break;
        }
        throw new Error(`HTTP ${r.status}: ${errText}`);
      }
      // ✅ 保存成功
      _savingIds.delete(saveKey);
      return true;
    } catch(e) {
      lastErr = e;
      if (attempt < retry - 1) {
        console.warn(`sbSave: リトライ ${attempt + 1}/${retry} [${table}]:`, e.message);
      }
    }
  }

  // ❌ 全リトライ失敗
  _savingIds.delete(saveKey);
  const errMsg = lastErr?.message || "不明なエラー";
  // 実エラー詳細をコンソールに記録
  console.error(`[GO-GROUP SAVE ERROR] table=${table} id=${data?.id||"?"} status=${lastStatus} err=${errMsg} body=${lastErrBody}`, new Date().toLocaleString("ja-JP"));
  _appendSaveErr(table, data?.id ?? null, errMsg);
  // ★ トースト: PGRST204（DB項目設定エラー）を優先判定してからHTTP statusで分岐
  const bodyStr = lastErrBody || "";
  const isPGRST204 = bodyStr.includes("PGRST204") || bodyStr.includes("schema cache");
  const toastMsg = isPGRST204
    ? _sbErrMsg(lastStatus, lastErr?.message, bodyStr)
    : lastStatus >= 400
      ? `⚠ 保存失敗 [${table}] HTTP ${lastStatus}:\n${lastErrBody||errMsg}`
      : _sbErrMsg(lastStatus, lastErr?.message, bodyStr);
  _sbErrCb?.(toastMsg, "error");
  return false;
}
async function sbLoad(table) {
  try {
    const r = await sb.from(table).select("*");
    // 論理削除フィルタ: is_deleted=true の行をJS側で除外
    // （is_deletedカラムがないテーブルは全件通過するため既存データに影響なし）
    return Array.isArray(r) ? r.filter(row => !row.is_deleted) : r;
  } catch(e) { console.error("Load error:", e); return []; }
}
// Supabase削除ヘルパー（成功:true / 失敗:false を返す）
async function sbDelete(table, id) {
  // ① 論理削除を試みる（is_deleted カラムがあるテーブルのみ有効）
  try {
    const now = new Date().toISOString();
    const hUpsert = {
      "apikey": SUPABASE_KEY,
      "Authorization": "Bearer " + SUPABASE_KEY,
      "Content-Type": "application/json",
      "Prefer": "resolution=merge-duplicates,return=minimal"
    };
    const r = await fetch(SUPABASE_URL + "/rest/v1/" + table, {
      method: "POST",
      headers: hUpsert,
      body: JSON.stringify({id, is_deleted: true, deleted_at: now})
    });
    if (r.ok) return true; // 論理削除成功
    // is_deleted カラムがない場合は物理削除にフォールバック
    const hDel = {"apikey": SUPABASE_KEY, "Authorization": "Bearer " + SUPABASE_KEY};
    const r2 = await fetch(SUPABASE_URL + "/rest/v1/" + table + "?id=eq." + encodeURIComponent(id), {method:"DELETE", headers:hDel});
    if (!r2.ok) throw new Error("HTTP " + r2.status);
    return true;
  } catch(e) {
    console.error("SB delete error [" + table + "]:", e);
    _sbErrCb?.("削除に失敗しました。管理者に確認してください。", "error");
    return false;
  }
}


// ==================== グローバルエラーログ ====================
// sbSave失敗・unhandledRejectionをここに蓄積し、管理画面で確認できる
// 最大100件保持（古いものは自動削除）
const _saveErrorLog = [];
let _saveErrLogCb = null; // useStore 起動後に登録される

function _appendSaveErr(table, dataId, message) {
  const entry = {
    id: `sav_${Date.now()}_${Math.random().toString(36).slice(2,5)}`,
    time: new Date().toISOString(),
    table:  table  || "unknown",
    dataId: dataId || null,
    message: message || "不明なエラー",
  };
  _saveErrorLog.unshift(entry);
  if (_saveErrorLog.length > 100) _saveErrorLog.length = 100;
  // useStoreの saveErrors stateを更新（登録されていれば）
  _saveErrLogCb?.([..._saveErrorLog]);
}

// ── グローバル unhandledrejection ──
// 全ての未処理Promise拒否をキャッチしてトースト＋ログに記録
// これにより try/catch を書き忘れた箇所の例外も補足される
if (typeof window !== "undefined") {
  window.addEventListener("unhandledrejection", (event) => {
    const msg = event.reason?.message || String(event.reason) || "不明なエラー";
    console.error("[UnhandledRejection] 未処理の例外を補足:", event.reason);
    _sbErrCb?.(`予期しないエラーが発生しました。ページを再読み込みしてください。`, "error");
    _appendSaveErr("unhandled_rejection", null, msg);
    event.preventDefault(); // ブラウザのデフォルトエラー出力を抑制
  });
}

// ==================== React ErrorBoundary ====================
// コンポーネントのレンダリング中に発生したエラーをキャッチし、
// 白画面（クラッシュ）の代わりに日本語エラー画面を表示する
class ErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { error: null, errorInfo: null };
  }
  componentDidCatch(error, errorInfo) {
    console.error("[ErrorBoundary] Reactレンダリングエラー:", error.message, errorInfo.componentStack);
    _appendSaveErr("react_render", null, error.message);
    this.setState({ error, errorInfo });
  }
  render() {
    if (this.state.error) {
      return (
        <div style={{padding:32, textAlign:"center", maxWidth:500, margin:"40px auto"}}>
          <div style={{fontSize:48, marginBottom:12}}>⚠️</div>
          <div style={{fontSize:17, fontWeight:700, color:"#c0392b", marginBottom:8}}>
            画面の表示でエラーが発生しました
          </div>
          <div style={{fontSize:12, color:"#555", marginBottom:12, lineHeight:1.7}}>
            {this.state.error.message}
          </div>
          <div style={{
            fontSize:10, color:"#888", marginBottom:20, textAlign:"left",
            background:"#f7f7f7", padding:"8px 12px", borderRadius:6,
            maxHeight:120, overflow:"auto", fontFamily:"monospace", whiteSpace:"pre-wrap",
          }}>
            {this.state.errorInfo?.componentStack?.slice(0, 400) || ""}
          </div>
          <div style={{display:"flex",gap:10,justifyContent:"center"}}>
            <button
              onClick={() => this.setState({ error: null, errorInfo: null })}
              style={{padding:"10px 24px", borderRadius:8, background:"#2563eb",
                color:"#fff", border:"none", fontSize:14, fontWeight:700, cursor:"pointer"}}>
              再試行
            </button>
            <button
              onClick={() => window.location.reload()}
              style={{padding:"10px 24px", borderRadius:8, background:"#6b7280",
                color:"#fff", border:"none", fontSize:14, fontWeight:700, cursor:"pointer"}}>
              ページ再読込
            </button>
          </div>
        </div>
      );
    }
    return this.props.children;
  }
}

// ==================== CSVダウンロードヘルパー ====================
// 全CSVエクスポートはこの関数を経由させる
// try/catch で例外を一元処理し、失敗時は日本語エラーを表示する
function downloadCSV(filename, content) {
  try {
    if (!content) throw new Error("出力データが空です");
    const bom  = "﻿"; // Excel用BOM
    const blob = new Blob([bom + content], { type: "text/csv;charset=utf-8;" });
    const url  = URL.createObjectURL(blob);
    const a    = document.createElement("a");
    a.href     = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    // メモリリーク防止（1秒後にオブジェクトURLを解放）
    setTimeout(() => URL.revokeObjectURL(url), 1000);
    return true;
  } catch(e) {
    console.error("[CSV出力エラー]", filename, e);
    _appendSaveErr("csv_export", filename, e.message);
    _sbErrCb?.(`CSV出力「${filename}」に失敗しました: ${e.message}`, "error");
    return false;
  }
}

// ==================== withTryCatch ====================
// 非同期UI操作をラップしてエラーを安全にキャッチするヘルパー。
// try/catch を書き忘れがちな非同期ハンドラに適用する。
//
// 使い方:
//   const handleSave = withTryCatch(async () => {
//     await doSomething();
//   }, "保存");
//   <button onClick={handleSave}>保存</button>
function withTryCatch(fn, label = "操作", onErr = null) {
  return async (...args) => {
    try {
      return await fn(...args);
    } catch(e) {
      console.error(`[${label}エラー]`, e);
      _appendSaveErr("ui_handler", label, e.message);
      _sbErrCb?.(`${label}中にエラーが発生しました: ${e.message}`, "error");
      onErr?.(e);
    }
  };
}

