    sbLoad("paid_leave_reqs").then(d=>{ if(d?.length) setPaidLeaveReqs(d.map(x=>x.data||x)); });
    sbLoad("qual_docs").then(d=>{ if(d?.length) setQualDocs(d.map(x=>x.data||x)); });
