// ==================== 有給管理画面 ====================
function PaidLeaveScreen({user, store, onBack}){
  const [tab,setTab]=useState("list");
  const [form,setForm]=useState({startDate:todayISO(),endDate:todayISO(),days:1,reason:"",type:"全日"});
  const [filterFac,setFilterFac]=useState(user.selectedFacilityId||"all");
  const isMgr=user.role==="manager"||user.role==="admin";
  const upd=(k,v)=>setForm(p=>({...p,[k]:v}));
  const myStaff=store.dynStaff.find(s=>s.id===user.staffId);
  const myGranted=myStaff?calcGrantedDays(myStaff.hireDate,myStaff.workDaysPerWeek||5):0;
  const myUsed=myStaff?calcUsedDays(myStaff.id,store.paidLeaveReqs):0;
  const myRemaining=myGranted-myUsed;
  const myReqs=store.paidLeaveReqs.filter(r=>r.staffId===user.staffId);
  const mgrStaff=store.dynStaff.filter(s=>(filterFac==="all"||s.facilityId===filterFac)&&s.active!==false);
  const pendingReqs=store.paidLeaveReqs.filter(r=>r.status==="申請中"&&(filterFac==="all"||r.facilityId===filterFac));
  const SS={"申請中":["rgba(224,168,40,0.18)","var(--am)"],"承認":["rgba(44,170,96,0.2)","var(--gr)"],"却下":["rgba(224,56,56,0.15)","var(--ro)"]};
  const submit=()=>{
    if(!form.reason.trim()) return;
    store.addPaidLeaveReq({id:genId(),staffId:user.staffId,staffName:user.displayName,facilityId:user.selectedFacilityId,...form,status:"申請中",appliedAt:todayISO()});
    setForm({startDate:todayISO(),endDate:todayISO(),days:1,reason:"",type:"全日"});
    setTab("list");
  };
  const csvExport=()=>{
    const rows=mgrStaff.map(s=>{const g=calcGrantedDays(s.hireDate,s.workDaysPerWeek||5);const u=calcUsedDays(s.id,store.paidLeaveReqs);return [s.name,FACILITIES.find(f=>f.id===s.facilityId)?.name,s.employmentType||"",s.hireDate||"",g,u,Math.max(0,g-u),nextGrantDate(s.hireDate)].join(",");});
    const csv=["氏名,施設,雇用形態,入職日,付与日数,取得済,残日数,次回付与日",...rows].join("\n");
    const a=document.createElement("a");a.href=URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv"}));a.download="有給管理_"+todayISO()+".csv";a.click();
  };

  return <div className="fl-wrap">
    <div className="fl-hd"><button className="bback" onClick={onBack}>← 戻る</button><div className="fl-title">🌴 有給管理</div></div>

    {/* 自分の有給サマリー */}
    {myStaff&&<div style={{background:"linear-gradient(135deg,#1a6b3a,#0080b8)",borderRadius:12,padding:"16px 18px",marginBottom:14,color:"#fff"}}>
      <div style={{fontSize:11,opacity:.8,marginBottom:8}}>{myStaff.name} の有給状況</div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:10}}>
        {[["付与日数",myGranted+"日","今年度"],["取得済み",myUsed+"日","承認済み"],["残日数",myRemaining+"日","利用可能"]].map(([l,v,s],i)=><div key={l} style={{background:"rgba(255,255,255,0.15)",borderRadius:8,padding:"10px",textAlign:"center"}}>
          <div style={{fontSize:9,opacity:.8,marginBottom:2}}>{l}</div>
          <div style={{fontSize:i===2?26:20,fontWeight:900,fontFamily:"'DM Mono',monospace"}}>{v}</div>
          <div style={{fontSize:9,opacity:.7,marginTop:1}}>{s}</div>
        </div>)}
      </div>
      <div style={{fontSize:11,opacity:.75}}>入職日: {myStaff.hireDate||"未設定"} ／ 次回付与: {nextGrantDate(myStaff.hireDate)}</div>
      <div style={{marginTop:8,height:5,background:"rgba(255,255,255,0.2)",borderRadius:3,overflow:"hidden"}}>
        <div style={{height:"100%",width:(myGranted>0?Math.min(100,myRemaining/myGranted*100):0)+"%",background:"#fff",borderRadius:3}}/>
      </div>
    </div>}

    {/* タブ */}
    <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
      {[["list","申請履歴"],["apply","📝 有給申請"],
        ...(isMgr?[["manage","👔 承認管理"],["staff","📊 スタッフ一覧"]]:[])]
        .map(([k,l])=><button key={k} onClick={()=>setTab(k)} style={{padding:"7px 14px",borderRadius:16,fontFamily:"'Noto Sans JP',sans-serif",fontSize:12,fontWeight:700,cursor:"pointer",whiteSpace:"nowrap",background:tab===k?"var(--tl)":"var(--wh)",color:tab===k?"#fff":"var(--tx3)",border:tab===k?"none":"1.5px solid var(--bd)",boxShadow:"var(--sh)"}}>
          {l}{k==="manage"&&pendingReqs.length>0&&<span style={{background:"var(--ro)",color:"#fff",borderRadius:8,padding:"1px 6px",fontSize:10,marginLeft:3}}>{pendingReqs.length}</span>}
        </button>)}
    </div>

    {/* 申請履歴 */}
    {tab==="list"&&<div>
      {myReqs.length===0?<div style={{textAlign:"center",color:"var(--tx3)",padding:"36px 0",fontSize:13}}>申請履歴がありません</div>
      :myReqs.sort((a,b)=>b.appliedAt>a.appliedAt?1:-1).map(r=>{const ss=SS[r.status]||["var(--bg)","var(--tx3)"];return <div key={r.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:11,padding:14,marginBottom:8,boxShadow:"var(--sh)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
          <div style={{fontWeight:700,fontSize:14}}>{r.startDate}{r.startDate!==r.endDate?" 〜 "+r.endDate:""}</div>
          <span style={{fontSize:11,padding:"3px 10px",borderRadius:10,fontWeight:700,background:ss[0],color:ss[1]}}>{r.status}</span>
        </div>
        <div style={{fontSize:12,color:"var(--tx3)",marginBottom:6}}>種別: {r.type} ／ {r.days}日 ／ 申請: {r.appliedAt}</div>
        <div style={{fontSize:13,color:"var(--tx2)",background:"var(--bg)",borderRadius:7,padding:"7px 9px"}}>{r.reason}</div>
        {r.comment&&<div style={{fontSize:12,color:"var(--tx3)",marginTop:5}}>管理者: {r.comment}</div>}
      </div>;})}
    </div>}

    {/* 有給申請 */}
    {tab==="apply"&&<div style={{paddingBottom:28}}>
      {myRemaining<=0&&<div style={{background:"rgba(224,56,56,0.08)",border:"1px solid rgba(224,56,56,0.4)",borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:13,color:"var(--ro)",fontWeight:700}}>⚠ 有給残日数がありません（残: {myRemaining}日）</div>}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:11,padding:16,marginBottom:12,boxShadow:"var(--sh)"}}>
        <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:2,marginBottom:12}}>有給休暇申請</div>
        <div style={{marginBottom:12}}>
          <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",display:"block",marginBottom:6}}>取得種別</label>
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
            {["全日","半日（午前）","半日（午後）","時間休"].map(t=><button key={t} onClick={()=>upd("type",t)} style={{padding:"7px 12px",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:form.type===t?"var(--tl)":"var(--bd)",background:form.type===t?"rgba(58,160,216,0.2)":"var(--bg)",color:form.type===t?"var(--tl)":"var(--tx3)"}}>
              {t}
            </button>)}
          </div>
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px",marginBottom:12}}>
          <div><label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",display:"block",marginBottom:5}}>開始日</label><input className="fi" type="date" value={form.startDate} onChange={e=>{upd("startDate",e.target.value);upd("endDate",e.target.value);}}/></div>
          <div><label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",display:"block",marginBottom:5}}>終了日</label><input className="fi" type="date" value={form.endDate} onChange={e=>upd("endDate",e.target.value)}/></div>
        </div>
        <div style={{marginBottom:12}}>
          <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",display:"block",marginBottom:6}}>取得日数</label>
          <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
            {[0.5,1,2,3,4,5].map(d=><button key={d} onClick={()=>upd("days",d)} style={{padding:"7px 11px",borderRadius:8,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'DM Mono',monospace",border:"1.5px solid",borderColor:form.days===d?"var(--tl)":"var(--bd)",background:form.days===d?"rgba(58,160,216,0.2)":"var(--bg)",color:form.days===d?"var(--tl)":"var(--tx3)"}}>
              {d}日
            </button>)}
          </div>
        </div>
        <div style={{marginBottom:12}}>
          <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",display:"block",marginBottom:5}}>取得理由 <span style={{color:"var(--ro)"}}>*</span></label>
          <textarea className="fta" style={{minHeight:72}} placeholder="例）私用のため / 子の学校行事 / 通院" value={form.reason} onChange={e=>upd("reason",e.target.value)}/>
        </div>
        <div style={{background:"rgba(58,160,216,0.1)",borderRadius:9,padding:"9px 12px",marginBottom:12,fontSize:12}}>
          申請後の残日数: <strong style={{color:myRemaining-form.days<0?"var(--ro)":"var(--gr)",fontSize:15}}>{myRemaining-form.days}日</strong>
        </div>
        <button className="bsave" disabled={!form.reason.trim()||myRemaining<form.days} onClick={submit}>申請する</button>
      </div>
    </div>}

    {/* 承認管理 */}
    {tab==="manage"&&isMgr&&<div>
      {user.role==="admin"&&<div style={{marginBottom:10}}><select className="fsm" value={filterFac} onChange={e=>setFilterFac(e.target.value)}><option value="all">全施設</option>{FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}</select></div>}
      {pendingReqs.length===0?<div style={{textAlign:"center",color:"var(--tx3)",padding:"28px 0",fontSize:13}}>承認待ちの申請はありません ✅</div>
      :pendingReqs.map(r=><ApprovalCard key={r.id} r={r} store={store}/>)}
      <div style={{fontSize:12,fontWeight:700,color:"var(--tx3)",margin:"16px 0 8px"}}>処理済み申請</div>
      {store.paidLeaveReqs.filter(r=>r.status!=="申請中"&&(filterFac==="all"||r.facilityId===filterFac)).sort((a,b)=>b.appliedAt>a.appliedAt?1:-1).map(r=>{const ss=SS[r.status]||[];return <div key={r.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:11,marginBottom:6,boxShadow:"var(--sh)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:3}}>
          <div style={{fontWeight:700,fontSize:13}}>{r.staffName}</div>
          <span style={{fontSize:10,padding:"2px 8px",borderRadius:8,fontWeight:700,background:ss[0],color:ss[1]}}>{r.status}</span>
        </div>
        <div style={{fontSize:11,color:"var(--tx3)"}}>{r.startDate}〜{r.endDate} / {r.type} / {r.days}日</div>
      </div>;})}
    </div>}

    {/* スタッフ別一覧 */}
    {tab==="staff"&&isMgr&&<div>
      {user.role==="admin"&&<div style={{marginBottom:10}}><select className="fsm" value={filterFac} onChange={e=>setFilterFac(e.target.value)}><option value="all">全施設</option>{FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}</select></div>}
      <div style={{overflowX:"auto",marginBottom:12}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:560}}>
          <thead><tr style={{background:"#e4e8f0"}}>
            {["氏名","施設","入職日","付与","取得","残","次回付与日"].map(h=><th key={h} style={{padding:"8px 10px",textAlign:h==="氏名"?"left":"center",fontSize:10,fontWeight:700,color:"var(--tx2)",borderBottom:"2px solid var(--bd)",whiteSpace:"nowrap"}}>{h}</th>)}
          </tr></thead>
          <tbody>{mgrStaff.map(s=>{
            const g=calcGrantedDays(s.hireDate,s.workDaysPerWeek||5);
            const u=calcUsedDays(s.id,store.paidLeaveReqs);
            const rem=Math.max(0,g-u);
            return <tr key={s.id} style={{borderBottom:"1px solid var(--bg2)"}}>
              <td style={{padding:"9px 10px",fontWeight:700}}>{s.name}</td>
              <td style={{padding:"9px 10px",textAlign:"center",fontSize:11,color:"var(--tx3)"}}>{FACILITIES.find(f=>f.id===s.facilityId)?.name}</td>
              <td style={{padding:"9px 10px",textAlign:"center",fontFamily:"'DM Mono',monospace",fontSize:11}}>{s.hireDate||"—"}</td>
              <td style={{padding:"9px 10px",textAlign:"center",fontWeight:700,color:"var(--tl)"}}>{g}日</td>
              <td style={{padding:"9px 10px",textAlign:"center",color:"var(--am)",fontWeight:700}}>{u}日</td>
              <td style={{padding:"9px 10px",textAlign:"center"}}><span style={{padding:"3px 9px",borderRadius:8,fontWeight:900,background:rem<=3?"rgba(224,56,56,0.15)":rem<=7?"rgba(224,168,40,0.18)":"rgba(44,170,96,0.2)",color:rem<=3?"var(--ro)":rem<=7?"var(--am)":"var(--gr)"}}>{rem}日</span></td>
              <td style={{padding:"9px 10px",textAlign:"center",fontSize:11,color:"var(--tx3)"}}>{nextGrantDate(s.hireDate)}</td>
            </tr>;
          })}</tbody>
        </table>
      </div>
      <button className="bexp" onClick={csvExport}>⬇ CSV出力</button>
    </div>}
  </div>;
}


// ==================== スタッフ詳細・資格証書管理 ====================
const QUAL_CATEGORIES = [
  "保育士",
  "社会福祉士",
  "精神保健福祉士",
  "介護福祉士",
  "児童指導員",
  "児童指導員5年以上",
  "児童発達支援管理責任者",
  "管理者",
  "臨床心理士・公認心理師",
  "作業療法士",
  "理学療法士",
  "言語聴覚士",
  "看護師・准看護師",
  "健康診断書",
  "その他",
];

function StaffDetail({s, store, isMgr, onBack, onEdit}){
  const [addMode, setAddMode] = useState(false);
  const [confirmDel, setConfirmDel] = useState(null);
  const [form, setForm] = useState({
    category:"保育士", name:"", issueDate:"", expiryDate:"",
    issuer:"", number:"", hasCopy:false, note:""
  });
  const [viewDoc, setViewDoc] = useState(null);
  const upd = (k,v) => setForm(p=>({...p,[k]:v}));

  const myDocs = store.qualDocs.filter(d=>d.staffId===s.id)
    .sort((a,b)=>a.category>b.category?1:-1);

  const fac = FACILITIES.find(f=>f.id===s.facilityId);
  const age = calcAge(s.dob);
  const granted = calcGrantedDays(s.hireDate, s.workDaysPerWeek||5);
  const used = calcUsedDays(s.id, store.paidLeaveReqs);
  const remaining = Math.max(0, granted - used);

  const saveDoc = () => {
    store.addQualDoc({
      id:genId(), staffId:s.id, staffName:s.name,
      facilityId:s.facilityId, registeredAt:todayISO(), ...form
    });
    setForm({category:"保育士",name:"",issueDate:"",expiryDate:"",issuer:"",number:"",hasCopy:false,note:""});
    setAddMode(false);
  };

  // 有効期限チェック
  const isExpiring = d => {
    if(!d.expiryDate) return null;
    const exp = new Date(d.expiryDate);
    const today = new Date();
    const diff = (exp - today) / (1000*60*60*24);
    if(diff < 0) return "expired";
    if(diff < 90) return "soon";
    return "ok";
  };

  const expStyle = status => ({
    expired: {bg:"rgba(224,56,56,0.15)",color:"var(--ro)",label:"期限切れ"},
    soon:    {bg:"rgba(224,168,40,0.18)",color:"var(--am)",label:"期限間近"},
    ok:      {bg:"rgba(44,170,96,0.2)",color:"var(--gr)",label:"有効"},
    null:    {bg:"var(--bg)",color:"var(--tx3)",label:"期限なし"},
  }[status||"null"]);

  // 詳細モーダル
  if(viewDoc) return (
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={()=>setViewDoc(null)}>← 戻る</button>
        <div className="fl-title">📄 資格証書詳細</div>
      </div>
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:18,marginBottom:12,boxShadow:"var(--sh)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:14}}>
          <div>
            <div style={{fontSize:18,fontWeight:900,marginBottom:3}}>{viewDoc.name||viewDoc.category}</div>
            <div style={{fontSize:12,color:"var(--tx3)"}}>{viewDoc.category}</div>
          </div>
          {(()=>{const st=isExpiring(viewDoc);const es=expStyle(st);return <span style={{padding:"4px 12px",borderRadius:10,fontSize:12,fontWeight:700,background:es.bg,color:es.color}}>{es.label}</span>;})()}
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 16px"}}>
          {[
            ["登録者",viewDoc.staffName],
            ["資格番号",viewDoc.number||"—"],
            ["発行機関",viewDoc.issuer||"—"],
            ["取得日",viewDoc.issueDate||"—"],
            ["有効期限",viewDoc.expiryDate||"期限なし"],
            ["登録日",viewDoc.registeredAt],
          ].map(([l,v])=><div key={l} style={{marginBottom:12}}>
            <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:4}}>{l}</div>
            <div style={{fontSize:13,color:"var(--tx)",borderBottom:"1px solid var(--bg2)",paddingBottom:4}}>{v}</div>
          </div>)}
        </div>
        {/* コピー画像欄 */}
        <div style={{marginTop:8}}>
          <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:8}}>証書コピー</div>
          {viewDoc.hasCopy
            ? <div style={{border:"1.5px solid rgba(44,170,96,0.4)",borderRadius:10,padding:"20px",background:"#eef8f2",textAlign:"center"}}>
                <div style={{fontSize:40,marginBottom:8}}>📄</div>
                <div style={{fontWeight:700,color:"var(--gr)",fontSize:13,marginBottom:4}}>コピー登録済み</div>
                <div style={{fontSize:11,color:"var(--tx3)"}}>登録日: {viewDoc.registeredAt}</div>
              </div>
            : <div style={{border:"2px dashed var(--bd)",borderRadius:10,padding:"20px",background:"var(--bg)",textAlign:"center",color:"var(--tx3)",fontSize:13}}>
                コピー未登録
              </div>
          }
        </div>
        {viewDoc.note&&<div style={{marginTop:12}}>
          <div style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,marginBottom:4}}>備考</div>
          <div style={{fontSize:13,color:"var(--tx2)",background:"var(--bg)",borderRadius:8,padding:"9px 11px"}}>{viewDoc.note}</div>
        </div>}
        {isMgr&&<div style={{marginTop:14,display:"flex",gap:8}}>
          <button onClick={()=>{if(!window.confirm("この資格証明書を削除しますか？\nこの操作は取り消せません。"))return;store.delQualDoc(viewDoc.id);setViewDoc(null);}} style={{padding:"8px 18px",borderRadius:9,background:"rgba(224,56,56,0.15)",border:"1.5px solid rgba(224,56,56,0.4)",color:"var(--ro)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🗑️ 削除</button>
        </div>}
      </div>
    </div>
  );

  // 追加フォーム
  if(addMode) return (
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={()=>setAddMode(false)}>← 戻る</button>
        <div className="fl-title">➕ 資格証書を登録</div>
      </div>
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:18,marginBottom:12,boxShadow:"var(--sh)"}}>
        <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:2,marginBottom:12}}>資格・証書の種類</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:16}}>
          {QUAL_CATEGORIES.map(c=><button key={c} onClick={()=>upd("category",c)} style={{padding:"7px 12px",borderRadius:9,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:form.category===c?"var(--tl)":"var(--bd)",background:form.category===c?"rgba(58,160,216,0.2)":"var(--bg)",color:form.category===c?"var(--tl)":"var(--tx2)"}}>
            {c}
          </button>)}
        </div>

        <div style={{marginBottom:12}}>
          <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>資格名・証書名（詳細）</label>
          <input className="fi" value={form.name} placeholder={"例）"+form.category+" 第〇〇号"} onChange={e=>upd("name",e.target.value)}/>
        </div>

        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px",marginBottom:0}}>
          <div style={{marginBottom:12}}>
            <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>資格番号</label>
            <input className="fi" value={form.number} placeholder="例）第12345号" onChange={e=>upd("number",e.target.value)}/>
          </div>
          <div style={{marginBottom:12}}>
            <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>発行機関</label>
            <input className="fi" value={form.issuer} placeholder="例）厚生労働大臣" onChange={e=>upd("issuer",e.target.value)}/>
          </div>
          <div style={{marginBottom:12}}>
            <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>取得日</label>
            <input className="fi" type="date" value={form.issueDate} onChange={e=>upd("issueDate",e.target.value)}/>
          </div>
          <div style={{marginBottom:12}}>
            <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>有効期限（任意）</label>
            <input className="fi" type="date" value={form.expiryDate} onChange={e=>upd("expiryDate",e.target.value)}/>
          </div>
        </div>

        {/* 証書コピー撮影 */}
        <div style={{marginBottom:14}}>
          <div style={{fontSize:10,fontWeight:700,color:"var(--pu)",letterSpacing:1,marginBottom:8}}>証書コピー</div>
          <div style={{border:"2px dashed var(--bd)",borderRadius:11,padding:18,background:form.hasCopy?"#eef8f2":"var(--bg)",textAlign:"center",transition:"all .2s"}}>
            {form.hasCopy
              ? <div>
                  <div style={{fontSize:36,marginBottom:6}}>✅</div>
                  <div style={{fontWeight:700,color:"var(--gr)",fontSize:13,marginBottom:4}}>コピー登録済み</div>
                  <div style={{fontSize:11,color:"var(--tx3)",marginBottom:10}}>実際の証書コピーが登録されました</div>
                  <button onClick={()=>upd("hasCopy",false)} style={{padding:"6px 14px",borderRadius:8,background:"rgba(224,56,56,0.15)",border:"1px solid rgba(224,56,56,0.4)",color:"var(--ro)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
                    削除して撮り直す
                  </button>
                </div>
              : <div>
                  <div style={{fontSize:36,marginBottom:6,opacity:.4}}>📄</div>
                  <div style={{fontSize:12,color:"var(--tx3)",marginBottom:12}}>資格証書・免許証のコピーを撮影して登録できます</div>
                  <div style={{display:"flex",gap:8,justifyContent:"center",flexWrap:"wrap"}}>
                    <button onClick={()=>upd("hasCopy",true)} style={{padding:"10px 20px",borderRadius:10,background:"var(--tl)",border:"none",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
                      📷 カメラで撮影
                    </button>
                    <button onClick={()=>upd("hasCopy",true)} style={{padding:"10px 20px",borderRadius:10,background:"var(--wh)",border:"1.5px solid var(--tl)",color:"var(--tl)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
                      🖼️ ファイルから選択
                    </button>
                  </div>
                </div>
            }
          </div>
        </div>

        <div style={{marginBottom:16}}>
          <label style={{fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,display:"block",marginBottom:5}}>備考</label>
          <textarea className="fta" style={{minHeight:60}} placeholder="更新予定・注意事項など" value={form.note} onChange={e=>upd("note",e.target.value)}/>
        </div>

        <button className="bsave" onClick={saveDoc}>資格証書を登録する</button>
      </div>
    </div>
  );

  // ===== 詳細メイン =====
  return (
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={onBack}>← 戻る</button>
        <div className="fl-title">👤 {s.name}</div>
        {isMgr&&<button className="bexp" style={{marginLeft:"auto"}} onClick={onEdit}>✏️ 編集</button>}
        {isMgr&&<button onClick={()=>{
          if(window.confirm(s.name+"さんのデータを完全に削除しますか？\nこの操作は取り消せません。")){
            store.delStaff(s.id);
            onBack();
          }
        }} style={{padding:"6px 12px",borderRadius:8,background:"rgba(224,56,56,0.15)",border:"1.5px solid rgba(224,56,56,0.4)",color:"var(--ro)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",marginLeft:6}}>🗑️ 削除</button>}
      </div>

      {/* プロフィール */}
      <div style={{background:"linear-gradient(135deg,var(--tl),var(--gr))",borderRadius:12,padding:"16px 18px",marginBottom:14,color:"#fff",display:"flex",gap:14,alignItems:"center"}}>
        <div style={{width:56,height:56,borderRadius:"50%",background:"rgba(255,255,255,0.25)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:26,fontWeight:900,flexShrink:0}}>
          {s.name.charAt(0)}
        </div>
        <div style={{flex:1}}>
          <div style={{fontSize:20,fontWeight:900,marginBottom:2}}>{s.name}</div>
          <div style={{fontSize:12,opacity:.85}}>{fac?.name} ／ {s.role==="manager"?"管理者":s.role==="cdsm"?"児童発達支援管理責任者":s.role==="specialist"?"専門職員":s.role==="part_qual"?"パート（指導員）":s.role==="part_noqual"?"パート（資格なし）":s.role==="consultant"?"相談支援員":"支援員"} ／ {s.employmentType||"正社員"}</div>
          {s.dob&&<div style={{fontSize:11,opacity:.75,marginTop:2}}>{s.dob}生（{age}歳）</div>}
        </div>
      </div>

      {/* 基本情報タイル */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:8,marginBottom:14}}>
        {[
          {label:"入職日",val:s.hireDate||"—",icon:"📅"},
          {label:"携帯",val:s.tel||"—",icon:"📞"},
          {label:"有給残",val:remaining+"日",icon:"🌴",color:remaining<=3?"var(--ro)":remaining<=7?"var(--am)":"var(--gr)"},
          {label:"次回有給付与",val:nextGrantDate(s.hireDate),icon:"🎁"},
        ].map(item=><div key={item.label} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"11px 13px",boxShadow:"var(--sh)"}}>
          <div style={{fontSize:10,color:"var(--tx3)",marginBottom:3}}>{item.icon} {item.label}</div>
          <div style={{fontSize:13,fontWeight:700,color:item.color||"var(--tx)"}}>{item.val}</div>
        </div>)}
      </div>

      {/* 資格・証書一覧 */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
        <div style={{fontSize:14,fontWeight:900,color:"var(--tx)"}}>📄 資格・証書一覧</div>
        {isMgr&&<button className="bsave" style={{width:"auto",padding:"8px 16px",marginTop:0,fontSize:12}} onClick={()=>setAddMode(true)}>
          ＋ 登録する
        </button>}
      </div>

      {/* 有効期限アラート */}
      {myDocs.filter(d=>isExpiring(d)==="expired"||isExpiring(d)==="soon").length>0&&(
        <div style={{background:"rgba(224,56,56,0.08)",border:"1px solid rgba(224,56,56,0.4)",borderRadius:10,padding:"10px 14px",marginBottom:12}}>
          <div style={{fontSize:12,fontWeight:700,color:"var(--ro)",marginBottom:4}}>⚠ 要確認の資格証書</div>
          {myDocs.filter(d=>isExpiring(d)==="expired").map(d=><div key={d.id} style={{fontSize:12,color:"var(--ro)"}}>・{d.name||d.category}（期限切れ: {d.expiryDate}）</div>)}
          {myDocs.filter(d=>isExpiring(d)==="soon").map(d=><div key={d.id} style={{fontSize:12,color:"var(--am)"}}>・{d.name||d.category}（期限間近: {d.expiryDate}）</div>)}
        </div>
      )}

      {myDocs.length===0
        ? <div style={{textAlign:"center",color:"var(--tx3)",padding:"36px 0",fontSize:13,background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:11,boxShadow:"var(--sh)"}}>
            資格証書が登録されていません<br/>
            {isMgr&&<button className="bsave" style={{width:"auto",padding:"9px 20px",marginTop:14,fontSize:13}} onClick={()=>setAddMode(true)}>＋ 最初の証書を登録する</button>}
          </div>
        : <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(150px,1fr))",gap:10,paddingBottom:28}}>
            {myDocs.map(d=>{
              const st=isExpiring(d);
              const es=expStyle(st);
              const cardBorderColor = st==="expired"?"rgba(224,56,56,0.4)":st==="soon"?"rgba(224,168,40,0.4)":"var(--bd)";
              return <div key={d.id} style={{background:"var(--wh)",border:"1.5px solid "+cardBorderColor,borderRadius:11,padding:13,cursor:"pointer",boxShadow:"var(--sh)",transition:"all .15s"}}
                onClick={()=>setViewDoc(d)}
                onMouseEnter={e=>e.currentTarget.style.borderColor="var(--tl)"}
                onMouseLeave={e=>e.currentTarget.style.borderColor=st==="expired"?"rgba(224,56,56,0.4)":st==="soon"?"rgba(224,168,40,0.4)":"var(--bd)"}>
                {/* アイコン */}
                <div style={{width:"100%",aspectRatio:"4/3",background:d.hasCopy?"rgba(58,160,216,0.12)":"var(--bg2)",borderRadius:8,display:"flex",alignItems:"center",justifyContent:"center",fontSize:28,marginBottom:9}}>
                  {d.hasCopy?"📄":"🔖"}
                </div>
                <div style={{fontSize:11,fontWeight:900,marginBottom:3,lineHeight:1.4}}>{d.name||d.category}</div>
                <div style={{fontSize:10,color:"var(--tx3)",marginBottom:6}}>{d.category}</div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <span style={{fontSize:9,padding:"2px 7px",borderRadius:7,fontWeight:700,background:es.bg,color:es.color}}>{es.label}</span>
                  {d.hasCopy&&<span style={{fontSize:9,color:"var(--tl)",fontWeight:700}}>📷コピー有</span>}
                </div>
                {d.expiryDate&&<div style={{fontSize:9,color:"var(--tx3)",marginTop:4}}>期限: {d.expiryDate}</div>}
              </div>;
            })}
          </div>
      }
    </div>
  );
}

// ==================== スタッフ管理 ====================
function StaffManagement({user, store, onBack}){
  const [screen, setScreen] = useState("list"); // list | register | edit | detail
  const [selStaff, setSelStaff] = useState(null);
  const [bulkMode, setBulkMode] = useState(false); // 一括削除モード
  const [checked, setChecked] = useState([]);       // 選択中のスタッフID
  const isMgr = user.role==="manager"||user.role==="admin";
  const staffList = store.dynStaff.filter(s=>user.role==="admin"||s.facilityId===user.selectedFacilityId);
  const active = staffList.filter(s=>s.active!==false);
  const inactive = staffList.filter(s=>s.active===false);

  // 一括削除実行
  const bulkDelete = () => {
    if(checked.length===0) return;
    if(!window.confirm(`選択した ${checked.length} 名を完全に削除しますか？\nこの操作は取り消せません。`)) return;
    checked.forEach(id => store.delStaff(id));
    setChecked([]);
    setBulkMode(false);
  };
  const toggleCheck = (id) => setChecked(p => p.includes(id) ? p.filter(x=>x!==id) : [...p, id]);
  const checkAll = () => setChecked(active.map(s=>s.id));

  // ===== 詳細・資格証書 =====
  if(screen==="detail"&&selStaff){
    return <StaffDetail s={selStaff} store={store} isMgr={isMgr}
      onBack={()=>setScreen("list")}
      onEdit={()=>setScreen("edit")}
    />;
  }

  // ===== 登録 / 編集 =====
  if(screen==="register"||screen==="edit"){
    const isEdit = screen==="edit";
    const init = isEdit&&selStaff ? {...selStaff} : {
      id:"", name:"", facilityId:user.selectedFacilityId||"f1",
      role:"staff", dob:"", gender:"", tel:"", email:"",
      address:"", emergencyName:"", emergencyTel:"", emergencyRelation:"",
      qualification:"", qualifications:[], hireDate:todayISO(), employmentType:"正社員",
      bankName:"", bankBranch:"", bankAccountType:"普通", bankAccountNo:"", bankAccountName:"",
      loginId:"", loginPassword:"",
      note:"", active:true
    };
    return <RegisterStaff init={init} isEdit={isEdit} user={user} store={store}
      onBack={()=>setScreen("list")}
      onSave={async s=>{
        let staffId = s.id;
        if(isEdit){ store.updStaff2(s.id,s); }
        else {
          // 意味のあるID: S-GH-0001 形式で採番
          staffId = genStaffId(s.facilityId||user.selectedFacilityId, store.dynStaff);
          store.addStaff({...s, id: staffId});
        }
        // ログインID/パスワードが入力されていれば Supabase Auth アカウントを作成/更新（ログイン可能にする）
        // パスワードは本APIでAuthにのみ渡り、DBには平文保存しない
        if(s.loginId && s.loginPassword){
          try{
            const r=await fetch("/api/create-staff",{method:"POST",headers:{"Content-Type":"application/json"},
              body:JSON.stringify({loginId:String(s.loginId).trim(),password:s.loginPassword,name:s.name,role:s.role,facilityId:s.facilityId,staffId})});
            const j=await r.json().catch(()=>({}));
            if(r.ok&&j.success) store.showToast("ログインアカウントを"+(j.action==="created"?"作成":"更新")+"しました ✅","success");
            else store.showToast("ログインアカウント作成に失敗: "+(j.error||"不明なエラー"),"error");
          }catch(e){ store.showToast("ログインアカウント作成に失敗しました（通信エラー）","error"); }
        }
        setScreen("list");
      }}
    />;
  }

  // ===== 一覧 =====
  const StaffCard = ({s}) => {
    const fac = FACILITIES.find(f=>f.id===s.facilityId);
    const isChecked = checked.includes(s.id);
    return <div onClick={bulkMode?()=>toggleCheck(s.id):undefined}
      style={{background:bulkMode&&isChecked?"rgba(224,56,56,0.08)":"var(--wh)",border:`1.5px solid ${bulkMode&&isChecked?"var(--ro)":"var(--bd)"}`,borderRadius:12,padding:14,boxShadow:"var(--sh)",transition:"all .15s",opacity:s.active===false?.6:1,cursor:bulkMode?"pointer":"default"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:9}}>
        <div style={{display:"flex",alignItems:"center",gap:10}}>
          {/* 一括削除モード時はチェックボックス表示 */}
          {bulkMode&&<input type="checkbox" checked={isChecked} onChange={()=>toggleCheck(s.id)}
            onClick={e=>e.stopPropagation()}
            style={{width:18,height:18,accentColor:"var(--ro)",cursor:"pointer",flexShrink:0}}/>}
          <div style={{width:42,height:42,borderRadius:"50%",background:s.role==="manager"?"linear-gradient(135deg,var(--tl),var(--tl))":"linear-gradient(135deg,var(--gr),var(--tl))",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,color:"#fff",fontWeight:700,flexShrink:0}}>
            {s.name.charAt(0)}
          </div>
          <div>
            <div style={{fontWeight:900,fontSize:14}}>{s.name}{s.active===false&&<span style={{fontSize:10,color:"var(--bda)",marginLeft:5}}>（無効）</span>}</div>
            <div style={{fontSize:11,color:"var(--tx3)",marginTop:1}}>{fac?.name}</div>
          </div>
        </div>
        {!bulkMode&&<div style={{display:"flex",gap:6,alignItems:"center"}}>
          <span style={{fontSize:10,padding:"3px 9px",borderRadius:10,fontWeight:700,background:s.role==="manager"?"rgba(58,160,216,0.2)":s.role==="admin"?"rgba(144,72,216,0.18)":"rgba(44,170,96,0.2)",color:s.role==="manager"?"var(--tl)":s.role==="admin"?"var(--pu)":"var(--gr)"}}>
            {s.role==="manager"?"施設管理者":s.role==="admin"?"本部管理者":"一般職員"}
          </span>
          <button onClick={()=>{setSelStaff(s);setScreen("detail");}} style={{padding:"4px 9px",borderRadius:7,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"rgba(58,160,216,0.1)",border:"1.5px solid rgba(58,160,216,0.35)",color:"var(--tl)"}}>詳細</button>
          {isMgr&&<button onClick={()=>{setSelStaff(s);setScreen("edit");}} style={{padding:"4px 9px",borderRadius:7,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg)",border:"1.5px solid var(--bd)",color:"var(--tx3)"}}>編集</button>}
        </div>}
        {bulkMode&&<span style={{fontSize:10,padding:"3px 9px",borderRadius:10,fontWeight:700,background:s.role==="manager"?"rgba(58,160,216,0.2)":s.role==="admin"?"rgba(144,72,216,0.18)":"rgba(44,170,96,0.2)",color:s.role==="manager"?"var(--tl)":s.role==="admin"?"var(--pu)":"var(--gr)"}}>
          {s.role==="manager"?"施設管理者":s.role==="admin"?"本部管理者":"一般職員"}
        </span>}
      </div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",fontSize:11,color:"var(--tx3)"}}>
        {s.employmentType&&<span style={{padding:"2px 7px",borderRadius:7,background:"var(--bg)",border:"1px solid var(--bd)"}}>{s.employmentType}</span>}
        {s.hireDate&&<span>入職: {s.hireDate}</span>}
        {(s.qualifications&&s.qualifications.length>0)
        ? s.qualifications.map(q=><span key={q} style={{padding:"2px 7px",borderRadius:7,background:"rgba(58,160,216,0.1)",border:"1px solid rgba(58,160,216,0.35)",color:"var(--tl)",marginRight:4,marginBottom:4,display:"inline-block"}}>{q}</span>)
        : s.qualification&&<span style={{padding:"2px 7px",borderRadius:7,background:"rgba(58,160,216,0.1)",border:"1px solid rgba(58,160,216,0.35)",color:"var(--tl)"}}>{s.qualification}</span>}
        {s.tel&&<span>📞 {s.tel}</span>}
      </div>
      <div style={{marginTop:7,padding:"6px 10px",background:"var(--bg)",borderRadius:7,display:"flex",gap:12,fontSize:11}}>
        {(()=>{const g=calcGrantedDays(s.hireDate,s.workDaysPerWeek||5);const u=calcUsedDays(s.id,store.paidLeaveReqs);const r=Math.max(0,g-u);return <>
          <span>付与: <strong style={{color:"var(--tl)"}}>{g}日</strong></span>
          <span>取得: <strong style={{color:"var(--am)"}}>{u}日</strong></span>
          <span>残: <strong style={{color:r<=3?"var(--ro)":r<=7?"var(--am)":"var(--gr)"}}>{r}日</strong></span>
        </>;})()} 
      </div>
    </div>;
  };

  return <div className="fl-wrap">
    <div className="fl-hd"><button className="bback" onClick={onBack}>← 戻る</button><div className="fl-title">👥 スタッフ管理</div></div>

    {/* ボタンエリア */}
    {isMgr&&!bulkMode&&<div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
      <button className="bsave" style={{maxWidth:200}} onClick={()=>setScreen("register")}>＋ 新規スタッフ登録</button>
      <button onClick={()=>{setBulkMode(true);setChecked([]);}}
        style={{padding:"9px 16px",borderRadius:9,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"rgba(224,56,56,0.1)",border:"1.5px solid rgba(224,56,56,0.4)",color:"var(--ro)"}}>
        🗑️ まとめて削除
      </button>
    </div>}

    {/* 一括削除モード バー */}
    {bulkMode&&<div style={{background:"rgba(224,56,56,0.08)",border:"1.5px solid rgba(224,56,56,0.4)",borderRadius:11,padding:"12px 14px",marginBottom:14,display:"flex",gap:10,alignItems:"center",flexWrap:"wrap"}}>
      <span style={{fontSize:13,fontWeight:700,color:"var(--ro)"}}>🗑️ 削除モード</span>
      <span style={{fontSize:12,color:"var(--tx3)"}}>{checked.length}名選択中</span>
      <button onClick={checkAll} style={{padding:"6px 12px",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg)",border:"1.5px solid var(--bd)",color:"var(--tx2)"}}>全選択</button>
      <button onClick={()=>setChecked([])} style={{padding:"6px 12px",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg)",border:"1.5px solid var(--bd)",color:"var(--tx2)"}}>選択解除</button>
      <button onClick={bulkDelete} disabled={checked.length===0}
        style={{padding:"6px 16px",borderRadius:8,fontSize:12,fontWeight:700,cursor:checked.length===0?"not-allowed":"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:checked.length===0?"var(--bg)":"var(--ro)",border:"none",color:checked.length===0?"var(--tx3)":"#fff",opacity:checked.length===0?.5:1}}>
        {checked.length}名を削除
      </button>
      <button onClick={()=>{setBulkMode(false);setChecked([]);}}
        style={{padding:"6px 12px",borderRadius:8,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg)",border:"1.5px solid var(--bd)",color:"var(--tx3)",marginLeft:"auto"}}>
        キャンセル
      </button>
    </div>}

    <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
      <div style={{background:"rgba(58,160,216,0.2)",borderRadius:9,padding:"9px 14px",fontSize:13,fontWeight:700,color:"var(--tl)"}}>在籍 {active.length}名</div>
      {inactive.length>0&&<div style={{background:"var(--bg)",borderRadius:9,padding:"9px 14px",fontSize:13,fontWeight:700,color:"var(--tx3)"}}>退職 {inactive.length}名</div>}
    </div>
    <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",letterSpacing:2,marginBottom:8}}>在籍スタッフ</div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:10,marginBottom:20}}>
      {active.map(s=><StaffCard key={s.id} s={s}/>)}
      {active.length===0&&<div style={{color:"var(--tx3)",fontSize:13,padding:"20px 0"}}>スタッフがいません</div>}
    </div>
    {inactive.length>0&&<><div style={{fontSize:11,fontWeight:700,color:"var(--tx3)",letterSpacing:2,marginBottom:8}}>退職・無効スタッフ</div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(260px,1fr))",gap:10,paddingBottom:28}}>
      {inactive.map(s=><StaffCard key={s.id} s={s}/>)}
    </div></>}
  </div>;
}

function RegisterStaff({init, isEdit, user, store, onBack, onSave}){
  const [form, setForm] = useState({...init});
  const upd = (k,v) => setForm(p=>({...p,[k]:v}));
  const [errors, setErrors] = useState({});

  const validate = () => {
    const e = {};
    if(!form.name?.trim()) e.name = "氏名は必須です";
    if(!form.facilityId) e.facilityId = "施設は必須です";
    // ログインIDの重複チェック（新規登録時のみ）
    if(!isEdit && form.loginId?.trim()){
      const taken = ACCOUNTS.some(a=>a.username===form.loginId)
        || (store.dynStaff||[]).some(s=>s.id!==form.id && s.loginId===form.loginId);
      if(taken) e.loginId = "このログインIDは既に使われています";
    }
    if(!isEdit && form.loginId?.trim() && !form.loginPassword?.trim()) e.loginPassword = "パスワードを入力してください";
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  // FormSection・FormFieldは外部定義を使用
  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">{isEdit?"✏️ スタッフ情報 編集":"➕ スタッフ 新規登録"}</div>
    </div>

    <FormSection title="■ 基本情報" color="var(--tl)">
      <FormField form={form} upd={upd} errors={errors}  label="氏名（フルネーム）" fkey="name" placeholder="田中 美穂" required/>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors}  label="生年月日" fkey="dob" type="date"/>
        <FormField form={form} upd={upd} errors={errors}  label="性別" fkey="gender" options={[{value:"",label:"選択"},{value:"男",label:"男"},{value:"女",label:"女"},{value:"その他",label:"その他"}]}/>
      </div>
      <FormField form={form} upd={upd} errors={errors}  label="所属施設" fkey="facilityId" required
        options={[{value:"",label:"選択してください"},...FACILITIES.map(f=>({value:f.id,label:f.name}))]}/>
      <FormField form={form} upd={upd} errors={errors}  label="役職・権限" fkey="role"
        options={[{value:"staff",label:"支援員"},{value:"specialist",label:"専門職員"},{value:"cdsm",label:"児童発達支援管理責任者"},{value:"manager",label:"管理者"},{value:"part_qual",label:"パート（指導員）"},{value:"part_noqual",label:"パート（資格なし）"},{value:"consultant",label:"相談支援員"}]}/>
      <FormField form={form} upd={upd} errors={errors}  label="雇用形態" fkey="employmentType"
        options={["正社員","パート・アルバイト","契約社員","派遣","業務委託"].map(v=>({value:v,label:v}))}/>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors}  label="入職日" fkey="hireDate" type="date"/>
      </div>
      <div style={{marginBottom:12}}>
        <label style={{display:"block",fontSize:10,fontWeight:700,color:"var(--tx2)",letterSpacing:1,marginBottom:6}}>資格・役職（複数選択可）</label>
        <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
          {QUAL_CATEGORIES.map(c=>{
            const selected = (form.qualifications||[]).includes(c);
            return <button key={c} type="button" onClick={()=>{
              const cur = form.qualifications||[];
              upd("qualifications", selected ? cur.filter(x=>x!==c) : [...cur, c]);
            }} style={{padding:"6px 12px",borderRadius:9,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:selected?"var(--tl)":"var(--bd)",background:selected?"rgba(58,160,216,0.2)":"var(--bg)",color:selected?"var(--tl)":"var(--tx2)"}}>
              {selected?"✓ ":""}{c}
            </button>;
          })}
        </div>
        {(form.qualifications||[]).length>0&&<div style={{marginTop:8,fontSize:11,color:"var(--tx3)"}}>選択中: {(form.qualifications||[]).join("・")}</div>}
      </div>
    </FormSection>

    <FormSection title="■ 連絡先情報" color="var(--ac)">
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors}  label="携帯電話" fkey="tel" placeholder="090-XXXX-XXXX" type="tel"/>
        <FormField form={form} upd={upd} errors={errors}  label="メールアドレス" fkey="email" placeholder="xxx@example.com" type="email"/>
      </div>
      <FormField form={form} upd={upd} errors={errors}  label="住所" fkey="address" placeholder="○○市△△1-2-3"/>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors}  label="緊急連絡先 氏名" fkey="emergencyName" placeholder="田中 次郎"/>
        <FormField form={form} upd={upd} errors={errors}  label="続柄" fkey="emergencyRelation" placeholder="父"/>
        <FormField form={form} upd={upd} errors={errors}  label="緊急連絡先 電話" fkey="emergencyTel" placeholder="090-XXXX-XXXX" type="tel"/>
      </div>
    </FormSection>

    <FormSection title="■ 給与振込口座" color="var(--gr)">
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors}  label="銀行名" fkey="bankName" placeholder="○○銀行"/>
        <FormField form={form} upd={upd} errors={errors}  label="支店名" fkey="bankBranch" placeholder="○○支店"/>
        <FormField form={form} upd={upd} errors={errors}  label="口座種別" fkey="bankAccountType"
          options={["普通","当座"].map(v=>({value:v,label:v}))}/>
        <FormField form={form} upd={upd} errors={errors}  label="口座番号" fkey="bankAccountNo" placeholder="1234567"/>
      </div>
      <FormField form={form} upd={upd} errors={errors}  label="口座名義（カタカナ）" fkey="bankAccountName" placeholder="タナカ ミホ"/>
    </FormSection>

    {/* ===== ログイン情報 ===== */}
    <FormSection title="■ ログイン情報" color="var(--pu)">
      <div style={{background:"rgba(144,72,216,0.07)",border:"1px solid rgba(144,72,216,0.25)",borderRadius:9,padding:"10px 12px",marginBottom:10,fontSize:12,color:"var(--tx3)"}}>
        🔑 ここで設定したIDとパスワードでアプリにログインできます。<br/>空欄のままにするとログイン不可となります。
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"0 12px"}}>
        <FormField form={form} upd={upd} errors={errors} label="ログインID" fkey="loginId" placeholder="例）tanaka-miho"/>
        <FormField form={form} upd={upd} errors={errors} label="パスワード" fkey="loginPassword" placeholder="例）pass1234"/>
      </div>
      {isEdit&&<div style={{fontSize:11,color:"var(--tx3)",marginTop:4}}>※ パスワードを変更しない場合は空欄のままにしてください</div>}
    </FormSection>

    <FormSection title="■ 備考" color="var(--tx3)">
      <textarea className="fta" style={{minHeight:72}} placeholder="特記事項・備考など" value={form.note||""} onChange={e=>upd("note",e.target.value)}/>
    </FormSection>

    {isEdit&&<div style={{background:"rgba(224,56,56,0.08)",border:"1px solid rgba(224,56,56,0.4)",borderRadius:11,padding:14,marginBottom:12}}>
      <div style={{fontSize:11,fontWeight:700,color:"var(--ro)",marginBottom:8}}>⚠ 在籍状況の変更</div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={()=>upd("active",true)} style={{padding:"8px 18px",borderRadius:8,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:form.active!==false?"rgba(44,170,96,0.4)":"var(--bd)",background:form.active!==false?"rgba(44,170,96,0.2)":"var(--bg)",color:form.active!==false?"var(--gr)":"var(--tx3)"}}>在籍中</button>
        <button onClick={()=>upd("active",false)} style={{padding:"8px 18px",borderRadius:8,fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:form.active===false?"rgba(224,56,56,0.4)":"var(--bd)",background:form.active===false?"rgba(224,56,56,0.15)":"var(--bg)",color:form.active===false?"var(--ro)":"var(--tx3)"}}>退職・無効</button>
      </div>
    </div>}

    <div style={{display:"flex",gap:10,paddingBottom:32}}>
      <button className="bsave" style={{background:"var(--bg)",color:"var(--tx2)",border:"1.5px solid var(--bd)"}} onClick={onBack}>キャンセル</button>
      <button className="bsave" style={{flex:2}} onClick={()=>{if(validate()) onSave(form);}}>{isEdit?"変更を保存する":"登録する"}</button>
    </div>
  </div>;
}

// ==================== HOME ====================
function HomeScreen({user,onNav,store}){
  const fac=FACILITIES.find(f=>f.id===user.selectedFacilityId);
  const isMgr=user.role==="manager"||user.role==="admin";
  const today=todayISO();

  // ===== 今日のデータ集計 =====
  const myFac = r => user.role==="admin" || (r.facilityId||r.facility_id)===user.selectedFacilityId;
  const todayRecs = store.recs.filter(r=>isTodayRec(r)&&myFac(r));

  const staffInToday = [...new Set(todayRecs.filter(r=>r.type==="staff_in").map(r=>r.staffId))].length;
  const arrivedIds   = [...new Set(todayRecs.filter(r=>r.type==="user_in").map(r=>r.userId))];
  const departedIds  = [...new Set(todayRecs.filter(r=>r.type==="user_out").map(r=>r.userId))];
  const serviceIds   = [...new Set(todayRecs.filter(r=>r.type==="service").map(r=>r.userId))];

  // 現在在所中（来所済み & 退所していない）
  const inFacility = arrivedIds.filter(id=>!departedIds.includes(id));
  // サービス記録未入力（来所済みだが未入力）
  const unrecordedIds = inFacility.filter(id=>!serviceIds.includes(id));
  // 今日の来所予定者（attデータから）
  const myUsers = store.dynUsers.filter(u=>u.active!==false&&(user.role==="admin"||u.facilityId===user.selectedFacilityId));
  const scheduledToday = myUsers.filter(u=>{
    const att=store.getAtt(u.id,today);
    return att==="予定"||att==="出席";
  });
  // 送迎予定（送迎フラグ付きの来所予定者）
  const transportUsers = scheduledToday.filter(u=>{
    const tr=store.trData.find(t=>t.userId===u.id);
    return tr&&(tr.method==="car"||tr.method==="bus");
  });

  // ===== アラート生成 =====
  const alerts = buildTodayAlerts(user,store);
  // 送迎予定アラートを先頭に追加（来所前）
  if(transportUsers.length>0){
    alerts.unshift({level:"info",icon:"🚗",text:`送迎予定 ${transportUsers.length}名（来所前）`,screen:"transport"});
  }

  // ===== 今日の残件（名前付き・優先度カラー） =====
  const getId2Name=id=>myUsers.find(u=>u.id===id)?.name||id;
  const todoItems=[];
  // danger: 体温 37.5以上の利用者（要注意）
  const highTempIds=[...new Set(todayRecs.filter(r=>r.type==="user_in"&&parseFloat(r.temp)>=37.5).map(r=>r.userId))];
  if(highTempIds.length>0){
    todoItems.push({level:"danger",icon:"🌡️",title:"高体温 要確認",names:highTempIds.map(getId2Name).filter(Boolean),screen:"user_arrive"});
  }
  // warn: サービス記録未入力
  if(unrecordedIds.length>0){
    todoItems.push({level:"warn",icon:"📋",title:"サービス記録 未入力",names:unrecordedIds.map(getId2Name).filter(Boolean),screen:"service"});
  }
  // warn: 体温未入力（来所済み）
  const noTempUserIds=[...new Set(todayRecs.filter(r=>r.type==="user_in"&&(!r.temp||r.temp==="")).map(r=>r.userId))];
  if(noTempUserIds.length>0){
    todoItems.push({level:"warn",icon:"🌡️",title:"体温 未入力",names:noTempUserIds.map(getId2Name).filter(Boolean),screen:"user_arrive",ids:noTempUserIds});
  }
  // warn: 写真記録なし（在所中）
  const photoIds=[...new Set(todayRecs.filter(r=>r.type==="photo").map(r=>r.userId))];
  const noPhotoIds=inFacility.filter(id=>!photoIds.includes(id));
  if(noPhotoIds.length>0){
    todoItems.push({level:"warn",icon:"📸",title:"写真記録 未撮影",names:noPhotoIds.map(getId2Name).filter(Boolean),screen:"photo"});
  }
  // info: 送迎未完了（来所済み・退所記録なし・送迎あり）
  const transportDoneIds=[...new Set(todayRecs.filter(r=>r.type==="user_out").map(r=>r.userId))];
  const transportWaitIds=inFacility.filter(id=>{
    const rec=todayRecs.filter(r=>r.type==="user_in"&&r.userId===id).slice(-1)[0];
    return rec?.transport==="あり";
  }).filter(id=>!transportDoneIds.includes(id));
  if(transportWaitIds.length>0){
    todoItems.push({level:"info",icon:"🚌",title:"送迎 未完了",names:transportWaitIds.map(getId2Name).filter(Boolean),screen:"transport"});
  }
  // info: 未読連絡
  const unreadCount2=store.msgs.filter(m=>(user.role==="admin"||m.facilityId===user.selectedFacilityId)&&!m.read).length;
  if(unreadCount2>0){
    todoItems.push({level:"info",icon:"💬",title:`保護者連絡 未読`,names:[`${unreadCount2}件の未読メッセージ`],screen:"messages"});
  }
  // info: ISP期限間近（30日以内）
  const now2=new Date();
  const ispSoonNames=(store.isps||[]).filter(isp=>{
    if(!isp.endDate) return false;
    const d=Math.ceil((new Date(isp.endDate)-now2)/(1000*60*60*24));
    return d>=0&&d<=30;
  }).map(isp=>isp.userName||(myUsers.find(u=>u.id===isp.userId)?.name)||"不明");
  if(ispSoonNames.length>0){
    todoItems.push({level:"info",icon:"📄",title:"ISP 期限間近（30日以内）",names:ispSoonNames,screen:"users"});
  }
  // W5: 受給者証 期限アラート（期限切れ・30日以内・60日以内）
  const myJkDocs=(store.jukyushaDocs||[]).filter(d=>{
    const u=myUsers.find(u=>u.id===d.userId);
    return u&&d.status==="有効"&&d.expiryDate;
  });
  const getName2=d=>myUsers.find(u=>u.id===d.userId)?.name||"不明";
  const jkExpired=myJkDocs.filter(d=>new Date(d.expiryDate)<now2);
  const jk30=myJkDocs.filter(d=>{const diff=Math.ceil((new Date(d.expiryDate)-now2)/(86400000));return diff>=0&&diff<=30;});
  const jk60=myJkDocs.filter(d=>{const diff=Math.ceil((new Date(d.expiryDate)-now2)/(86400000));return diff>30&&diff<=60;});
  if(jkExpired.length>0) todoItems.push({level:"danger",icon:"📋",title:"受給者証 期限切れ",names:jkExpired.map(getName2),screen:"users"});
  if(jk30.length>0)      todoItems.push({level:"warn",  icon:"📋",title:"受給者証 30日以内に期限切れ",names:jk30.map(getName2),screen:"users"});
  if(jk60.length>0)      todoItems.push({level:"info",  icon:"📋",title:"受給者証 60日以内に期限切れ",names:jk60.map(getName2),screen:"users"});
  // 管理者・施設長のみ: 職員書類アラート
  if(isMgr){
    const sdToday=new Date();
    const facCheck = s => user.role==="admin" || s.facilityId===user.selectedFacilityId;
    const activeS = (store.dynStaff||[]).filter(s=>s.active!==false&&facCheck(s));
    // 期限切れ書類
    const expiredDocs=(store.staffDocs||[]).filter(d=>{
      const ds=d.expiryDate||d.endDate; if(!ds) return false;
      const s=(store.dynStaff||[]).find(x=>x.id===d.staffId); if(!facCheck(s||{})) return false;
      return new Date(ds)<sdToday;
    });
    // 30日以内期限
    const soon30Docs=(store.staffDocs||[]).filter(d=>{
      const ds=d.expiryDate||d.endDate; if(!ds) return false;
      const s=(store.dynStaff||[]).find(x=>x.id===d.staffId); if(!facCheck(s||{})) return false;
      const diff=Math.floor((new Date(ds)-sdToday)/(1000*60*60*24));
      return diff>=0&&diff<=30;
    });
    // 必須書類未提出職員
    const reqTypes=STAFF_DOC_TYPES.filter(t=>t.required);
    const missingDocStaff=activeS.filter(s=>reqTypes.some(t=>!(store.staffDocs||[]).find(d=>d.staffId===s.id&&d.documentType===t.id)));
    // 未対応更新依頼
    const pendingReqs=(store.staffDocRequests||[]).filter(r=>{
      const s=(store.dynStaff||[]).find(x=>x.id===r.staffId); if(!facCheck(s||{})) return false;
      return r.status==="送信済み"||r.status==="対応中";
    });
    if(expiredDocs.length>0) todoItems.push({level:"danger",icon:"📂",title:"職員書類 期限切れ",names:[`${expiredDocs.length}件が期限切れ`],screen:"staff_documents"});
    if(soon30Docs.length>0) todoItems.push({level:"warn",icon:"📂",title:"職員書類 30日以内期限",names:[`${soon30Docs.length}件`],screen:"staff_documents"});
    if(missingDocStaff.length>0) todoItems.push({level:"warn",icon:"📂",title:"職員書類 必須未提出",names:[`${missingDocStaff.length}名`],screen:"staff_documents"});
    if(pendingReqs.length>0) todoItems.push({level:"info",icon:"📬",title:"書類提出依頼 未完了",names:[`${pendingReqs.length}件`],screen:"staff_documents"});
    // 返戻期限超過チェック
    const overdueRets=(store.claimHistory||[]).filter(r=>(user.role==="admin"||r.facility_id===user.selectedFacilityId)&&r.status==="returned"&&r.correction_deadline&&r.correction_deadline<new Date().toISOString().slice(0,10));
    if(overdueRets.length>0) todoItems.push({level:"danger",icon:"↩️",title:"返戻 修正期限超過",names:[`${overdueRets.length}件の返戻が期限切れ`],screen:"returns"});
    // 返戻14日以内期限
    const soonRets=(store.claimHistory||[]).filter(r=>{
      if(r.status!=="returned"||!r.correction_deadline) return false;
      if(user.role!=="admin"&&r.facility_id!==user.selectedFacilityId) return false;
      const d=new Date(r.correction_deadline);const diff=Math.floor((d-new Date())/(1000*60*60*24));
      return diff>=0&&diff<=14;
    });
    if(soonRets.length>0) todoItems.push({level:"warn",icon:"↩️",title:"返戻 期限14日以内",names:[`${soonRets.length}件の返戻が期限近迫`],screen:"returns"});
  }

  // ===== クイックアクション =====
  const quickCards=[
    {id:"clock_in",  icon:"🟢",title:"職員 出勤",  desc:"打刻・体温",  cls:"c1"},
    {id:"clock_out", icon:"🟡",title:"職員 退勤",  desc:"退勤打刻",    cls:"c2"},
    {id:"user_arrive",icon:"🌟",title:"利用者 来所",desc:"来所・体温",  cls:"c3"},
    {id:"user_depart",icon:"🏠",title:"利用者 退所",desc:"退所記録",    cls:"c4"},
    {id:"service",   icon:"📋",title:"サービス記録",desc:"支援内容",    cls:"c3"},
    {id:"messages",  icon:"💬",title:"保護者連絡", desc:"連絡帳",      cls:"c9"},
    {id:"daily",     icon:"📓",title:"業務日報",   desc:"日報作成",    cls:"c8"},
    {id:"photo",     icon:"📸",title:"写真記録",   desc:"活動・撮影",  cls:"c5"},
    {id:"jisseki",     icon:"📋",title:"実績管理",        desc:"当日来所・打刻",      cls:"c8"},
    {id:"support_plan",icon:"📄",title:"個別支援計画",    desc:"5領域・AI補助・監査",  cls:"c3"},
    {id:"schedule_ocr",icon:"🗓️",title:"予定表 読み取り",desc:"カメラでOCR自動登録",cls:"c6"},
    {id:"activity_calendar",icon:"📅",title:"活動カレンダー",  desc:"店舗別イベント・一括通知",  cls:"c6"},
    {id:"parent_connect",icon:"📢",title:"連絡センター",      desc:"お知らせ・アンケート・欠席",cls:"c5"},
    {id:"transport_live",icon:"🚌",title:"送迎ライブ追跡",   desc:"乗車確認・遅延メモ",    cls:"c9"},
    {id:"kintai_dash",   icon:"⏱",title:"勤怠ダッシュボード",desc:"出勤・36協定・修正申請",cls:"c8"},
    {id:"activity_ai",   icon:"🤖",title:"AI活動記録",      desc:"AI文章自動生成",        cls:"c6"},
    {id:"parent_contacts",icon:"💬",title:"保護者連絡",     desc:"通知・メッセージ管理",  cls:"c5"},
    {id:"photo_album",   icon:"📸",title:"写真アルバム",    desc:"活動写真・保護者共有",  cls:"c3"},
    // 管理者・マネージャーのみ表示
    ...(isMgr?[
      {id:"billing_mgmt",   icon:"💴",title:"請求管理",       desc:"加算・集計・CSV出力",  cls:"c1"},
      {id:"billing_check",  icon:"🔍",title:"請求前チェック",desc:"ミス・漏れを自動確認",cls:"c2"},
      {id:"returns",        icon:"↩️",title:"返戻管理",      desc:"返戻・再請求・ロック",cls:"c4"},
      {id:"staff_monitor",  icon:"👥",title:"スタッフ管理",  desc:"配置・出勤モニター",   cls:"c8"},
      {id:"management_dash",icon:"📊",title:"経営ダッシュボード",desc:"KPI・ISP期限管理", cls:"c3"},
      {id:"audit_mode",     icon:"🔒",title:"監査ログ",      desc:"変更履歴・証跡管理",   cls:"c7"},
      {id:"data_analytics",   icon:"📊",title:"データ分析",    desc:"グラフ・帳票出力",      cls:"c3"},
      {id:"staff_documents",  icon:"📂",title:"職員書類管理",  desc:"契約書・資格証・AI判定", cls:"c7"},
    ]:[]),
  ];

  const getName=id=>(store.dynUsers.find(u=>u.id===id)?.name)||id;

  return <div>
    {/* ===== ヘッダー ===== */}
    <div className="hh">
      <div className="ht">{fac?.name||"全店舗"}</div>
      <div className="hs">今日の現場</div>
      <div className="hd">{todayDisplay()}</div>
    </div>

    {/* ===== アラートセクション ===== */}
    {alerts.length>0&&<div className="dash-section">
      <div className="dash-title">⚠ 要確認</div>
      {alerts.map((a,i)=>(
        <div key={i} className={`alert-row alert-${a.level}`} onClick={()=>onNav(a.screen, a.ids ? {ids:a.ids} : {})}>
          <span className="alert-icon">{a.icon}</span>
          <span className="alert-text lv-${a.level}" style={{color:a.level==="danger"?"var(--ro)":a.level==="warn"?"var(--ac)":a.level==="success"?"var(--gr)":"var(--tl)"}}>{a.text}</span>
          <span className="alert-arrow" style={{color:a.level==="danger"?"var(--ro)":a.level==="warn"?"var(--ac)":"var(--tl)"}}>›</span>
        </div>
      ))}
    </div>}

    {/* ===== 今日の残件（優先度カラー付き） ===== */}
    {todoItems.length>0&&<div className="dash-section">
      <div className="dash-title">📌 今日の残件</div>
      {todoItems.map((item,i)=>(
        <div key={i} className={`todo-card ${item.level||"warn"}`} onClick={()=>onNav(item.screen, item.ids ? {ids:item.ids} : {})} style={{cursor:"pointer"}}>
          <div className="todo-card-hd">
            <span className="todo-card-icon">{item.icon}</span>
            <span className="todo-card-title" style={{color:item.level==="danger"?"var(--ro)":item.level==="info"?"var(--tl)":"var(--ac)"}}>{item.title}</span>
            <span className={`todo-card-count ${item.level||"warn"}`}>{item.names.length}</span>
          </div>
          <div className="todo-names">
            {item.names.map(n=><span key={n} className={`todo-name-chip ${item.level||"warn"}`}>{n}</span>)}
          </div>
        </div>
      ))}
    </div>}

    {/* ===== 今日のサマリー ===== */}
    <div className="stat-grid">
      {[
        {label:"出勤職員",     val:staffInToday,        color:"var(--tl)", icon:"👤"},
        {label:"在所中",       val:inFacility.length,   color:"var(--gr)", icon:"🌟"},
        {label:"来所予定",     val:scheduledToday.length,color:"var(--tx2)",icon:"📅"},
      ].map(s=><div key={s.label} className="stat-card">
        <div className="stat-label">{s.icon} {s.label}</div>
        <div className="stat-val" style={{color:s.color}}>{s.val}</div>
      </div>)}
    </div>

    {/* ===== 在所中ユーザー（サービス記録状況つき）===== */}
    {inFacility.length>0&&<div className="dash-section">
      <div className="dash-title">🌟 在所中 ({inFacility.length}名)</div>
      <div style={{display:"flex",flexWrap:"wrap"}}>
        {inFacility.map(id=>{
          const recorded=serviceIds.includes(id);
          return <span key={id}
            className={`user-tag ${recorded?"user-tag-in":"user-tag-unrecorded"}`}
            onClick={()=>!recorded&&onNav("service")}
            title={recorded?"記録済":"タップでサービス記録へ"}>
            {getName(id)}{recorded?" ✓":" 未記録"}
          </span>;
        })}
      </div>
    </div>}

    {/* ===== 来所待ち（予定だが未到着）===== */}
    {(()=>{
      const waiting=scheduledToday.filter(u=>!arrivedIds.includes(u.id)&&!departedIds.includes(u.id));
      if(waiting.length===0) return null;
      return <div className="dash-section">
        <div className="dash-title">📅 来所待ち ({waiting.length}名)</div>
        <div style={{display:"flex",flexWrap:"wrap"}}>
          {waiting.map(u=><span key={u.id} className="user-tag user-tag-pending">
            {u.name}
          </span>)}
        </div>
      </div>;
    })()}

    <hr className="dash-divider"/>

    {/* ===== W6: よく使う操作（最優先・スタッフ導線） ===== */}
    <div className="dash-title">⚡ よく使う操作</div>
    <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
      {[
        {id:"user_arrive", icon:"🌟", label:"来所記録"},
        {id:"service",     icon:"📋", label:"サービス記録"},
        {id:"transport",   icon:"🚌", label:"送迎"},
        {id:"daily",       icon:"📓", label:"日報"},
        {id:"parent_connect",icon:"📢",label:"欠席・連絡"},
        {id:"messages",    icon:"💬", label:"保護者連絡"},
      ].map(c=>(
        <div key={c.id} onClick={()=>onNav(c.id)}
          style={{background:"var(--wh)",border:"1.5px solid var(--bd)",borderRadius:12,padding:"12px 6px",textAlign:"center",cursor:"pointer",minHeight:70,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:4,userSelect:"none",WebkitTapHighlightColor:"transparent",transition:"background 0.15s"}}>
          <div style={{fontSize:22}}>{c.icon}</div>
          <div style={{fontSize:11,fontWeight:700,color:"var(--tx2)",lineHeight:1.2}}>{c.label}</div>
        </div>
      ))}
    </div>

    {/* ===== クイックアクション（全機能） ===== */}
    <div className="dash-title">Quick Actions</div>
    <div className="hg">
      {quickCards.map(c=>(
        <div key={c.id} className={`hc ${c.cls}`} onClick={()=>onNav(c.id)}>
          <div className="ci">{c.icon}</div>
          <div className="ct">{c.title}</div>
          <div className="cd2">{c.desc}</div>
        </div>
      ))}
    </div>
  </div>;
}

// ── アラートセクション ヘルパーコンポーネント ──
function AlertSection({icon,title,color,count,children}){
  const [open,setOpen]=useState(true);
  return <div style={{marginBottom:14,background:"var(--wh)",border:`2px solid ${count>0?color:"var(--bd)"}`,borderRadius:12,overflow:"hidden"}}>
    <div onClick={()=>setOpen(o=>!o)} style={{display:"flex",alignItems:"center",gap:8,padding:"10px 14px",cursor:"pointer",background:count>0?`${color}18`:"var(--bg2)",userSelect:"none"}}>
      <span style={{fontSize:18}}>{icon}</span>
      <span style={{fontWeight:700,fontSize:13,flex:1,color:count>0?color:"var(--tx2)"}}>{title}</span>
      {count>0
        ?<span style={{background:color,color:"#fff",borderRadius:14,padding:"1px 10px",fontSize:12,fontWeight:700}}>{count}件</span>
        :<span style={{background:"var(--gr)",color:"#fff",borderRadius:14,padding:"1px 10px",fontSize:11,fontWeight:700}}>✅ 問題なし</span>
      }
      <span style={{fontSize:11,color:"var(--tx3)",marginLeft:4}}>{open?"▲":"▼"}</span>
    </div>
    {open&&<div style={{padding:"10px 14px"}}>{children}</div>}
  </div>;
}

// ==================== 監査モード ====================
function AuditScreen({user,onBack,store}){
  const today=todayISO();
  const [tab,setTab]=useState("daily");
  const [dateFrom,setDateFrom]=useState(today);
  const [dateTo,setDateTo]=useState(today);
  const [expandUser,setExpandUser]=useState(null);
  const [vm,setVm]=useState(()=>{const d=new Date();return{y:d.getFullYear(),m:d.getMonth()+1};});

  const myFac=r=>(user.role==="admin")||(r.facilityId||r.facility_id)===user.selectedFacilityId;
  const myUsers=store.dynUsers.filter(u=>u.active!==false&&(user.role==="admin"||u.facilityId===user.selectedFacilityId));
  const fac=FACILITIES.find(f=>f.id===user.selectedFacilityId);

  // 期間フィルタ
  const inRange=r=>{const d=r.time?.slice(0,10)||"";return d>=dateFrom&&d<=dateTo;};
  const rangeRecs=store.recs.filter(r=>myFac(r)&&inRange(r));

  // 利用者ごとの集計
  const arrivedUserIds=[...new Set(rangeRecs.filter(r=>r.type==="user_in").map(r=>r.userId))];
  const serviceUserIds=[...new Set(rangeRecs.filter(r=>r.type==="service").map(r=>r.userId))];
  const photoUserIds  =[...new Set(rangeRecs.filter(r=>r.type==="photo").map(r=>r.userId))];
  const tempOkIds     =[...new Set(rangeRecs.filter(r=>r.type==="user_in"&&r.temp&&r.temp!=="").map(r=>r.userId))];
  const highTempIds   =[...new Set(rangeRecs.filter(r=>r.type==="user_in"&&parseFloat(r.temp)>=37.5).map(r=>r.userId))];

  const total=arrivedUserIds.length;
  const fullOk=arrivedUserIds.filter(id=>serviceUserIds.includes(id)&&tempOkIds.includes(id)).length;

  // 利用者ごとの体温履歴
  const getTempHistory=uid=>rangeRecs.filter(r=>r.type==="user_in"&&r.userId===uid&&r.temp).map(r=>({date:r.time?.slice(0,16)||"",temp:r.temp,by:r.createdBy||""}));
  // 変更履歴（record.history配列）
  const getChangeHistory=uid=>rangeRecs.filter(r=>r.userId===uid&&(r.history||[]).length>0).flatMap(r=>(r.history||[]).map(h=>({...h,recordType:r.type,recordTime:r.time?.slice(0,16)||""})));

  // ===== 月次帳票: 月次サービス提供記録表 =====
  const printMonthlyServiceTable=()=>{
    const facName=fac?.name||"";
    const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
    const inMonth=r=>recYM(r)===yearMonth&&myFac(r);
    const monthRecs=store.recs.filter(inMonth);
    const daysInM=new Date(vm.y,vm.m,0).getDate();
    const dayHeaders=Array.from({length:daysInM},(_,i)=>`<th style="min-width:18px;font-size:7pt;">${i+1}</th>`).join("");
    const dow=["日","月","火","水","木","金","土"];
    const dowHeaders=Array.from({length:daysInM},(_,i)=>{
      const d=new Date(vm.y,vm.m-1,i+1).getDay();
      const col=d===0?"#c0392b":d===6?"#1a4a8a":"#333";
      return `<th style="min-width:18px;font-size:7pt;color:${col};">${dow[d]}</th>`;
    }).join("");
    const userRows=myUsers.map(u=>{
      const arrivals=monthRecs.filter(r=>r.type==="user_in"&&r.userId===u.id);
      const services=monthRecs.filter(r=>r.type==="service"&&r.userId===u.id);
      const arrivedDates=new Set(arrivals.map(r=>(r.time||"").slice(8,10).replace(/^0/,"")));
      const svcDates=new Set(services.map(r=>(r.time||"").slice(8,10).replace(/^0/,"")));
      const tempMap={};arrivals.forEach(r=>{const d=(r.time||"").slice(8,10).replace(/^0/,"");tempMap[d]=r.temp||"";});
      const cells=Array.from({length:daysInM},(_,i)=>{
        const d=String(i+1);
        const arr=arrivedDates.has(d);const svc=svcDates.has(d);const tmp=tempMap[d]||"";
        const bg=arr?(svc?"#e6f5ec":"#fdf0ee"):"";
        const content=arr?`<div style="font-size:7pt;color:${svc?"#155a30":"#c0392b"};font-weight:700;">${svc?"○":"△"}</div>${tmp?`<div style="font-size:6pt;color:#444;">${tmp}℃</div>`:""}`:""
        return `<td style="background:${bg};padding:1px;text-align:center;vertical-align:top;height:28px;">${content}</td>`;
      }).join("");
      const totalDays=arrivedDates.size;const svcTotal=svcDates.size;
      return `<tr>
        <td style="text-align:left;padding:3px 5px;font-weight:700;font-size:9pt;white-space:nowrap;border-right:2px solid #bbb;">${u.name}</td>
        <td style="font-size:7pt;padding:1px 4px;color:#555;border-right:1px solid #ccc;">${(u.data||u).jukyushaNo||"—"}</td>
        ${cells}
        <td style="font-weight:700;text-align:center;color:#1a4a8a;border-left:2px solid #bbb;">${totalDays}</td>
        <td style="font-weight:700;text-align:center;color:${svcTotal<totalDays?"#c0392b":"#1a7a3a"};">${svcTotal}</td>
      </tr>`;
    }).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>月次サービス提供記録表 ${vm.y}年${vm.m}月</title>
    <style>
      @page{size:A3 landscape;margin:8mm 6mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h2{font-size:13pt;margin-bottom:3px;} .meta{font-size:8pt;color:#555;margin-bottom:8px;}
      table{border-collapse:collapse;width:100%;}
      th,td{border:1px solid #ccc;padding:1px 2px;text-align:center;}
      th{background:#dce8f8;font-weight:700;}
      .sign-row{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-top:12px;}
      .sign-box{border:1px solid #aaa;padding:6px;min-height:40px;border-radius:3px;}
      .sign-lbl{font-size:7pt;color:#666;}
      .legend{display:flex;gap:10px;margin-bottom:6px;font-size:8pt;}
      .leg{display:flex;align-items:center;gap:3px;}
    </style></head><body>
    <h2>📋 月次サービス提供記録表</h2>
    <div class="meta">事業所: ${facName}　対象: ${vm.y}年${vm.m}月　出力日: ${new Date().toLocaleDateString("ja-JP")}</div>
    <div class="legend">
      <div class="leg"><div style="width:14px;height:14px;background:#e6f5ec;border:1px solid #90c090;"></div>○ 来所+記録完備</div>
      <div class="leg"><div style="width:14px;height:14px;background:#fdf0ee;border:1px solid #e09090;"></div>△ 来所のみ（記録不足）</div>
      <div style="font-size:7pt;color:#888;">数字は体温(℃)</div>
    </div>
    <table>
      <thead>
        <tr><th rowspan="2" style="min-width:70px;text-align:left;padding:3px 5px;">利用者名</th>
        <th rowspan="2" style="min-width:80px;">受給者証番号</th>
        ${dayHeaders}
        <th rowspan="2" style="min-width:24px;">来所<br/>日数</th>
        <th rowspan="2" style="min-width:24px;">記録<br/>日数</th></tr>
        <tr>${dowHeaders}</tr>
      </thead>
      <tbody>${userRows}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">児発管 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">担当職員</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=1300,height=800");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // ===== 月次帳票: 利用者別支援記録台帳 =====
  const printUserLedger=(userId)=>{
    const u=myUsers.find(x=>x.id===userId);
    if(!u) return;
    const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
    const inMonth=r=>recYM(r)===yearMonth&&r.userId===userId;
    const svcRecs=store.recs.filter(r=>inMonth(r)&&r.type==="service").sort((a,b)=>a.time>b.time?1:-1);
    const arrRecs=store.recs.filter(r=>inMonth(r)&&r.type==="user_in").sort((a,b)=>a.time>b.time?1:-1);
    const ud=u.data||u;
    // 有効ISP
    const activeIsp=(store.isps||[]).filter(x=>x.userId===userId).sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
    const ispRecAct=(store.ispRecords||[]).filter(r=>r.userId===userId&&r.docType==="isp_plan"&&["finalized","parent_consented","manager_confirmed"].includes(r.status)).sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
    const ispGoal=ispRecAct?.content?.shortGoal||activeIsp?.shortGoal||"—";
    const ispDomains=ispRecAct?.content?.domains?.join("・")||activeIsp?.goals?.map(g=>g.domain||"").join("・")||"—";
    const recRows=svcRecs.map(s=>{
      const arrOnDate=arrRecs.find(r=>r.time?.slice(0,10)===s.time?.slice(0,10));
      return `<tr style="page-break-inside:avoid;">
        <td style="padding:5px 7px;white-space:nowrap;font-weight:700;">${(s.time||"").slice(0,16)}</td>
        <td style="padding:5px 7px;white-space:nowrap;">${s.arrival||arrOnDate?.time?.slice(11,16)||"—"} 〜 ${s.departure||"—"}</td>
        <td style="padding:5px 7px;text-align:center;">${arrOnDate?.temp||"—"}</td>
        <td style="padding:5px 7px;text-align:center;">${arrOnDate?.transport||"—"}</td>
        <td style="padding:5px 7px;font-size:9pt;">${(s.items||[]).join("・")||"—"}</td>
        <td style="padding:5px 7px;font-size:9pt;">${s.supportNote||s.note||"—"}</td>
        <td style="padding:5px 7px;text-align:center;font-size:9pt;">${s.staffName||s.createdBy||"—"}</td>
      </tr>`;
    }).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>支援記録台帳 ${u.name}</title>
    <style>
      @page{size:A4 portrait;margin:15mm 12mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:10pt;color:#111;}
      h2{font-size:14pt;border-bottom:2px solid #1a3a6a;padding-bottom:5px;margin-bottom:10px;}
      .info-grid{display:grid;grid-template-columns:1fr 1fr;gap:6px;margin-bottom:12px;}
      .info-item{border:1px solid #ccc;padding:5px 8px;border-radius:3px;}
      .info-lbl{font-size:7pt;color:#666;margin-bottom:1px;}
      .info-val{font-size:10pt;font-weight:700;}
      table{border-collapse:collapse;width:100%;font-size:9pt;margin-top:8px;}
      th,td{border:1px solid #ccc;padding:4px 6px;}
      th{background:#dce8f8;font-weight:700;text-align:center;}
      .isp-box{background:#e8f5ec;border:1px solid #90c090;border-radius:4px;padding:8px;margin-bottom:10px;font-size:9pt;}
      .sign-row{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:16px;}
      .sign-box{border:1px solid #aaa;padding:8px;min-height:48px;border-radius:3px;}
      .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <h2>📋 個別支援記録台帳</h2>
    <div class="info-grid">
      <div class="info-item"><div class="info-lbl">氏名</div><div class="info-val">${u.name}</div></div>
      <div class="info-item"><div class="info-lbl">受給者証番号</div><div class="info-val">${ud.jukyushaNo||"（未入力）"}</div></div>
      <div class="info-item"><div class="info-lbl">対象年月</div><div class="info-val">${vm.y}年${vm.m}月</div></div>
      <div class="info-item"><div class="info-lbl">事業所名</div><div class="info-val">${fac?.name||""}</div></div>
    </div>
    <div class="isp-box">
      <div style="font-weight:700;margin-bottom:3px;">📋 適用中の個別支援計画</div>
      <div>短期目標: ${ispGoal}</div>
      <div style="font-size:8pt;color:#444;margin-top:2px;">支援領域: ${ispDomains}</div>
    </div>
    <table>
      <thead><tr>
        <th>日時</th><th>在所時間</th><th>体温</th><th>送迎</th>
        <th>支援内容・活動</th><th>支援の記録・様子</th><th>担当者</th>
      </tr></thead>
      <tbody>${recRows||`<tr><td colspan="7" style="text-align:center;color:#999;padding:12px;">この月の記録なし</td></tr>`}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">担当職員 確認サイン</div></div>
      <div class="sign-box"><div class="sign-lbl">管理者 確認サイン　　確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div>
    </body></html>`;
    const w=window.open("","_blank","width=900,height=750");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // ===== 月次帳票: ISP整合確認表 =====
  const printIspCompliance=()=>{
    const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
    const facName=fac?.name||"";
    const inMonth=r=>recYM(r)===yearMonth&&myFac(r);
    const monthSvcRecs=store.recs.filter(r=>inMonth(r)&&r.type==="service");
    const userRows=myUsers.map(u=>{
      const ud=u.data||u;
      const urecs=monthSvcRecs.filter(r=>r.userId===u.id);
      const activeIsp=(store.isps||[]).filter(x=>x.userId===u.id).sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
      const ispRec=(store.ispRecords||[]).filter(r=>r.userId===u.id&&r.docType==="isp_plan").sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
      const ispGoal=ispRec?.content?.shortGoal||activeIsp?.shortGoal||"—";
      const ispStatus=ispRec?.status||"—";
      const ispColor={"finalized":"#155a30","parent_consented":"#1a4a8a","manager_confirmed":"#7a5000"}[ispStatus]||"#c0392b";
      const ispStatusLabel={"finalized":"確定済","parent_consented":"保護者同意済","manager_confirmed":"管理者確認済","cdsm_approved":"児発管承認","staff_checked":"職員確認","ai_draft":"下書き","—":"未作成"}[ispStatus]||ispStatus;
      const recCount=urecs.length;
      // ISP連携率（ispId or shortGoalへの言及を含む記録）
      const linked=urecs.filter(r=>r.ispId||(r.supportNote||"").includes(ispGoal.slice(0,10))).length;
      const linkRate=recCount>0?Math.round(linked/recCount*100):0;
      const statusColor=linkRate>=80?"#155a30":linkRate>=50?"#7a5000":"#c0392b";
      return `<tr>
        <td style="padding:5px 7px;font-weight:700;">${u.name}</td>
        <td style="padding:5px 7px;font-size:8pt;">${ud.jukyushaNo||"—"}</td>
        <td style="padding:5px 7px;font-size:9pt;">${ispGoal.slice(0,40)}${ispGoal.length>40?"…":""}</td>
        <td style="padding:5px 7px;text-align:center;color:${ispColor};font-weight:700;">${ispStatusLabel}</td>
        <td style="padding:5px 7px;text-align:center;">${recCount}</td>
        <td style="padding:5px 7px;text-align:center;">${linked}</td>
        <td style="padding:5px 7px;text-align:center;font-weight:700;color:${statusColor};">${linkRate}%</td>
        <td style="padding:5px 7px;text-align:center;">${ispRec?.content?.supportPeriod||activeIsp?.period||"—"}</td>
      </tr>`;
    }).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>ISP整合確認表 ${vm.y}年${vm.m}月</title>
    <style>
      @page{size:A4 landscape;margin:12mm 10mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h2{font-size:13pt;margin-bottom:4px;} .meta{font-size:8pt;color:#555;margin-bottom:8px;}
      table{border-collapse:collapse;width:100%;font-size:9pt;}
      th,td{border:1px solid #ccc;padding:5px 7px;}
      th{background:#dce8f8;font-weight:700;text-align:center;}
      .sign-row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-top:14px;}
      .sign-box{border:1px solid #aaa;padding:8px;min-height:44px;border-radius:3px;}
      .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <h2>📊 個別支援計画 整合確認表</h2>
    <div class="meta">事業所: ${facName}　対象: ${vm.y}年${vm.m}月　出力日: ${new Date().toLocaleDateString("ja-JP")}</div>
    <div style="font-size:8pt;color:#666;margin-bottom:8px;">※ ISP連携率 = サービス記録のうちISP目標に言及した記録の割合（80%以上推奨）</div>
    <table>
      <thead><tr>
        <th>利用者名</th><th>受給者証番号</th><th>ISP短期目標</th>
        <th>ISPステータス</th><th>記録件数</th><th>ISP連携件数</th><th>ISP連携率</th><th>支援期間</th>
      </tr></thead>
      <tbody>${userRows}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">児発管 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=1200,height=800");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // ===== 月次帳票: 欠落チェックレポート =====
  const printGapReport=()=>{
    const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
    const facName=fac?.name||"";
    const inMonth=r=>recYM(r)===yearMonth&&myFac(r);
    const monthRecs=store.recs.filter(inMonth);
    const reportRows=myUsers.map(u=>{
      const arr=monthRecs.filter(r=>r.type==="user_in"&&r.userId===u.id);
      const svc=monthRecs.filter(r=>r.type==="service"&&r.userId===u.id);
      const dep=monthRecs.filter(r=>r.type==="user_out"&&r.userId===u.id);
      const arrDates=[...new Set(arr.map(r=>r.time?.slice(0,10)))].filter(Boolean);
      const svcDates=[...new Set(svc.map(r=>r.time?.slice(0,10)))].filter(Boolean);
      const depDates=[...new Set(dep.map(r=>r.time?.slice(0,10)))].filter(Boolean);
      const noTemp=arr.filter(r=>!r.temp||r.temp==="").length;
      const noSvc=arrDates.filter(d=>!svcDates.includes(d));
      const noDep=arrDates.filter(d=>!depDates.includes(d));
      const isp=(store.isps||[]).filter(x=>x.userId===u.id).sort((a,b)=>b.endDate>a.endDate?1:-1)[0];
      const fs=store.facesheets.find(f=>f.userId===u.id);
      const issues=[];
      if(noTemp>0) issues.push(`体温未入力 ${noTemp}件`);
      if(noSvc.length>0) issues.push(`サービス記録なし ${noSvc.length}日 (${noSvc.join(",").slice(0,20)})`);
      if(noDep.length>0) issues.push(`退所記録なし ${noDep.length}日`);
      if(!isp) issues.push("ISP未作成");
      else if(isp.endDate<yearMonth+"-01") issues.push(`ISP期限切れ(${isp.endDate})`);
      if(!fs) issues.push("フェイスシート未作成");
      const level=issues.length===0?"ok":issues.some(i=>i.includes("サービス記録")||i.includes("ISP"))?"ng":"warn";
      const bg=level==="ok"?"#e6f5ec":level==="ng"?"#fdf0ee":"#fffaec";
      return `<tr style="background:${bg};">
        <td style="padding:5px 7px;font-weight:700;">${level==="ok"?"✅":level==="ng"?"🚨":"⚠️"} ${u.name}</td>
        <td style="padding:5px 7px;text-align:center;">${arrDates.length}</td>
        <td style="padding:5px 7px;text-align:center;color:${noTemp>0?"#c0392b":"#1a7a3a"};font-weight:700;">${noTemp>0?"✗ "+noTemp+"件":"✓"}</td>
        <td style="padding:5px 7px;text-align:center;color:${noSvc.length>0?"#c0392b":"#1a7a3a"};font-weight:700;">${noSvc.length>0?"✗ "+noSvc.length+"日":"✓"}</td>
        <td style="padding:5px 7px;text-align:center;color:${noDep.length>0?"#e08020":"#1a7a3a"};">${noDep.length>0?"△ "+noDep.length+"日":"✓"}</td>
        <td style="padding:5px 7px;text-align:center;color:${!isp||isp.endDate<yearMonth+"-01"?"#c0392b":"#1a7a3a"};font-weight:700;">${!isp?"✗ 未作成":isp.endDate<yearMonth+"-01"?"✗ 期限切れ":"✓ 有効"}</td>
        <td style="padding:5px 7px;text-align:center;color:${!fs?"#e08020":"#1a7a3a"};">${!fs?"△ 未作成":"✓"}</td>
        <td style="padding:5px 7px;font-size:8pt;color:#444;">${issues.join(" / ")||"—"}</td>
      </tr>`;
    }).join("");
    const ngCount=myUsers.filter(u=>{
      const arr=monthRecs.filter(r=>r.type==="user_in"&&r.userId===u.id);
      const svc=monthRecs.filter(r=>r.type==="service"&&r.userId===u.id);
      return arr.length>0&&svc.length===0;
    }).length;
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>欠落チェックレポート ${vm.y}年${vm.m}月</title>
    <style>
      @page{size:A4 landscape;margin:12mm 10mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h2{font-size:13pt;margin-bottom:4px;} .meta{font-size:8pt;color:#555;margin-bottom:8px;}
      table{border-collapse:collapse;width:100%;font-size:9pt;}
      th,td{border:1px solid #ccc;padding:4px 7px;}
      th{background:#dce8f8;font-weight:700;text-align:center;}
      .sign-row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-top:14px;}
      .sign-box{border:1px solid #aaa;padding:8px;min-height:44px;border-radius:3px;}
      .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <h2>🔍 監査対応 欠落チェックレポート</h2>
    <div class="meta">事業所: ${facName}　対象: ${vm.y}年${vm.m}月　出力日: ${new Date().toLocaleDateString("ja-JP")}</div>
    ${ngCount>0?`<div style="background:#fdf0ee;border:1px solid #e09090;padding:6px 10px;border-radius:4px;margin-bottom:8px;font-size:9pt;color:#8a2010;font-weight:700;">🚨 サービス記録が不足している利用者が ${ngCount}名 います。提出前に確認してください。</div>`:""}
    <table>
      <thead><tr>
        <th>利用者名</th><th>来所日数</th><th>体温入力</th><th>サービス記録</th><th>退所記録</th><th>ISP</th><th>フェイスシート</th><th>課題内容</th>
      </tr></thead>
      <tbody>${reportRows}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">児発管 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=1200,height=800");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // ===== 強化版監査PDF =====
  const printAudit=()=>{
    const facName=fac?.name||"全施設";
    const rows=myUsers.filter(u=>arrivedUserIds.includes(u.id));
    const now=new Date().toLocaleString("ja-JP");

    const userDetailHtml=rows.map(u=>{
      const tempHist=getTempHistory(u.id);
      const svcRecs=rangeRecs.filter(r=>r.type==="service"&&r.userId===u.id);
      const inRecs=rangeRecs.filter(r=>r.type==="user_in"&&r.userId===u.id);
      const changeHist=getChangeHistory(u.id);
      const hasTemp=tempOkIds.includes(u.id);
      const hasSvc=serviceUserIds.includes(u.id);
      const hasHigh=highTempIds.includes(u.id);
      return `
      <div class="user-block" style="page-break-inside:avoid;margin-bottom:18px;border:1px solid #bbb;border-radius:6px;overflow:hidden;">
        <div class="user-hd" style="background:${hasSvc&&hasTemp?"#e8f5ec":"#fdf0ee"};padding:8px 12px;border-bottom:1px solid #bbb;display:flex;justify-content:space-between;align-items:center;">
          <span style="font-size:14px;font-weight:700;">${u.name}</span>
          <span style="font-size:11px;color:${hasSvc&&hasTemp?"#155a30":"#c0392b"};font-weight:700;">${hasSvc&&hasTemp?"✅ 記録完備":"⚠ 要確認"}</span>
        </div>
        <div style="padding:8px 12px;">
          <!-- チェックリスト -->
          <table style="border-collapse:collapse;width:100%;font-size:11px;margin-bottom:8px;">
            <tr>
              <td style="border:1px solid #ddd;padding:4px 8px;">来所</td><td style="border:1px solid #ddd;padding:4px 8px;color:#1a7a3a;font-weight:700;">✓ ${inRecs.length}回</td>
              <td style="border:1px solid #ddd;padding:4px 8px;">体温</td><td style="border:1px solid #ddd;padding:4px 8px;color:${hasTemp?"#1a7a3a":"#c0392b"};font-weight:700;">${hasTemp?"✓ 記録あり":"✗ 未入力"}${hasHigh?" 🔴発熱あり":""}</td>
              <td style="border:1px solid #ddd;padding:4px 8px;">サービス記録</td><td style="border:1px solid #ddd;padding:4px 8px;color:${hasSvc?"#1a7a3a":"#c0392b"};font-weight:700;">${hasSvc?"✓ 入力済":"✗ 未入力"}</td>
              <td style="border:1px solid #ddd;padding:4px 8px;">写真</td><td style="border:1px solid #ddd;padding:4px 8px;color:${photoUserIds.includes(u.id)?"#1a7a3a":"#999"};">${photoUserIds.includes(u.id)?"✓ あり":"— なし"}</td>
            </tr>
          </table>
          <!-- 体温履歴 -->
          ${tempHist.length>0?`<div style="margin-bottom:6px;"><div style="font-size:10px;font-weight:700;color:#555;margin-bottom:3px;">🌡 体温履歴</div><div style="display:flex;flex-wrap:wrap;gap:5px;">${tempHist.map(t=>`<span style="background:${parseFloat(t.temp)>=37.5?"#fdf0ee":"#f0f8f0"};border:1px solid ${parseFloat(t.temp)>=37.5?"#e09090":"#90c090"};border-radius:4px;padding:2px 7px;font-size:10px;font-family:monospace;">${t.date.slice(5)} ${t.temp}℃</span>`).join("")}</div></div>`:""}
          <!-- サービス記録概要 -->
          ${svcRecs.length>0?`<div style="margin-bottom:6px;"><div style="font-size:10px;font-weight:700;color:#555;margin-bottom:3px;">📋 サービス提供記録</div>${svcRecs.map(s=>`<div style="font-size:10px;padding:3px 0;border-bottom:1px dotted #ddd;">${s.time?.slice(0,16)||""} 在所:${s.arrival||"-"}〜${s.departure||"-"} ${(s.items||[]).slice(0,3).join("・")}</div>`).join("")}</div>`:""}
          <!-- 変更履歴 -->
          ${changeHist.length>0?`<div><div style="font-size:10px;font-weight:700;color:#555;margin-bottom:3px;">📝 変更履歴</div>${changeHist.slice(0,5).map(h=>`<div style="font-size:9px;color:#666;padding:2px 0;">${h.at||""} ${h.by||""}: ${h.desc||h.action||""}</div>`).join("")}</div>`:""}
        </div>
      </div>`;
    }).join("");

    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>監査提出書類 — ${facName}</title>
    <style>
      @page{size:A4 portrait;margin:15mm 12mm;}
      *{box-sizing:border-box;margin:0;padding:0;}
      body{font-family:'MS Gothic','Hiragino Kaku Gothic Pro',Meiryo,sans-serif;font-size:10pt;color:#111;background:#fff;}
      .cover{text-align:center;padding:30px 20px 20px;border-bottom:3px solid #1a3a6a;margin-bottom:20px;}
      .cover h1{font-size:20pt;font-weight:900;color:#1a3a6a;}
      .cover .sub{font-size:11pt;color:#555;margin-top:8px;}
      .summary-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:18px;}
      .summary-box{border:1px solid #ccc;border-radius:6px;padding:10px;text-align:center;}
      .summary-box .val{font-size:22pt;font-weight:900;font-family:monospace;}
      .summary-box .lbl{font-size:9pt;color:#666;}
      .sign-row{display:grid;grid-template-columns:1fr 1fr 1fr;gap:16px;margin:24px 0 16px;}
      .sign-box{border:1px solid #aaa;border-radius:6px;padding:10px 12px;min-height:64px;}
      .sign-box .sign-lbl{font-size:9pt;color:#555;margin-bottom:8px;}
      .sign-box .sign-line{border-bottom:1px solid #888;margin-top:32px;}
    </style></head><body>
    <div class="cover">
      <h1>📋 監査提出書類</h1>
      <div class="sub">${facName}　　期間：${dateFrom} 〜 ${dateTo}</div>
      <div class="sub" style="font-size:9pt;color:#888;margin-top:4px;">出力日時：${now}</div>
    </div>
    <!-- サマリー -->
    <div class="summary-grid">
      <div class="summary-box"><div class="val" style="color:#005a9a">${total}</div><div class="lbl">来所者数</div></div>
      <div class="summary-box"><div class="val" style="color:#1a7a3a">${fullOk}</div><div class="lbl">記録完備</div></div>
      <div class="summary-box"><div class="val" style="color:${total-fullOk>0?"#c0392b":"#999"}">${total-fullOk}</div><div class="lbl">未完備</div></div>
      <div class="summary-box"><div class="val" style="color:${highTempIds.length>0?"#c0392b":"#999"}">${highTempIds.length}</div><div class="lbl">高体温者数</div></div>
    </div>
    <!-- 利用者別詳細 -->
    ${userDetailHtml}
    <!-- サイン欄 -->
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認サイン</div><div class="sign-line"></div></div>
      <div class="sign-box"><div class="sign-lbl">担当職員 サイン</div><div class="sign-line"></div></div>
      <div class="sign-box"><div class="sign-lbl">確認日時</div><div style="font-size:11pt;font-weight:700;margin-top:12px;">${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div>
    </body></html>`;
    const w=window.open("","_blank","width=900,height=750");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // 書類一覧: 利用者別の帳票完備状況
  const docStatusRows=myUsers.map(u=>{
    const ud=u.data||u;
    const fs=store.facesheets.find(f=>f.userId===u.id);
    const asses=(store.assessments||[]).filter(a=>a.userId===u.id);
    const isps=(store.isps||[]).filter(x=>x.userId===u.id);
    const ispRecs=(store.ispRecords||[]).filter(r=>r.userId===u.id&&r.docType==="isp_plan");
    const mons=(store.monitorings||[]).filter(m=>m.userId===u.id);
    const latestIsp=isps.sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
    const latestIspRec=ispRecs.sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
    const ispOk=latestIsp||latestIspRec;
    const ispExpired=latestIsp&&latestIsp.endDate&&latestIsp.endDate<todayISO();
    const jukyushaOk=ud.jukyushaNo||false;
    const score=[!!fs,!!asses.length,ispOk&&!ispExpired,!!mons.length,jukyushaOk].filter(Boolean).length;
    return {u,ud,fs,asses,latestIsp,latestIspRec,mons,score,jukyushaOk,ispExpired};
  });

  // ── アラート計算（vmで選択中の年月をベースに算出）──
  const alertYM=vm.y+"-"+String(vm.m).padStart(2,"0");
  const alertMonthRecs=store.recs.filter(r=>myFac(r)&&recYM(r)===alertYM);

  // 1. 未記録アラート（来所日にサービス記録なし）
  const noSvcAlerts=[];
  myUsers.forEach(u=>{
    const arrDates=[...new Set(alertMonthRecs.filter(r=>r.type==="user_in"&&r.userId===u.id).map(r=>r.time?.slice(0,10)))].filter(Boolean);
    const svcDates=new Set(alertMonthRecs.filter(r=>r.type==="service"&&r.userId===u.id).map(r=>r.time?.slice(0,10)));
    arrDates.forEach(d=>{if(!svcDates.has(d))noSvcAlerts.push({userId:u.id,userName:u.name,date:d});});
  });

  // 2. 署名漏れ（ISP承認フロー停滞 / 同意書署名未取得）
  const signAlerts=[];
  const ISP_NEED_SIGN_STATES=["staff_checked","cdsm_approved","manager_confirmed","parent_explained"];
  const ISP_SIGN_LABELS={"staff_checked":"職員確認待ち","cdsm_approved":"児発管承認待ち","manager_confirmed":"保護者説明待ち","parent_explained":"保護者同意待ち"};
  (store.ispRecords||[]).filter(r=>myFac(r)&&r.docType==="isp_plan"&&ISP_NEED_SIGN_STATES.includes(r.status)).forEach(r=>{
    const u=myUsers.find(x=>x.id===r.userId);if(!u)return;
    signAlerts.push({userId:u.id,userName:u.name,doc:"個別支援計画",status:ISP_SIGN_LABELS[r.status]||r.status,date:(r.updatedAt||r.createdAt||"").slice(0,10)});
  });
  (store.ispRecords||[]).filter(r=>myFac(r)&&r.docType==="consent"&&!r.content?.parentSignedAt).forEach(r=>{
    const u=myUsers.find(x=>x.id===r.userId);if(!u)return;
    signAlerts.push({userId:u.id,userName:u.name,doc:"同意書",status:"保護者署名未取得"+(r.content?.checkedTypes?.includes("isp")?" (ISP同意含む)":""),date:(r.createdAt||"").slice(0,10)});
  });

  // 3. 支援時間不足（2時間未満 or 退所時刻未入力）
  const shortAlerts=[];
  alertMonthRecs.filter(r=>r.type==="service").forEach(r=>{
    const u=myUsers.find(x=>x.id===r.userId);if(!u)return;
    if(r.arrival&&r.departure){
      const toMin=t=>{const[h,m]=t.split(":").map(Number);return h*60+(m||0);};
      const mins=toMin(r.departure)-toMin(r.arrival);
      if(mins>0&&mins<120)shortAlerts.push({userId:u.id,userName:u.name,date:r.time?.slice(0,10)||"",arrival:r.arrival,departure:r.departure,mins,type:"short"});
    }else if(r.arrival&&!r.departure){
      shortAlerts.push({userId:u.id,userName:u.name,date:r.time?.slice(0,10)||"",arrival:r.arrival,departure:null,mins:null,type:"nodep"});
    }
  });

  // 4. 加算漏れ（送迎加算・個別サポート加算の請求設定確認）
  const addonAlerts=[];
  const facKokuho=(store.kokuho||[]).filter(k=>k.facilityId===user.selectedFacilityId&&k.yearMonth===alertYM);
  myUsers.forEach(u=>{
    const hasTr=alertMonthRecs.some(r=>r.type==="user_in"&&r.userId===u.id&&r.transport==="あり");
    const billing=facKokuho.find(k=>k.userId===u.id);
    const billAddons=billing?.addons||[];
    // 送迎記録があるのに送迎加算が請求に未設定
    if(hasTr&&!billAddons.some(a=>a.key?.startsWith("tr_"))){
      addonAlerts.push({userId:u.id,userName:u.name,type:"送迎加算",detail:"送迎記録あり・請求に加算未設定"});
    }
    // ISP確定済で請求データがあるのに個別サポート加算が未設定
    if(billing&&billing.serviceDays>0){
      const hasIspFinal=(store.ispRecords||[]).some(r=>r.userId===u.id&&r.docType==="isp_plan"&&["finalized","parent_consented"].includes(r.status));
      if(hasIspFinal&&!billAddons.some(a=>a.key==="indiv"||a.key==="indiv2")){
        addonAlerts.push({userId:u.id,userName:u.name,type:"個別サポート加算",detail:"ISP確定済・個別サポート加算の確認を推奨"});
      }
    }
  });

  // 5. モニタリング期限（ISP有効期限・モニタリング未実施）
  const monAlerts=[];
  const d60=new Date(today);d60.setDate(d60.getDate()+60);const d60ISO=d60.toISOString().slice(0,10);
  const d180=new Date(today);d180.setDate(d180.getDate()-180);const d180ISO=d180.toISOString().slice(0,10);
  const seenMonUser=new Set();
  myUsers.forEach(u=>{
    // ISP有効期限チェック
    const ispRecs=(store.ispRecords||[]).filter(r=>r.userId===u.id&&r.docType==="isp_plan"&&["finalized","parent_consented","manager_confirmed"].includes(r.status)).sort((a,b)=>b.createdAt>a.createdAt?1:-1);
    if(ispRecs.length>0){
      const lat=ispRecs[0];
      const validTo=lat.content?.validTo||lat.content?.supportPeriodTo||"";
      if(validTo&&validTo<=d60ISO){
        const days=Math.round((new Date(validTo)-new Date(today))/(1000*60*60*24));
        monAlerts.push({userId:u.id,userName:u.name,type:days<0?"ISP期限切れ":"ISP期限間近",detail:`有効期限: ${validTo}`,days,level:days<0?"danger":"warn"});
      }
    }
    // モニタリング未実施チェック（monitoringsテーブル＋ispRecordsのmonitoring）
    const lastMon=store.monitorings.filter(m=>m.userId===u.id).sort((a,b)=>b.date>a.date?1:-1)[0];
    const lastMonRec=(store.ispRecords||[]).filter(r=>r.userId===u.id&&r.docType==="monitoring").sort((a,b)=>b.createdAt>a.createdAt?1:-1)[0];
    const lastMonDate=lastMon?.date||(lastMonRec?.createdAt||"").slice(0,10)||"";
    if(!seenMonUser.has(u.id)&&(!lastMonDate||lastMonDate<d180ISO)){
      seenMonUser.add(u.id);
      monAlerts.push({userId:u.id,userName:u.name,type:"モニタリング未実施",detail:lastMonDate?`最終: ${lastMonDate}（6ヶ月超経過）`:"記録なし",level:"warn"});
    }
  });

  // アラート合計件数
  const totalAlerts=noSvcAlerts.length+signAlerts.length+shortAlerts.length+addonAlerts.length+monAlerts.length;

  // ── アラートレポートPDF印刷 ──
  const printAlertReport=()=>{
    const facName=fac?.name||"";
    const now=new Date().toLocaleString("ja-JP");
    const section=(title,rows,cols)=>`
      <h3 style="font-size:12pt;font-weight:700;border-left:4px solid #1a3a6a;padding-left:8px;margin:16px 0 6px;">${title}</h3>
      ${rows.length===0?`<p style="color:#1a7a3a;font-size:10pt;">✅ 問題なし</p>`:`
      <table style="border-collapse:collapse;width:100%;font-size:9pt;margin-bottom:6px;">
        <thead><tr>${cols.map(c=>`<th style="background:#dce8f8;border:1px solid #ccc;padding:4px 8px;text-align:left;">${c}</th>`).join("")}</tr></thead>
        <tbody>${rows}</tbody>
      </table>`}`;
    const noSvcRows=noSvcAlerts.map(a=>`<tr style="background:#fdf0ee;"><td style="border:1px solid #ccc;padding:4px 8px;">${a.date}</td><td style="border:1px solid #ccc;padding:4px 8px;font-weight:700;">${a.userName}</td><td style="border:1px solid #ccc;padding:4px 8px;color:#c0392b;font-weight:700;">サービス記録なし</td></tr>`).join("");
    const signRows=signAlerts.map(a=>`<tr style="background:#fffaec;"><td style="border:1px solid #ccc;padding:4px 8px;font-weight:700;">${a.userName}</td><td style="border:1px solid #ccc;padding:4px 8px;">${a.doc}</td><td style="border:1px solid #ccc;padding:4px 8px;color:#c0392b;">${a.status}</td><td style="border:1px solid #ccc;padding:4px 8px;color:#888;">${a.date}</td></tr>`).join("");
    const shortRows=shortAlerts.map(a=>`<tr style="background:#fffaec;"><td style="border:1px solid #ccc;padding:4px 8px;">${a.date}</td><td style="border:1px solid #ccc;padding:4px 8px;font-weight:700;">${a.userName}</td><td style="border:1px solid #ccc;padding:4px 8px;">${a.arrival||"—"}〜${a.departure||"未記録"}</td><td style="border:1px solid #ccc;padding:4px 8px;color:#c0392b;">${a.type==="nodep"?"退所未記録":a.mins+"分（2時間未満）"}</td></tr>`).join("");
    const addonRows=addonAlerts.map(a=>`<tr style="background:#f3eeff;"><td style="border:1px solid #ccc;padding:4px 8px;font-weight:700;">${a.userName}</td><td style="border:1px solid #ccc;padding:4px 8px;color:#6020a0;font-weight:700;">${a.type}</td><td style="border:1px solid #ccc;padding:4px 8px;">${a.detail}</td></tr>`).join("");
    const monRows=monAlerts.map(a=>`<tr style="background:${a.level==="danger"?"#fdf0ee":"#fffaec"};"><td style="border:1px solid #ccc;padding:4px 8px;font-weight:700;">${a.userName}</td><td style="border:1px solid #ccc;padding:4px 8px;color:${a.level==="danger"?"#c0392b":"#e08020"};font-weight:700;">${a.type}</td><td style="border:1px solid #ccc;padding:4px 8px;">${a.detail}${a.days!=null&&a.days>=0?` (残${a.days}日)`:""}</td></tr>`).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>監査アラートレポート ${alertYM}</title>
    <style>@page{size:A4 portrait;margin:14mm 12mm;}*{box-sizing:border-box;margin:0;padding:0;}
    body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:10pt;color:#111;}
    .hd{text-align:center;border-bottom:3px solid #1a3a6a;padding-bottom:10px;margin-bottom:14px;}
    .hd h1{font-size:18pt;font-weight:900;color:#1a3a6a;}
    .hd .sub{font-size:10pt;color:#555;margin-top:4px;}
    .summary{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:14px;}
    .sc{border:1px solid #ccc;border-radius:4px;padding:6px 4px;text-align:center;}
    .sc .val{font-size:18pt;font-weight:900;font-family:monospace;}
    .sc .lbl{font-size:8pt;color:#666;}
    .sign-row{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:18px;}
    .sign-box{border:1px solid #aaa;padding:8px;min-height:44px;border-radius:3px;}
    .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <div class="hd"><h1>🔍 監査アラートレポート</h1>
    <div class="sub">事業所: ${facName}　対象: ${vm.y}年${vm.m}月　出力: ${now}</div></div>
    <div class="summary">
      <div class="sc"><div class="val" style="color:${noSvcAlerts.length>0?"#c0392b":"#1a7a3a"}">${noSvcAlerts.length}</div><div class="lbl">未記録</div></div>
      <div class="sc"><div class="val" style="color:${signAlerts.length>0?"#c0392b":"#1a7a3a"}">${signAlerts.length}</div><div class="lbl">署名漏れ</div></div>
      <div class="sc"><div class="val" style="color:${shortAlerts.length>0?"#e08020":"#1a7a3a"}">${shortAlerts.length}</div><div class="lbl">時間不足</div></div>
      <div class="sc"><div class="val" style="color:${addonAlerts.length>0?"#6020a0":"#1a7a3a"}">${addonAlerts.length}</div><div class="lbl">加算漏れ</div></div>
      <div class="sc"><div class="val" style="color:${monAlerts.length>0?"#1a4a8a":"#1a7a3a"}">${monAlerts.length}</div><div class="lbl">期限</div></div>
    </div>
    ${section("📝 未記録アラート（来所日にサービス記録なし）",noSvcRows,["日付","利用者名","状態"])}
    ${section("✍️ 署名漏れ（ISP承認フロー停滞・同意書署名未取得）",signRows,["利用者名","書類種別","状態","作成日"])}
    ${section("⏱ 支援時間不足（2時間未満・退所未記録）",shortRows,["日付","利用者名","時刻","内容"])}
    ${section("💴 加算漏れ（請求加算の確認）",addonRows,["利用者名","加算種別","詳細"])}
    ${section("📅 モニタリング期限（ISP有効期限・モニタリング未実施）",monRows,["利用者名","種別","詳細"])}
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=900,height=750");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">🔍 監査モード</div>
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:16,alignItems:"center"}}>
      {[
        {id:"daily",  icon:"📅",label:"日次チェック"},
        {id:"monthly",icon:"📋",label:"月次帳票出力"},
        {id:"docs",   icon:"📂",label:"書類一覧"},
        {id:"alerts", icon:"🚨",label:"アラート一覧",badge:totalAlerts},
      ].map(t=><button key={t.id} onClick={()=>setTab(t.id)}
        style={{position:"relative",padding:"8px 16px",borderRadius:9,border:"2px solid",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontSize:12,fontWeight:700,transition:"all .15s",
          borderColor:tab===t.id?"var(--tl)":"var(--bd)",
          background:tab===t.id?"rgba(58,160,216,0.2)":"var(--bg)",
          color:tab===t.id?"var(--tl)":"var(--tx3)"}}>
        {t.icon} {t.label}
        {t.badge>0&&<span style={{position:"absolute",top:-7,right:-7,background:"var(--ro)",color:"#fff",borderRadius:"50%",width:18,height:18,fontSize:10,fontWeight:900,display:"flex",alignItems:"center",justifyContent:"center",lineHeight:1}}>{t.badge>9?"9+":t.badge}</span>}
      </button>)}
    </div>

    {/* ── 日次チェックタブ ── */}
    {tab==="daily"&&<>
      <div style={{display:"flex",gap:10,alignItems:"center",flexWrap:"wrap",marginBottom:16,background:"var(--wh)",padding:14,borderRadius:12,border:"1px solid var(--bd)"}}>
        <span style={{fontSize:12,fontWeight:700,color:"var(--tx3)"}}>期間：</span>
        <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)}
          style={{padding:"8px 10px",borderRadius:8,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx)",fontSize:16,fontFamily:"'DM Mono',monospace",outline:"none"}}/>
        <span style={{color:"var(--tx3)"}}>〜</span>
        <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)}
          style={{padding:"8px 10px",borderRadius:8,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx)",fontSize:16,fontFamily:"'DM Mono',monospace",outline:"none"}}/>
        <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
          {[["今日",0,0],["今週",-(new Date().getDay()||7)+1,0],["今月",-(new Date().getDate()-1),0]].map(([label,from,to])=>(
            <button key={label} onClick={()=>{
              const d=new Date();const f=new Date(d);f.setDate(d.getDate()+from);const t2=new Date(d);t2.setDate(d.getDate()+to);
              setDateFrom(f.toISOString().slice(0,10));setDateTo(t2.toISOString().slice(0,10));
            }} style={{padding:"6px 12px",borderRadius:8,border:"1px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
              {label}
            </button>
          ))}
        </div>
        <button className="bexp" style={{marginLeft:"auto",background:"#fff8f0",borderColor:"var(--ac)",color:"var(--ac)"}} onClick={printAudit}>🖨️ 監査PDF</button>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:9,marginBottom:18}}>
        {[{label:"来所者数",val:total,color:"var(--tl)"},{label:"記録完備",val:fullOk,color:"var(--gr)"},{label:"未完備",val:total-fullOk,color:total-fullOk>0?"var(--ro)":"var(--tx3)"},{label:"高体温者",val:highTempIds.length,color:highTempIds.length>0?"var(--ro)":"var(--tx3)"}].map(s=>(
          <div key={s.label} className="stat-card"><div className="stat-label">{s.label}</div><div className="stat-val" style={{color:s.color,fontSize:22}}>{s.val}</div></div>
        ))}
      </div>
      {arrivedUserIds.length===0
        ?<div style={{textAlign:"center",color:"var(--tx3)",padding:"32px 0",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>指定期間内に来所記録がありません</div>
        :myUsers.filter(u=>arrivedUserIds.includes(u.id)).map(u=>{
          const hasTemp=tempOkIds.includes(u.id),hasService=serviceUserIds.includes(u.id);
          const hasPhoto=photoUserIds.includes(u.id),hasHigh=highTempIds.includes(u.id);
          const allOk=hasTemp&&hasService,expanded=expandUser===u.id;
          const tempHist=getTempHistory(u.id),changeHist=getChangeHistory(u.id);
          return <div key={u.id} className="audit-user-row"
            style={{borderColor:hasHigh?"rgba(224,56,56,0.6)":allOk?"rgba(44,170,96,0.4)":"rgba(224,56,56,0.3)",cursor:"pointer"}}
            onClick={()=>setExpandUser(expanded?null:u.id)}>
            <div className="audit-user-name" style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span>{allOk&&!hasHigh?"✅":"⚠️"} {u.name}{hasHigh&&<span style={{fontSize:10,fontWeight:700,color:"var(--ro)",marginLeft:6}}>🌡 高体温</span>}</span>
              <span style={{fontSize:11,color:"var(--tx3)"}}>{expanded?"▲ 閉じる":"▼ 詳細"}</span>
            </div>
            <div className="audit-checks">
              <span className="audit-check audit-ok">来所 ✓</span>
              <span className={`audit-check ${hasTemp?"audit-ok":"audit-ng"}`}>体温 {hasTemp?"✓":"✗"}</span>
              <span className={`audit-check ${hasService?"audit-ok":"audit-ng"}`}>サービス記録 {hasService?"✓":"✗"}</span>
              <span className={`audit-check ${hasPhoto?"audit-ok":"audit-na"}`}>写真 {hasPhoto?"✓":"—"}</span>
            </div>
            {expanded&&<div style={{marginTop:10,paddingTop:10,borderTop:"1px solid var(--bd)"}}>
              {tempHist.length>0&&<div style={{marginBottom:8}}>
                <div style={{fontSize:10,fontWeight:700,color:"var(--tx3)",marginBottom:5}}>🌡 体温履歴</div>
                <div style={{display:"flex",flexWrap:"wrap",gap:5}}>
                  {tempHist.map((t,i)=><span key={i} style={{fontSize:11,padding:"3px 9px",borderRadius:7,border:"1px solid",fontFamily:"'DM Mono',monospace",fontWeight:700,
                    borderColor:parseFloat(t.temp)>=37.5?"rgba(224,56,56,0.5)":"rgba(44,170,96,0.4)",
                    background:parseFloat(t.temp)>=37.5?"rgba(224,56,56,0.1)":"rgba(44,170,96,0.1)",
                    color:parseFloat(t.temp)>=37.5?"var(--ro)":"var(--gr)"}}>
                    {t.date.slice(5,16)} {t.temp}℃
                  </span>)}
                </div>
              </div>}
              {changeHist.length>0&&<div>
                <div style={{fontSize:10,fontWeight:700,color:"var(--tx3)",marginBottom:5}}>📝 変更履歴</div>
                {changeHist.slice(0,8).map((h,i)=><div key={i} style={{fontSize:11,color:"var(--tx3)",padding:"3px 0",borderBottom:"1px dotted var(--bd)"}}>
                  {h.at||h.recordTime||""} {h.by&&<span style={{color:"var(--tl)"}}>{h.by}</span>} {h.desc||h.action||""}
                </div>)}
              </div>}
              {tempHist.length===0&&changeHist.length===0&&<div style={{fontSize:11,color:"var(--tx3)"}}>詳細履歴なし</div>}
            </div>}
          </div>;
        })
      }
    </>}

    {/* ── 月次帳票出力タブ ── */}
    {tab==="monthly"&&<>
      {/* 年月選択 */}
      <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:16,background:"var(--wh)",padding:12,borderRadius:12,border:"1px solid var(--bd)"}}>
        <span style={{fontSize:12,fontWeight:700,color:"var(--tx3)"}}>対象年月：</span>
        <select className="fsm" value={vm.y} onChange={e=>setVm(v=>({...v,y:+e.target.value}))}>
          {Array.from({length:5},(_,i)=>2024+i).map(y=><option key={y} value={y}>{y}年</option>)}
        </select>
        <select className="fsm" value={vm.m} onChange={e=>setVm(v=>({...v,m:+e.target.value}))}>
          {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
        </select>
        <span style={{fontSize:11,color:"var(--tx3)",marginLeft:8}}>👉 帳票を選んで印刷してください</span>
      </div>
      {/* 帳票カード一覧 */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))",gap:12,marginBottom:20}}>
        {[
          {icon:"📊",title:"月次サービス提供記録表",desc:"全利用者の来所日をA3カレンダーで確認。体温・記録状況を色で表示",color:"linear-gradient(135deg,#1a6b3a,#2d9e58)",action:printMonthlyServiceTable},
          {icon:"📋",title:"欠落チェックレポート",desc:"体温未入力・サービス記録不足・ISP期限切れを一覧で確認",color:"linear-gradient(135deg,#8a2010,#c0392b)",action:printGapReport},
          {icon:"📊",title:"ISP整合確認表",desc:"ISP目標とサービス記録の連携率を利用者ごとに数値で確認",color:"linear-gradient(135deg,#1a4a8a,#2d6ed6)",action:printIspCompliance},
        ].map(c=>(
          <button key={c.title} onClick={c.action}
            style={{display:"flex",flexDirection:"column",gap:8,padding:"16px 14px",borderRadius:14,background:c.color,color:"#fff",border:"none",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",textAlign:"left",transition:"transform .1s,box-shadow .1s",boxShadow:"0 4px 16px rgba(0,0,0,0.2)"}}>
            <div style={{fontSize:26}}>{c.icon}</div>
            <div style={{fontWeight:700,fontSize:13,lineHeight:1.4}}>{c.title}</div>
            <div style={{fontSize:11,opacity:.85,lineHeight:1.5}}>{c.desc}</div>
            <div style={{marginTop:4,fontSize:11,fontWeight:700,opacity:.9}}>🖨 クリックして印刷</div>
          </button>
        ))}
      </div>
      {/* 利用者別支援記録台帳 */}
      <div className="dash-title" style={{marginBottom:10}}>📋 利用者別 支援記録台帳（個別印刷）</div>
      <div style={{display:"flex",flexDirection:"column",gap:7}}>
        {myUsers.map(u=>{
          const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
          const svcCount=store.recs.filter(r=>r.type==="service"&&r.userId===u.id&&recYM(r)===yearMonth).length;
          const arrCount=store.recs.filter(r=>r.type==="user_in"&&r.userId===u.id&&recYM(r)===yearMonth).length;
          return <div key={u.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:11,padding:"10px 13px",display:"flex",alignItems:"center",gap:10}}>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:13}}>{u.name}</div>
              <div style={{fontSize:11,color:"var(--tx3)",marginTop:2}}>
                来所 <span style={{fontWeight:700,color:"var(--tl)"}}>{arrCount}日</span>
                サービス記録 <span style={{fontWeight:700,color:svcCount>=arrCount?"var(--gr)":svcCount>0?"var(--am)":"var(--ro)"}}>{svcCount}件</span>
              </div>
            </div>
            <button onClick={()=>printUserLedger(u.id)}
              style={{padding:"8px 14px",borderRadius:9,background:"rgba(58,160,216,0.12)",border:"1px solid rgba(58,160,216,0.4)",color:"var(--tl)",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",whiteSpace:"nowrap"}}>
              🖨 台帳印刷
            </button>
          </div>;
        })}
        {myUsers.length===0&&<div style={{textAlign:"center",color:"var(--tx3)",padding:24}}>利用者が登録されていません</div>}
      </div>
    </>}

    {/* ── 書類一覧タブ ── */}
    {tab==="docs"&&<>
      <div className="dash-title" style={{marginBottom:10}}>📂 利用者別 書類完備状況</div>
      <div style={{overflowX:"auto"}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:600}}>
          <thead><tr style={{background:"var(--bg2)"}}>
            {["利用者名","受給者証番号","フェイスシート","アセスメント","個別支援計画","モニタリング","完備スコア"].map(h=>(
              <th key={h} style={{padding:"7px 9px",textAlign:"left",color:"var(--tx2)",fontSize:10,fontWeight:700,borderBottom:"2px solid var(--bd)",whiteSpace:"nowrap"}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>{docStatusRows.map(({u,ud,fs,asses,latestIsp,latestIspRec,mons,score,jukyushaOk,ispExpired})=>{
            const Cell=({ok,warn,text})=><td style={{padding:"7px 9px"}}>
              <span style={{fontSize:11,fontWeight:700,color:ok?"var(--gr)":warn?"var(--am)":"var(--ro)"}}>{ok?"✅":warn?"⚠️":"✗"} {text}</span>
            </td>;
            const ispOk=(latestIsp||latestIspRec)&&!ispExpired;
            const ispText=latestIspRec?`${latestIspRec.status==="finalized"?"確定済":"作成中"}`
              :latestIsp?`${ispExpired?"期限切れ":"有効"}(〜${latestIsp.endDate||"?"})` :"未作成";
            return <tr key={u.id} style={{borderBottom:"1px solid var(--bd)"}}>
              <td style={{padding:"7px 9px",fontWeight:700}}>{u.name}</td>
              <td style={{padding:"7px 9px",fontFamily:"'DM Mono',monospace",fontSize:11,color:jukyushaOk?"var(--tx)":"var(--ro)"}}>{ud.jukyushaNo||"未入力"}</td>
              <Cell ok={!!fs} text={fs?"作成済":"未作成"}/>
              <Cell ok={asses.length>0} text={asses.length>0?`${asses.length}件`:"未作成"}/>
              <Cell ok={ispOk} warn={latestIsp&&ispExpired} text={ispText}/>
              <Cell ok={mons.length>0} text={mons.length>0?`${mons.length}件`:"未作成"}/>
              <td style={{padding:"7px 9px"}}>
                <div style={{display:"flex",alignItems:"center",gap:7}}>
                  <div style={{flex:1,height:8,background:"var(--bd)",borderRadius:4,overflow:"hidden"}}>
                    <div style={{height:"100%",width:`${score/5*100}%`,background:score>=4?"var(--gr)":score>=2?"var(--am)":"var(--ro)",borderRadius:4,transition:"width .3s"}}/>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,color:score>=4?"var(--gr)":score>=2?"var(--am)":"var(--ro)"}}>{score}/5</span>
                </div>
              </td>
            </tr>;
          })}</tbody>
        </table>
      </div>
    </>}

    {/* ── アラート一覧タブ ── */}
    {tab==="alerts"&&<>
      {/* 年月選択 + サマリーバー */}
      <div style={{display:"flex",gap:8,alignItems:"center",flexWrap:"wrap",marginBottom:14,background:"var(--wh)",padding:12,borderRadius:12,border:"1px solid var(--bd)"}}>
        <span style={{fontSize:12,fontWeight:700,color:"var(--tx3)"}}>対象年月：</span>
        <select className="fsm" value={vm.y} onChange={e=>setVm(v=>({...v,y:+e.target.value}))}>
          {Array.from({length:5},(_,i)=>2024+i).map(y=><option key={y} value={y}>{y}年</option>)}
        </select>
        <select className="fsm" value={vm.m} onChange={e=>setVm(v=>({...v,m:+e.target.value}))}>
          {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
        </select>
        {totalAlerts>0
          ?<span style={{marginLeft:6,background:"var(--ro)",color:"#fff",borderRadius:20,padding:"3px 12px",fontSize:12,fontWeight:700}}>⚠ {totalAlerts}件のアラート</span>
          :<span style={{marginLeft:6,color:"var(--gr)",fontWeight:700,fontSize:12}}>✅ 全て問題なし</span>}
        <button className="bexp" style={{marginLeft:"auto",background:"#fff8f0",borderColor:"var(--ac)",color:"var(--ac)"}} onClick={printAlertReport}>🖨 アラートレポート印刷</button>
      </div>

      {/* アラートサマリーカード（5種） */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(145px,1fr))",gap:9,marginBottom:18}}>
        {[
          {label:"未記録",count:noSvcAlerts.length,icon:"📝",color:"var(--ro)",desc:"来所→記録なし"},
          {label:"署名漏れ",count:signAlerts.length,icon:"✍️",color:"var(--am)",desc:"ISP・同意書"},
          {label:"時間不足",count:shortAlerts.length,icon:"⏱",color:"var(--am)",desc:"2時間未満・退所漏れ"},
          {label:"加算漏れ",count:addonAlerts.length,icon:"💴",color:"#9048d8",desc:"請求加算確認"},
          {label:"期限アラート",count:monAlerts.length,icon:"📅",color:"var(--tl)",desc:"ISP期限・モニタリング"},
        ].map(s=>(
          <div key={s.label} style={{background:"var(--wh)",border:`2px solid ${s.count>0?s.color:"var(--bd)"}`,borderRadius:12,padding:"12px 8px",textAlign:"center"}}>
            <div style={{fontSize:22}}>{s.icon}</div>
            <div style={{fontSize:26,fontWeight:900,color:s.count>0?s.color:"var(--tx3)",fontFamily:"'DM Mono',monospace",marginTop:2}}>{s.count}</div>
            <div style={{fontSize:11,fontWeight:700,color:"var(--tx2)",marginTop:2}}>{s.label}</div>
            <div style={{fontSize:10,color:"var(--tx3)",marginTop:1}}>{s.desc}</div>
          </div>
        ))}
      </div>

      {/* 1. 未記録アラート */}
      <AlertSection icon="📝" title="未記録アラート" color="var(--ro)" count={noSvcAlerts.length}>
        {noSvcAlerts.length===0
          ?<div style={{color:"var(--gr)",fontSize:12,padding:"6px 0"}}>✅ 全来所日にサービス記録があります</div>
          :<div style={{display:"flex",flexDirection:"column",gap:5}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:4}}>来所記録はあるが、サービス（活動）記録が入力されていない日があります。</div>
            {noSvcAlerts.map((a,i)=><div key={i} style={{display:"flex",gap:10,alignItems:"center",padding:"7px 11px",background:"rgba(224,56,56,0.06)",borderRadius:8,border:"1px solid rgba(224,56,56,0.2)"}}>
              <span style={{fontSize:11,fontFamily:"'DM Mono',monospace",color:"var(--tx3)",whiteSpace:"nowrap",minWidth:80}}>{a.date}</span>
              <span style={{fontWeight:700,fontSize:13}}>{a.userName}</span>
              <span style={{fontSize:11,color:"var(--ro)",fontWeight:700,marginLeft:"auto",whiteSpace:"nowrap"}}>サービス記録なし 🚨</span>
            </div>)}
          </div>
        }
      </AlertSection>

      {/* 2. 署名漏れ */}
      <AlertSection icon="✍️" title="署名漏れ" color="var(--am)" count={signAlerts.length}>
        {signAlerts.length===0
          ?<div style={{color:"var(--gr)",fontSize:12,padding:"6px 0"}}>✅ 署名・同意書の漏れはありません</div>
          :<div style={{display:"flex",flexDirection:"column",gap:5}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:4}}>ISP承認フローが途中で止まっている、または同意書の保護者署名が未取得です。</div>
            {signAlerts.map((a,i)=><div key={i} style={{display:"flex",gap:8,alignItems:"center",padding:"7px 11px",background:"rgba(240,112,32,0.06)",borderRadius:8,border:"1px solid rgba(240,112,32,0.2)"}}>
              <span style={{fontWeight:700,fontSize:13,minWidth:80}}>{a.userName}</span>
              <span style={{fontSize:11,color:"var(--tx3)",background:"var(--bg2)",borderRadius:6,padding:"2px 7px"}}>{a.doc}</span>
              <span style={{fontSize:11,color:"var(--am)",fontWeight:700,marginLeft:"auto",whiteSpace:"nowrap"}}>{a.status} ✍</span>
              {a.date&&<span style={{fontSize:10,color:"var(--tx3)",fontFamily:"'DM Mono',monospace"}}>{a.date}</span>}
            </div>)}
          </div>
        }
      </AlertSection>

      {/* 3. 支援時間不足 */}
      <AlertSection icon="⏱" title="支援時間不足" color="var(--am)" count={shortAlerts.length}>
        {shortAlerts.length===0
          ?<div style={{color:"var(--gr)",fontSize:12,padding:"6px 0"}}>✅ 全記録で2時間以上の支援が確認されています</div>
          :<div style={{display:"flex",flexDirection:"column",gap:5}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:4}}>支援時間が2時間未満、または退所時刻が未入力のサービス記録があります。放課後等デイサービスの算定要件に注意してください。</div>
            {shortAlerts.map((a,i)=><div key={i} style={{display:"flex",gap:8,alignItems:"center",padding:"7px 11px",background:"rgba(240,112,32,0.06)",borderRadius:8,border:"1px solid rgba(240,112,32,0.2)"}}>
              <span style={{fontSize:11,fontFamily:"'DM Mono',monospace",color:"var(--tx3)",whiteSpace:"nowrap",minWidth:80}}>{a.date}</span>
              <span style={{fontWeight:700,fontSize:13}}>{a.userName}</span>
              <span style={{fontSize:11,fontFamily:"'DM Mono',monospace",color:"var(--tx3)"}}>{a.arrival}〜{a.departure||"?"}</span>
              <span style={{fontSize:11,color:"var(--am)",fontWeight:700,marginLeft:"auto",whiteSpace:"nowrap"}}>
                {a.type==="nodep"?"退所未記録 ⚠":`${a.mins}分（2時間未満） ⚠`}
              </span>
            </div>)}
          </div>
        }
      </AlertSection>

      {/* 4. 加算漏れ */}
      <AlertSection icon="💴" title="加算漏れ" color="#9048d8" count={addonAlerts.length}>
        {addonAlerts.length===0
          ?<div style={{color:"var(--gr)",fontSize:12,padding:"6px 0"}}>✅ 加算漏れは検出されませんでした</div>
          :<div style={{display:"flex",flexDirection:"column",gap:5}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:4}}>請求データに加算が設定されていない可能性があります。国保連請求画面で確認・設定してください。</div>
            {addonAlerts.map((a,i)=><div key={i} style={{display:"flex",gap:8,alignItems:"center",padding:"7px 11px",background:"rgba(144,72,216,0.06)",borderRadius:8,border:"1px solid rgba(144,72,216,0.2)"}}>
              <span style={{fontWeight:700,fontSize:13,minWidth:80}}>{a.userName}</span>
              <span style={{fontSize:11,fontWeight:700,color:"#9048d8",background:"rgba(144,72,216,0.1)",borderRadius:6,padding:"2px 8px"}}>{a.type}</span>
              <span style={{fontSize:11,color:"var(--tx3)",marginLeft:"auto"}}>{a.detail}</span>
            </div>)}
          </div>
        }
      </AlertSection>

      {/* 5. モニタリング期限 */}
      <AlertSection icon="📅" title="モニタリング期限" color="var(--tl)" count={monAlerts.length}>
        {monAlerts.length===0
          ?<div style={{color:"var(--gr)",fontSize:12,padding:"6px 0"}}>✅ 期限切れ・モニタリング未実施はありません</div>
          :<div style={{display:"flex",flexDirection:"column",gap:5}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:4}}>ISP有効期限が近い、または半年以上モニタリングが実施されていない利用者がいます。</div>
            {monAlerts.map((a,i)=>{
              const c=a.level==="danger"?"var(--ro)":a.level==="warn"?"var(--am)":"var(--tl)";
              const bg=a.level==="danger"?"rgba(224,56,56,0.06)":a.level==="warn"?"rgba(240,112,32,0.06)":"rgba(58,160,216,0.06)";
              const bc=a.level==="danger"?"rgba(224,56,56,0.2)":a.level==="warn"?"rgba(240,112,32,0.2)":"rgba(58,160,216,0.2)";
              return <div key={i} style={{display:"flex",gap:8,alignItems:"center",padding:"7px 11px",background:bg,borderRadius:8,border:`1px solid ${bc}`}}>
                <span style={{fontWeight:700,fontSize:13,minWidth:80}}>{a.userName}</span>
                <span style={{fontSize:11,fontWeight:700,color:c,background:`${c}18`,borderRadius:6,padding:"2px 8px"}}>{a.type}</span>
                <span style={{fontSize:11,color:"var(--tx3)",marginLeft:"auto"}}>{a.detail}{a.days!=null&&a.days>=0?` (残${a.days}日)`:""}</span>
              </div>;
            })}
          </div>
        }
      </AlertSection>
    </>}
  </div>;
}

// ==================== 勤務実績 ====================
function WorkRecordScreen({user,store,onBack}){
  const [vm,setVm]=useState(()=>{const d=new Date();return{y:d.getFullYear(),m:d.getMonth()+1};});
  const [tab,setTab]=useState("summary");
  const [selStaffId,setSelStaffId]=useState(null);

  const isMgr=user.role==="manager"||user.role==="admin";
  const fStaff=store.dynStaff.filter(s=>user.role==="admin"||s.facilityId===user.selectedFacilityId);
  const facName=FACILITIES.find(f=>f.id===user.selectedFacilityId)?.name||"";
  const days=daysInMonth(vm.y,vm.m);
  const mk=d=>`${vm.y}-${String(vm.m).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
  const yearMonth=vm.y+"-"+String(vm.m).padStart(2,"0");
  const dow=["日","月","火","水","木","金","土"];

  // シフトの開始・終了時刻をパース (例: "8:00〜17:00" → {start:480, end:1020})
  const parseShiftTime=key=>{
    const st=SHIFT_TYPES.find(s=>s.key===key);
    if(!st||!st.time.includes("〜")) return null;
    const [s,e]=st.time.split("〜");
    const toMin=t=>{const [h,m]=t.trim().split(":").map(Number);return h*60+(m||0);};
    return {start:toMin(s),end:toMin(e),hours:(toMin(e)-toMin(s)-60)/60}; // 休憩1h控除
  };

  // 実打刻を取得 (in:最早, out:最遅)
  const getActual=(staffId,dateStr)=>{
    const ins=store.recs.filter(r=>r.type==="staff_in"&&r.staffId===staffId&&(r.time||"").startsWith(dateStr));
    const outs=store.recs.filter(r=>r.type==="staff_out"&&r.staffId===staffId&&(r.time||"").startsWith(dateStr));
    const parseTime=t=>{
      // "2025/06/10 8:30:00" → minutes from midnight
      const m=t.match(/(\d+):(\d+)/);return m?+m[1]*60+ +m[2]:null;
    };
    const inTimes=ins.map(r=>parseTime(r.time)).filter(t=>t!==null);
    const outTimes=outs.map(r=>parseTime(r.time)).filter(t=>t!==null);
    const actualIn=inTimes.length?Math.min(...inTimes):null;
    const actualOut=outTimes.length?Math.max(...outTimes):null;
    const inRec=ins.length?ins.reduce((a,b)=>(parseTime(a.time)||9999)<(parseTime(b.time)||9999)?a:b):null;
    const outRec=outs.length?outs.reduce((a,b)=>(parseTime(a.time)||0)>(parseTime(b.time)||0)?a:b):null;
    return {actualIn,actualOut,inRec,outRec};
  };

  // 1日の勤務実績計算
  const calcDay=(staffId,dateStr)=>{
    const shiftKey=store.getShift(staffId,dateStr)||"none";
    const dw=new Date(dateStr).getDay();
    const isWe=dw===0||dw===6;
    if(isWe||shiftKey==="none") return {shiftKey,isWe,status:"休日"};
    if(shiftKey==="off") return {shiftKey,isWe:false,status:"公休"};
    if(shiftKey==="holiday") return {shiftKey,isWe:false,status:"有給"};
    const sched=parseShiftTime(shiftKey);
    const {actualIn,actualOut,inRec,outRec}=getActual(staffId,dateStr);
    if(actualIn===null) return {shiftKey,sched,status:"未打刻",actualIn:null,actualOut:null,workedH:0,overtimeH:0,lateMin:0,earlyMin:0};
    const workedH=actualOut!==null?(actualOut-actualIn-60)/60:null; // 休憩1h控除
    const lateMin=sched&&actualIn>sched.start+5?actualIn-sched.start:0;
    const earlyMin=sched&&actualOut!==null&&actualOut<sched.end-5?sched.end-actualOut:0;
    const overtimeH=sched&&workedH!==null&&workedH>sched.hours+0.5?workedH-sched.hours:0;
    const fmtMin=m=>{if(m===null) return "—";const h=Math.floor(m/60);const min=m%60;return h>0?`${h}:${String(min).padStart(2,"0")}`:`${String(min).padStart(2,"0")}`;}
    return {shiftKey,sched,status:outRec?"出勤":"退勤未打刻",actualIn,actualOut,workedH,overtimeH,lateMin,earlyMin,inTime:fmtMin(actualIn),outTime:fmtMin(actualOut),inRec,outRec};
  };

  // 職員ごとの月次集計
  const calcMonthSummary=staffId=>{
    let workDays=0,totalH=0,overtimeH=0,lateDays=0,earlyDays=0,noClockDays=0,punchDays=0;
    for(let i=1;i<=days;i++){
      const r=calcDay(staffId,mk(i));
      if(r.status==="出勤"||r.status==="退勤未打刻"){
        workDays++;
        if(r.workedH>0){totalH+=r.workedH;punchDays++;}
        else if(r.status==="退勤未打刻") noClockDays++;
        if(r.overtimeH>0) overtimeH+=r.overtimeH;
        if(r.lateMin>0) lateDays++;
        if(r.earlyMin>0) earlyDays++;
      } else if(r.status==="未打刻"&&store.getShift(staffId,mk(i))&&store.getShift(staffId,mk(i))!=="none"&&store.getShift(staffId,mk(i))!=="off"&&store.getShift(staffId,mk(i))!=="holiday"){
        noClockDays++;workDays++;
      }
    }
    return {workDays,totalH:Math.round(totalH*10)/10,overtimeH:Math.round(overtimeH*10)/10,lateDays,earlyDays,noClockDays,punchDays};
  };

  // 月次集計印刷
  const printMonthly=()=>{
    const rows=fStaff.map(s=>{
      const m=calcMonthSummary(s.id);
      return `<tr>
        <td style="font-weight:700;text-align:left;padding:5px 7px;">${s.name}</td>
        <td style="text-align:center;">${(s.data||s).role==="manager"?"管理者":(s.data||s).employmentType||"—"}</td>
        <td style="text-align:center;font-weight:700;color:#1a4a8a;">${m.workDays}日</td>
        <td style="text-align:center;font-weight:700;color:#1a7a3a;">${m.totalH}h</td>
        <td style="text-align:center;color:${m.overtimeH>0?"#c0392b":"#999"};font-weight:${m.overtimeH>0?700:400};">${m.overtimeH>0?"+"+m.overtimeH+"h":"—"}</td>
        <td style="text-align:center;color:${m.lateDays>0?"#e08020":"#999"};">${m.lateDays>0?m.lateDays+"日":"—"}</td>
        <td style="text-align:center;color:${m.earlyDays>0?"#e08020":"#999"};">${m.earlyDays>0?m.earlyDays+"日":"—"}</td>
        <td style="text-align:center;color:${m.noClockDays>0?"#c0392b":"#999"};font-weight:${m.noClockDays>0?700:400};">${m.noClockDays>0?m.noClockDays+"日":"—"}</td>
        <td style="border-left:1px dashed #ccc;min-width:60px;"></td>
      </tr>`;
    }).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>勤務実績集計表 ${vm.y}年${vm.m}月</title>
    <style>
      @page{size:A4 landscape;margin:12mm 10mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h2{font-size:13pt;margin-bottom:4px;} .meta{font-size:8pt;color:#555;margin-bottom:8px;}
      table{border-collapse:collapse;width:100%;font-size:9pt;}
      th,td{border:1px solid #ccc;padding:4px 6px;}
      th{background:#dce8f8;font-weight:700;text-align:center;}
      .sign-row{display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-top:14px;}
      .sign-box{border:1px solid #aaa;padding:8px;min-height:44px;border-radius:3px;}
      .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <h2>⏱ 勤務実績集計表</h2>
    <div class="meta">事業所: ${facName}　対象: ${vm.y}年${vm.m}月　出力日: ${new Date().toLocaleDateString("ja-JP")}</div>
    <div style="font-size:8pt;color:#888;margin-bottom:6px;">※ 勤務時間は打刻データから自動計算（休憩1時間控除）。シフトと打刻の差から遅刻・残業を判定。</div>
    <table>
      <thead><tr>
        <th style="text-align:left;">氏名</th><th>職種・雇用</th>
        <th>出勤日数</th><th>実働時間</th><th>時間外</th><th>遅刻日数</th><th>早退日数</th><th>未打刻日</th>
        <th>確認サイン</th>
      </tr></thead>
      <tbody>${rows}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">管理者 確認印</div></div>
      <div class="sign-box"><div class="sign-lbl">作成者</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=1200,height=800");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // 個人別勤怠台帳 印刷
  const printPersonal=staffId=>{
    const s=fStaff.find(x=>x.id===staffId);if(!s) return;
    const rows=Array.from({length:days},(_,i)=>{
      const d=i+1;const date=mk(d);const dw=new Date(date).getDay();
      const r=calcDay(staffId,date);
      const st=SHIFT_TYPES.find(x=>x.key===r.shiftKey);
      const rowBg=r.status==="公休"?"#f8f8f8":r.status==="有給"?"#f5eeff":r.status==="未打刻"?"#fdf0ee":"";
      return `<tr style="background:${rowBg};">
        <td style="text-align:center;font-size:8pt;color:${dw===0?"#c0392b":dw===6?"#1a4a8a":"#333"};font-weight:700;">${d}（${dow[dw]}）</td>
        <td style="text-align:center;font-size:8pt;color:${st?.text||"#999"};">${st?.label||"—"}</td>
        <td style="text-align:center;font-family:monospace;">${r.inTime||"—"}</td>
        <td style="text-align:center;font-family:monospace;">${r.outTime||"—"}</td>
        <td style="text-align:center;font-family:monospace;font-weight:700;">${r.workedH!=null&&r.workedH>0?r.workedH+"h":"—"}</td>
        <td style="text-align:center;color:${r.overtimeH>0?"#c0392b":"#999"};">${r.overtimeH>0?"+"+r.overtimeH+"h":"—"}</td>
        <td style="text-align:center;font-size:9pt;">
          ${r.lateMin>0?`<span style="color:#e08020;font-weight:700;">遅${r.lateMin}分</span>`:""}
          ${r.earlyMin>0?`<span style="color:#e08020;font-weight:700;">早${r.earlyMin}分</span>`:""}
          ${r.status==="未打刻"||r.status==="退勤未打刻"?`<span style="color:#c0392b;font-weight:700;">${r.status}</span>`:""}
          ${r.status==="公休"?"公休":r.status==="有給"?"有給":""}
        </td>
        <td style="min-width:50px;border-left:1px dashed #ccc;"></td>
      </tr>`;
    }).join("");
    const m=calcMonthSummary(staffId);
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>勤怠台帳 ${s.name} ${vm.y}年${vm.m}月</title>
    <style>
      @page{size:A4 portrait;margin:15mm 12mm;}
      *{box-sizing:border-box;} body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h2{font-size:14pt;border-bottom:2px solid #1a3a6a;padding-bottom:5px;margin-bottom:8px;}
      .info-grid{display:grid;grid-template-columns:1fr 1fr 1fr;gap:6px;margin-bottom:10px;}
      .info-item{border:1px solid #ccc;padding:5px 8px;border-radius:3px;}
      .info-lbl{font-size:7pt;color:#666;margin-bottom:1px;}
      .info-val{font-size:10pt;font-weight:700;}
      .sum-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:5px;margin-bottom:10px;}
      .sum-box{border:1px solid #ccc;padding:5px 7px;text-align:center;border-radius:3px;}
      .sum-val{font-size:13pt;font-weight:900;font-family:monospace;}
      .sum-lbl{font-size:7pt;color:#666;}
      table{border-collapse:collapse;width:100%;font-size:9pt;}
      th,td{border:1px solid #ccc;padding:4px 6px;}
      th{background:#dce8f8;font-weight:700;text-align:center;}
      .sign-row{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-top:14px;}
      .sign-box{border:1px solid #aaa;padding:8px;min-height:48px;border-radius:3px;}
      .sign-lbl{font-size:8pt;color:#666;}
    </style></head><body>
    <h2>⏱ 勤怠台帳（個人）</h2>
    <div class="info-grid">
      <div class="info-item"><div class="info-lbl">氏名</div><div class="info-val">${s.name}</div></div>
      <div class="info-item"><div class="info-lbl">所属施設</div><div class="info-val">${facName}</div></div>
      <div class="info-item"><div class="info-lbl">対象年月</div><div class="info-val">${vm.y}年${vm.m}月</div></div>
    </div>
    <div class="sum-grid">
      <div class="sum-box"><div class="sum-val" style="color:#1a4a8a;">${m.workDays}</div><div class="sum-lbl">出勤日数</div></div>
      <div class="sum-box"><div class="sum-val" style="color:#1a7a3a;">${m.totalH}h</div><div class="sum-lbl">実働時間</div></div>
      <div class="sum-box"><div class="sum-val" style="color:${m.overtimeH>0?"#c0392b":"#999"};">${m.overtimeH>0?"+"+m.overtimeH:"0"}h</div><div class="sum-lbl">時間外</div></div>
      <div class="sum-box"><div class="sum-val" style="color:${m.noClockDays>0?"#c0392b":"#999"};">${m.noClockDays}</div><div class="sum-lbl">未打刻日</div></div>
    </div>
    <table>
      <thead><tr><th>日付</th><th>シフト</th><th>出勤</th><th>退勤</th><th>実働</th><th>残業</th><th>備考</th><th>確認</th></tr></thead>
      <tbody>${rows}</tbody>
    </table>
    <div class="sign-row">
      <div class="sign-box"><div class="sign-lbl">本人 確認サイン</div></div>
      <div class="sign-box"><div class="sign-lbl">管理者 確認印　　確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div></body></html>`;
    const w=window.open("","_blank","width=900,height=750");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // 勤怠集計 CSV出力（強化版：給与計算基礎項目付き）
  const downloadCSV=()=>{
    const headers=[
      "職員ID","氏名","雇用区分","所属施設",
      "出勤日数","実働時間(h)","時間外(h)","深夜残業(h,概算)",
      "遅刻日数","早退日数","未打刻日数","有給取得日数","公休日数",
      "勤怠備考（給与計算用）"
    ];
    const rows=fStaff.map(s=>{
      const mo=calcMonthSummary(s.id);
      const sd=s.data||s;
      const fac=FACILITIES.find(f=>f.id===(s.facilityId||user.selectedFacilityId))?.name||"";
      // 有給・公休数（シフトから）
      let holCnt=0,offCnt=0;
      for(let i=1;i<=days;i++){const t=store.getShift(s.id,mk(i));if(t==="holiday")holCnt++;else if(t==="off")offCnt++;}
      // 備考（遅刻・残業ありの場合）
      const note=[];
      if(mo.lateDays>0) note.push(`遅刻${mo.lateDays}日`);
      if(mo.earlyDays>0) note.push(`早退${mo.earlyDays}日`);
      if(mo.overtimeH>45) note.push("残業45h超");
      if(mo.noClockDays>0) note.push(`打刻漏れ${mo.noClockDays}日`);
      return [s.id,s.name,sd.employmentType||"—",fac,
        mo.workDays,mo.totalH,mo.overtimeH,0, // 深夜は0で概算
        mo.lateDays,mo.earlyDays,mo.noClockDays,holCnt,offCnt,
        note.length>0?note.join("・"):"問題なし"];
    });
    const csv=[headers,...rows].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a=document.createElement("a");a.href=URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download=`kintai_${yearMonth}_${facName}.csv`;a.click();
  };

  // 全職員分の日次明細CSVエクスポート（勤怠管理システム連携用）
  const downloadDetailCSV=()=>{
    const headers=["職員ID","氏名","日付","曜日","シフト","出勤時刻","退勤時刻","実働(h)","残業(h)","遅刻(分)","早退(分)","ステータス"];
    const rows=[];
    fStaff.forEach(s=>{
      for(let i=1;i<=days;i++){
        const date=mk(i);const dw=["日","月","火","水","木","金","土"][new Date(date).getDay()];
        const r=calcDay(s.id,date);
        if(r.status==="休日") return;
        rows.push([s.id,s.name,date,dw,r.shiftKey||"—",
          r.inTime||"—",r.outTime||"—",
          r.workedH!=null?Math.round(r.workedH*10)/10:"—",
          r.overtimeH||0,r.lateMin||0,r.earlyMin||0,r.status]);
      }
    });
    const csv=[headers,...rows].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a=document.createElement("a");a.href=URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download=`kintai_detail_${yearMonth}_${facName}.csv`;a.click();
  };

  const selStaff=fStaff.find(s=>s.id===selStaffId)||fStaff[0];

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">⏱ 勤務実績</div>
    </div>

    {/* 年月ナビ */}
    <div style={{display:"flex",alignItems:"center",gap:9,marginBottom:12,flexWrap:"wrap"}}>
      <button className="cn" onClick={()=>setVm(v=>v.m===1?{y:v.y-1,m:12}:{y:v.y,m:v.m-1})}>‹</button>
      <div style={{fontSize:16,fontWeight:900,minWidth:90,textAlign:"center"}}>{vm.y}年 {vm.m}月</div>
      <button className="cn" onClick={()=>setVm(v=>v.m===12?{y:v.y+1,m:1}:{y:v.y,m:v.m+1})}>›</button>
      <div style={{display:"flex",gap:5,marginLeft:8,flexWrap:"wrap"}}>
        {[{id:"summary",icon:"📊",label:"月次集計"},{id:"personal",icon:"👤",label:"個人別実績"},{id:"alert",icon:"🚨",label:"アラート"}].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{padding:"7px 13px",borderRadius:9,border:"2px solid",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontSize:12,fontWeight:700,
              borderColor:tab===t.id?"var(--tl)":"var(--bd)",background:tab===t.id?"rgba(58,160,216,0.2)":"var(--bg)",color:tab===t.id?"var(--tl)":"var(--tx3)"}}>
            {t.icon} {t.label}
          </button>
        ))}
      </div>
      {isMgr&&<div style={{display:"flex",gap:6,marginLeft:"auto",flexWrap:"wrap"}}>
        <button className="bexp" onClick={downloadCSV}>⬇ 集計CSV</button>
        <button className="bexp" style={{background:"rgba(44,170,96,0.1)",borderColor:"var(--gr)",color:"var(--gr)"}} onClick={downloadDetailCSV}>⬇ 日次明細CSV</button>
        <button className="bexp" style={{background:"#fff8f0",borderColor:"var(--ac)",color:"var(--ac)"}} onClick={printMonthly}>🖨️ 集計印刷</button>
      </div>}
    </div>

    {/* ── 月次集計タブ ── */}
    {tab==="summary"&&<>
      <div style={{overflowX:"auto",marginBottom:16}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:560}}>
          <thead><tr style={{background:"var(--bg2)"}}>
            {["職員名","雇用区分","出勤日数","実働時間","時間外","遅刻","早退","未打刻","台帳"].map(h=>(
              <th key={h} style={{padding:"8px 9px",textAlign:"left",color:"var(--tx2)",fontSize:10,fontWeight:700,borderBottom:"2px solid var(--bd)",whiteSpace:"nowrap"}}>{h}</th>
            ))}
          </tr></thead>
          <tbody>{fStaff.map(s=>{
            const m=calcMonthSummary(s.id);const sd=s.data||s;
            return <tr key={s.id} style={{borderBottom:"1px solid var(--bd)"}}>
              <td style={{padding:"8px 9px",fontWeight:700}}>{s.name}</td>
              <td style={{padding:"8px 9px",fontSize:11,color:"var(--tx3)"}}>{sd.role==="manager"?"管理者":sd.employmentType||"—"}</td>
              <td style={{padding:"8px 9px",textAlign:"right",fontFamily:"'DM Mono',monospace",fontWeight:700,color:"var(--tl)"}}>{m.workDays}日</td>
              <td style={{padding:"8px 9px",textAlign:"right",fontFamily:"'DM Mono',monospace",fontWeight:700,color:"var(--gr)"}}>{m.totalH}h</td>
              <td style={{padding:"8px 9px",textAlign:"right",fontFamily:"'DM Mono',monospace",fontWeight:m.overtimeH>0?700:400,color:m.overtimeH>0?"var(--ro)":"var(--tx3)"}}>{m.overtimeH>0?"+"+m.overtimeH+"h":"—"}</td>
              <td style={{padding:"8px 9px",textAlign:"right",color:m.lateDays>0?"var(--am)":"var(--tx3)",fontWeight:m.lateDays>0?700:400}}>{m.lateDays>0?m.lateDays+"日":"—"}</td>
              <td style={{padding:"8px 9px",textAlign:"right",color:m.earlyDays>0?"var(--am)":"var(--tx3)",fontWeight:m.earlyDays>0?700:400}}>{m.earlyDays>0?m.earlyDays+"日":"—"}</td>
              <td style={{padding:"8px 9px",textAlign:"right",color:m.noClockDays>0?"var(--ro)":"var(--tx3)",fontWeight:m.noClockDays>0?700:400}}>{m.noClockDays>0?m.noClockDays+"日":"—"}</td>
              <td style={{padding:"8px 9px"}}>
                <button onClick={()=>printPersonal(s.id)}
                  style={{fontSize:11,padding:"4px 9px",borderRadius:7,background:"rgba(58,160,216,0.1)",border:"1px solid rgba(58,160,216,0.4)",color:"var(--tl)",fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
                  🖨
                </button>
              </td>
            </tr>;
          })}</tbody>
        </table>
      </div>
      {/* 全体集計カード */}
      <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(130px,1fr))",gap:8}}>
        {(()=>{
          const all=fStaff.map(s=>calcMonthSummary(s.id));
          return [
            {label:"総出勤日数",val:all.reduce((s,m)=>s+m.workDays,0)+"日",color:"var(--tl)"},
            {label:"総実働時間",val:Math.round(all.reduce((s,m)=>s+m.totalH,0)*10)/10+"h",color:"var(--gr)"},
            {label:"時間外合計",val:Math.round(all.reduce((s,m)=>s+m.overtimeH,0)*10)/10+"h",color:"var(--ro)"},
            {label:"遅刻延べ日数",val:all.reduce((s,m)=>s+m.lateDays,0)+"日",color:"var(--am)"},
            {label:"未打刻件数",val:all.reduce((s,m)=>s+m.noClockDays,0)+"件",color:"var(--ro)"},
          ].map(c=>(
            <div key={c.label} style={{background:"var(--bg2)",borderRadius:9,padding:"10px 12px",textAlign:"center"}}>
              <div style={{fontSize:18,fontWeight:900,color:c.color,fontFamily:"'DM Mono',monospace"}}>{c.val}</div>
              <div style={{fontSize:10,color:"var(--tx3)",marginTop:3}}>{c.label}</div>
            </div>
          ));
        })()}
      </div>
    </>}

    {/* ── 個人別実績タブ ── */}
    {tab==="personal"&&<>
      <div style={{display:"flex",gap:7,flexWrap:"wrap",marginBottom:12}}>
        {fStaff.map(s=>(
          <button key={s.id} onClick={()=>setSelStaffId(s.id)}
            style={{padding:"8px 14px",borderRadius:9,border:"2px solid",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontSize:12,fontWeight:700,
              borderColor:(selStaffId||fStaff[0]?.id)===s.id?"var(--tl)":"var(--bd)",
              background:(selStaffId||fStaff[0]?.id)===s.id?"rgba(58,160,216,0.2)":"var(--bg)",
              color:(selStaffId||fStaff[0]?.id)===s.id?"var(--tl)":"var(--tx3)"}}>
            {s.name}
          </button>
        ))}
      </div>
      {selStaff&&(()=>{
        const m=calcMonthSummary(selStaff.id);
        return <>
          <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginBottom:12}}>
            {[{label:"出勤日数",val:m.workDays+"日",c:"var(--tl)"},{label:"実働時間",val:m.totalH+"h",c:"var(--gr)"},{label:"時間外",val:m.overtimeH>0?"+"+m.overtimeH+"h":"0h",c:m.overtimeH>0?"var(--ro)":"var(--tx3)"},{label:"未打刻",val:m.noClockDays+"日",c:m.noClockDays>0?"var(--ro)":"var(--tx3)"}].map(c=>(
              <div key={c.label} className="stat-card"><div className="stat-label">{c.label}</div><div className="stat-val" style={{color:c.c,fontSize:20}}>{c.val}</div></div>
            ))}
          </div>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:11,minWidth:500}}>
              <thead><tr style={{background:"var(--bg2)"}}>
                {["日付","シフト","出勤打刻","退勤打刻","実働時間","時間外","備考"].map(h=>(
                  <th key={h} style={{padding:"7px 8px",textAlign:"center",color:"var(--tx2)",fontSize:10,fontWeight:700,borderBottom:"2px solid var(--bd)",whiteSpace:"nowrap"}}>{h}</th>
                ))}
              </tr></thead>
              <tbody>{Array.from({length:days},(_,i)=>{
                const d=i+1;const date=mk(d);const dw=new Date(date).getDay();
                const r=calcDay(selStaff.id,date);
                const st=SHIFT_TYPES.find(x=>x.key===r.shiftKey);
                const rowBg=r.status==="公休"?"rgba(100,116,139,0.07)":r.status==="有給"?"rgba(144,72,216,0.07)":r.status==="未打刻"||r.status==="退勤未打刻"?"rgba(224,56,56,0.06)":"";
                return <tr key={d} style={{borderBottom:"1px solid var(--bd)",background:rowBg}}>
                  <td style={{padding:"6px 8px",textAlign:"center",fontWeight:700,color:dw===0?"var(--ro)":dw===6?"var(--tl)":"var(--tx)",fontFamily:"'DM Mono',monospace",fontSize:11}}>
                    {vm.m}/{d}（{dow[dw]}）
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center"}}>
                    {st?<span style={{fontSize:10,padding:"2px 7px",borderRadius:6,background:st.color,color:st.text,fontWeight:700}}>{st.label}</span>:<span style={{color:"var(--tx3)",fontSize:10}}>—</span>}
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center",fontFamily:"'DM Mono',monospace",color:r.lateMin>0?"var(--am)":"var(--tx)"}}>
                    {r.inTime||<span style={{color:"var(--tx3)"}}>—</span>}
                    {r.lateMin>0&&<span style={{fontSize:9,color:"var(--am)",marginLeft:3}}>+{r.lateMin}分</span>}
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center",fontFamily:"'DM Mono',monospace",color:r.earlyMin>0?"var(--am)":"var(--tx)"}}>
                    {r.outTime||<span style={{color:"var(--tx3)"}}>—</span>}
                    {r.earlyMin>0&&<span style={{fontSize:9,color:"var(--am)",marginLeft:3}}>-{r.earlyMin}分</span>}
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center",fontFamily:"'DM Mono',monospace",fontWeight:700,color:"var(--tl)"}}>
                    {r.workedH>0?r.workedH+"h":"—"}
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center",fontFamily:"'DM Mono',monospace",color:"var(--ro)",fontWeight:700}}>
                    {r.overtimeH>0?"+"+r.overtimeH+"h":"—"}
                  </td>
                  <td style={{padding:"6px 8px",textAlign:"center",fontSize:10}}>
                    {r.status==="公休"&&<span style={{color:"var(--tx3)"}}>公休</span>}
                    {r.status==="有給"&&<span style={{color:"var(--pu)",fontWeight:700}}>有給</span>}
                    {r.status==="未打刻"&&<span style={{color:"var(--ro)",fontWeight:700}}>未打刻</span>}
                    {r.status==="退勤未打刻"&&<span style={{color:"var(--am)",fontWeight:700}}>退勤未打刻</span>}
                  </td>
                </tr>;
              })}</tbody>
            </table>
          </div>
          <div style={{marginTop:10,display:"flex",justifyContent:"flex-end"}}>
            <button onClick={()=>printPersonal(selStaff.id)}
              style={{padding:"9px 18px",borderRadius:10,background:"linear-gradient(135deg,#1a4a8a,#2d6ed6)",color:"#fff",border:"none",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
              🖨 勤怠台帳を印刷
            </button>
          </div>
        </>;
      })()}
    </>}

    {/* ── アラートタブ ── */}
    {tab==="alert"&&<>
      <div className="dash-title" style={{marginBottom:10}}>🚨 打刻アラート（{vm.y}年{vm.m}月）</div>
      {(()=>{
        const alerts=[];
        fStaff.forEach(s=>{
          for(let i=1;i<=days;i++){
            const date=mk(i);const r=calcDay(s.id,date);
            if(r.status==="未打刻") alerts.push({level:"danger",text:`${s.name}：${vm.m}/${i}（${dow[new Date(date).getDay()]}）出勤打刻なし（シフト: ${SHIFT_TYPES.find(x=>x.key===r.shiftKey)?.label||r.shiftKey}）`,staffId:s.id,date});
            else if(r.status==="退勤未打刻") alerts.push({level:"warn",text:`${s.name}：${vm.m}/${i}（${dow[new Date(date).getDay()]}）退勤打刻なし`,staffId:s.id,date});
            else if(r.lateMin>=10) alerts.push({level:"warn",text:`${s.name}：${vm.m}/${i}（${dow[new Date(date).getDay()]}）遅刻 ${r.lateMin}分`,staffId:s.id,date});
            else if(r.overtimeH>=1) alerts.push({level:"info",text:`${s.name}：${vm.m}/${i}（${dow[new Date(date).getDay()]}）残業 ${r.overtimeH}時間`,staffId:s.id,date});
          }
        });
        if(alerts.length===0) return <div style={{background:"rgba(44,170,96,0.1)",border:"1px solid rgba(44,170,96,0.4)",borderRadius:10,padding:"14px 16px",display:"flex",gap:10,alignItems:"center"}}>
          <span style={{fontSize:20}}>✅</span><span style={{fontWeight:700,color:"var(--gr)"}}>打刻アラートはありません</span>
        </div>;
        return <div>{alerts.map((a,i)=>(
          <div key={i} className={"alert-row alert-"+(a.level==="danger"?"danger":a.level==="warn"?"warn":"na")} style={{marginBottom:5}}>
            <span className="alert-icon">{a.level==="danger"?"🚨":a.level==="warn"?"⚠️":"ℹ️"}</span>
            <span className="alert-text" style={{color:a.level==="danger"?"var(--ro)":a.level==="warn"?"var(--am)":"var(--tl)"}}>{a.text}</span>
          </div>
        ))}</div>;
      })()}
    </>}
  </div>;
}

// ==================== APP ROOT ====================

// ==================== 生徒予定表 ====================
const SCHEDULE_STATUS = {
  "来所予定": { label:"来所予定", color:"var(--tl)", bg:"rgba(58,160,216,0.2)", short:"予" },
  "来所":     { label:"来所（入室）", color:"var(--gr)", bg:"rgba(44,170,96,0.2)", short:"来" },
  "欠席":     { label:"欠席", color:"var(--ro)", bg:"rgba(224,56,56,0.15)", short:"欠" },
  "体調不良": { label:"体調不良", color:"#8a6200", bg:"#fef8e6", short:"体" },
  "キャンセル":{ label:"キャンセル", color:"#555", bg:"#e8e8e8", short:"キャ" },
  "休所":     { label:"休所", color:"#7030b8", bg:"rgba(144,72,216,0.18)", short:"休" },
};

// ==================== 保護者連絡先・LINE通知管理 ====================
function ParentContactsScreen({user, store, onBack}){
  const facilityId=user.selectedFacilityId;
  const myUsers=store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);
  const [editId,setEditId]=useState(null);
  const [form,setForm]=useState({parent_name:"",line_user_id:"",phone:"",email:"",notification_enabled:true});
  const [sendConfirm,setSendConfirm]=useState(null); // {userId, message} 誤送信防止確認
  const [lineSending,setLineSending]=useState(false);

  const getContact=uid=>(store.parentContacts||[]).find(c=>c.child_id===uid)||{child_id:uid,notification_enabled:true};

  const openEdit=u=>{
    const c=getContact(u.id);
    setForm({parent_name:c.parent_name||"",line_user_id:c.line_user_id||"",phone:c.phone||"",email:c.email||"",notification_enabled:c.notification_enabled!==false});
    setEditId(u.id);
  };

  const saveContact=()=>{
    const c={id:editId+"_contact",child_id:editId,facility_id:facilityId,...form,updated_at:new Date().toISOString()};
    store.saveParentContact(c);
    setEditId(null);
    store.showToast("保護者情報を保存しました","success");
  };

  const toggleNotify=uid=>{
    const c=getContact(uid);
    const updated={id:uid+"_contact",child_id:uid,facility_id:facilityId,...c,notification_enabled:!c.notification_enabled,updated_at:new Date().toISOString()};
    store.saveParentContact(updated);
    store.showToast(updated.notification_enabled?"通知ON":"通知OFF","success");
  };

  // 送信前確認（誤送信防止）
  const requestSend=(userId,userName,msgType)=>{
    setSendConfirm({userId,userName,msgType,message:{
      arrive:`${userName}さんが来所しました（${nowHM()}）`,
      depart:`${userName}さんが退所しました（${nowHM()}）`,
      notice:"施設からのお知らせがあります。アプリをご確認ください。",
    }[msgType]||""});
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">👨‍👩‍👧 保護者連絡管理</div>
    </div>

    <div style={{fontSize:11,color:"var(--tx3)",padding:"8px 12px",background:"var(--bg2)",borderRadius:8,marginBottom:14,lineHeight:1.7}}>
      📋 通知送信前に確認ダイアログを表示します。誤送信を防止するため、必ず内容を確認してから送信してください。
    </div>

    {myUsers.map(u=>{
      const c=getContact(u.id);
      const isEdit=editId===u.id;
      const notify=c.notification_enabled!==false;
      return <div key={u.id} style={{background:"var(--wh)",border:"1.5px solid var(--bd)",borderRadius:12,marginBottom:10,overflow:"hidden"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",background:notify?"rgba(44,170,96,0.05)":"var(--wh)"}}>
          <div style={{width:36,height:36,borderRadius:"50%",background:"rgba(58,160,216,0.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0,overflow:"hidden"}}>
            {u.photo?<img src={u.photo} style={{width:36,height:36,borderRadius:"50%",objectFit:"cover"}} alt=""/>:"👤"}
          </div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontWeight:700,fontSize:14,color:"var(--tx)"}}>{u.name}</div>
            <div style={{fontSize:11,color:"var(--tx3)"}}>
              {c.parent_name&&<span style={{marginRight:8}}>👤 {c.parent_name}</span>}
              {c.phone&&<span>📞 {c.phone}</span>}
            </div>
          </div>
          <button style={{padding:"4px 10px",borderRadius:20,border:`1.5px solid ${notify?"var(--gr)":"var(--bd)"}`,background:notify?"rgba(44,170,96,0.1)":"var(--bg)",color:notify?"var(--gr)":"var(--tx3)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>toggleNotify(u.id)}>
            {notify?"🔔 通知ON":"🔕 通知OFF"}
          </button>
          <button style={{fontSize:11,color:"var(--tl)",border:"none",background:"none",cursor:"pointer",padding:"4px",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>isEdit?setEditId(null):openEdit(u)}>✏️</button>
        </div>

        {/* クイック通知ボタン */}
        <div style={{display:"flex",gap:6,padding:"8px 14px",borderTop:"1px solid var(--bd)",flexWrap:"wrap"}}>
          {[{type:"arrive",label:"来所通知"},{type:"depart",label:"退所通知"},{type:"notice",label:"お知らせ"}].map(b=>(
            <button key={b.type}
              style={{flex:1,minWidth:70,padding:"6px 4px",borderRadius:8,border:"1.5px solid var(--bd)",background:notify?"var(--bg)":"var(--bg2)",color:notify?"var(--tx2)":"var(--tx3)",fontSize:11,fontWeight:700,cursor:notify?"pointer":"not-allowed",fontFamily:"'Noto Sans JP',sans-serif"}}
              disabled={!notify}
              onClick={()=>notify&&requestSend(u.id,u.name,b.type)}>
              {b.label}
            </button>
          ))}
        </div>

        {/* 編集フォーム */}
        {isEdit&&<div style={{padding:"12px 14px",background:"var(--bg2)",borderTop:"1px solid var(--bd)"}}>
          {[{key:"parent_name",label:"保護者名",type:"text",ph:"山田 花子"},{key:"line_user_id",label:"LINE ID",type:"text",ph:"LINE IDまたはユーザーID"},{key:"phone",label:"電話番号",type:"tel",ph:"090-0000-0000"},{key:"email",label:"メール",type:"email",ph:"example@email.com"}].map(f=>(
            <div key={f.key} style={{marginBottom:8}}>
              <div className="slbl">{f.label}</div>
              <input type={f.type} className="fi" value={form[f.key]||""} onChange={e=>setForm(p=>({...p,[f.key]:e.target.value}))} placeholder={f.ph}/>
            </div>
          ))}
          <label style={{display:"flex",alignItems:"center",gap:8,fontSize:12,color:"var(--tx2)",cursor:"pointer",marginBottom:12}}>
            <input type="checkbox" checked={form.notification_enabled} onChange={e=>setForm(p=>({...p,notification_enabled:e.target.checked}))}/>
            LINE通知を有効にする
          </label>
          <div style={{display:"flex",gap:8}}>
            <button className="bsave" style={{flex:1}} onClick={saveContact}>保存</button>
            <button style={{flex:1,padding:"10px",borderRadius:9,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>setEditId(null)}>キャンセル</button>
          </div>
        </div>}
      </div>;
    })}

    {/* 送信確認モーダル（誤送信防止） */}
    {sendConfirm&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:300,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 16px"}}>
      <div style={{background:"var(--wh)",borderRadius:16,padding:"22px 18px",width:"100%",maxWidth:400}}>
        <div style={{fontWeight:700,fontSize:15,marginBottom:8,color:"var(--tx)"}}>📤 送信確認</div>
        <div style={{fontSize:12,color:"var(--tx3)",marginBottom:10}}>送信先：{sendConfirm.userName}の保護者</div>
        <div style={{padding:"12px",background:"var(--bg2)",borderRadius:10,fontSize:13,color:"var(--tx)",lineHeight:1.7,marginBottom:16,border:"1px solid var(--bd)"}}>
          {sendConfirm.message}
        </div>
        <div style={{fontSize:11,color:"var(--ro)",marginBottom:14}}>⚠️ 送信後の取り消しはできません。内容を確認してください。</div>
        <div style={{display:"flex",gap:10}}>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"none",background:"var(--tl)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={async()=>{
              setLineSending(true);
              const u=myUsers.find(x=>x.id===sendConfirm.userId);
              const contact=getContact(sendConfirm.userId);
              const lineId=u?.lineUserId||contact?.line_user_id;
              if(lineId){
                try{
                  await fetch("/api/line-push",{method:"POST",headers:{"Content-Type":"application/json"},
                    body:JSON.stringify({lineUserId:lineId,message:sendConfirm.message})});
                  store.showToast("LINE通知を送信しました","success");
                }catch(e){store.showToast("LINE送信エラー。アプリ内通知のみ送信しました","warn");}
              } else {
                store.showToast("通知を記録しました（LINE未登録のためアプリ内のみ）","success");
              }
              store.addMsg({id:genId(),userId:sendConfirm.userId,userName:u?.name||"",facilityId,from:user.displayName,body:sendConfirm.message,time:nowStr(),read:true,parentRead:false,parentReadAt:null,replies:[],isBroadcast:false,isUrgent:false});
              setLineSending(false);setSendConfirm(null);
            }}>
            {lineSending?"送信中...":"✅ 送信する"}
          </button>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>setSendConfirm(null)}>キャンセル</button>
        </div>
      </div>
    </div>}
  </div>;
}

// ==================== スタッフ配置モニター ====================
// 今日の出勤状況・配置基準・AI警告を表示
function StaffMonitorScreen({user, store, onBack}){
  const facilityId=user.selectedFacilityId;
  const today=todayISO();

  // 今日の出退勤記録
  const todayIn=store.recs.filter(r=>r.type==="staff_in"&&r.facilityId===facilityId&&isTodayRec(r));
  const todayOut=store.recs.filter(r=>r.type==="staff_out"&&r.facilityId===facilityId&&isTodayRec(r));
  // 在勤スタッフ（出勤済み・退勤していない）
  const inStaffIds=[...new Set(todayIn.map(r=>r.staffId))].filter(id=>!todayOut.some(r=>r.staffId===id));
  // 今日の来所児童
  const todayChildIn=[...new Set(store.recs.filter(r=>r.type==="user_in"&&r.facilityId===facilityId&&isTodayRec(r)).map(r=>r.userId))];
  const todayChildOut=[...new Set(store.recs.filter(r=>r.type==="user_out"&&r.facilityId===facilityId&&isTodayRec(r)).map(r=>r.userId))];
  const currentChildren=todayChildIn.filter(id=>!todayChildOut.includes(id));

  // 配置基準チェック（放課後等デイ：10:2以上が基本）
  const minStaff=2;
  const requiredByRatio=currentChildren.length>0?Math.max(minStaff,Math.ceil(currentChildren.length/10)+1):minStaff;
  const staffShort=inStaffIds.length<requiredByRatio;

  // AI警告生成
  const warnings=[];
  if(staffShort) warnings.push({level:"danger",icon:"🚨",text:`配置不足：在勤${inStaffIds.length}名（必要${requiredByRatio}名）。加算・配置基準を満たしていません`});
  if(currentChildren.length>10&&inStaffIds.length<3) warnings.push({level:"warn",icon:"⚠️",text:"10名超の児童がいます。追加スタッフの配置を検討してください"});
  // 長時間勤務チェック
  todayIn.forEach(r=>{
    const h=(new Date()-new Date(r.time||0))/(1000*60*60);
    if(h>=8) warnings.push({level:"warn",icon:"⏰",text:`${r.staffName}：勤務${Math.floor(h)}時間（8時間超）`});
  });
  if(warnings.length===0&&inStaffIds.length>=minStaff) warnings.push({level:"ok",icon:"✅",text:"配置基準を満たしています"});

  // 施設スタッフ一覧
  const allStaff=store.dynStaff.filter(s=>s.facilityId===facilityId&&s.active!==false);

  const getClockIn=staffId=>{
    const r=todayIn.filter(x=>x.staffId===staffId).slice(-1)[0];
    return r?parseRecTime(r.time).time:null;
  };
  const getClockOut=staffId=>{
    const r=todayOut.filter(x=>x.staffId===staffId).slice(-1)[0];
    return r?parseRecTime(r.time).time:null;
  };
  const getTemp=staffId=>{
    const r=todayIn.filter(x=>x.staffId===staffId).slice(-1)[0];
    return r?.temp||null;
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">👥 スタッフ配置モニター</div>
    </div>

    {/* サマリーカード */}
    <div style={{display:"flex",gap:8,marginBottom:14}}>
      {[
        {label:"在勤スタッフ",val:inStaffIds.length,color:staffShort?"var(--ro)":"var(--gr)"},
        {label:"必要人数",     val:requiredByRatio, color:"var(--tx2)"},
        {label:"在所児童",     val:currentChildren.length,color:"var(--tl)"},
      ].map(s=><div key={s.label} style={{flex:1,background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
        <div style={{fontSize:10,color:"var(--tx3)",marginBottom:2}}>{s.label}</div>
        <div style={{fontSize:24,fontWeight:800,color:s.color}}>{s.val}</div>
      </div>)}
    </div>

    {/* AI警告 */}
    {warnings.map((w,i)=>(
      <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",marginBottom:8,borderRadius:10,border:`1.5px solid ${w.level==="danger"?"var(--ro)":w.level==="warn"?"var(--ac)":"var(--gr)"}`,background:w.level==="danger"?"rgba(224,56,56,0.08)":w.level==="warn"?"rgba(255,160,0,0.08)":"rgba(44,170,96,0.08)"}}>
        <span style={{fontSize:18,flexShrink:0}}>{w.icon}</span>
        <span style={{fontSize:12,color:w.level==="danger"?"var(--ro)":w.level==="warn"?"var(--ac)":"var(--gr)",fontWeight:700,lineHeight:1.5}}>{w.text}</span>
      </div>
    ))}

    {/* スタッフ別状況 */}
    <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,overflow:"hidden",marginBottom:14}}>
      <div style={{padding:"10px 14px",fontWeight:700,fontSize:13,color:"var(--tx)",borderBottom:"1px solid var(--bd)"}}>スタッフ出勤状況</div>
      {allStaff.map(s=>{
        const cIn=getClockIn(s.id);
        const cOut=getClockOut(s.id);
        const isIn=inStaffIds.includes(s.id);
        const temp=getTemp(s.id);
        return <div key={s.id} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",borderBottom:"1px solid var(--bd)"}}>
          <div style={{width:8,height:8,borderRadius:"50%",background:isIn?"var(--gr)":cIn?"var(--tx3)":"var(--bd)",flexShrink:0}}/>
          <div style={{flex:1}}>
            <div style={{fontWeight:600,fontSize:13,color:"var(--tx)"}}>{s.name}</div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>
              {cIn?<span style={{marginRight:6}}>出勤 {cIn}</span>:<span style={{marginRight:6,color:"var(--tx3)"}}>未出勤</span>}
              {cOut&&<span>退勤 {cOut}</span>}
              {temp&&<span style={{marginLeft:6}}>🌡️ {temp}℃</span>}
            </div>
          </div>
          <div style={{fontSize:11,fontWeight:700,color:isIn?"var(--gr)":cIn?"var(--tx3)":"var(--bd)"}}>
            {isIn?"在勤":cIn?"退勤":"―"}
          </div>
        </div>;
      })}
      {allStaff.length===0&&<div style={{padding:"20px",textAlign:"center",color:"var(--tx3)",fontSize:12}}>スタッフが登録されていません</div>}
    </div>

    {/* 加算条件メモ */}
    <div style={{padding:"12px 14px",background:"rgba(58,160,216,0.06)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:10,fontSize:11,color:"var(--tx2)",lineHeight:1.8}}>
      📌 <strong>配置基準メモ</strong><br/>
      放課後等デイサービス：利用者10名に対し2名以上（うち1名は常勤）<br/>
      専門的支援加算：理学療法士・作業療法士・言語聴覚士等が配置
    </div>
  </div>;
}

// ==================== 活動記録 AI自動生成 ====================
// 活動種別を選択→AI提案→人間確認→保存。自動確定禁止。
const AI_ACTIVITY_TYPES = [
  {id:"sst",label:"🗣️ SST",desc:"ソーシャルスキルトレーニング"},
  {id:"cooking",label:"🍳 調理実習",desc:"おやつ・料理作り"},
  {id:"outdoor",label:"🏃 外出支援",desc:"公園・地域活動"},
  {id:"gym",label:"🏀 体育館活動",desc:"スポーツ・運動"},
  {id:"trip",label:"🚌 社会見学",desc:"校外学習・見学"},
  {id:"individual",label:"📚 個別課題",desc:"学習支援・個別療育"},
  {id:"art",label:"🎨 創作活動",desc:"工作・絵画・音楽"},
  {id:"celebration",label:"🎂 誕生会",desc:"月間誕生日会"},
];

function ActivityAIScreen({user, store, onBack}){
  const facilityId=user.selectedFacilityId;
  const myUsers=store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);
  const [step,setStep]=useState("select"); // select|generating|review|done
  const [selDate,setSelDate]=useState(todayISO());
  const [selActivity,setSelActivity]=useState(null);
  const [selChildren,setSelChildren]=useState([]); // 参加児童IDs
  const [addInfo,setAddInfo]=useState(""); // 追加情報
  const [aiResult,setAiResult]=useState(null); // {activityDesc, individualNotes, parentMessage}
  const [editedDesc,setEditedDesc]=useState("");
  const [editedParent,setEditedParent]=useState("");
  const [saving,setSaving]=useState(false);

  const toggleChild=id=>setSelChildren(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);

  // AI生成
  const generate=async()=>{
    if(!selActivity){alert("活動を選択してください");return;}
    if(selChildren.length===0){alert("参加児童を1名以上選択してください");return;}
    setStep("generating");
    const children=myUsers.filter(u=>selChildren.includes(u.id)).map(u=>({id:u.id,name:u.name,age:u.age||""}));
    try{
      const resp=await fetch("/api/activity-ai",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({activityType:selActivity.label,activityId:selActivity.id,date:selDate,children,additionalInfo:addInfo,facilityName:FACILITIES.find(f=>f.id===facilityId)?.name||""})
      });
      const d=await resp.json();
      if(d.success){
        setAiResult(d);
        setEditedDesc(d.activityDescription||"");
        setEditedParent(d.parentMessage||"");
        setStep("review");
      } else { alert("AI生成エラー: "+(d.error||"不明")); setStep("select"); }
    }catch(e){alert("通信エラー: "+e.message);setStep("select");}
  };

  // 保存（人間確認後）
  const save=()=>{
    setSaving(true);
    // 活動記録をrecordとして保存
    store.addRec({
      id:genId(), type:"service", facilityId, facilityName:FACILITIES.find(f=>f.id===facilityId)?.name||"",
      time:buildDTForDate(selDate,nowHM()),
      userId:selChildren[0], userName:myUsers.find(u=>u.id===selChildren[0])?.name||"",
      items:[selActivity.label],
      supportNote:editedDesc,
      specialNote:`参加児童: ${myUsers.filter(u=>selChildren.includes(u.id)).map(u=>u.name).join("・")}`,
      bodyNote:"", mood:"🙂",
      arrival:"",departure:"",
      createdBy:user.displayName||"",history:[],
    });
    // 参加児童全員の活動ログも記録
    selChildren.forEach(uid=>{
      const note=(aiResult?.individualNotes||{})[uid]||"";
      sbSave("activity_records",{id:genId(),child_id:uid,facility_id:facilityId,activity_date:selDate,activity_type:selActivity.id,activity_label:selActivity.label,description:editedDesc,individual_note:note,parent_message:editedParent,created_by:user.displayName||"",created_at:new Date().toISOString()});
    });
    setSaving(false);
    setStep("done");
  };

  if(step==="done") return <div className="succ">
    <div className="si">✅</div>
    <div className="st">活動記録を保存しました</div>
    <div className="sd">{selDate} {selActivity?.label} — {selChildren.length}名</div>
    <div style={{display:"flex",gap:10,marginTop:14}}>
      <button className="bpri" style={{maxWidth:160}} onClick={()=>{setStep("select");setSelActivity(null);setSelChildren([]);setAiResult(null);}}>続けて入力</button>
      <button className="bpri" style={{maxWidth:140,background:"rgba(255,255,255,0.1)"}} onClick={onBack}>ホームへ</button>
    </div>
  </div>;

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={step==="review"?()=>setStep("select"):onBack}>← 戻る</button>
      <div className="fl-title">🤖 活動AI記録生成</div>
    </div>

    {/* STEP 1: 選択 */}
    {(step==="select")&&<>
      <div style={{background:"rgba(58,160,216,0.06)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:10,padding:"8px 14px",marginBottom:14,fontSize:11,color:"var(--tx2)"}}>
        📌 AI提案は必ず確認・修正してから保存してください。自動確定はしません。
      </div>
      <div className="slbl">活動日</div>
      <input type="date" className="fi" style={{marginBottom:14}} value={selDate} onChange={e=>setSelDate(e.target.value)}/>
      <div className="slbl">活動の種類</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:14}}>
        {AI_ACTIVITY_TYPES.map(a=>(
          <div key={a.id} onClick={()=>setSelActivity(a)}
            style={{padding:"12px 10px",borderRadius:10,border:`1.5px solid ${selActivity?.id===a.id?"var(--tl)":"var(--bd)"}`,background:selActivity?.id===a.id?"rgba(58,160,216,0.08)":"var(--wh)",cursor:"pointer",textAlign:"center",userSelect:"none"}}>
            <div style={{fontSize:20,marginBottom:4}}>{a.label.split(" ")[0]}</div>
            <div style={{fontSize:11,fontWeight:700,color:"var(--tx)"}}>{a.label.split(" ").slice(1).join(" ")}</div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>{a.desc}</div>
          </div>
        ))}
      </div>
      <div className="slbl">参加児童（複数選択可）</div>
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
        {myUsers.map(u=>(
          <div key={u.id} onClick={()=>toggleChild(u.id)}
            style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${selChildren.includes(u.id)?"var(--tl)":"var(--bd)"}`,background:selChildren.includes(u.id)?"rgba(58,160,216,0.1)":"var(--wh)",color:selChildren.includes(u.id)?"var(--tl)":"var(--tx2)",fontSize:12,fontWeight:700,cursor:"pointer",userSelect:"none"}}>
            {selChildren.includes(u.id)?"✓ ":""}{u.name}
          </div>
        ))}
      </div>
      <div className="slbl">追加情報（任意：場所・特記事項）</div>
      <input className="fi" value={addInfo} onChange={e=>setAddInfo(e.target.value)} placeholder="例：公園で実施、雨天のため室内変更など" style={{marginBottom:16}}/>
      <button className="bsave" style={{width:"100%",fontSize:15,padding:"14px"}} onClick={generate}
        disabled={!selActivity||selChildren.length===0}>
        🤖 AIで活動記録を生成する
      </button>
    </>}

    {/* STEP 2: 生成中 */}
    {step==="generating"&&<div style={{textAlign:"center",padding:"60px 20px"}}>
      <div style={{fontSize:48,marginBottom:16}}>🤖</div>
      <div style={{fontSize:14,fontWeight:700,color:"var(--tl)",marginBottom:8}}>AIが活動記録を作成中...</div>
      <div style={{fontSize:12,color:"var(--tx3)"}}>10〜20秒ほどお待ちください</div>
    </div>}

    {/* STEP 3: 確認・修正 */}
    {step==="review"&&aiResult&&<>
      <div style={{background:"rgba(44,170,96,0.08)",border:"1px solid rgba(44,170,96,0.3)",borderRadius:10,padding:"8px 14px",marginBottom:14,fontSize:11,color:"var(--gr)",fontWeight:700}}>
        ✅ AI生成完了 — 内容を確認・修正してから保存してください
      </div>
      <div style={{marginBottom:14}}>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:6}}>
          <div className="slbl" style={{margin:0,flex:1}}>活動記録（内容を確認・修正）</div>
        </div>
        <textarea className="fta" rows={6} value={editedDesc} onChange={e=>setEditedDesc(e.target.value)} style={{resize:"vertical"}}/>
      </div>
      {/* 個別メモ表示 */}
      {aiResult.individualNotes&&Object.keys(aiResult.individualNotes).length>0&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"12px 14px",marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:12,color:"var(--tx)",marginBottom:8}}>👤 個別メモ（各児童）</div>
        {Object.entries(aiResult.individualNotes).map(([uid,note])=>{
          const u=myUsers.find(x=>x.id===uid);
          return <div key={uid} style={{marginBottom:8,paddingBottom:8,borderBottom:"1px solid var(--bd)"}}>
            <div style={{fontSize:11,fontWeight:700,color:"var(--tx2)",marginBottom:3}}>{u?.name||uid}</div>
            <div style={{fontSize:12,color:"var(--tx)",lineHeight:1.6}}>{note}</div>
          </div>;
        })}
      </div>}
      <div style={{marginBottom:14}}>
        <div className="slbl">保護者向けメッセージ案</div>
        <textarea className="fta" rows={3} value={editedParent} onChange={e=>setEditedParent(e.target.value)} style={{resize:"vertical"}}/>
      </div>
      <button className="bsave" style={{width:"100%",fontSize:15,padding:"14px",marginBottom:8}} onClick={save} disabled={saving}>
        {saving?"保存中...":"💾 確認済み — 記録を保存する"}
      </button>
      <button style={{width:"100%",padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
        onClick={()=>setStep("select")}>← 選択に戻る</button>
    </>}
  </div>;
}

// ==================== 管理ダッシュボード ====================
// manager/admin向けの月次KPI・期限管理・売上予測
function ManagementDashboardScreen({user, store, onNav, onBack}){
  const now=new Date();
  const [selFacility,setSelFacility]=useState(user.selectedFacilityId||"f1");
  const [selYear,setSelYear]=useState(now.getFullYear());
  const [selMonth,setSelMonth]=useState(now.getMonth()+1);
  const monthStr=`${selYear}-${String(selMonth).padStart(2,"0")}`;
  const isAdmin=user.role==="admin";
  const facUsers=store.dynUsers.filter(u=>u.active!==false&&(selFacility==="all"||u.facilityId===selFacility));

  // ── 月次集計 ──
  const daysInM=new Date(selYear,selMonth,0).getDate();
  let totalAttended=0;
  facUsers.forEach(u=>{
    for(let d=1;d<=daysInM;d++){
      const ds=`${monthStr}-${String(d).padStart(2,"0")}`;
      if(store.getAtt(u.id,ds)==="出席") totalAttended++;
    }
  });

  // 売上予測（国保連データから）
  const facBilling=(store.kokuho||[]).filter(k=>k.year===selYear&&k.month===selMonth&&(selFacility==="all"||k.facilityId===selFacility));
  const totalRevEst=facBilling.reduce((s,k)=>{
    const days=k.serviceDays||0;
    const unitPrice=k.unitPrice||530;
    return s+(days*unitPrice*10); // 概算：単価×日数×10（1単位10円換算）
  },0);

  // ISP期限アラート（30日以内）
  const ispExpiry=(store.supportPlans||[]).filter(p=>{
    if(!p.end_date||p.status==="completed") return false;
    const days=Math.ceil((new Date(p.end_date)-now)/(1000*60*60*24));
    return days>=0&&days<=30&&(selFacility==="all"||p.facility_id===selFacility);
  }).map(p=>({...p,daysLeft:Math.ceil((new Date(p.end_date)-now)/(1000*60*60*24)),childName:facUsers.find(u=>u.id===p.child_id)?.name||p.child_name||p.child_id}));

  // 請求エラー（billing_check_resultsから）
  const billingErrors=(store.auditLogs||[]).filter(l=>l.action_type==="billing_error"&&(selFacility==="all"||l.facility_id===selFacility));

  // 配置状況
  const today=todayISO();
  const todayStaffIn=[...new Set(store.recs.filter(r=>r.type==="staff_in"&&isTodayRec(r)&&(selFacility==="all"||r.facilityId===selFacility)).map(r=>r.staffId))];
  const todayKids=[...new Set(store.recs.filter(r=>r.type==="user_in"&&isTodayRec(r)&&(selFacility==="all"||r.facilityId===selFacility)).map(r=>r.userId))];

  // サービス記録未入力
  const svcDone=[...new Set(store.recs.filter(r=>r.type==="service"&&isTodayRec(r)&&(selFacility==="all"||r.facilityId===selFacility)).map(r=>r.userId))];
  const svcMissing=todayKids.filter(id=>!svcDone.includes(id));

  const KpiCard=({icon,label,val,sub,color,onClick,alert})=>(
    <div onClick={onClick} style={{background:"var(--wh)",border:`1.5px solid ${alert?"var(--ro)":"var(--bd)"}`,borderRadius:12,padding:"14px",cursor:onClick?"pointer":"default",flex:"1 1 140px"}}>
      <div style={{fontSize:18,marginBottom:4}}>{icon}</div>
      <div style={{fontSize:10,color:"var(--tx3)",marginBottom:3}}>{label}</div>
      <div style={{fontSize:24,fontWeight:800,color:color||"var(--tx)"}}>{val}</div>
      {sub&&<div style={{fontSize:10,color:"var(--tx3)",marginTop:2}}>{sub}</div>}
      {alert&&<div style={{fontSize:10,color:"var(--ro)",fontWeight:700,marginTop:3}}>要対応</div>}
    </div>
  );

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">📊 管理ダッシュボード</div>
    </div>

    {/* 条件選択 */}
    <div style={{display:"flex",gap:8,marginBottom:14,flexWrap:"wrap"}}>
      {isAdmin&&<select className="fsm" style={{flex:"2 1 120px"}} value={selFacility} onChange={e=>setSelFacility(e.target.value)}>
        <option value="all">全施設</option>
        {FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
      </select>}
      <select className="fsm" style={{flex:"1 1 80px"}} value={selYear} onChange={e=>setSelYear(+e.target.value)}>
        {[2024,2025,2026,2027].map(y=><option key={y} value={y}>{y}年</option>)}
      </select>
      <select className="fsm" style={{flex:"1 1 60px"}} value={selMonth} onChange={e=>setSelMonth(+e.target.value)}>
        {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
      </select>
    </div>

    {/* 今日のKPI */}
    <div style={{fontWeight:700,fontSize:12,color:"var(--tx3)",marginBottom:8}}>📅 本日の状況</div>
    <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:16}}>
      <KpiCard icon="👥" label="在勤スタッフ" val={todayStaffIn.length} color="var(--tl)" onClick={()=>onNav&&onNav("staff_monitor")}/>
      <KpiCard icon="🌟" label="来所児童" val={todayKids.length} color="var(--gr)" onClick={()=>onNav&&onNav("jisseki")}/>
      <KpiCard icon="📋" label="記録未入力" val={svcMissing.length} color="var(--ro)" alert={svcMissing.length>0} onClick={()=>onNav&&onNav("service")}/>
    </div>

    {/* 月次KPI */}
    <div style={{fontWeight:700,fontSize:12,color:"var(--tx3)",marginBottom:8}}>💴 {selYear}年{selMonth}月 実績</div>
    <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:16}}>
      <KpiCard icon="📅" label="総出席日数" val={totalAttended} sub={`${facUsers.length}名合計`} color="var(--tx)"/>
      <KpiCard icon="💰" label="売上概算" val={`¥${Math.round(totalRevEst/10000)}万`} sub="国保連請求ベース" color="var(--gr)"/>
      <KpiCard icon="👤" label="登録利用者" val={facUsers.length} color="var(--tl)"/>
    </div>

    {/* ISP期限アラート */}
    {ispExpiry.length>0&&<>
      <div style={{fontWeight:700,fontSize:12,color:"var(--ro)",marginBottom:8}}>⚠️ 個別支援計画 期限間近（30日以内）</div>
      {ispExpiry.sort((a,b)=>a.daysLeft-b.daysLeft).map(p=>(
        <div key={p.id} onClick={()=>onNav&&onNav("support_plan")}
          style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",marginBottom:6,background:"rgba(224,56,56,0.06)",border:"1px solid rgba(224,56,56,0.25)",borderRadius:10,cursor:"pointer"}}>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,fontSize:13,color:"var(--tx)"}}>{p.childName}</div>
            <div style={{fontSize:11,color:"var(--tx3)"}}>終了日: {p.end_date}</div>
          </div>
          <div style={{padding:"4px 10px",borderRadius:20,background:"rgba(224,56,56,0.1)",color:"var(--ro)",fontSize:11,fontWeight:700}}>
            あと{p.daysLeft}日
          </div>
        </div>
      ))}
    </>}

    {/* 請求リンク */}
    <div style={{display:"flex",gap:8,marginTop:8}}>
      {[{icon:"🔍",label:"請求前チェック",screen:"billing_check"},{icon:"💴",label:"国保連請求",screen:"kokuho"},{icon:"↩️",label:"返戻管理",screen:"returns"}].map(l=>(
        <button key={l.screen} style={{flex:1,padding:"10px 4px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--wh)",color:"var(--tx2)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
          onClick={()=>onNav&&onNav(l.screen)}>
          {l.icon}<br/>{l.label}
        </button>
      ))}
    </div>
  </div>;
}

// ==================== 監査モード（統合ログビューア） ====================
// 全監査ログを統合表示・PDF印刷対応
function AuditModeScreen({user, store, onBack}){
  const [filterType,setFilterType]=useState("all");
  const [filterFac,setFilterFac]=useState(user.selectedFacilityId||"all");
  const [dateFrom,setDateFrom]=useState("");
  const [dateTo,setDateTo]=useState("");
  const isAdmin=user.role==="admin";

  // 全ログを統合
  const allLogs=[
    ...(store.auditLogs||[]).map(l=>({...l,_src:"billing",_label:"請求"})),
    ...(store.ispAuditLogs||[]).map(l=>({...l,_src:"isp",_label:"支援計画"})),
    ...(store.claimHistory||[]).filter(r=>r.updated_at).map(r=>({
      id:r.id+"_claim",facility_id:r.facility_id,claim_id:r.id,
      action_type:"claim_"+r.status,
      before_data:{},after_data:{status:r.status,child_name:r.child_name},
      user_name:r.created_by||"",reason:r.return_reason||r.status,
      created_at:r.updated_at||r.created_at,
      _src:"claim",_label:"返戻",
    })),
  ].filter(l=>{
    if(filterType!=="all"&&l._src!==filterType) return false;
    if(filterFac!=="all"&&l.facility_id!==filterFac) return false;
    if(dateFrom&&(l.created_at||"")<dateFrom) return false;
    if(dateTo&&(l.created_at||"")>dateTo+"T23:59:59") return false;
    return true;
  }).sort((a,b)=>new Date(b.created_at||0)-new Date(a.created_at||0));

  const ACTION_LABEL={status_change:"ステータス変更",lock:"月次ロック",unlock:"ロック解除",update:"内容更新",billing_error:"請求エラー",claim_returned:"返戻登録",claim_correcting:"修正開始",claim_corrected:"修正完了",claim_resubmitted:"再請求",claim_closed:"完了"};
  const SRC_COLOR={billing:"var(--tl)",isp:"var(--gr)",claim:"var(--ro)"};

  // PDF印刷
  const printAudit=()=>{
    const rows=allLogs.slice(0,200).map(l=>`<tr><td>${(l.created_at||"").slice(0,16).replace("T"," ")}</td><td><span style="color:${SRC_COLOR[l._src]}">${l._label}</span></td><td>${ACTION_LABEL[l.action_type]||l.action_type||""}</td><td>${l.user_name||""}</td><td>${(l.reason||"").slice(0,60)}</td></tr>`).join("");
    const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"/><style>body{font-family:'Noto Sans JP',sans-serif;font-size:8pt;margin:10mm;}h1{font-size:13pt;border-bottom:2px solid #333;padding-bottom:4px;}table{width:100%;border-collapse:collapse;}th,td{border:1px solid #ccc;padding:3px 5px;font-size:7.5pt;}th{background:#e8f0ff;font-weight:700;}</style></head><body><h1>監査ログ — ${FACILITIES.find(f=>f.id===filterFac)?.name||"全施設"}</h1><p style="font-size:8pt;color:#666">出力: ${new Date().toLocaleString("ja-JP")}</p><table><thead><tr><th>日時</th><th>種別</th><th>アクション</th><th>担当者</th><th>理由/内容</th></tr></thead><tbody>${rows}</tbody></table></body></html>`;
    const w=window.open("","_blank");if(!w){alert("ポップアップがブロックされています。許可してから再実行してください。");return;}w.document.write(html);w.document.close();w.print();
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">🔐 監査モード</div>
    </div>

    {/* フィルター */}
    <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"12px 14px",marginBottom:14}}>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:10}}>
        {isAdmin&&<select className="fsm" style={{flex:"2 1 120px"}} value={filterFac} onChange={e=>setFilterFac(e.target.value)}>
          <option value="all">全施設</option>
          {FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
        </select>}
        <select className="fsm" style={{flex:"1 1 100px"}} value={filterType} onChange={e=>setFilterType(e.target.value)}>
          <option value="all">全種別</option>
          <option value="billing">請求</option>
          <option value="isp">支援計画</option>
          <option value="claim">返戻</option>
        </select>
      </div>
      <div style={{display:"flex",gap:8}}>
        <input type="date" className="fi" style={{flex:1}} value={dateFrom} onChange={e=>setDateFrom(e.target.value)} placeholder="開始日"/>
        <input type="date" className="fi" style={{flex:1}} value={dateTo} onChange={e=>setDateTo(e.target.value)} placeholder="終了日"/>
      </div>
      <div style={{display:"flex",gap:8,marginTop:10,alignItems:"center"}}>
        <div style={{fontSize:11,color:"var(--tx3)",flex:1}}>{allLogs.length}件のログ</div>
        <button style={{padding:"8px 16px",borderRadius:9,border:"1.5px solid var(--tl)",background:"rgba(58,160,216,0.1)",color:"var(--tl)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
          onClick={printAudit}>🖨️ PDF出力</button>
      </div>
    </div>

    {/* ログ一覧 */}
    {allLogs.length===0&&<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
      <div style={{fontSize:32,marginBottom:10}}>🔐</div>該当するログがありません
    </div>}

    {allLogs.slice(0,100).map((log,i)=>(
      <div key={log.id||i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,marginBottom:7,overflow:"hidden"}}>
        <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px"}}>
          <div style={{width:6,height:30,borderRadius:3,background:SRC_COLOR[log._src]||"var(--bd)",flexShrink:0}}/>
          <div style={{flex:1,minWidth:0}}>
            <div style={{display:"flex",alignItems:"center",gap:6,marginBottom:2}}>
              <span style={{fontSize:10,padding:"2px 7px",borderRadius:10,background:SRC_COLOR[log._src]+"22",color:SRC_COLOR[log._src],fontWeight:700}}>{log._label}</span>
              <span style={{fontSize:11,fontWeight:700,color:"var(--tx)"}}>{ACTION_LABEL[log.action_type]||log.action_type}</span>
            </div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>
              {log.user_name&&<span style={{marginRight:8}}>👤 {log.user_name}</span>}
              <span>{(log.created_at||"").slice(0,16).replace("T"," ")}</span>
            </div>
            {log.reason&&<div style={{fontSize:11,color:"var(--tx2)",marginTop:2,lineHeight:1.5}}>📝 {log.reason}</div>}
          </div>
        </div>
        {/* before/after差分（コンパクト） */}
        {(log.after_data&&Object.keys(log.after_data).length>0)&&<div style={{padding:"6px 14px 8px 30px",background:"var(--bg2)",borderTop:"1px solid var(--bd)",fontSize:10,color:"var(--tx3)"}}>
          変更後: {JSON.stringify(log.after_data).slice(0,100)}
        </div>}
      </div>
    ))}
    {allLogs.length>100&&<div style={{textAlign:"center",padding:"12px",fontSize:11,color:"var(--tx3)"}}>
      ※表示は最新100件です。全件はPDF出力で確認できます。
    </div>}
  </div>;
}

// ==================== データ分析・帳票出力 ====================
// 月次利用状況・スタッフ稼働・加算内訳・統合月次レポート出力

function DataAnalyticsScreen({user, store, onBack}) {
  const facilityId = user.selectedFacilityId;
  const today = todayISO();
  const nowY = +today.slice(0,4);
  const nowM = +today.slice(5,7);
  const [tab, setTab] = useState("attendance");   // attendance | staff | billing | report
  const [selYear, setSelYear] = useState(nowY);
  const [selMonth, setSelMonth] = useState(`${nowY}-${String(nowM).padStart(2,"0")}`);
  const [reportMonth, setReportMonth] = useState(`${nowY}-${String(nowM).padStart(2,"0")}`);

  const fac = (store.facilities||FACILITIES).find(f=>f.id===facilityId);
  const children = store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);
  const fStaff = store.dynStaff.filter(s=>s.facilityId===facilityId);

  // ── 過去12か月のラベル生成 ──
  const last12Months = Array.from({length:12},(_,i)=>{
    const d = new Date(nowY, nowM-1-i, 1);
    return `${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`;
  }).reverse();

  // ── 月別出席数集計 ──
  const monthlyAttendance = last12Months.map(ym => {
    const cnt = store.serviceRecs.filter(r=>
      (r.visit_date||"").startsWith(ym)&&
      (r.facility_id===facilityId||!facilityId)&&
      r.attendance_status==="attended"
    ).length;
    return {ym, cnt, label:`${ym.slice(5)}月`};
  });
  const maxMonthly = Math.max(...monthlyAttendance.map(m=>m.cnt), 1);

  // ── 利用者別出席率（当月） ──
  const selMonthRecs = store.serviceRecs.filter(r=>
    (r.visit_date||"").startsWith(selMonth)&&
    (r.facility_id===facilityId||!facilityId)
  );
  const childAttendance = children.map(c => {
    const cRecs = selMonthRecs.filter(r=>r.child_id===c.id);
    const attended = cRecs.filter(r=>r.attendance_status==="attended").length;
    const planned = cRecs.length || 0;
    const pct = planned>0 ? Math.round(attended/planned*100) : 0;
    return {child:c, attended, planned, pct};
  }).filter(c=>c.planned>0).sort((a,b)=>b.pct-a.pct);

  // ── スタッフ稼働率（当月） ──
  const daysInM = daysInMonth(+selMonth.slice(0,4), +selMonth.slice(5,7));
  const staffWorkDays = fStaff.map(s => {
    let workDays=0;
    for(let i=1;i<=daysInM;i++){
      const d = `${selMonth}-${String(i).padStart(2,"0")}`;
      const sk = store.getShift ? store.getShift(s.id,d)||"none" : "none";
      if(sk&&sk!=="none"&&sk!=="off"&&sk!=="holiday") workDays++;
    }
    return {staff:s, workDays};
  });
  const avgWorkDays = staffWorkDays.length ? Math.round(staffWorkDays.reduce((s,x)=>s+x.workDays,0)/staffWorkDays.length*10)/10 : 0;

  // ── 加算内訳（当月） ──
  const selMonthAdditions = store.additionItems.filter(a=>
    a.service_month===selMonth&&(a.facility_id===facilityId||!facilityId)
  );
  const addByType = {};
  selMonthAdditions.forEach(a=>{
    addByType[a.addition_label||a.addition_type] = (addByType[a.addition_label||a.addition_type]||0) + (a.total_units||0);
  });
  const addEntries = Object.entries(addByType).sort((a,b)=>b[1]-a[1]);
  const totalAddUnits = addEntries.reduce((s,[,v])=>s+v,0);

  // ── 欠席率・欠席理由 ──
  const totalRecs = selMonthRecs.length;
  const absentRecs = selMonthRecs.filter(r=>r.attendance_status==="absent").length;
  const absRate = totalRecs>0 ? Math.round(absentRecs/totalRecs*100) : 0;

  // ── 月次運営レポート印刷 ──
  const printMonthlyReport = () => {
    const [ry, rm] = reportMonth.split("-").map(Number);
    const rmRecs = store.serviceRecs.filter(r=>
      (r.visit_date||"").startsWith(reportMonth)&&
      (r.facility_id===facilityId||!facilityId)
    );
    const attended = rmRecs.filter(r=>r.attendance_status==="attended").length;
    const absent   = rmRecs.filter(r=>r.attendance_status==="absent").length;
    const rmBilling = store.billingItems.filter(b=>b.service_month===reportMonth&&(b.facility_id===facilityId||!facilityId));
    const rmAdditions = store.additionItems.filter(a=>a.service_month===reportMonth&&(a.facility_id===facilityId||!facilityId));
    const totalBaseUnits = rmBilling.reduce((s,b)=>s+(b.total_base_units||0),0);
    const totalAddUnitsR = rmAdditions.reduce((s,a)=>s+(a.total_units||0),0);
    const totalUnits = totalBaseUnits + totalAddUnitsR;
    const totalYen = Math.floor(totalUnits * UNIT_PRICE_YEN);
    const childRows = children.map(c=>{
      const cR=rmRecs.filter(r=>r.child_id===c.id);
      const att=cR.filter(r=>r.attendance_status==="attended").length;
      const pln=cR.length;
      const bl=rmBilling.find(b=>b.child_id===c.id);
      const addU=rmAdditions.filter(a=>a.child_id===c.id).reduce((s,a)=>s+(a.total_units||0),0);
      return `<tr>
        <td style="padding:5px 8px;border:1px solid #ddd;font-weight:700;">${c.name}</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:center;">${att}/${pln}日</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:center;">${pln>0?Math.round(att/pln*100):0}%</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:center;">${bl?.total_base_units?.toLocaleString()||"—"}</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:center;">${addU.toLocaleString()}</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:right;font-weight:700;color:#1a4a8a;">¥${bl?(Math.floor(((bl.total_base_units||0)+addU)*UNIT_PRICE_YEN)).toLocaleString():"—"}</td>
        <td style="padding:5px 8px;border:1px solid #ddd;text-align:center;">${BILLING_STATUS_DEF[bl?.status]?.label||"未作成"}</td>
      </tr>`;
    }).join("");
    const addRows = addEntries.length ? addEntries.map(([lb,u])=>`<tr>
      <td style="padding:4px 8px;border:1px solid #ddd;">${lb}</td>
      <td style="padding:4px 8px;border:1px solid #ddd;text-align:right;">${u.toLocaleString()}単位</td>
      <td style="padding:4px 8px;border:1px solid #ddd;text-align:right;">¥${Math.floor(u*UNIT_PRICE_YEN).toLocaleString()}</td>
    </tr>`).join("") : "<tr><td colspan='3' style='padding:8px;color:#999;text-align:center;'>加算なし</td></tr>";
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>月次運営レポート ${reportMonth}</title>
    <style>
      @page{size:A4;margin:12mm 10mm;}
      *{box-sizing:border-box;}
      body{font-family:'MS Gothic',Meiryo,sans-serif;font-size:9pt;color:#111;}
      h1{font-size:15pt;margin:0 0 4px;color:#1a3a6a;}
      h2{font-size:11pt;margin:14px 0 6px;border-left:4px solid #3aa0d8;padding-left:8px;color:#1a3a6a;}
      .meta{font-size:8pt;color:#666;margin-bottom:12px;}
      .kpi-row{display:grid;grid-template-columns:repeat(5,1fr);gap:8px;margin-bottom:14px;}
      .kpi{border:1px solid #ccc;padding:8px;text-align:center;border-radius:4px;}
      .kpi-val{font-size:16pt;font-weight:900;font-family:monospace;}
      .kpi-lbl{font-size:7pt;color:#666;margin-top:2px;}
      table{border-collapse:collapse;width:100%;font-size:8.5pt;margin-bottom:12px;}
      th{background:#dce8f8;padding:5px 8px;border:1px solid #ddd;font-weight:700;text-align:center;}
      .sign{display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;margin-top:16px;}
      .sign-box{border:1px solid #aaa;min-height:44px;padding:8px;border-radius:3px;}
      .sign-lbl{font-size:7pt;color:#666;}
    </style></head><body>
    <h1>📊 月次運営レポート</h1>
    <div class="meta">
      事業所: <b>${fac?.name||""}</b>　対象月: <b>${ry}年${rm}月</b>　出力日: ${new Date().toLocaleDateString("ja-JP")}
    </div>
    <div class="kpi-row">
      <div class="kpi"><div class="kpi-val" style="color:#1a4a8a;">${children.length}</div><div class="kpi-lbl">登録児童数</div></div>
      <div class="kpi"><div class="kpi-val" style="color:#1a7a3a;">${attended}</div><div class="kpi-lbl">延べ出席日数</div></div>
      <div class="kpi"><div class="kpi-val" style="color:#c0392b;">${absent}</div><div class="kpi-lbl">延べ欠席日数</div></div>
      <div class="kpi"><div class="kpi-val" style="color:#1a4a8a;">${totalUnits.toLocaleString()}</div><div class="kpi-lbl">総請求単位数</div></div>
      <div class="kpi"><div class="kpi-val" style="color:#1a7a3a;">¥${(totalYen/10000).toFixed(1)}万</div><div class="kpi-lbl">概算請求額</div></div>
    </div>
    <h2>👦 利用者別実績</h2>
    <table><thead><tr><th style="text-align:left;">氏名</th><th>出席/計画</th><th>出席率</th><th>基本単位</th><th>加算単位</th><th>概算金額</th><th>請求状況</th></tr></thead>
    <tbody>${childRows}</tbody></table>
    <h2>➕ 加算内訳</h2>
    <table style="width:50%;"><thead><tr><th style="text-align:left;">加算種別</th><th>単位数</th><th>概算金額</th></tr></thead>
    <tbody>${addRows}</tbody></table>
    <h2>👥 スタッフ稼働（${rm}月）</h2>
    <table><thead><tr><th style="text-align:left;">氏名</th><th>出勤日数</th><th>雇用区分</th></tr></thead>
    <tbody>${fStaff.map(s=>{
      let wd=0;
      for(let i=1;i<=daysInMonth(ry,rm);i++){
        const d=`${reportMonth}-${String(i).padStart(2,"0")}`;
        const sk=store.getShift?store.getShift(s.id,d)||"none":"none";
        if(sk&&sk!=="none"&&sk!=="off"&&sk!=="holiday")wd++;
      }
      return `<tr><td style="padding:4px 8px;border:1px solid #ddd;font-weight:700;">${s.name}</td><td style="padding:4px 8px;border:1px solid #ddd;text-align:center;">${wd}日</td><td style="padding:4px 8px;border:1px solid #ddd;">${(s.data||s).employmentType||"—"}</td></tr>`;
    }).join("")}</tbody></table>
    <div class="sign">
      <div class="sign-box"><div class="sign-lbl">管理者 確認</div></div>
      <div class="sign-box"><div class="sign-lbl">作成者</div></div>
      <div class="sign-box"><div class="sign-lbl">確認日: ${new Date().toLocaleDateString("ja-JP")}</div></div>
    </div>
    </body></html>`;
    const w=window.open("","_blank","width=1000,height=750");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // 利用実績台帳 出力
  const printKidaicho = () => {
    const [ry, rm] = selMonth.split("-").map(Number);
    const dmCnt = daysInMonth(ry,rm);
    const dateHeaders = Array.from({length:dmCnt},(_,i)=>{
      const d=i+1; const dw=new Date(ry,rm-1,d).getDay();
      const c=dw===0?"color:#c0392b":dw===6?"color:#1a4a8a":"";
      return `<th style="min-width:22px;font-size:7pt;border:1px solid #ccc;padding:3px 1px;text-align:center;${c}">${d}</th>`;
    }).join("");
    const childRows2 = children.map(c=>{
      const cells = Array.from({length:dmCnt},(_,i)=>{
        const d=`${selMonth}-${String(i+1).padStart(2,"0")}`;
        const rec = selMonthRecs.find(r=>r.child_id===c.id&&r.visit_date===d);
        const val = rec?.attendance_status==="attended"?"○":rec?.attendance_status==="absent"?"×":"";
        const col = val==="○"?"color:#1a7a3a":val==="×"?"color:#c0392b":"";
        return `<td style="border:1px solid #ccc;text-align:center;font-size:9pt;font-weight:700;${col}">${val}</td>`;
      }).join("");
      const att = selMonthRecs.filter(r=>r.child_id===c.id&&r.attendance_status==="attended").length;
      return `<tr><td style="padding:4px 8px;border:1px solid #ccc;font-weight:700;white-space:nowrap;">${c.name}</td>${cells}<td style="padding:4px 8px;border:1px solid #ccc;text-align:center;font-weight:900;color:#1a4a8a;">${att}</td></tr>`;
    }).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>利用実績台帳 ${selMonth}</title>
    <style>@page{size:A4 landscape;margin:10mm;}body{font-family:'MS Gothic',sans-serif;font-size:8pt;}h2{font-size:12pt;border-bottom:2px solid #3aa0d8;padding-bottom:5px;}table{border-collapse:collapse;width:100%;}</style>
    </head><body>
    <h2>📋 利用実績台帳</h2>
    <div style="font-size:8pt;color:#666;margin-bottom:8px;">事業所: ${fac?.name||""}　対象月: ${ry}年${rm}月　出力日: ${new Date().toLocaleDateString("ja-JP")}</div>
    <table><thead><tr>
      <th style="padding:4px 8px;border:1px solid #ccc;text-align:left;min-width:80px;">氏名</th>
      ${dateHeaders}
      <th style="min-width:30px;border:1px solid #ccc;padding:3px;text-align:center;font-size:8pt;">計</th>
    </tr></thead><tbody>${childRows2}</tbody></table>
    <div style="margin-top:8px;font-size:7pt;color:#888;">○=出席　×=欠席</div>
    </body></html>`;
    const w=window.open("","_blank","width=1200,height=700");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  // CSV出力（月次実績）
  const exportAttendanceCSV = () => {
    const dmCnt = daysInMonth(+selMonth.slice(0,4), +selMonth.slice(5,7));
    const dateHeaders = Array.from({length:dmCnt},(_,i)=>`${i+1}日`);
    const hdr = ["氏名", ...dateHeaders, "出席日数", "欠席日数", "出席率"];
    const rows = children.map(c=>{
      const cells = Array.from({length:dmCnt},(_,i)=>{
        const d=`${selMonth}-${String(i+1).padStart(2,"0")}`;
        const rec = selMonthRecs.find(r=>r.child_id===c.id&&r.visit_date===d);
        return rec?.attendance_status==="attended"?"○":rec?.attendance_status==="absent"?"×":"";
      });
      const att = cells.filter(x=>x==="○").length;
      const abs = cells.filter(x=>x==="×").length;
      const pct = (att+abs)>0?`${Math.round(att/(att+abs)*100)}%`:"—";
      return [c.name,...cells,att,abs,pct];
    });
    const csv = [hdr,...rows].map(r=>r.join(",")).join("\n");
    const a=document.createElement("a");
    a.href=URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download=`利用実績_${selMonth}.csv`; a.click();
    store.showToast("CSVを出力しました","success");
  };

  // SVGライングラフ（月次推移）
  const LineChart = ({data, maxVal, width=320, height=140}) => {
    const pad={t:10,r:16,b:24,l:32};
    const w=width-pad.l-pad.r, h=height-pad.t-pad.b;
    const pts = data.map((d,i)=>({
      x: pad.l + i/(data.length-1||1)*w,
      y: pad.t + h - (d.cnt/maxVal)*h,
      ...d
    }));
    const pathD = pts.map((p,i)=>`${i===0?"M":"L"}${p.x.toFixed(1)},${p.y.toFixed(1)}`).join(" ");
    const areaD = pathD + ` L${pts[pts.length-1].x.toFixed(1)},${(pad.t+h).toFixed(1)} L${pts[0].x.toFixed(1)},${(pad.t+h).toFixed(1)} Z`;
    return <svg width={width} height={height} style={{overflow:"visible"}}>
      {/* Y軸グリッド */}
      {[0,0.25,0.5,0.75,1].map(f=>(
        <g key={f}>
          <line x1={pad.l} y1={pad.t+h*(1-f)} x2={pad.l+w} y2={pad.t+h*(1-f)} stroke="var(--bd)" strokeDasharray="3,3"/>
          <text x={pad.l-4} y={pad.t+h*(1-f)+4} textAnchor="end" fontSize={9} fill="var(--tx3)">{Math.round(maxVal*f)}</text>
        </g>
      ))}
      {/* エリア */}
      <path d={areaD} fill="rgba(58,160,216,0.12)"/>
      {/* ライン */}
      <path d={pathD} fill="none" stroke="var(--tl)" strokeWidth={2} strokeLinejoin="round"/>
      {/* データポイント */}
      {pts.map((p,i)=>(
        <g key={i}>
          <circle cx={p.x} cy={p.y} r={4} fill="var(--tl)" stroke="#fff" strokeWidth={1.5}/>
          {i%3===0&&<text x={p.x} y={pad.t+h+14} textAnchor="middle" fontSize={8} fill="var(--tx3)">{p.label}</text>}
        </g>
      ))}
    </svg>;
  };

  // CSS バーチャート
  const BarChart = ({items, maxVal, colorFn}) => (
    <div style={{display:"flex",flexDirection:"column",gap:6}}>
      {items.map((item,i)=>(
        <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
          <div style={{width:80,fontSize:11,textAlign:"right",color:"var(--tx3)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.label}</div>
          <div style={{flex:1,background:"var(--bg2)",borderRadius:4,height:14,position:"relative",overflow:"hidden"}}>
            <div style={{position:"absolute",left:0,top:0,height:"100%",width:`${maxVal?item.val/maxVal*100:0}%`,background:colorFn?colorFn(item,i):"var(--tl)",borderRadius:4,transition:"width 0.5s"}}/>
          </div>
          <div style={{width:36,fontSize:11,fontWeight:700,color:"var(--tx)"}}>{item.val}{item.unit||""}</div>
        </div>
      ))}
    </div>
  );

  const moveMonth = dir => {
    const [y,m] = selMonth.split("-").map(Number);
    const d = new Date(y,m-1+dir,1);
    setSelMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`);
  };

  return <div>
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <h2 style={{margin:0,fontSize:17}}>📊 データ分析・帳票出力</h2>
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,margin:"12px 0",overflowX:"auto",paddingBottom:4}}>
      {[["attendance","📈 利用状況"],["staff","👥 スタッフ稼働"],["billing","💴 請求・加算"],["report","📄 帳票出力"]].map(([id,lb])=>(
        <button key={id} onClick={()=>setTab(id)}
          style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${tab===id?"var(--tl)":"var(--bd)"}`,background:tab===id?"var(--tl)":"var(--wh)",color:tab===id?"#fff":"var(--tx)",fontWeight:tab===id?700:400,fontSize:12,whiteSpace:"nowrap",cursor:"pointer"}}>
          {lb}
        </button>
      ))}
    </div>

    {/* 月選択（report以外） */}
    {tab!=="report"&&<div style={{display:"flex",alignItems:"center",gap:8,marginBottom:14,background:"var(--wh)",padding:"8px 12px",borderRadius:10,border:"1px solid var(--bd)"}}>
      <button className="nb" style={{padding:"5px 12px"}} onClick={()=>moveMonth(-1)}>‹</button>
      <input type="month" className="fi" style={{flex:1,margin:0,textAlign:"center"}} value={selMonth} onChange={e=>setSelMonth(e.target.value)}/>
      <button className="nb" style={{padding:"5px 12px"}} onClick={()=>moveMonth(1)}>›</button>
    </div>}

    {/* ===== 利用状況タブ ===== */}
    {tab==="attendance"&&<div>
      {/* KPIカード */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:8,marginBottom:14}}>
        {[
          {icon:"👦",label:"登録児童",val:`${children.length}名`,color:"var(--tl)"},
          {icon:"✅",label:"延べ出席",val:`${selMonthRecs.filter(r=>r.attendance_status==="attended").length}日`,color:"var(--gr)"},
          {icon:"✖",label:"欠席率",val:`${absRate}%`,color:absRate>20?"var(--ro)":"var(--tx3)"},
          {icon:"📊",label:"平均出席",val:children.length?`${Math.round(selMonthRecs.filter(r=>r.attendance_status==="attended").length/children.length*10)/10}日`:"—",color:"var(--tl)"},
        ].map((k,i)=>(
          <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
            <div style={{fontSize:18,marginBottom:2}}>{k.icon}</div>
            <div style={{fontSize:13,fontWeight:700,color:k.color}}>{k.val}</div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>{k.label}</div>
          </div>
        ))}
      </div>

      {/* 月次推移グラフ */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>📈 月次出席数推移（直近12か月）</div>
        <div style={{overflowX:"auto"}}>
          <LineChart data={monthlyAttendance} maxVal={maxMonthly} width={Math.max(320, last12Months.length*32)} height={140}/>
        </div>
      </div>

      {/* 利用者別出席率 */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>👦 利用者別出席率（{selMonth}）</div>
        {childAttendance.length===0
          ? <div style={{color:"var(--tx3)",fontSize:12,textAlign:"center",padding:14}}>実績データなし</div>
          : <BarChart
              items={childAttendance.map(c=>({label:c.child.name,val:c.pct,unit:"%"}))}
              maxVal={100}
              colorFn={(item)=>item.val>=80?"var(--gr)":item.val>=60?"var(--tl)":item.val>=40?"var(--ac)":"var(--ro)"}
            />
        }
      </div>

      {/* 欠席理由内訳 */}
      {selMonthRecs.filter(r=>r.attendance_status==="absent").length>0&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:8}}>📋 欠席状況</div>
        <div style={{display:"flex",gap:8}}>
          {[
            {label:"欠席",val:selMonthRecs.filter(r=>r.attendance_status==="absent").length,color:"var(--ro)"},
            {label:"遅刻",val:selMonthRecs.filter(r=>r.attendance_status==="late").length,color:"var(--ac)"},
            {label:"早退",val:selMonthRecs.filter(r=>r.attendance_status==="early_leave").length,color:"var(--ac)"},
            {label:"キャンセル",val:selMonthRecs.filter(r=>r.attendance_status==="cancelled").length,color:"var(--tx3)"},
          ].map((c,i)=>(c.val>0?
            <div key={i} style={{flex:1,background:`${c.color}11`,border:`1px solid ${c.color}44`,borderRadius:8,padding:"8px 4px",textAlign:"center"}}>
              <div style={{fontSize:16,fontWeight:700,color:c.color}}>{c.val}</div>
              <div style={{fontSize:10,color:"var(--tx3)"}}>{c.label}</div>
            </div>:null
          )).filter(Boolean)}
        </div>
      </div>}
    </div>}

    {/* ===== スタッフ稼働タブ ===== */}
    {tab==="staff"&&<div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
        {[
          {icon:"👥",label:"スタッフ数",val:`${fStaff.length}名`},
          {icon:"📅",label:"平均出勤日数",val:`${avgWorkDays}日`},
          {icon:"⚡",label:"残業注意",val:`${fStaff.filter(s=>{
            let otH=0;
            for(let i=1;i<=daysInM;i++){
              const d=`${selMonth}-${String(i).padStart(2,"0")}`;
              const sk=store.getShift?store.getShift(s.id,d)||"none":"none";
              if(sk==="none"||sk==="off"||sk==="holiday") continue;
              const ins=store.recs.filter(r=>r.type==="staff_in"&&r.staffId===s.id&&(r.time||"").startsWith(d));
              const outs=store.recs.filter(r=>r.type==="staff_out"&&r.staffId===s.id&&(r.time||"").startsWith(d));
              const pt=t=>{const m=t.match(/(\d+):(\d+)/);return m?+m[1]*60+ +m[2]:null;};
              const inTs=ins.map(r=>pt(r.time)).filter(t=>t!==null);
              const outTs=outs.map(r=>pt(r.time)).filter(t=>t!==null);
              if(inTs.length&&outTs.length) otH+=Math.max(0,(Math.max(...outTs)-Math.min(...inTs)-60)/60-8);
            }
            return otH>=20;
          }).length}名`,color:"var(--ac)"},
        ].map((k,i)=>(
          <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
            <div style={{fontSize:18,marginBottom:2}}>{k.icon}</div>
            <div style={{fontSize:13,fontWeight:700,color:k.color||"var(--tl)"}}>{k.val}</div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>{k.label}</div>
          </div>
        ))}
      </div>

      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>👤 スタッフ別出勤日数（{selMonth}）</div>
        <BarChart
          items={staffWorkDays.map(x=>({label:x.staff.name,val:x.workDays,unit:"日"}))}
          maxVal={daysInM}
          colorFn={(item)=>item.val>=20?"var(--gr)":item.val>=15?"var(--tl)":"var(--ac)"}
        />
      </div>
    </div>}

    {/* ===== 請求・加算タブ ===== */}
    {tab==="billing"&&<div>
      {/* 月次請求サマリー */}
      {(()=>{
        const mb = store.billingItems.filter(b=>b.service_month===selMonth&&(b.facility_id===facilityId||!facilityId));
        const totalU = mb.reduce((s,b)=>{
          const addU = store.additionItems.filter(a=>a.service_month===selMonth&&a.child_id===b.child_id).reduce((s,a)=>s+(a.total_units||0),0);
          return s+(b.total_base_units||0)+addU;
        },0);
        return <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
          {[
            {icon:"👦",label:"請求対象",val:`${mb.length}名`},
            {icon:"📊",label:"総単位数",val:totalU.toLocaleString()},
            {icon:"💴",label:"概算請求額",val:`¥${Math.floor(totalU*UNIT_PRICE_YEN).toLocaleString()}`},
          ].map((k,i)=>(
            <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
              <div style={{fontSize:18,marginBottom:2}}>{k.icon}</div>
              <div style={{fontSize:13,fontWeight:700,color:"var(--tl)"}}>{k.val}</div>
              <div style={{fontSize:10,color:"var(--tx3)"}}>{k.label}</div>
            </div>
          ))};
        </div>;
      })()}

      {/* 加算内訳グラフ */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>➕ 加算内訳（{selMonth}）</div>
        {addEntries.length===0
          ? <div style={{color:"var(--tx3)",fontSize:12,textAlign:"center",padding:14}}>加算なし</div>
          : <>
              <BarChart
                items={addEntries.map(([lb,u])=>({label:lb.slice(0,8),val:u,unit:"単位"}))}
                maxVal={Math.max(...addEntries.map(([,v])=>v),1)}
                colorFn={(_,i)=>{const cols=["var(--tl)","var(--gr)","#a78bfa","var(--ac)","var(--ro)","#06b6d4"];return cols[i%cols.length];}}
              />
              <div style={{marginTop:10,fontSize:11,color:"var(--tx3)",textAlign:"right"}}>
                加算合計：{totalAddUnits.toLocaleString()}単位 ≒ ¥{Math.floor(totalAddUnits*UNIT_PRICE_YEN).toLocaleString()}
              </div>
            </>
        }
      </div>

      {/* 年間請求推移 */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>📈 月次概算請求額推移</div>
        {(()=>{
          const data = last12Months.map(ym=>{
            const mb=store.billingItems.filter(b=>b.service_month===ym&&(b.facility_id===facilityId||!facilityId));
            const addU=store.additionItems.filter(a=>a.service_month===ym&&(a.facility_id===facilityId||!facilityId)).reduce((s,a)=>s+(a.total_units||0),0);
            const totU=mb.reduce((s,b)=>s+(b.total_base_units||0),0)+addU;
            return {ym,cnt:Math.floor(totU*UNIT_PRICE_YEN/10000),label:`${ym.slice(5)}月`};
          });
          const maxV=Math.max(...data.map(d=>d.cnt),1);
          return <div style={{overflowX:"auto"}}>
            <LineChart data={data} maxVal={maxV} width={Math.max(320,last12Months.length*32)} height={130}/>
            <div style={{fontSize:10,color:"var(--tx3)",textAlign:"right",marginTop:4}}>単位：万円</div>
          </div>;
        })()}
      </div>
    </div>}

    {/* ===== 帳票出力タブ ===== */}
    {tab==="report"&&<div>
      <div style={{marginBottom:14}}>
        <div className="slbl">対象月を選択</div>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:16}}>
          <button className="nb" style={{padding:"6px 14px"}} onClick={()=>{const[y,m]=reportMonth.split("-").map(Number);const d=new Date(y,m-2,1);setReportMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`)}}>‹</button>
          <input type="month" className="fi" style={{flex:1,margin:0,textAlign:"center"}} value={reportMonth} onChange={e=>setReportMonth(e.target.value)}/>
          <button className="nb" style={{padding:"6px 14px"}} onClick={()=>{const[y,m]=reportMonth.split("-").map(Number);const d=new Date(y,m,1);setReportMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`)}}>›</button>
        </div>
      </div>

      <div style={{display:"flex",flexDirection:"column",gap:10}}>
        {[
          {icon:"📊",title:"月次運営レポート",desc:"利用実績・加算・スタッフ稼働を1枚にまとめた総合レポート（A4縦）",action:printMonthlyReport,color:"var(--tl)"},
          {icon:"📋",title:"利用実績台帳",desc:"カレンダー形式の月次出席状況一覧表（A4横・監査対応）",action:printKidaicho,color:"var(--gr)"},
          {icon:"📥",title:"利用実績CSV",desc:"表計算ソフトで加工可能な出席データ（○×形式）",action:exportAttendanceCSV,color:"#a78bfa"},
        ].map((item,i)=>(
          <div key={i} style={{background:"var(--wh)",border:`1px solid var(--bd)`,borderRadius:12,padding:16,display:"flex",alignItems:"center",gap:14}}>
            <div style={{fontSize:36,minWidth:44,textAlign:"center"}}>{item.icon}</div>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:14,marginBottom:4}}>{item.title}</div>
              <div style={{fontSize:12,color:"var(--tx3)"}}>{item.desc}</div>
            </div>
            <button onClick={item.action}
              style={{padding:"10px 16px",borderRadius:10,border:"none",background:item.color,color:"#fff",fontWeight:700,fontSize:12,cursor:"pointer",whiteSpace:"nowrap"}}>
              出力
            </button>
          </div>
        ))}
      </div>

      <div style={{marginTop:20,background:"rgba(58,160,216,0.05)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:10,padding:"12px 14px"}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:6}}>📌 その他の帳票</div>
        <div style={{display:"flex",flexDirection:"column",gap:6,fontSize:12,color:"var(--tx3)"}}>
          <div>→ 個別支援計画・モニタリング：「個別支援計画」画面から印刷</div>
          <div>→ 勤務実績・個人台帳：「勤務実績」画面から印刷</div>
          <div>→ シフト表：「シフト管理」画面から印刷</div>
          <div>→ 送迎ルート表：「送迎管理」「送迎ライブ追跡」から印刷</div>
          <div>→ 欠席連絡一覧：「連絡センター」の欠席連絡タブから印刷</div>
          <div>→ 業務日報：「業務日報」画面から印刷・Excel出力</div>
        </div>
      </div>
    </div>}
  </div>;
}

// ==================== 職員書類管理・AI判定 ====================
const STAFF_DOC_TYPES = [
  {id:"employment_contract", label:"雇用契約書", icon:"📋", required:true,  hasExpiry:true,  color:"#2563eb"},
  {id:"resume",              label:"履歴書",     icon:"📄", required:true,  hasExpiry:false, color:"#059669"},
  {id:"qualification",       label:"資格証",     icon:"🏆", required:false, hasExpiry:true,  color:"#d97706"},
  {id:"training_cert",       label:"研修修了証", icon:"📜", required:false, hasExpiry:true,  color:"#7c3aed"},
  {id:"id_document",         label:"身分証",     icon:"🪪", required:true,  hasExpiry:true,  color:"#dc2626"},
  {id:"other",               label:"その他",     icon:"📁", required:false, hasExpiry:false, color:"#64748b"},
];
const SDOC_AI_STATUS = {
  pending: {label:"未判定",   icon:"⏳", color:"var(--tx3)", bg:"var(--bg2)"},
  ok:      {label:"問題なし", icon:"✅", color:"var(--gr)",  bg:"rgba(44,170,96,0.1)"},
  warning: {label:"要確認",   icon:"⚠️", color:"#d97706",   bg:"rgba(217,119,6,0.1)"},
  expired: {label:"期限切れ", icon:"🔴", color:"var(--ro)",  bg:"rgba(224,56,56,0.1)"},
  error:   {label:"エラー",   icon:"❌", color:"var(--ro)",  bg:"rgba(224,56,56,0.05)"},
};
const SDOC_ADMIN_STATUS = {
  unreviewed:     {label:"未確認",   color:"var(--tx3)", bg:"var(--bg2)"},
  confirmed:      {label:"確認済み", color:"var(--gr)",  bg:"rgba(44,170,96,0.1)"},
  requires_update:{label:"要更新",   color:"var(--ro)",  bg:"rgba(224,56,56,0.08)"},
};

// ── 書類カード ──
function StaffDocCard({doc, store, user, onView, getStaffName, getDocTypeInfo, getExpiryBadge}){
  const dt = getDocTypeInfo(doc.documentType);
  const ai = SDOC_AI_STATUS[doc.aiStatus]||SDOC_AI_STATUS.pending;
  const adm= SDOC_ADMIN_STATUS[doc.adminStatus]||SDOC_ADMIN_STATUS.unreviewed;
  return (
    <div onClick={onView} style={{background:"var(--wh)",border:`1.5px solid ${doc.aiStatus==="expired"?"rgba(224,56,56,0.4)":doc.aiStatus==="warning"?"rgba(217,119,6,0.35)":"var(--bd)"}`,borderRadius:12,padding:"12px 14px",marginBottom:10,cursor:"pointer",transition:"box-shadow .15s"}}
      onMouseEnter={e=>e.currentTarget.style.boxShadow="0 2px 12px rgba(0,0,0,0.1)"}
      onMouseLeave={e=>e.currentTarget.style.boxShadow="none"}>
      <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
        <div style={{fontSize:24,lineHeight:1,flexShrink:0}}>{dt.icon}</div>
        <div style={{flex:1,minWidth:0}}>
          <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap",marginBottom:4}}>
            <span style={{fontWeight:700,fontSize:13,color:"var(--tx)"}}>{dt.label}</span>
            <span style={{padding:"1px 7px",borderRadius:5,fontSize:10,fontWeight:700,background:ai.bg,color:ai.color}}>{ai.icon} {ai.label}</span>
            <span style={{padding:"1px 7px",borderRadius:5,fontSize:10,fontWeight:700,background:adm.bg,color:adm.color}}>{adm.label}</span>
            {getExpiryBadge(doc)}
          </div>
          <div style={{fontSize:12,color:"var(--tx2)",marginBottom:2}}>👤 {getStaffName(doc.staffId)}</div>
          {doc.aiSummary&&<div style={{fontSize:11,color:"var(--tx3)",lineHeight:1.5,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{doc.aiSummary}</div>}
          {(doc.aiWarnings||[]).length>0&&<div style={{marginTop:4,fontSize:10,color:"var(--ro)"}}>⚠️ {doc.aiWarnings[0]}{doc.aiWarnings.length>1?` 他${doc.aiWarnings.length-1}件`:""}</div>}
        </div>
        <div style={{fontSize:11,color:"var(--tx3)",flexShrink:0,textAlign:"right"}}>
          {(doc.uploadedAt||"").slice(0,10)}
        </div>
      </div>
    </div>
  );
}

// ── アラートタブ ──
function StaffDocAlertTab({alerts, missingDocs, store, getStaffName, getDocTypeInfo, getExpiryInfo, filteredStaff}){
  const today = new Date();
  const expired = alerts.filter(d=>{
    const info=getExpiryInfo(d); return info&&info.diffDays<0;
  });
  const warn30 = alerts.filter(d=>{
    const info=getExpiryInfo(d); return info&&info.diffDays>=0&&info.diffDays<=30;
  });
  const warn60 = alerts.filter(d=>{
    const info=getExpiryInfo(d); return info&&info.diffDays>30&&info.diffDays<=60;
  });
  const aiWarn = alerts.filter(d=>d.aiStatus==="warning"||d.aiStatus==="expired");

  const Section=({title,color,items,emptyMsg})=>(
    <div style={{marginBottom:18}}>
      <div style={{fontWeight:700,fontSize:13,color,marginBottom:8}}>{title}（{items.length}件）</div>
      {items.length===0
        ?<div style={{fontSize:12,color:"var(--tx3)",padding:"8px 0"}}>{emptyMsg}</div>
        :items.map(d=>{
          const dt=getDocTypeInfo(d.documentType);
          const info=getExpiryInfo(d);
          return <div key={d.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 12px",marginBottom:8,display:"flex",gap:10,alignItems:"center"}}>
            <span style={{fontSize:20}}>{dt.icon}</span>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:12,color:"var(--tx)"}}>{getStaffName(d.staffId)} — {dt.label}</div>
              {info&&<div style={{fontSize:11,color,marginTop:2}}>期限: {info.dateStr}（{info.diffDays<0?`${Math.abs(info.diffDays)}日超過`:`残${info.diffDays}日`}）</div>}
              {(d.aiWarnings||[]).map((w,i)=><div key={i} style={{fontSize:11,color:"var(--ro)",marginTop:1}}>・{w}</div>)}
            </div>
          </div>;
        })
      }
    </div>
  );

  return <div>
    <Section title="🔴 期限切れ" color="var(--ro)" items={expired} emptyMsg="期限切れの書類はありません"/>
    <Section title="⚠️ 30日以内に期限切れ" color="var(--ro)" items={warn30} emptyMsg="該当なし"/>
    <Section title="⏰ 60日以内に期限切れ" color="#d97706" items={warn60} emptyMsg="該当なし"/>
    <Section title="🤖 AI判定：要確認" color="#d97706" items={aiWarn.filter(d=>!expired.includes(d)&&!warn30.includes(d)&&!warn60.includes(d))} emptyMsg="AI判定の警告はありません"/>
    <div style={{marginBottom:18}}>
      <div style={{fontWeight:700,fontSize:13,color:"var(--ac)",marginBottom:8}}>📋 必須書類未提出（{missingDocs.length}名）</div>
      {missingDocs.length===0
        ?<div style={{fontSize:12,color:"var(--tx3)"}}>全員提出済みです</div>
        :missingDocs.map(s=>{
          const required=STAFF_DOC_TYPES.filter(t=>t.required);
          const missing=required.filter(t=>!(store.staffDocs||[]).find(d=>d.staffId===s.id&&d.documentType===t.id));
          return <div key={s.id} style={{background:"var(--wh)",border:"1px solid rgba(217,119,6,0.3)",borderRadius:10,padding:"10px 12px",marginBottom:8}}>
            <div style={{fontWeight:700,fontSize:12,color:"var(--tx)",marginBottom:4}}>👤 {s.name}</div>
            <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
              {missing.map(t=><span key={t.id} style={{padding:"2px 8px",borderRadius:5,fontSize:11,background:"rgba(217,119,6,0.1)",color:"#d97706",fontWeight:700}}>{t.icon} {t.label}</span>)}
            </div>
          </div>;
        })
      }
    </div>
  </div>;
}

// ── 職員別タブ ──
function StaffDocByStaffTab({filteredStaff, store, getDocTypeInfo, getExpiryBadge, onUpload}){
  const [openId, setOpenId] = useState(null);
  const [summaryStaff, setSummaryStaff] = useState(null);
  return <div>
    {filteredStaff.length===0&&<div style={{textAlign:"center",padding:"40px 0",color:"var(--tx3)"}}>職員が登録されていません</div>}
    {filteredStaff.map(s=>{
      const docs=(store.staffDocs||[]).filter(d=>d.staffId===s.id);
      const hasExpired=docs.some(d=>d.aiStatus==="expired");
      const hasWarn=docs.some(d=>d.aiStatus==="warning");
      const open=openId===s.id;
      return <div key={s.id} style={{background:"var(--wh)",border:`1.5px solid ${hasExpired?"rgba(224,56,56,0.4)":hasWarn?"rgba(217,119,6,0.3)":"var(--bd)"}`,borderRadius:12,marginBottom:10,overflow:"hidden"}}>
        <div onClick={()=>setOpenId(open?null:s.id)} style={{padding:"12px 14px",cursor:"pointer",display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:36,height:36,borderRadius:"50%",background:"rgba(58,160,216,0.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:16,fontWeight:700,color:"var(--tl)",flexShrink:0}}>
            {s.name?.[0]||"?"}
          </div>
          <div style={{flex:1}}>
            <div style={{fontWeight:700,fontSize:13,color:"var(--tx)"}}>{s.name}</div>
            <div style={{fontSize:11,color:"var(--tx3)"}}>
              {docs.length}件の書類
              {STAFF_DOC_TYPES.filter(t=>t.required).map(t=>{
                const has=docs.find(d=>d.documentType===t.id);
                return <span key={t.id} style={{marginLeft:6,padding:"1px 5px",borderRadius:4,fontSize:10,background:has?"rgba(44,170,96,0.1)":"rgba(224,56,56,0.08)",color:has?"var(--gr)":"var(--ro)",fontWeight:700}}>{t.icon}</span>;
              })}
            </div>
          </div>
          {hasExpired&&<span style={{fontSize:11,color:"var(--ro)",fontWeight:700}}>🔴 期限切れ</span>}
          {!hasExpired&&hasWarn&&<span style={{fontSize:11,color:"#d97706",fontWeight:700}}>⚠️ 要確認</span>}
          <button onClick={e=>{e.stopPropagation();setSummaryStaff(s);}} style={{fontSize:10,padding:"3px 8px",border:"1px solid var(--tl)",borderRadius:12,background:"var(--wh)",color:"var(--tl)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,flexShrink:0}}>🤖 AI</button>
          <span style={{fontSize:12,color:"var(--tx3)"}}>{open?"▲":"▼"}</span>
        </div>
        {open&&<div style={{padding:"0 14px 14px"}}>
          {docs.length===0
            ?<div style={{fontSize:12,color:"var(--tx3)",textAlign:"center",padding:"12px 0"}}>書類未提出</div>
            :docs.map(doc=>{
              const dt=getDocTypeInfo(doc.documentType);
              const ai=SDOC_AI_STATUS[doc.aiStatus]||SDOC_AI_STATUS.pending;
              return <div key={doc.id} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderTop:"1px solid var(--bg)"}}>
                <span style={{fontSize:16}}>{dt.icon}</span>
                <span style={{flex:1,fontSize:12,color:"var(--tx)"}}>{dt.label}</span>
                {getExpiryBadge(doc)}
                <span style={{padding:"1px 6px",borderRadius:5,fontSize:10,fontWeight:700,background:ai.bg,color:ai.color}}>{ai.icon}</span>
                <span style={{fontSize:11,color:"var(--tx3)"}}>{(doc.uploadedAt||"").slice(0,10)}</span>
              </div>;
            })
          }
        </div>}
      </div>;
    })}
    {summaryStaff&&<StaffDocSummaryModal staff={summaryStaff} docs={(store.staffDocs||[]).filter(d=>d.staffId===summaryStaff.id)} onClose={()=>setSummaryStaff(null)}/>}
  </div>;
}

// ── アップロードモーダル ──
function StaffDocUploadModal({user, store, filteredStaff, onClose}){
  const [step, setStep] = useState("select"); // select|preview|ocr|confirm|saving
  const [selStaff, setSelStaff] = useState(filteredStaff[0]?.id||"");
  const [selType, setSelType] = useState("employment_contract");
  const [imgB64, setImgB64] = useState("");
  const [imgUrl, setImgUrl] = useState("");
  const [imgFileRef, setImgFileRef] = useState(null); // Storageアップロード用にFileオブジェクトを保持
  const [imgFileType, setImgFileType] = useState("image/jpeg");
  const [fileName, setFileName] = useState("");
  const [ocrResult, setOcrResult] = useState(null);
  const [memo, setMemo] = useState("");
  const [error, setError] = useState("");
  const fileRef = useRef();

  const staffInfo = filteredStaff.find(s=>s.id===selStaff);
  const docType = STAFF_DOC_TYPES.find(t=>t.id===selType)||STAFF_DOC_TYPES[0];

  const handleFile = async e => {
    const input = e.target;
    const file = input.files?.[0];
    if(!file) return;
    setError("");
    try {
      // ★ 生の readAsDataURL では iPhone写真の原寸base64が /api/staff-doc-ai に送られ、
      //   Vercelの4.5MBボディ上限で 413(text/plain) になる。
      //   maxPx=2000: 資格証・契約書の細かい文字（登録番号・日付）を残せる解像度。
      //   PDFは圧縮できないので _ocrPrepare が上限超過を送信前に弾く。
      const prepared = await _ocrPrepare(file, {maxPx: 2000, quality: 0.85});
      setFileName(file.name);
      setImgFileRef(file);           // Storage用にFileオブジェクト保持（アップロード時に再圧縮）
      setImgFileType(prepared.mediaType);
      setImgUrl(prepared.dataUrl);
      setImgB64(prepared.base64);
      setStep("preview");
    } catch(err) {
      console.warn("[職員書類] 画像の準備に失敗:", err?.stage||"", err?.message||err);
      setError(`${err?.stage||"画像の準備"}: ${err?.message||"画像を読み込めませんでした"}`);
    }
    try{ input.value=""; }catch(_){}   // 同じファイルを選び直せるようにする
  };

  const runOCR = async () => {
    if(!imgB64){setError("ファイルを選択してください");return;}
    setStep("ocr");setError("");
    try{
      const resp = await fetch("/api/staff-doc-ai",{
        method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          imageBase64:imgB64,
          mediaType:imgFileType,     // handleFile で圧縮済み（image/jpeg か application/pdf）
          documentType:selType,
          staffName:staffInfo?.name||"",
        }),
      });
      // ★ resp.text()→throw だと 413 の生HTMLがそのまま画面に出るため段階別に変換する
      const d = await _ocrReadJson(resp);
      if(d.success){
        setOcrResult(d);
        setStep("confirm");
      } else {
        setOcrResult({aiStatus:"error",aiWarnings:[d.error||"解析失敗"],aiSummary:"",extracted:{}});
        setStep("confirm");
      }
    }catch(e){
      console.warn("[職員書類OCR] 失敗:", e?.stage||"", e?.message||e);
      setError(`${e?.stage||"OCR処理"}: ${e?.message||"エラーが発生しました"}`);
      setStep("preview");
    }
  };

  const save = async () => {
    if(!selStaff){setError("職員を選択してください");return;}
    setStep("saving");
    // Storage アップロード（失敗時はdata URLフォールバック）
    let fileUrl = imgUrl; // デフォルト: base64 data URL
    if(imgFileRef) {
      const uploaded = await uploadToStorage(imgFileRef, "staff-documents", selStaff);
      if(uploaded?.url) fileUrl = uploaded.url;
    }
    const now = new Date().toISOString();
    const docId = genId();
    const doc = {
      id:docId, staffId:selStaff,
      facilityId:staffInfo?.facilityId||user.selectedFacilityId,
      documentType:selType,
      fileUrl, fileName,
      uploadedAt:now, uploadedBy:user.displayName||"",
      extractedText:JSON.stringify(ocrResult?.extracted||{}),
      aiSummary:ocrResult?.aiSummary||"",
      aiDetectedName:ocrResult?.aiDetectedName||"",
      issueDate:ocrResult?.issueDate||null,
      startDate:ocrResult?.startDate||null,
      endDate:ocrResult?.endDate||null,
      expiryDate:ocrResult?.expiryDate||null,
      qualificationName:ocrResult?.qualificationName||null,
      registrationNumber:ocrResult?.registrationNumber||null,
      issuingAuthority:ocrResult?.issuingAuthority||null,
      employmentType:ocrResult?.employmentType||null,
      aiStatus:ocrResult?.aiStatus||"pending",
      aiWarnings:ocrResult?.aiWarnings||[],
      adminStatus:"unreviewed",
      memo, createdAt:now,
    };
    store.saveStaffDoc(doc);
    store.saveStaffDocAudit({id:genId(),staffDocId:docId,staffId:selStaff,action:"upload",userId:user.id||user.staffId,userName:user.displayName,detail:`${docType.label}をアップロード`,createdAt:now});

    // ── OCR抽出データをスタッフ管理にも反映 ──
    // 書類の種類に応じて関連フィールドをdynStaffに自動書き込み
    const staffUpdate = {};
    // 雇用契約書: 雇用形態・入職日を反映
    if (selType === "employment_contract") {
      if (doc.employmentType) staffUpdate.employmentType = doc.employmentType;
      if (doc.startDate) staffUpdate.hireDate = doc.startDate;
    }
    // 資格証明書: 資格名を qualifications 配列に追加
    if (doc.qualificationName) {
      const currentStaff = (store.dynStaff||[]).find(s=>s.id===selStaff);
      const existing = currentStaff?.qualifications||[];
      if (!existing.includes(doc.qualificationName)) {
        staffUpdate.qualifications = [...existing, doc.qualificationName];
      }
    }
    // 何か更新フィールドがあればスタッフ情報を更新
    if (Object.keys(staffUpdate).length > 0) {
      store.updStaff2(selStaff, staffUpdate);
      store.showToast(`✅ スタッフ情報を更新しました（${Object.keys(staffUpdate).join("・")}）`);
    } else {
      store.showToast("書類を保存しました");
    }
    onClose();
  };

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:9000,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:"var(--wh)",borderRadius:"20px 20px 0 0",width:"100%",maxWidth:600,maxHeight:"90vh",overflow:"auto",padding:"20px 20px 32px"}}>
        <div style={{display:"flex",alignItems:"center",marginBottom:18}}>
          <div style={{fontWeight:700,fontSize:16,flex:1}}>📂 書類アップロード</div>
          <button onClick={onClose} style={{fontSize:20,background:"none",border:"none",cursor:"pointer",color:"var(--tx3)"}}>✕</button>
        </div>

        {/* STEP 1: 選択 */}
        {(step==="select"||step==="preview")&&<>
          <div className="slbl">対象職員</div>
          <select className="fi" style={{marginBottom:12}} value={selStaff} onChange={e=>setSelStaff(e.target.value)}>
            <option value="">-- 選択してください --</option>
            {filteredStaff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          <div className="slbl">書類種別</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:16}}>
            {STAFF_DOC_TYPES.map(t=>(
              <div key={t.id} onClick={()=>setSelType(t.id)}
                style={{padding:"10px 12px",borderRadius:10,border:`2px solid ${selType===t.id?t.color:"var(--bd)"}`,background:selType===t.id?`${t.color}15`:"var(--wh)",cursor:"pointer",textAlign:"center"}}>
                <div style={{fontSize:20}}>{t.icon}</div>
                <div style={{fontSize:11,fontWeight:700,color:selType===t.id?t.color:"var(--tx)"}}>{t.label}</div>
                {t.required&&<div style={{fontSize:9,color:"var(--ro)"}}>必須</div>}
              </div>
            ))}
          </div>

          {step==="preview"&&imgUrl&&<>
            <div className="slbl">選択したファイル</div>
            <div style={{marginBottom:12,borderRadius:10,overflow:"hidden",border:"1px solid var(--bd)"}}>
              {imgUrl.startsWith("data:image")
                ?<img src={imgUrl} alt="preview" style={{width:"100%",maxHeight:200,objectFit:"contain",background:"#f5f5f5"}}/>
                :<div style={{padding:16,textAlign:"center",color:"var(--tx3)",fontSize:13}}>📎 {fileName}</div>
              }
            </div>
          </>}

          <input type="file" ref={fileRef} accept="image/*,application/pdf" style={{display:"none"}} onChange={handleFile}/>
          {step==="select"
            ?<button className="bsave" style={{width:"100%"}} onClick={()=>fileRef.current?.click()}>📷 撮影 / ファイル選択</button>
            :<div style={{display:"flex",gap:8}}>
              <button className="bcancel" style={{flex:1}} onClick={()=>{setStep("select");setImgB64("");setImgUrl("");setFileName("");}}>選び直す</button>
              <button className="bsave" style={{flex:2}} onClick={runOCR} disabled={!selStaff}>🤖 AI/OCR で解析する</button>
            </div>
          }
          {error&&<div style={{marginTop:8,color:"var(--ro)",fontSize:12}}>{error}</div>}
        </>}

        {/* STEP 2: OCR中 */}
        {step==="ocr"&&<div style={{textAlign:"center",padding:"48px 0"}}>
          <div style={{fontSize:48,marginBottom:16}}>🤖</div>
          <div style={{fontWeight:700,color:"var(--tl)",marginBottom:8}}>AI解析中...</div>
          <div style={{fontSize:12,color:"var(--tx3)"}}>書類の内容を読み取っています（10〜20秒）</div>
        </div>}

        {/* STEP 3: 確認 */}
        {step==="confirm"&&ocrResult&&<>
          <div style={{background:ocrResult.aiStatus==="expired"?"rgba(224,56,56,0.08)":ocrResult.aiStatus==="warning"?"rgba(217,119,6,0.08)":"rgba(44,170,96,0.08)",border:`1px solid ${ocrResult.aiStatus==="expired"?"rgba(224,56,56,0.3)":ocrResult.aiStatus==="warning"?"rgba(217,119,6,0.3)":"rgba(44,170,96,0.3)"}`,borderRadius:10,padding:"10px 12px",marginBottom:14}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:6}}>
              {SDOC_AI_STATUS[ocrResult.aiStatus]?.icon} AI判定結果: {SDOC_AI_STATUS[ocrResult.aiStatus]?.label}
            </div>
            {ocrResult.aiSummary&&<div style={{fontSize:12,color:"var(--tx2)",marginBottom:4}}>{ocrResult.aiSummary}</div>}
            {(ocrResult.aiWarnings||[]).map((w,i)=><div key={i} style={{fontSize:11,color:"var(--ro)",marginTop:2}}>⚠️ {w}</div>)}
          </div>

          <div style={{background:"var(--bg)",borderRadius:10,padding:"10px 12px",marginBottom:14,fontSize:12}}>
            <div style={{fontWeight:700,color:"var(--tx)",marginBottom:8}}>📋 抽出されたデータ</div>
            {Object.entries(ocrResult.extracted||{}).filter(([k,v])=>v!==null&&v!==undefined&&v!=="").map(([k,v])=>(
              <div key={k} style={{display:"flex",gap:8,marginBottom:4,alignItems:"flex-start"}}>
                <span style={{color:"var(--tx3)",minWidth:100,flexShrink:0,fontSize:10}}>{k}</span>
                <span style={{color:"var(--tx)",fontWeight:600,wordBreak:"break-all"}}>{Array.isArray(v)?v.join("、"):String(v)}</span>
              </div>
            ))}
          </div>

          <div className="slbl">メモ（任意）</div>
          <textarea className="fta" rows={2} value={memo} onChange={e=>setMemo(e.target.value)} placeholder="管理者コメントなど" style={{marginBottom:14}}/>

          <div style={{background:"rgba(58,160,216,0.06)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:8,padding:"8px 12px",marginBottom:14,fontSize:11,color:"var(--tx2)"}}>
            📌 AI判定はあくまで参考情報です。必ず管理者が内容を確認し「確認済み」にしてください。
          </div>

          <div style={{display:"flex",gap:8}}>
            <button className="bcancel" style={{flex:1}} onClick={()=>setStep("preview")}>← 戻る</button>
            <button className="bsave" style={{flex:2}} onClick={save}>💾 保存する</button>
          </div>
        </>}

        {step==="saving"&&<div style={{textAlign:"center",padding:"40px 0"}}>
          <div style={{fontSize:36,marginBottom:12}}>💾</div>
          <div style={{fontWeight:700,color:"var(--tl)"}}>保存中...</div>
        </div>}
      </div>
    </div>
  );
}

// ── 書類詳細モーダル ──
function StaffDocDetailModal({doc, store, user, getStaffName, getDocTypeInfo, getExpiryBadge, onClose}){
  const [adminStatus, setAdminStatus] = useState(doc.adminStatus||"unreviewed");
  const [memo, setMemo] = useState(doc.memo||"");
  const [saving, setSaving] = useState(false);
  const isMgr = ["admin","manager"].includes(user.role);
  const dt = getDocTypeInfo(doc.documentType);
  const ai = SDOC_AI_STATUS[doc.aiStatus]||SDOC_AI_STATUS.pending;

  const saveCheck = () => {
    setSaving(true);
    const updated = {...doc, adminStatus, adminCheckedBy:user.displayName, adminCheckedAt:new Date().toISOString(), memo};
    store.saveStaffDoc(updated);
    store.saveStaffDocAudit({id:genId(),staffDocId:doc.id,staffId:doc.staffId,action:"admin_check",userId:user.id||user.staffId,userName:user.displayName,detail:`管理者確認: ${SDOC_ADMIN_STATUS[adminStatus]?.label}`,createdAt:new Date().toISOString()});
    store.showToast("確認状況を保存しました");
    setSaving(false);
    onClose();
  };

  const doDelete = () => {
    if(!window.confirm("この書類を削除しますか？\nこの操作は取り消せません。")) return;
    store.saveStaffDocAudit({id:genId(),staffDocId:doc.id,staffId:doc.staffId,action:"delete",userId:user.id||user.staffId,userName:user.displayName,detail:`${dt.label}を削除`,createdAt:new Date().toISOString()});
    store.delStaffDoc(doc.id);
    store.showToast("書類を削除しました","warn");
    onClose();
  };

  const extracted = typeof doc.extractedText==="string"?JSON.parse(doc.extractedText||"{}"):doc.extractedText||{};

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.6)",zIndex:9000,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={e=>{if(e.target===e.currentTarget)onClose();}}>
      <div style={{background:"var(--wh)",borderRadius:"20px 20px 0 0",width:"100%",maxWidth:600,maxHeight:"90vh",overflow:"auto",padding:"20px 20px 32px"}}>
        <div style={{display:"flex",alignItems:"center",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:16,flex:1}}>{dt.icon} {dt.label}</div>
          <button onClick={onClose} style={{fontSize:20,background:"none",border:"none",cursor:"pointer",color:"var(--tx3)"}}>✕</button>
        </div>

        {/* 基本情報 */}
        <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12}}>
          <span style={{padding:"3px 10px",borderRadius:6,fontSize:12,fontWeight:700,background:ai.bg,color:ai.color}}>{ai.icon} {ai.label}</span>
          <span style={{padding:"3px 10px",borderRadius:6,fontSize:12,fontWeight:700,background:SDOC_ADMIN_STATUS[adminStatus]?.bg,color:SDOC_ADMIN_STATUS[adminStatus]?.color}}>{SDOC_ADMIN_STATUS[adminStatus]?.label}</span>
          {getExpiryBadge(doc)}
        </div>
        <div style={{fontSize:12,color:"var(--tx2)",marginBottom:4}}>👤 {getStaffName(doc.staffId)}</div>
        <div style={{fontSize:11,color:"var(--tx3)",marginBottom:12}}>アップロード: {(doc.uploadedAt||"").slice(0,10)} by {doc.uploadedBy}</div>

        {/* AI警告 */}
        {(doc.aiWarnings||[]).length>0&&<div style={{background:"rgba(224,56,56,0.06)",border:"1px solid rgba(224,56,56,0.25)",borderRadius:10,padding:"10px 12px",marginBottom:12}}>
          <div style={{fontWeight:700,fontSize:12,color:"var(--ro)",marginBottom:6}}>⚠️ AI警告</div>
          {(doc.aiWarnings||[]).map((w,i)=><div key={i} style={{fontSize:12,color:"var(--ro)",marginBottom:2}}>・{w}</div>)}
        </div>}

        {/* 抽出データ */}
        {Object.keys(extracted).length>0&&<div style={{background:"var(--bg)",borderRadius:10,padding:"10px 12px",marginBottom:12}}>
          <div style={{fontWeight:700,fontSize:12,color:"var(--tx)",marginBottom:8}}>📋 OCR抽出データ</div>
          {Object.entries(extracted).filter(([k,v])=>v!==null&&v!==undefined&&v!=="").map(([k,v])=>(
            <div key={k} style={{display:"flex",gap:8,marginBottom:4,fontSize:12}}>
              <span style={{color:"var(--tx3)",minWidth:100,flexShrink:0,fontSize:11}}>{k}</span>
              <span style={{color:"var(--tx)",fontWeight:600,wordBreak:"break-all"}}>{Array.isArray(v)?v.join("、"):String(v)}</span>
            </div>
          ))}
        </div>}

        {/* 画像プレビュー */}
        {doc.fileUrl&&doc.fileUrl.startsWith("data:image")&&<div style={{marginBottom:12,borderRadius:10,overflow:"hidden",border:"1px solid var(--bd)"}}>
          <img src={doc.fileUrl} alt="書類画像" style={{width:"100%",maxHeight:250,objectFit:"contain",background:"#f5f5f5"}}/>
        </div>}

        {/* 管理者確認 */}
        {isMgr&&<>
          <div className="slbl">管理者確認ステータス</div>
          <div style={{display:"flex",gap:8,marginBottom:12}}>
            {Object.entries(SDOC_ADMIN_STATUS).map(([k,v])=>(
              <button key={k} onClick={()=>setAdminStatus(k)}
                style={{flex:1,padding:"8px 4px",borderRadius:9,border:`2px solid ${adminStatus===k?v.color:"var(--bd)"}`,background:adminStatus===k?v.bg:"var(--wh)",color:adminStatus===k?v.color:"var(--tx2)",fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
                {v.label}
              </button>
            ))}
          </div>
          <div className="slbl">メモ</div>
          <textarea className="fta" rows={2} value={memo} onChange={e=>setMemo(e.target.value)} style={{marginBottom:14}}/>
          <div style={{display:"flex",gap:8,marginBottom:8}}>
            <button onClick={doDelete} style={{padding:"10px 14px",borderRadius:10,background:"rgba(224,56,56,0.1)",border:"1px solid rgba(224,56,56,0.3)",color:"var(--ro)",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🗑️ 削除</button>
            <button onClick={saveCheck} disabled={saving} className="bsave" style={{flex:1}}>
              {saving?"保存中…":"✅ 確認結果を保存"}
            </button>
          </div>
          {doc.adminCheckedBy&&<div style={{fontSize:11,color:"var(--tx3)",textAlign:"center"}}>前回確認: {doc.adminCheckedBy} / {(doc.adminCheckedAt||"").slice(0,10)}</div>}
        </>}
      </div>
    </div>
  );
}

// ── AI職員プロファイル要約モーダル ──
function StaffDocSummaryModal({staff, docs, onClose}){
  const [loading,setLoading]=useState(false);
  const [result,setResult]=useState(null);
  const [error,setError]=useState("");

  const runSummary=async()=>{
    setLoading(true);setError("");setResult(null);
    try{
      const docList=docs.map(d=>({
        documentType:d.documentType,
        typeLabel:STAFF_DOC_TYPES.find(t=>t.id===d.documentType)?.label||d.documentType,
        qualificationName:d.qualificationName||null,
        expiryDate:d.expiryDate||null, issueDate:d.issueDate||null,
        issuingAuthority:d.issuingAuthority||null, employmentType:d.employmentType||null,
        aiWarnings:d.aiWarnings||[], aiStatus:d.aiStatus,
      }));
      const resp=await fetch("/api/staff-doc-summary",{method:"POST",headers:{"Content-Type":"application/json"},
        body:JSON.stringify({staffName:staff.name,staffRole:staff.position||staff.employmentType||"",documents:docList})});
      const data=await resp.json();
      if(data.success)setResult(data);
      else setError(data.error||"生成に失敗しました");
    }catch(e){setError(e.message);}
    setLoading(false);
  };

  useEffect(()=>{if(docs.length>0)runSummary();},[]);

  const ratingColor=r=>r==="良好"?"var(--gr)":r==="要対応"?"var(--ro)":"var(--ac)";

  return(
    <div className="modal-ov" onClick={onClose}>
      <div className="modal-box" onClick={e=>e.stopPropagation()} style={{maxWidth:520}}>
        <div className="modal-hd">
          <span>🤖 AI職員プロファイル要約</span>
          <button className="mclose" onClick={onClose}>✕</button>
        </div>
        <div style={{padding:"12px 0"}}>
          <div style={{fontWeight:700,fontSize:15,marginBottom:10}}>{staff.name} さんの書類状況</div>
          <div style={{fontSize:12,color:"var(--tx3)",marginBottom:12}}>登録書類: {docs.length}件</div>
          {loading&&<div style={{textAlign:"center",padding:"32px 0",color:"var(--tx3)"}}>🤖 AI解析中...</div>}
          {error&&<div style={{color:"var(--ro)",padding:"12px",background:"rgba(224,56,56,0.07)",borderRadius:8,fontSize:13}}>{error}</div>}
          {result&&<>
            {result.overallRating&&<div style={{display:"inline-block",padding:"4px 14px",borderRadius:20,fontWeight:700,fontSize:13,background:ratingColor(result.overallRating)+"20",color:ratingColor(result.overallRating),marginBottom:12}}>
              総合評価: {result.overallRating}
            </div>}
            {result.profileSummary&&<div style={{background:"var(--bg2)",borderRadius:10,padding:"12px",fontSize:13,lineHeight:1.7,marginBottom:12}}>{result.profileSummary}</div>}
            {result.qualifications?.length>0&&<div style={{marginBottom:10}}>
              <div style={{fontWeight:700,fontSize:12,color:"var(--tx2)",marginBottom:6}}>🏆 保有資格・免許</div>
              <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
                {result.qualifications.map((q,i)=><span key={i} style={{padding:"3px 10px",background:"rgba(5,150,105,0.1)",color:"var(--gr)",borderRadius:20,fontSize:12,fontWeight:600}}>{q}</span>)}
              </div>
            </div>}
            {result.expiryRisks?.length>0&&<div style={{marginBottom:10}}>
              <div style={{fontWeight:700,fontSize:12,color:"var(--ro)",marginBottom:6}}>⚠️ 期限リスク</div>
              {result.expiryRisks.map((r,i)=><div key={i} style={{fontSize:12,color:"var(--ro)",padding:"2px 0"}}>・{r}</div>)}
            </div>}
            {result.missingRisks?.length>0&&<div style={{marginBottom:10}}>
              <div style={{fontWeight:700,fontSize:12,color:"var(--ac)",marginBottom:6}}>📌 注意点</div>
              {result.missingRisks.map((r,i)=><div key={i} style={{fontSize:12,color:"var(--ac)",padding:"2px 0"}}>・{r}</div>)}
            </div>}
            {result.recommendations&&<div style={{background:"rgba(58,160,216,0.07)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:8,padding:"10px",fontSize:12,color:"var(--tx)",marginTop:10}}>
              💡 <strong>アドバイス:</strong> {result.recommendations}
            </div>}
          </>}
          {docs.length===0&&!loading&&<div style={{textAlign:"center",padding:"20px 0",color:"var(--tx3)"}}>書類がありません</div>}
          <div style={{display:"flex",gap:8,marginTop:16}}>
            <button className="bback" onClick={onClose} style={{flex:1}}>閉じる</button>
            {docs.length>0&&<button className="bsave" onClick={runSummary} disabled={loading} style={{flex:1}}>🔄 再生成</button>}
          </div>
        </div>
      </div>
    </div>
  );
}

// ── 書類更新依頼モーダル（職員ごと） ──
function StaffDocUpdateRequestModal({staff, store, user, onClose}){
  const [docType,setDocType]=useState(STAFF_DOC_TYPES[0].id);
  const [message,setMessage]=useState("");
  const [dueDate,setDueDate]=useState("");
  const [saving,setSaving]=useState(false);

  const myRequests=(store.staffDocRequests||[]).filter(r=>r.staffId===staff.id);
  const STATUS_COLOR={"未送信":"var(--tx3)","送信済み":"var(--tl)","対応中":"var(--ac)","完了":"var(--gr)"};

  const handleSend=()=>{
    if(!message.trim()){alert("依頼メッセージを入力してください");return;}
    setSaving(true);
    const req={
      id:genId(),staffId:staff.id,facilityId:staff.facilityId||null,
      docType,requestMessage:message.trim(),status:"送信済み",
      dueDate:dueDate||null,createdBy:user.displayName||user.username,
      createdAt:new Date().toISOString(),
    };
    store.saveStaffDocRequest(req);
    const notif={
      id:genId(),staffId:staff.id,staffDocId:null,notifType:"update_request",
      message:`書類提出依頼: ${STAFF_DOC_TYPES.find(t=>t.id===docType)?.label||docType}（${user.displayName}より）`,
      isRead:false,createdBy:user.displayName,createdAt:new Date().toISOString(),
    };
    store.saveStaffDocNotif(notif);
    store.showToast("更新依頼を送信しました","success");
    setSaving(false);setMessage("");setDueDate("");
  };

  const updStatus=(req,ns)=>{
    store.saveStaffDocRequest({...req,status:ns,respondedAt:new Date().toISOString()});
    store.showToast(`ステータスを「${ns}」に更新しました`);
  };

  return(
    <div className="modal-ov" onClick={onClose}>
      <div className="modal-box" onClick={e=>e.stopPropagation()} style={{maxWidth:520}}>
        <div className="modal-hd">
          <span>📬 書類提出依頼 — {staff.name}</span>
          <button className="mclose" onClick={onClose}>✕</button>
        </div>
        <div style={{padding:"12px 0"}}>
          {/* 新規依頼フォーム */}
          <div style={{background:"var(--bg2)",borderRadius:10,padding:"14px",marginBottom:16}}>
            <div style={{fontWeight:700,fontSize:13,marginBottom:10}}>＋ 新しい依頼を作成</div>
            <div style={{marginBottom:8}}>
              <div style={{fontSize:12,color:"var(--tx2)",marginBottom:4}}>書類種別</div>
              <select className="fsm" value={docType} onChange={e=>setDocType(e.target.value)} style={{width:"100%"}}>
                {STAFF_DOC_TYPES.map(t=><option key={t.id} value={t.id}>{t.icon} {t.label}</option>)}
              </select>
            </div>
            <div style={{marginBottom:8}}>
              <div style={{fontSize:12,color:"var(--tx2)",marginBottom:4}}>依頼メッセージ</div>
              <textarea value={message} onChange={e=>setMessage(e.target.value)} rows={3}
                placeholder="例：雇用契約書の更新が必要です。以下の書類をご提出ください。"
                style={{width:"100%",boxSizing:"border-box",border:"1px solid var(--bd)",borderRadius:7,padding:"8px",fontSize:13,fontFamily:"'Noto Sans JP',sans-serif",resize:"vertical"}}/>
            </div>
            <div style={{marginBottom:12}}>
              <div style={{fontSize:12,color:"var(--tx2)",marginBottom:4}}>提出期限（任意）</div>
              <input type="date" value={dueDate} onChange={e=>setDueDate(e.target.value)}
                style={{border:"1px solid var(--bd)",borderRadius:7,padding:"8px",fontSize:13}}/>
            </div>
            <button className="bsave" onClick={handleSend} disabled={saving} style={{width:"100%"}}>
              {saving?"送信中...":"📨 依頼を送信"}
            </button>
          </div>
          {/* 既存依頼一覧 */}
          {myRequests.length>0&&<div>
            <div style={{fontWeight:700,fontSize:13,marginBottom:8}}>過去の依頼 ({myRequests.length}件)</div>
            {[...myRequests].reverse().map(req=>(
              <div key={req.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"12px",marginBottom:8}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <span style={{fontWeight:700,fontSize:13}}>{STAFF_DOC_TYPES.find(t=>t.id===req.docType)?.label||req.docType}</span>
                  <span style={{fontSize:11,fontWeight:700,padding:"2px 8px",borderRadius:20,background:(STATUS_COLOR[req.status]||"var(--tx3)")+"20",color:STATUS_COLOR[req.status]||"var(--tx3)"}}>{req.status}</span>
                </div>
                <div style={{fontSize:12,color:"var(--tx2)",marginBottom:6}}>{req.requestMessage}</div>
                {req.dueDate&&<div style={{fontSize:11,color:"var(--tx3)",marginBottom:6}}>期限: {req.dueDate}</div>}
                <div style={{display:"flex",gap:6,marginTop:6}}>
                  {req.status==="送信済み"&&<button className="bsave" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>updStatus(req,"対応中")}>対応中へ</button>}
                  {req.status==="対応中"&&<button className="bsave" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>updStatus(req,"完了")}>完了にする</button>}
                  {req.status!=="完了"&&<button style={{fontSize:11,padding:"4px 10px",border:"1px solid var(--bd)",borderRadius:6,background:"var(--wh)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>{if(window.confirm("この依頼を削除しますか？"))store.delStaffDocRequest(req.id);}}>削除</button>}
                </div>
              </div>
            ))}
          </div>}
          {myRequests.length===0&&<div style={{textAlign:"center",padding:"20px 0",color:"var(--tx3)",fontSize:13}}>まだ依頼はありません</div>}
          <button className="bback" onClick={onClose} style={{width:"100%",marginTop:8}}>閉じる</button>
        </div>
      </div>
    </div>
  );
}

// ── 監査出力パネル ──
function StaffDocAuditExportPanel({store, filteredStaff, getStaffName, user}){
  const [selStaffId,setSelStaffId]=useState("all");
  const [dateFrom,setDateFrom]=useState("");
  const [dateTo,setDateTo]=useState("");

  const filteredLogs=(store.staffDocAuditLogs||[]).filter(l=>{
    if(selStaffId!=="all"&&(l.staff_id||l.staffId)!==selStaffId) return false;
    const at=(l.created_at||l.createdAt||"").slice(0,10);
    if(dateFrom&&at<dateFrom) return false;
    if(dateTo&&at>dateTo) return false;
    return true;
  });

  const handleExport=()=>{
    if(filteredLogs.length===0){alert("出力対象のログがありません");return;}
    const staffLabel=selStaffId==="all"?"全職員":getStaffName(selStaffId);
    const period=[dateFrom,dateTo].filter(Boolean).join(" 〜 ")||"全期間";
    const rows=[...filteredLogs].reverse().map(l=>`
      <tr>
        <td>${(l.created_at||l.createdAt||"").slice(0,16).replace("T"," ")}</td>
        <td>${getStaffName(l.staff_id||l.staffId)}</td>
        <td>${l.user_name||l.userName||""}</td>
        <td>${l.action||""}</td>
        <td style="max-width:200px;word-break:break-all;">${l.detail||""}</td>
      </tr>`).join("");
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8">
      <title>職員書類 操作ログ</title>
      <style>
        body{font-family:'Noto Sans JP',sans-serif;font-size:11px;padding:20px;}
        h2{font-size:15px;margin-bottom:4px;}
        .meta{color:#666;font-size:10px;margin-bottom:16px;}
        table{width:100%;border-collapse:collapse;}
        th,td{border:1px solid #ccc;padding:5px 7px;text-align:left;}
        th{background:#e8f0fe;font-weight:700;}
        tr:nth-child(even){background:#f8fafc;}
      </style></head><body>
      <h2>📂 職員書類 操作ログ（監査用）</h2>
      <div class="meta">対象: ${staffLabel} | 期間: ${period} | 出力日: ${new Date().toLocaleString("ja-JP")} | 出力者: ${user.displayName}</div>
      <table><thead><tr><th>日時</th><th>対象職員</th><th>操作者</th><th>アクション</th><th>詳細</th></tr></thead>
      <tbody>${rows}</tbody></table>
    </body></html>`;
    const w=window.open("","_blank");
    if(!w){alert("ポップアップがブロックされています。許可してから再実行してください。");return;}
    w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);
  };

  return(
    <div>
      <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:12}}>📄 監査ログ出力</div>
      <div style={{background:"var(--bg2)",borderRadius:10,padding:"14px",marginBottom:14}}>
        <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:10,alignItems:"center"}}>
          <select className="fsm" value={selStaffId} onChange={e=>setSelStaffId(e.target.value)}>
            <option value="all">全職員</option>
            {filteredStaff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
          </select>
          <input type="date" value={dateFrom} onChange={e=>setDateFrom(e.target.value)}
            style={{border:"1px solid var(--bd)",borderRadius:7,padding:"7px",fontSize:13}}/>
          <span style={{color:"var(--tx3)",alignSelf:"center"}}>〜</span>
          <input type="date" value={dateTo} onChange={e=>setDateTo(e.target.value)}
            style={{border:"1px solid var(--bd)",borderRadius:7,padding:"7px",fontSize:13}}/>
          <button className="bsave" onClick={handleExport} style={{padding:"7px 14px",fontSize:12}}>
            🖨️ PDF出力 ({filteredLogs.length}件)
          </button>
        </div>
        <div style={{fontSize:11,color:"var(--tx3)"}}>※ 監査用ログはPDFで出力できます</div>
      </div>
      {filteredLogs.length===0
        ?<div style={{textAlign:"center",padding:"30px 0",color:"var(--tx3)"}}>該当するログがありません</div>
        :[...filteredLogs].reverse().slice(0,200).map((l,i)=>(
          <div key={l.id||i} style={{display:"flex",gap:8,padding:"8px 0",borderBottom:"1px solid var(--bg)",fontSize:12,flexWrap:"wrap"}}>
            <span style={{color:"var(--tx3)",flexShrink:0,minWidth:120}}>{(l.created_at||l.createdAt||"").slice(0,16).replace("T"," ")}</span>
            <span style={{color:"var(--tx2)",flexShrink:0,minWidth:70,fontWeight:600}}>{getStaffName(l.staff_id||l.staffId)}</span>
            <span style={{color:"var(--tl)",fontWeight:700,flexShrink:0,minWidth:60}}>{l.user_name||l.userName}</span>
            <span style={{color:"var(--tx)"}}>{l.action}</span>
            <span style={{color:"var(--tx3)",flex:1,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{l.detail}</span>
          </div>
        ))
      }
    </div>
  );
}

// ── 更新依頼管理タブ ──
function StaffDocRequestsTab({store, filteredStaff, user, getStaffName}){
  const [filterStatus,setFilterStatus]=useState("all");
  const [requestStaff,setRequestStaff]=useState(null);
  const [summaryStaff,setSummaryStaff]=useState(null);

  const STATUS_COLOR={"未送信":"var(--tx3)","送信済み":"var(--tl)","対応中":"var(--ac)","完了":"var(--gr)"};
  const facCheck=s=>user.role==="admin"||(s?.facilityId||s?.facility_id)===user.selectedFacilityId;

  const allReqs=(store.staffDocRequests||[]).filter(r=>{
    const s=(store.dynStaff||[]).find(x=>x.id===r.staffId);
    if(!facCheck(s)) return false;
    if(filterStatus!=="all"&&r.status!==filterStatus) return false;
    return true;
  });
  const pendingCount=(store.staffDocRequests||[]).filter(r=>{
    const s=(store.dynStaff||[]).find(x=>x.id===r.staffId);
    return facCheck(s)&&(r.status==="送信済み"||r.status==="対応中");
  }).length;

  return(
    <div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:13,color:"var(--tx)"}}>
          📬 書類更新依頼
          {pendingCount>0&&<span style={{marginLeft:6,background:"var(--ro)",color:"#fff",borderRadius:20,padding:"1px 7px",fontSize:10,fontWeight:700}}>{pendingCount}</span>}
        </div>
        <select className="fsm" value={filterStatus} onChange={e=>setFilterStatus(e.target.value)} style={{fontSize:11}}>
          <option value="all">全ステータス</option>
          {["未送信","送信済み","対応中","完了"].map(s=><option key={s} value={s}>{s}</option>)}
        </select>
      </div>
      {/* 職員別依頼作成ボタン */}
      <div style={{background:"var(--bg2)",borderRadius:10,padding:"10px 12px",marginBottom:14}}>
        <div style={{fontSize:12,color:"var(--tx2)",marginBottom:8}}>職員を選んで依頼を作成 ▼</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
          {filteredStaff.slice(0,20).map(s=>(
            <button key={s.id} onClick={()=>setRequestStaff(s)}
              style={{padding:"6px 12px",border:"1px solid var(--bd)",borderRadius:20,background:"var(--wh)",fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",display:"flex",alignItems:"center",gap:4}}>
              {s.name} <span style={{color:"var(--tl)",fontWeight:700}}>＋</span>
            </button>
          ))}
        </div>
      </div>
      {/* 依頼一覧 */}
      {allReqs.length===0
        ?<div style={{textAlign:"center",padding:"30px 0",color:"var(--tx3)"}}>依頼がありません</div>
        :[...allReqs].reverse().map(req=>{
          const s=filteredStaff.find(x=>x.id===req.staffId);
          const dtInfo=STAFF_DOC_TYPES.find(t=>t.id===req.docType);
          return(
            <div key={req.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"12px",marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4}}>
                <div style={{fontWeight:700,fontSize:13}}>{s?.name||getStaffName(req.staffId)}</div>
                <span style={{fontSize:11,fontWeight:700,padding:"2px 8px",borderRadius:20,background:(STATUS_COLOR[req.status]||"var(--tx3)")+"20",color:STATUS_COLOR[req.status]||"var(--tx3)"}}>{req.status}</span>
              </div>
              <div style={{fontSize:12,color:"var(--tl)",marginBottom:4,fontWeight:600}}>
                {dtInfo?.icon||"📁"} {dtInfo?.label||req.docType}
              </div>
              <div style={{fontSize:12,color:"var(--tx2)",marginBottom:6}}>{req.requestMessage}</div>
              <div style={{display:"flex",gap:8,fontSize:11,color:"var(--tx3)",marginBottom:8}}>
                {req.dueDate&&<span>📅 期限: {req.dueDate}</span>}
                <span>{(req.createdAt||"").slice(0,10)} — {req.createdBy}</span>
              </div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {req.status==="送信済み"&&<button className="bsave" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>store.saveStaffDocRequest({...req,status:"対応中",respondedAt:new Date().toISOString()})}>対応中</button>}
                {req.status==="対応中"&&<button className="bsave" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>store.saveStaffDocRequest({...req,status:"完了",respondedAt:new Date().toISOString()})}>完了</button>}
                {s&&<button style={{fontSize:11,padding:"4px 10px",border:"1px solid var(--tl)",borderRadius:6,background:"var(--wh)",color:"var(--tl)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>setSummaryStaff(s)}>🤖 AI要約</button>}
                {req.status!=="完了"&&<button style={{fontSize:11,padding:"4px 10px",border:"1px solid var(--bd)",borderRadius:6,background:"var(--wh)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>{if(window.confirm("この依頼を削除しますか？"))store.delStaffDocRequest(req.id);}}>削除</button>}
              </div>
            </div>
          );
        })
      }
      {/* モーダル */}
      {requestStaff&&<StaffDocUpdateRequestModal staff={requestStaff} store={store} user={user} onClose={()=>setRequestStaff(null)}/>}
      {summaryStaff&&<StaffDocSummaryModal staff={summaryStaff} docs={(store.staffDocs||[]).filter(d=>d.staffId===summaryStaff.id)} onClose={()=>setSummaryStaff(null)}/>}
    </div>
  );
}

// ── メイン画面 ──
function StaffDocumentScreen({user, store, onBack}){
  const isPrivileged = ["admin","manager"].includes(user.role);
  if(!isPrivileged) return (
    <div style={{padding:32,textAlign:"center"}}>
      <div style={{fontSize:56,marginBottom:12}}>🔒</div>
      <div style={{fontWeight:700,fontSize:16,color:"var(--ro)",marginBottom:8}}>アクセス権限がありません</div>
      <div style={{fontSize:13,color:"var(--tx3)",marginBottom:20}}>管理者・施設長のみ閲覧できます</div>
      <button className="bback" onClick={onBack}>← ホームへ戻る</button>
    </div>
  );

  const [tab, setTab] = useState("list");
  const [selFacility, setSelFacility] = useState(user.role==="admin"?"all":user.selectedFacilityId);
  const [selStaff, setSelStaff] = useState("all");
  const [selDocType, setSelDocType] = useState("all");
  const [uploadModal, setUploadModal] = useState(false);
  const [viewDoc, setViewDoc] = useState(null);
  const [summaryStaff, setSummaryStaff] = useState(null);
  const isAdmin = user.role==="admin";
  const today = new Date();

  const filteredStaff = (store.dynStaff||[]).filter(s=>{
    if(s.active===false) return false;
    if(selFacility==="all") return true;
    return s.facilityId===selFacility;
  });

  const filteredDocs = (store.staffDocs||[]).filter(d=>{
    if(selFacility!=="all"){
      const s=(store.dynStaff||[]).find(x=>x.id===d.staffId);
      if(s?.facilityId!==selFacility) return false;
    }
    if(selStaff!=="all"&&d.staffId!==selStaff) return false;
    if(selDocType!=="all"&&d.documentType!==selDocType) return false;
    return true;
  });

  const getExpiryInfo = doc => {
    const dateStr = doc.expiryDate||doc.endDate;
    if(!dateStr) return null;
    const expiry = new Date(dateStr);
    const diffDays = Math.floor((expiry-today)/(1000*60*60*24));
    return {diffDays, dateStr};
  };

  const alertDocs = (store.staffDocs||[]).filter(d=>{
    if(selFacility!=="all"){const s=(store.dynStaff||[]).find(x=>x.id===d.staffId);if(s?.facilityId!==selFacility)return false;}
    const info=getExpiryInfo(d);
    if(info&&info.diffDays<=60) return true;
    if(d.aiStatus==="warning"||d.aiStatus==="expired") return true;
    return false;
  });

  const missingDocs = filteredStaff.filter(s=>{
    const req=STAFF_DOC_TYPES.filter(t=>t.required);
    return req.some(t=>!(store.staffDocs||[]).find(d=>d.staffId===s.id&&d.documentType===t.id));
  });

  const alertCount = alertDocs.length+missingDocs.length;

  const getStaffName = id=>(store.dynStaff||[]).find(s=>s.id===id)?.name||id;
  const getDocTypeInfo = id=>STAFF_DOC_TYPES.find(t=>t.id===id)||{label:id,icon:"📁"};
  const getExpiryBadge = doc=>{
    const info=getExpiryInfo(doc);
    if(!info) return null;
    const {diffDays}=info;
    if(diffDays<0) return <span style={{padding:"2px 7px",borderRadius:5,fontSize:10,fontWeight:700,background:"rgba(224,56,56,0.12)",color:"var(--ro)"}}>🔴 期限切れ</span>;
    if(diffDays<=30) return <span style={{padding:"2px 7px",borderRadius:5,fontSize:10,fontWeight:700,background:"rgba(224,56,56,0.08)",color:"var(--ro)"}}>⚠️ 30日以内</span>;
    if(diffDays<=60) return <span style={{padding:"2px 7px",borderRadius:5,fontSize:10,fontWeight:700,background:"rgba(217,119,6,0.1)",color:"#d97706"}}>⏰ 60日以内</span>;
    return null;
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">📂 職員書類管理</div>
    </div>

    {/* 要対応サマリー */}
    {alertCount>0&&<div style={{background:"rgba(224,56,56,0.07)",border:"1px solid rgba(224,56,56,0.25)",borderRadius:12,padding:"10px 14px",marginBottom:14}}>
      <div style={{fontWeight:700,fontSize:13,color:"var(--ro)",marginBottom:4}}>🚨 要対応: {alertCount}件</div>
      <div style={{display:"flex",gap:12,flexWrap:"wrap",fontSize:12}}>
        {alertDocs.length>0&&<span style={{color:"var(--ro)"}}>{alertDocs.length}件：期限切れ・AI警告</span>}
        {missingDocs.length>0&&<span style={{color:"#d97706"}}>{missingDocs.length}名：必須書類未提出</span>}
      </div>
    </div>}

    {/* フィルター */}
    <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:14}}>
      {isAdmin&&<select className="fsm" value={selFacility} onChange={e=>{setSelFacility(e.target.value);setSelStaff("all");}}>
        <option value="all">全施設</option>
        {FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
      </select>}
      <select className="fsm" value={selStaff} onChange={e=>setSelStaff(e.target.value)}>
        <option value="all">全職員</option>
        {filteredStaff.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
      </select>
      <select className="fsm" value={selDocType} onChange={e=>setSelDocType(e.target.value)}>
        <option value="all">全種別</option>
        {STAFF_DOC_TYPES.map(t=><option key={t.id} value={t.id}>{t.icon} {t.label}</option>)}
      </select>
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
      {(()=>{
        const pendingReqs=(store.staffDocRequests||[]).filter(r=>{
          const s=(store.dynStaff||[]).find(x=>x.id===r.staffId);
          if(!isAdmin&&s?.facilityId!==user.selectedFacilityId) return false;
          return r.status==="送信済み"||r.status==="対応中";
        }).length;
        return [
          {id:"list",     label:`書類一覧 (${filteredDocs.length})`},
          {id:"alerts",   label:`アラート (${alertCount})`, warn:alertCount>0},
          {id:"by_staff", label:"職員別"},
          {id:"requests", label:`更新依頼${pendingReqs>0?` (${pendingReqs})`:""}`, warn:pendingReqs>0},
          {id:"audit_export", label:"監査出力"},
        ].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{padding:"8px 12px",borderRadius:9,border:`2px solid ${tab===t.id?"var(--tl)":"var(--bd)"}`,
              background:tab===t.id?"rgba(58,160,216,0.1)":"var(--wh)",
              color:tab===t.id?"var(--tl)":t.warn?"var(--ro)":"var(--tx2)",
              fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
            {t.label}
          </button>
        ));
      })()}
      <button className="bsave" style={{marginLeft:"auto",padding:"8px 14px",fontSize:12}} onClick={()=>setUploadModal(true)}>
        ＋ アップロード
      </button>
    </div>

    {/* 書類一覧 */}
    {tab==="list"&&(filteredDocs.length===0
      ?<div style={{textAlign:"center",padding:"48px 0",color:"var(--tx3)"}}>
          書類がありません<br/><span style={{fontSize:12}}>「＋ アップロード」から追加できます</span>
        </div>
      :filteredDocs.map(doc=>(
        <StaffDocCard key={doc.id} doc={doc} store={store} user={user}
          onView={()=>setViewDoc(doc)}
          getStaffName={getStaffName} getDocTypeInfo={getDocTypeInfo} getExpiryBadge={getExpiryBadge}
        />
      ))
    )}

    {/* アラート */}
    {tab==="alerts"&&<StaffDocAlertTab
      alerts={alertDocs} missingDocs={missingDocs} store={store}
      getStaffName={getStaffName} getDocTypeInfo={getDocTypeInfo} getExpiryInfo={getExpiryInfo}
      filteredStaff={filteredStaff}
    />}

    {/* 職員別 */}
    {tab==="by_staff"&&<StaffDocByStaffTab
      filteredStaff={filteredStaff} store={store}
      getDocTypeInfo={getDocTypeInfo} getExpiryBadge={getExpiryBadge}
      onUpload={()=>setUploadModal(true)}
    />}

    {/* 更新依頼タブ */}
    {tab==="requests"&&<StaffDocRequestsTab
      store={store} filteredStaff={filteredStaff} user={user} getStaffName={getStaffName}
    />}

    {/* 監査出力タブ */}
    {tab==="audit_export"&&<StaffDocAuditExportPanel
      store={store} filteredStaff={filteredStaff} getStaffName={getStaffName} user={user}
    />}

    {/* モーダル */}
    {uploadModal&&<StaffDocUploadModal user={user} store={store} filteredStaff={filteredStaff.length?filteredStaff:(store.dynStaff||[]).filter(s=>s.active!==false)} onClose={()=>setUploadModal(false)}/>}
    {viewDoc&&<StaffDocDetailModal doc={viewDoc} store={store} user={user} getStaffName={getStaffName} getDocTypeInfo={getDocTypeInfo} getExpiryBadge={getExpiryBadge} onClose={()=>setViewDoc(null)}/>}
    {summaryStaff&&<StaffDocSummaryModal staff={summaryStaff} docs={(store.staffDocs||[]).filter(d=>d.staffId===summaryStaff.id)} onClose={()=>setSummaryStaff(null)}/>}
  </div>;
}

// ==================== 写真アルバム ====================
// 活動写真を保護者に共有するアルバム機能

function PhotoAlbumScreen({user, store, onBack}){
  const facilityId=user.selectedFacilityId;
  const [mode,setMode]=useState("list"); // list|create|view
  const [viewAlbum,setViewAlbum]=useState(null);
  const [form,setForm]=useState({title:"",description:"",takenDate:todayISO(),childIds:[],photos:[],isShared:false});
  const [saving,setSaving]=useState(false);
  const [uploadingCount,setUploadingCount]=useState(0); // アップロード中の枚数カウント
  const fileRef=useRef();

  const myAlbums=(store.photoAlbums||[]).filter(a=>a.facilityId===facilityId||user.role==="admin")
    .sort((a,b)=>(b.takenDate||b.createdAt||"")>(a.takenDate||a.createdAt||"")?1:-1);
  const myUsers=store.dynUsers.filter(u=>(user.role==="admin"||u.facilityId===facilityId)&&u.active!==false);

  // 写真追加：Storage にアップロード（失敗時はdata URLフォールバック）
  const addPhotos=async e=>{
    const files=Array.from(e.target.files||[]);
    // サイズ確認後、アップロード中カウントをインクリメント
    // uploadToStorage / フォールバックの双方で縮小するため上限は50MB
    const validFiles=files.filter(f=>checkFileSize(f,COMPRESSED_FILE_SIZE_MB));
    if(validFiles.length===0) return;
    setUploadingCount(c=>c+validFiles.length);
    for(const file of validFiles){
      try{
        const uploaded=await uploadToStorage(file,"album-photos",facilityId);
        if(uploaded?.url){
          // Storage URL 保存成功
          setForm(p=>({...p,photos:[...p.photos,{id:genId(),url:uploaded.url,name:file.name,size:file.size}]}));
        } else {
          // フォールバック: data URL（オフライン時や一時エラー）
          // ★ 原寸のままだとアルバム1件に数MB×枚数が入り、保存リクエストが上限を超える。
          //   maxPx=2000: 保護者に共有する写真なので閲覧に耐える解像度を残す。
          const {dataUrl:url}=await _ocrPrepare(file,{maxPx:2000,quality:0.85});
          setForm(p=>({...p,photos:[...p.photos,{id:genId(),url,name:file.name,size:file.size}]}));
        }
      } catch(e){
        // フォールバックも失敗（未対応形式など）→ その1枚だけ諦めて理由を出す
        console.warn("[アルバム] 写真の取り込み失敗:",e?.stage||"",e?.message||e);
        store.showToast(`⚠️ ${file.name}: ${e?.message||"写真を読み込めませんでした"}`,"warn");
      } finally{
        setUploadingCount(c=>c-1);
      }
    }
  };

  const removePhoto=id=>setForm(p=>({...p,photos:p.photos.filter(ph=>ph.id!==id)}));
  const toggleChild=cid=>setForm(p=>({...p,childIds:p.childIds.includes(cid)?p.childIds.filter(x=>x!==cid):[...p.childIds,cid]}));

  const saveAlbum=()=>{
    if(!form.title.trim()){store.showToast("タイトルを入力してください","error");return;}
    if(form.photos.length===0){store.showToast("写真を1枚以上追加してください","error");return;}
    setSaving(true);
    const album={id:genId(),facilityId,...form,createdBy:user.displayName,createdAt:new Date().toISOString(),sharedAt:form.isShared?new Date().toISOString():null};
    store.savePhotoAlbum(album);
    store.showToast("アルバムを保存しました","success");
    setSaving(false);
    setMode("list");
    setForm({title:"",description:"",takenDate:todayISO(),childIds:[],photos:[],isShared:false});
  };

  const toggleShare=album=>{
    const updated={...album,isShared:!album.isShared,sharedAt:!album.isShared?new Date().toISOString():null};
    store.savePhotoAlbum(updated);
    store.showToast(updated.isShared?"保護者に公開しました":"非公開にしました");
  };

  const doDelete=album=>{
    if(!window.confirm(`「${album.title}」を削除しますか？\nこの操作は取り消せません。`))return;
    store.delPhotoAlbum(album.id);
    store.showToast("アルバムを削除しました","warn");
    if(viewAlbum?.id===album.id)setViewAlbum(null);
    setMode("list");
  };

  // ── 新規作成フォーム ──
  if(mode==="create") return(
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={()=>setMode("list")}>← 戻る</button>
        <div className="fl-title">📸 新規アルバム作成</div>
      </div>
      <div className="slbl">タイトル</div>
      <input className="fi" value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))} placeholder="例：水遊び活動 / 工作の時間"/>
      <div className="slbl">活動日</div>
      <input type="date" className="fi" value={form.takenDate} onChange={e=>setForm(p=>({...p,takenDate:e.target.value}))}/>
      <div className="slbl">説明（任意）</div>
      <textarea className="fta" rows={2} value={form.description} onChange={e=>setForm(p=>({...p,description:e.target.value}))} placeholder="活動の内容・コメント"/>

      <div className="slbl">対象児童（任意）</div>
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
        {myUsers.map(u=>{
          const sel=form.childIds.includes(u.id);
          return <button key={u.id} onClick={()=>toggleChild(u.id)}
            style={{padding:"5px 12px",borderRadius:20,border:`1.5px solid ${sel?"var(--tl)":"var(--bd)"}`,background:sel?"rgba(58,160,216,0.1)":"var(--wh)",color:sel?"var(--tl)":"var(--tx2)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
            {u.name}
          </button>;
        })}
      </div>

      <div className="slbl">写真追加</div>
      <input ref={fileRef} type="file" accept="image/*" multiple style={{display:"none"}} onChange={addPhotos}/>
      <button style={{width:"100%",padding:"14px",border:"2px dashed var(--bd)",borderRadius:12,background:"var(--bg2)",color:"var(--tl)",fontSize:13,fontWeight:700,cursor:"pointer",marginBottom:6,fontFamily:"'Noto Sans JP',sans-serif"}}
        onClick={()=>fileRef.current?.click()} disabled={uploadingCount>0}>
        {uploadingCount>0?`📤 アップロード中… (${uploadingCount}枚)`:"📷 写真を選択（複数可）"}
      </button>
      {uploadingCount>0&&<div style={{fontSize:11,color:"var(--tl)",textAlign:"center",marginBottom:8}}>写真をサーバーに保存中です。しばらくお待ちください…</div>}
      {form.photos.length>0&&<div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
        {form.photos.map(ph=>(
          <div key={ph.id} style={{position:"relative",aspectRatio:"1",borderRadius:10,overflow:"hidden",background:"#000"}}>
            <img src={ph.url} style={{width:"100%",height:"100%",objectFit:"cover"}} alt=""/>
            <button onClick={()=>removePhoto(ph.id)} style={{position:"absolute",top:4,right:4,width:22,height:22,borderRadius:"50%",background:"rgba(0,0,0,0.6)",border:"none",color:"#fff",fontSize:12,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center"}}>✕</button>
          </div>
        ))}
      </div>}

      <label style={{display:"flex",alignItems:"center",gap:8,fontSize:13,color:"var(--tx2)",cursor:"pointer",marginBottom:16}}>
        <input type="checkbox" checked={form.isShared} onChange={e=>setForm(p=>({...p,isShared:e.target.checked}))}/>
        保護者に公開する（作成時から共有）
      </label>
      <button className="bsave" style={{width:"100%"}} onClick={saveAlbum} disabled={saving||uploadingCount>0}>
        {saving?"保存中...":uploadingCount>0?"写真アップロード完了後に保存できます":"💾 アルバムを保存"}
      </button>
    </div>
  );

  // ── アルバム詳細 ──
  if(mode==="view"&&viewAlbum) return(
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={()=>setMode("list")}>← 戻る</button>
        <div className="fl-title">{viewAlbum.title}</div>
      </div>
      <div style={{fontSize:12,color:"var(--tx3)",marginBottom:4}}>{viewAlbum.takenDate} · {viewAlbum.photos?.length||0}枚</div>
      {viewAlbum.description&&<div style={{fontSize:13,color:"var(--tx2)",marginBottom:12,background:"var(--bg2)",borderRadius:8,padding:"10px"}}>{viewAlbum.description}</div>}
      {(viewAlbum.childIds||[]).length>0&&<div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:12}}>
        {viewAlbum.childIds.map(cid=>{
          const c=myUsers.find(u=>u.id===cid);
          return c?<span key={cid} style={{padding:"2px 10px",borderRadius:20,background:"rgba(58,160,216,0.1)",color:"var(--tl)",fontSize:11,fontWeight:700}}>{c.name}</span>:null;
        })}
      </div>}
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:6,marginBottom:16}}>
        {(viewAlbum.photos||[]).map(ph=>(
          <div key={ph.id} style={{aspectRatio:"1",borderRadius:10,overflow:"hidden",background:"#000",cursor:"pointer"}}
            onClick={()=>{const w=window.open("","_blank");if(!w)return;w.document.write(`<html><body style="margin:0;background:#000"><img src="${ph.url}" style="max-width:100vw;max-height:100vh;object-fit:contain"/></body></html>`);w.document.close();}}>
            <img src={ph.url} style={{width:"100%",height:"100%",objectFit:"cover"}} alt={ph.name||""}/>
          </div>
        ))}
      </div>
      <div style={{display:"flex",gap:8}}>
        <button onClick={()=>toggleShare(viewAlbum)} style={{flex:1,padding:"10px",borderRadius:10,border:`1.5px solid ${viewAlbum.isShared?"var(--ro)":"var(--gr)"}`,background:viewAlbum.isShared?"rgba(224,56,56,0.07)":"rgba(44,170,96,0.07)",color:viewAlbum.isShared?"var(--ro)":"var(--gr)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
          {viewAlbum.isShared?"🔒 非公開にする":"📢 保護者に公開"}
        </button>
        <button onClick={()=>doDelete(viewAlbum)} style={{padding:"10px 14px",borderRadius:10,border:"1.5px solid rgba(224,56,56,0.3)",background:"rgba(224,56,56,0.07)",color:"var(--ro)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🗑️</button>
      </div>
    </div>
  );

  // ── 一覧 ──
  return(
    <div className="fl-wrap">
      <div className="fl-hd">
        <button className="bback" onClick={onBack}>← 戻る</button>
        <div className="fl-title">📸 写真アルバム</div>
      </div>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
        <div style={{fontSize:12,color:"var(--tx3)"}}>{myAlbums.length}件のアルバム</div>
        <button className="bsave" style={{padding:"8px 14px",fontSize:12}} onClick={()=>setMode("create")}>＋ 新規作成</button>
      </div>
      {myAlbums.length===0&&<div style={{textAlign:"center",padding:"60px 0",color:"var(--tx3)"}}>
        <div style={{fontSize:48,marginBottom:12}}>📸</div>
        <div>アルバムがありません<br/><span style={{fontSize:12}}>「＋ 新規作成」から活動写真を追加できます</span></div>
      </div>}
      <div style={{display:"grid",gridTemplateColumns:"repeat(2,1fr)",gap:10}}>
        {myAlbums.map(album=>(
          <div key={album.id} style={{background:"var(--wh)",border:"1.5px solid var(--bd)",borderRadius:12,overflow:"hidden",cursor:"pointer"}} onClick={()=>{setViewAlbum(album);setMode("view");}}>
            <div style={{aspectRatio:"16/9",background:"#1e293b",overflow:"hidden",position:"relative"}}>
              {album.photos?.[0]?.url
                ?<img src={album.photos[0].url} style={{width:"100%",height:"100%",objectFit:"cover"}} alt=""/>
                :<div style={{display:"flex",alignItems:"center",justifyContent:"center",height:"100%",color:"#64748b",fontSize:28}}>📷</div>}
              {album.isShared&&<div style={{position:"absolute",top:6,right:6,background:"rgba(44,170,96,0.9)",color:"#fff",borderRadius:20,padding:"2px 8px",fontSize:10,fontWeight:700}}>📢 公開中</div>}
              {album.photos?.length>1&&<div style={{position:"absolute",bottom:6,right:6,background:"rgba(0,0,0,0.6)",color:"#fff",borderRadius:20,padding:"2px 8px",fontSize:10}}>+{album.photos.length-1}</div>}
            </div>
            <div style={{padding:"10px"}}>
              <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:2,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{album.title}</div>
              <div style={{fontSize:11,color:"var(--tx3)"}}>{album.takenDate} · {album.photos?.length||0}枚</div>
              {(album.childIds||[]).length>0&&<div style={{fontSize:10,color:"var(--tl)",marginTop:2}}>{(album.childIds||[]).length}名</div>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ==================== 保護者ポータル ====================
// role="parent" でログインした保護者が自分の子のメッセージ・お知らせを閲覧

function ParentPortalScreen({user, store, onBack}){
  const [tab,setTab]=useState("messages"); // messages|announcements|absence
  const today=todayISO();

  // 保護者に紐づく子供の特定（userのchildIdフィールドから）
  const childId=user.childId||null;
  const childName=user.childName||user.displayName||"お子様";
  const facilityId=user.facilityId||user.selectedFacilityId;

  // 自分の子のメッセージ
  const myMsgs=(store.msgs||[]).filter(m=>m.userId===childId).sort((a,b)=>a.time>b.time?1:-1);
  // お知らせ
  const myAnns=(store.announcements||[]).filter(a=>a.facilityId===facilityId&&
    (a.targetIds?.length===0||a.targetIds?.includes(childId))).sort((a,b)=>b.id>a.id?1:-1);
  // 欠席連絡フォーム
  const [absDate,setAbsDate]=useState(today);
  const [absReason,setAbsReason]=useState("");
  const [absSent,setAbsSent]=useState(false);

  const submitAbsence=()=>{
    if(!absReason.trim()){alert("欠席理由を入力してください");return;}
    store.saveAbsenceReport({id:genId(),childId,childName,facilityId,absenceDate:absDate,reason:absReason,contactMethod:"ポータル",status:"受付",createdAt:new Date().toISOString()});
    setAbsSent(true);setAbsReason("");
    store.showToast("欠席連絡を送信しました","success");
  };

  return(
    <div className="fl-wrap">
      <div className="fl-hd">
        <div className="fl-title">👪 保護者ポータル</div>
      </div>
      <div style={{background:"rgba(58,160,216,0.07)",borderRadius:10,padding:"10px 14px",marginBottom:14,fontSize:12,color:"var(--tl)"}}>
        こんにちは！ <strong>{childName}</strong> さんの保護者の方へ
      </div>

      <div style={{display:"flex",gap:6,marginBottom:14}}>
        {[{id:"messages",label:"連絡帳"},{id:"announcements",label:"お知らせ"},{id:"absence",label:"欠席連絡"}].map(t=>(
          <button key={t.id} onClick={()=>setTab(t.id)}
            style={{flex:1,padding:"8px 4px",borderRadius:9,border:`2px solid ${tab===t.id?"var(--tl)":"var(--bd)"}`,background:tab===t.id?"rgba(58,160,216,0.1)":"var(--wh)",color:tab===t.id?"var(--tl)":"var(--tx2)",fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
            {t.label}
          </button>
        ))}
      </div>

      {/* 連絡帳 */}
      {tab==="messages"&&<div>
        {myMsgs.length===0
          ?<div style={{textAlign:"center",padding:"40px 0",color:"var(--tx3)"}}>メッセージはありません</div>
          :<div style={{display:"flex",flexDirection:"column",gap:8}}>
            {myMsgs.map(m=>{
              const isStaff=m.from!=="保護者"&&!m.from?.includes("保護者");
              return(
                <div key={m.id} style={{display:"flex",justifyContent:isStaff?"flex-start":"flex-end"}}>
                  <div style={{maxWidth:"80%",padding:"10px 14px",borderRadius:isStaff?"4px 14px 14px 14px":"14px 4px 14px 14px",background:isStaff?"var(--wh)":"rgba(58,160,216,0.15)",border:`1px solid ${isStaff?"var(--bd)":"rgba(58,160,216,0.3)"}`,fontSize:13}}>
                    {isStaff&&<div style={{fontSize:10,color:"var(--tl)",fontWeight:700,marginBottom:4}}>{m.from}</div>}
                    {m.body&&<div style={{lineHeight:1.6}}>{m.body}</div>}
                    {m.photoData&&<img src={m.photoData} style={{maxWidth:200,borderRadius:8,marginTop:6}} alt="添付写真"/>}
                    <div style={{fontSize:10,color:"var(--tx3)",marginTop:4,textAlign:"right"}}>{m.time}</div>
                  </div>
                </div>
              );
            })}
          </div>
        }
      </div>}

      {/* お知らせ */}
      {tab==="announcements"&&<div>
        {myAnns.length===0
          ?<div style={{textAlign:"center",padding:"40px 0",color:"var(--tx3)"}}>お知らせはありません</div>
          :myAnns.map(a=>(
            <div key={a.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:10}}>
              {a.isUrgent&&<div style={{fontSize:11,color:"var(--ro)",fontWeight:700,marginBottom:4}}>🚨 緊急連絡</div>}
              <div style={{fontWeight:700,fontSize:14,marginBottom:6}}>{a.title}</div>
              <div style={{fontSize:13,color:"var(--tx2)",lineHeight:1.7,marginBottom:8}}>{a.body}</div>
              <div style={{fontSize:11,color:"var(--tx3)"}}>{a.category} · {a.createdAt}</div>
            </div>
          ))
        }
      </div>}

      {/* 欠席連絡 */}
      {tab==="absence"&&<div>
        {absSent&&<div style={{background:"rgba(44,170,96,0.1)",border:"1px solid var(--gr)",borderRadius:10,padding:"12px",marginBottom:12,fontSize:13,color:"var(--gr)",fontWeight:700}}>✅ 欠席連絡を送信しました</div>}
        <div className="slbl">欠席日</div>
        <input type="date" className="fi" value={absDate} onChange={e=>setAbsDate(e.target.value)} min={today}/>
        <div className="slbl">欠席理由</div>
        <textarea className="fta" rows={3} value={absReason} onChange={e=>setAbsReason(e.target.value)} placeholder="例：発熱のため / 通院のため"/>
        <button className="bsave" style={{width:"100%",marginTop:8}} onClick={submitAbsence}>📨 欠席を連絡する</button>
        <div style={{marginTop:24,fontWeight:700,fontSize:13,marginBottom:10}}>欠席連絡の履歴</div>
        {(store.absenceReports||[]).filter(r=>r.childId===childId).sort((a,b)=>b.absenceDate>a.absenceDate?1:-1).slice(0,10).map(r=>(
          <div key={r.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"8px 0",borderBottom:"1px solid var(--bg)",fontSize:12}}>
            <span>{r.absenceDate}</span>
            <span style={{color:"var(--tx2)"}}>{r.reason}</span>
            <span style={{padding:"2px 8px",borderRadius:20,fontSize:11,fontWeight:700,background:r.status==="確認済"?"rgba(44,170,96,0.1)":"var(--bg2)",color:r.status==="確認済"?"var(--gr)":"var(--tx3)"}}>{r.status}</span>
          </div>
        ))}
      </div>}
    </div>
  );
}

// ==================== 保護者連絡強化 ====================
// お知らせ管理・既読確認・アンケート・欠席連絡受付

const ANNOUNCE_CATEGORIES = ["お知らせ","行事予定","緊急連絡","持ち物","お迎え変更","その他"];
const ANNOUNCE_CAT_COLORS = {
  "お知らせ":  {color:"var(--tl)",  bg:"rgba(58,160,216,0.1)"},
  "行事予定":  {color:"#a78bfa",    bg:"rgba(167,139,250,0.1)"},
  "緊急連絡":  {color:"var(--ro)",  bg:"rgba(224,56,56,0.1)"},
  "持ち物":    {color:"var(--gr)",  bg:"rgba(44,170,96,0.1)"},
  "お迎え変更":{color:"var(--ac)",  bg:"rgba(255,160,0,0.1)"},
  "その他":    {color:"var(--tx3)", bg:"var(--bg2)"},
};

function ParentConnectScreen({user, store, onNav, onBack}) {
  const facilityId = user.selectedFacilityId;
  const isMgr = user.role==="admin"||user.role==="manager";
  const today = todayISO();
  const [tab, setTab] = useState("announce"); // announce | survey | absence
  // お知らせ
  const [showAnnForm, setShowAnnForm] = useState(false);
  const [annForm, setAnnForm] = useState({title:"",body:"",category:"お知らせ",isUrgent:false,dueDate:"",targetIds:[]});
  const [selAnn, setSelAnn] = useState(null);
  // アンケート
  const [showSvForm, setShowSvForm] = useState(false);
  const [svForm, setSvForm] = useState({title:"",question:"",options:["はい","いいえ"],dueDate:""});
  const [selSurvey, setSelSurvey] = useState(null);
  // 欠席連絡
  const [absForm, setAbsForm] = useState({childId:"",absenceDate:today,reason:"",contactMethod:"電話"});
  const [selAbs, setSelAbs] = useState(null);

  const children = store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);
  const facAnns = store.announcements.filter(a=>a.facilityId===facilityId).sort((a,b)=>b.id>a.id?1:-1);
  const facSurveys = store.surveys.filter(s=>s.facilityId===facilityId).sort((a,b)=>b.id>a.id?1:-1);
  const facAbsences = store.absenceReports.filter(r=>r.facilityId===facilityId).sort((a,b)=>b.absenceDate>a.absenceDate?1:-1);

  // お知らせの既読数を計算
  const getReadCount = annId => store.announcementReads.filter(r=>r.announcementId===annId).length;
  const getTargetCount = ann => (ann.targetIds||[]).length || children.length;
  const isRead = (annId, childId) => store.announcementReads.some(r=>r.announcementId===annId&&r.childId===childId);
  const markRead = (annId, childId) => {
    if(isRead(annId,childId)) return;
    store.saveAnnouncementRead({id:genId(),announcementId:annId,childId,readAt:todayISO()});
  };

  // お知らせ送信
  const submitAnn = () => {
    if(!annForm.title.trim()||!annForm.body.trim()){store.showToast("タイトルと本文を入力してください","error");return;}
    store.saveAnnouncement({
      id:genId(), facilityId, ...annForm,
      targetIds: annForm.targetIds.length ? annForm.targetIds : children.map(c=>c.id),
      createdBy: user.displayName, createdAt: todayISO(),
    });
    setAnnForm({title:"",body:"",category:"お知らせ",isUrgent:false,dueDate:"",targetIds:[]});
    setShowAnnForm(false);
    store.showToast("お知らせを送信しました","success");
  };

  // アンケート送信
  const submitSurvey = () => {
    if(!svForm.title.trim()||!svForm.question.trim()){store.showToast("タイトルと質問を入力してください","error");return;}
    if(svForm.options.filter(o=>o.trim()).length<2){store.showToast("選択肢を2つ以上入力してください","error");return;}
    store.saveSurvey({
      id:genId(), facilityId, ...svForm,
      options: svForm.options.filter(o=>o.trim()),
      createdBy: user.displayName, createdAt: todayISO(), status:"受付中",
    });
    setSvForm({title:"",question:"",options:["はい","いいえ"],dueDate:""});
    setShowSvForm(false);
    store.showToast("アンケートを送信しました","success");
  };

  // アンケート回答
  const answerSurvey = (surveyId, childId, answer) => {
    const child = children.find(c=>c.id===childId);
    const exist = store.surveyResponses.find(r=>r.surveyId===surveyId&&r.childId===childId);
    if(exist) { store.showToast("既に回答済みです","warn"); return; }
    store.saveSurveyResponse({id:genId(),surveyId,childId,childName:child?.name||"",answer,respondedAt:todayISO()});
    store.showToast(`${child?.name||""}：回答を記録しました`,"success");
  };

  // アンケートの回答集計
  const getSurveyStats = surveyId => {
    const resps = store.surveyResponses.filter(r=>r.surveyId===surveyId);
    const sv = facSurveys.find(s=>s.id===surveyId);
    if(!sv) return {};
    const counts = {};
    (sv.options||[]).forEach(o=>{ counts[o]=resps.filter(r=>r.answer===o).length; });
    return {counts, total:resps.length, target:children.length};
  };

  // 欠席連絡受付
  const submitAbsence = () => {
    if(!absForm.childId){store.showToast("児童を選択してください","error");return;}
    const child = children.find(c=>c.id===absForm.childId);
    store.saveAbsenceReport({
      id:genId(), facilityId, ...absForm,
      childName: child?.name||"",
      status:"受付", receivedAt:todayISO(), receivedBy:user.displayName,
    });
    setAbsForm({childId:"",absenceDate:today,reason:"",contactMethod:"電話"});
    store.showToast("欠席連絡を受け付けました","success");
  };

  // 欠席ステータス更新
  const updAbsenceStatus = (id, status, note) => {
    const r = store.absenceReports.find(x=>x.id===id);
    if(!r) return;
    store.saveAbsenceReport({...r, status, staffNote:note||r.staffNote});
    store.showToast("ステータスを更新しました","success");
  };

  // 欠席印刷（一覧）
  const printAbsences = () => {
    const todayAbs = facAbsences.filter(r=>r.absenceDate===today);
    const rows = todayAbs.map(r=>`<tr>
      <td style="padding:6px 10px;border:1px solid #ccc;font-weight:700;">${r.childName}</td>
      <td style="padding:6px 10px;border:1px solid #ccc;">${r.reason||"理由なし"}</td>
      <td style="padding:6px 10px;border:1px solid #ccc;text-align:center;">${r.contactMethod||"—"}</td>
      <td style="padding:6px 10px;border:1px solid #ccc;text-align:center;">${r.status||"受付"}</td>
      <td style="padding:6px 10px;border:1px solid #ccc;">${r.staffNote||""}</td>
    </tr>`).join("");
    const fac = FACILITIES.find(f=>f.id===facilityId);
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>欠席連絡一覧 ${today}</title>
    <style>@page{size:A4;margin:12mm;}body{font-family:'MS Gothic',sans-serif;font-size:9pt;}h2{font-size:13pt;border-bottom:2px solid #3aa0d8;padding-bottom:5px;}table{border-collapse:collapse;width:100%;}th{background:#e8f0ff;padding:6px 8px;border:1px solid #ccc;text-align:left;}</style>
    </head><body>
    <h2>📋 欠席連絡一覧</h2>
    <div style="font-size:10pt;margin-bottom:10px;">施設: <b>${fac?.name||""}</b>　日付: <b>${today}</b>　欠席者数: <b>${todayAbs.length}名</b></div>
    <table><thead><tr><th>氏名</th><th>欠席理由</th><th>連絡方法</th><th>ステータス</th><th>スタッフメモ</th></tr></thead>
    <tbody>${rows||"<tr><td colspan='5' style='text-align:center;padding:14px;color:#999;'>欠席者なし</td></tr>"}</tbody></table>
    </body></html>`;
    const w=window.open("","_blank","width=900,height=650");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  const ABS_STATUS_DEF = {
    "受付":   {color:"var(--tl)",  bg:"rgba(58,160,216,0.1)", icon:"📥"},
    "確認済": {color:"var(--gr)",  bg:"rgba(44,170,96,0.1)",  icon:"✅"},
    "要確認": {color:"var(--ac)",  bg:"rgba(255,160,0,0.1)",  icon:"⚠️"},
  };

  return <div>
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <h2 style={{margin:0,fontSize:17}}>📢 保護者連絡センター</h2>
      <button className="nb" style={{marginLeft:"auto",fontSize:11,padding:"5px 10px"}} onClick={()=>onNav&&onNav("messages")}>
        チャット →
      </button>
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,margin:"12px 0",overflowX:"auto",paddingBottom:4}}>
      {[
        ["announce",`📢 お知らせ${facAnns.filter(a=>a.isUrgent).length>0?` 🔴`:""}`],
        ["survey",`📊 アンケート${facSurveys.filter(s=>s.status==="受付中").length>0?` (${facSurveys.filter(s=>s.status==="受付中").length})`:""}`,],
        ["absence",`📋 欠席連絡${facAbsences.filter(r=>r.absenceDate===today&&r.status==="受付").length>0?` (${facAbsences.filter(r=>r.absenceDate===today&&r.status==="受付").length})`:""}`,],
      ].map(([id,lb])=>(
        <button key={id} onClick={()=>setTab(id)}
          style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${tab===id?"var(--tl)":"var(--bd)"}`,background:tab===id?"var(--tl)":"var(--wh)",color:tab===id?"#fff":"var(--tx)",fontWeight:tab===id?700:400,fontSize:12,whiteSpace:"nowrap",cursor:"pointer"}}>
          {lb}
        </button>
      ))}
    </div>

    {/* ===== お知らせタブ ===== */}
    {tab==="announce"&&<div>
      {isMgr&&!showAnnForm&&!selAnn&&(
        <button className="bsave" style={{width:"100%",marginBottom:12}} onClick={()=>setShowAnnForm(true)}>
          ＋ お知らせを作成する
        </button>
      )}

      {/* 作成フォーム */}
      {showAnnForm&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:12}}>📢 お知らせ作成</div>
        <div className="slbl">カテゴリー</div>
        <div style={{display:"flex",gap:6,flexWrap:"wrap",marginBottom:10}}>
          {ANNOUNCE_CATEGORIES.map(cat=>{
            const cs = ANNOUNCE_CAT_COLORS[cat]||{};
            return <button key={cat} onClick={()=>setAnnForm(p=>({...p,category:cat}))}
              style={{padding:"5px 12px",borderRadius:20,border:`1.5px solid ${annForm.category===cat?cs.color:"var(--bd)"}`,background:annForm.category===cat?cs.bg:"var(--wh)",color:annForm.category===cat?cs.color:"var(--tx3)",fontWeight:700,fontSize:11,cursor:"pointer"}}>
              {cat}
            </button>;
          })}
        </div>
        <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:10}}>
          <label style={{display:"flex",alignItems:"center",gap:6,cursor:"pointer",fontSize:13}}>
            <input type="checkbox" checked={annForm.isUrgent} onChange={e=>setAnnForm(p=>({...p,isUrgent:e.target.checked}))}/>
            🚨 緊急フラグ
          </label>
        </div>
        <div className="slbl">タイトル（必須）</div>
        <input className="fi" value={annForm.title} onChange={e=>setAnnForm(p=>({...p,title:e.target.value}))} placeholder="例：明日の持ち物について"/>
        <div className="slbl">本文（必須）</div>
        <textarea className="fi fta" rows={4} value={annForm.body} onChange={e=>setAnnForm(p=>({...p,body:e.target.value}))} placeholder="保護者へのメッセージを入力してください"/>
        <div className="slbl">期限日（任意）</div>
        <input type="date" className="fi" value={annForm.dueDate} onChange={e=>setAnnForm(p=>({...p,dueDate:e.target.value}))}/>
        <div className="slbl">送信対象（未選択=全員）</div>
        <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:10}}>
          {children.map(c=>(
            <button key={c.id} onClick={()=>setAnnForm(p=>({...p,targetIds:p.targetIds.includes(c.id)?p.targetIds.filter(id=>id!==c.id):[...p.targetIds,c.id]}))}
              style={{padding:"4px 12px",borderRadius:20,border:`1.5px solid ${annForm.targetIds.includes(c.id)?"var(--tl)":"var(--bd)"}`,background:annForm.targetIds.includes(c.id)?"rgba(58,160,216,0.1)":"var(--wh)",fontSize:12,cursor:"pointer",fontWeight:annForm.targetIds.includes(c.id)?700:400}}>
              {c.name}
            </button>
          ))}
        </div>
        <div style={{display:"flex",gap:8}}>
          <button className="bsave" style={{flex:1}} onClick={submitAnn}>📢 送信する</button>
          <button className="nb" style={{flex:1}} onClick={()=>setShowAnnForm(false)}>キャンセル</button>
        </div>
      </div>}

      {/* お知らせ詳細（既読管理） */}
      {selAnn&&(()=>{
        const ann = facAnns.find(a=>a.id===selAnn);
        if(!ann) return null;
        const target = (ann.targetIds||[]).length ? children.filter(c=>ann.targetIds.includes(c.id)) : children;
        const readCnt = getReadCount(selAnn);
        const cs = ANNOUNCE_CAT_COLORS[ann.category]||{color:"var(--tx3)",bg:"var(--bg2)"};
        return <div>
          <button className="bback" style={{marginBottom:12}} onClick={()=>setSelAnn(null)}>← 一覧に戻る</button>
          <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:12}}>
            <div style={{display:"flex",gap:8,alignItems:"center",marginBottom:8}}>
              <span style={{fontSize:11,fontWeight:700,color:cs.color,background:cs.bg,padding:"3px 10px",borderRadius:20}}>{ann.category}</span>
              {ann.isUrgent&&<span style={{fontSize:11,fontWeight:700,color:"var(--ro)",background:"rgba(224,56,56,0.1)",padding:"3px 10px",borderRadius:20}}>🚨 緊急</span>}
            </div>
            <div style={{fontWeight:700,fontSize:15,marginBottom:8}}>{ann.title}</div>
            <div style={{fontSize:13,lineHeight:1.7,whiteSpace:"pre-wrap",marginBottom:10}}>{ann.body}</div>
            {ann.dueDate&&<div style={{fontSize:12,color:"var(--ac)"}}>⏰ 期限：{ann.dueDate}</div>}
            <div style={{fontSize:11,color:"var(--tx3)",marginTop:6}}>送信日：{ann.createdAt} ／ 送信者：{ann.createdBy}</div>
          </div>
          {/* 既読管理 */}
          <div style={{fontWeight:700,fontSize:14,marginBottom:8}}>
            📖 既読管理 — {readCnt}/{target.length}名
          </div>
          <div style={{background:"var(--bg2)",borderRadius:6,height:8,overflow:"hidden",marginBottom:10}}>
            <div style={{height:"100%",width:`${target.length?readCnt/target.length*100:0}%`,background:"var(--gr)",borderRadius:6}}/>
          </div>
          <div style={{display:"flex",flexDirection:"column",gap:6}}>
            {target.map(c=>{
              const read = isRead(selAnn, c.id);
              return <div key={c.id} style={{background:"var(--wh)",border:`1px solid ${read?"var(--gr)33":"var(--bd)"}`,borderRadius:10,padding:"10px 14px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <span style={{fontWeight:600,fontSize:13}}>{c.name}</span>
                <div style={{display:"flex",gap:8,alignItems:"center"}}>
                  <span style={{fontSize:11,fontWeight:700,color:read?"var(--gr)":"var(--tx3)"}}>{read?"✅ 既読":"⬜ 未読"}</span>
                  {isMgr&&!read&&<button className="nb" style={{fontSize:11,padding:"4px 10px"}} onClick={()=>markRead(selAnn,c.id)}>既読にする</button>}
                </div>
              </div>;
            })}
          </div>
        </div>;
      })()}

      {/* お知らせ一覧 */}
      {!selAnn&&!showAnnForm&&<div>
        {facAnns.length===0
          ? <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
              <div style={{fontSize:40,marginBottom:8}}>📭</div>
              <div>お知らせがありません</div>
            </div>
          : facAnns.map(ann=>{
              const cs = ANNOUNCE_CAT_COLORS[ann.category]||{color:"var(--tx3)",bg:"var(--bg2)"};
              const readCnt = getReadCount(ann.id);
              const target = (ann.targetIds||[]).length||children.length;
              return <div key={ann.id} style={{background:"var(--wh)",border:`1.5px solid ${ann.isUrgent?"var(--ro)33":"var(--bd)"}`,borderRadius:12,padding:14,marginBottom:8,cursor:"pointer"}}
                onClick={()=>setSelAnn(ann.id)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <div style={{display:"flex",gap:6,alignItems:"center"}}>
                    <span style={{fontSize:10,fontWeight:700,color:cs.color,background:cs.bg,padding:"2px 8px",borderRadius:20}}>{ann.category}</span>
                    {ann.isUrgent&&<span style={{fontSize:10,fontWeight:700,color:"var(--ro)"}}>🚨</span>}
                  </div>
                  <span style={{fontSize:11,color:"var(--tx3)"}}>{ann.createdAt}</span>
                </div>
                <div style={{fontWeight:700,fontSize:13,marginBottom:4}}>{ann.title}</div>
                <div style={{fontSize:11,color:"var(--tx3)",marginBottom:6}}>{ann.body.slice(0,50)}{ann.body.length>50?"…":""}</div>
                {/* 既読率プログレスバー */}
                <div style={{marginTop:4}}>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:readCnt>=target?"var(--gr)":"var(--ac)",fontWeight:700,marginBottom:3}}>
                    <span>既読 {readCnt}/{target}名</span>
                    <span>{target>0?Math.round(readCnt/target*100):0}%</span>
                  </div>
                  <div style={{height:5,background:"var(--bg)",borderRadius:10,overflow:"hidden"}}>
                    <div style={{height:"100%",width:`${target>0?Math.round(readCnt/target*100):0}%`,background:readCnt>=target?"var(--gr)":"var(--tl)",borderRadius:10,transition:"width 0.4s"}}/>
                  </div>
                </div>
              </div>;
            })
        }
      </div>}
    </div>}

    {/* ===== アンケートタブ ===== */}
    {tab==="survey"&&<div>
      {isMgr&&!showSvForm&&!selSurvey&&(
        <button className="bsave" style={{width:"100%",marginBottom:12}} onClick={()=>setShowSvForm(true)}>
          ＋ アンケートを作成する
        </button>
      )}

      {/* アンケート作成フォーム */}
      {showSvForm&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:12}}>📊 アンケート作成</div>
        <div className="slbl">タイトル（必須）</div>
        <input className="fi" value={svForm.title} onChange={e=>setSvForm(p=>({...p,title:e.target.value}))} placeholder="例：遠足の参加確認"/>
        <div className="slbl">質問内容（必須）</div>
        <textarea className="fi fta" rows={2} value={svForm.question} onChange={e=>setSvForm(p=>({...p,question:e.target.value}))} placeholder="例：7月15日の遠足に参加しますか？"/>
        <div className="slbl">選択肢（最大4つ）</div>
        {svForm.options.map((opt,i)=>(
          <div key={i} style={{display:"flex",gap:8,marginBottom:6}}>
            <input className="fi" style={{flex:1,margin:0}} value={opt} onChange={e=>setSvForm(p=>({...p,options:p.options.map((o,j)=>j===i?e.target.value:o)}))} placeholder={`選択肢 ${i+1}`}/>
            {svForm.options.length>2&&<button className="nb" style={{padding:"6px 10px"}} onClick={()=>setSvForm(p=>({...p,options:p.options.filter((_,j)=>j!==i)}))}>✕</button>}
          </div>
        ))}
        {svForm.options.length<4&&<button className="nb" style={{fontSize:12,padding:"5px 14px",marginBottom:10}} onClick={()=>setSvForm(p=>({...p,options:[...p.options,""]}))}>＋ 選択肢を追加</button>}
        <div className="slbl">回答期限</div>
        <input type="date" className="fi" value={svForm.dueDate} onChange={e=>setSvForm(p=>({...p,dueDate:e.target.value}))}/>
        <div style={{display:"flex",gap:8,marginTop:4}}>
          <button className="bsave" style={{flex:1}} onClick={submitSurvey}>📊 送信する</button>
          <button className="nb" style={{flex:1}} onClick={()=>setShowSvForm(false)}>キャンセル</button>
        </div>
      </div>}

      {/* アンケート詳細（回答・集計） */}
      {selSurvey&&(()=>{
        const sv = facSurveys.find(s=>s.id===selSurvey);
        if(!sv) return null;
        const stats = getSurveyStats(selSurvey);
        const responded = store.surveyResponses.filter(r=>r.surveyId===selSurvey);
        return <div>
          <button className="bback" style={{marginBottom:12}} onClick={()=>setSelSurvey(null)}>← 一覧に戻る</button>
          <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:12}}>
            <div style={{fontWeight:700,fontSize:15,marginBottom:6}}>{sv.title}</div>
            <div style={{fontSize:13,marginBottom:10,background:"var(--bg2)",borderRadius:8,padding:"8px 12px"}}>{sv.question}</div>
            {sv.dueDate&&<div style={{fontSize:12,color:"var(--ac)",marginBottom:8}}>⏰ 回答期限：{sv.dueDate}</div>}
            {/* 集計 */}
            <div style={{fontWeight:700,fontSize:13,marginBottom:8}}>📊 回答集計 — {stats.total||0}/{stats.target||0}名</div>
            {(sv.options||[]).map(opt=>{
              const cnt = stats.counts?.[opt]||0;
              const pct = stats.total ? Math.round(cnt/stats.total*100) : 0;
              return <div key={opt} style={{marginBottom:8}}>
                <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:3}}>
                  <span style={{fontWeight:700}}>{opt}</span>
                  <span style={{color:"var(--tl)",fontWeight:700}}>{cnt}票 ({pct}%)</span>
                </div>
                <div style={{background:"var(--bg2)",borderRadius:4,height:8,overflow:"hidden"}}>
                  <div style={{height:"100%",width:pct+"%",background:"var(--tl)",borderRadius:4}}/>
                </div>
              </div>;
            })}
          </div>
          {/* 個別回答入力（管理者が代理入力） */}
          {isMgr&&<div style={{fontWeight:700,fontSize:13,marginBottom:8}}>📝 個別回答記録</div>}
          {isMgr&&children.map(c=>{
            const resp = responded.find(r=>r.childId===c.id);
            return <div key={c.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 14px",marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
              <span style={{fontWeight:600,fontSize:13}}>{c.name}</span>
              {resp
                ? <span style={{fontSize:12,fontWeight:700,color:"var(--gr)"}}>✅ {resp.answer}</span>
                : <div style={{display:"flex",gap:4}}>
                    {(sv.options||[]).map(opt=>(
                      <button key={opt} className="nb" style={{fontSize:11,padding:"5px 10px"}} onClick={()=>answerSurvey(selSurvey,c.id,opt)}>{opt}</button>
                    ))}
                  </div>
              }
            </div>;
          })}
        </div>;
      })()}

      {/* アンケート一覧 */}
      {!selSurvey&&!showSvForm&&<div>
        {facSurveys.length===0
          ? <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
              <div style={{fontSize:40,marginBottom:8}}>📊</div>
              <div>アンケートがありません</div>
            </div>
          : facSurveys.map(sv=>{
              const stats = getSurveyStats(sv.id);
              const pct = stats.target ? Math.round((stats.total||0)/stats.target*100) : 0;
              const isActive = !sv.dueDate||sv.dueDate>=today;
              return <div key={sv.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:8,cursor:"pointer"}} onClick={()=>setSelSurvey(sv.id)}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <span style={{fontSize:11,fontWeight:700,color:isActive?"var(--gr)":"var(--tx3)",background:isActive?"rgba(44,170,96,0.1)":"var(--bg2)",padding:"2px 8px",borderRadius:20}}>{isActive?"受付中":"終了"}</span>
                  {sv.dueDate&&<span style={{fontSize:11,color:"var(--tx3)"}}>期限: {sv.dueDate}</span>}
                </div>
                <div style={{fontWeight:700,fontSize:13,marginBottom:4}}>{sv.title}</div>
                <div style={{fontSize:11,color:"var(--tx3)",marginBottom:6}}>{sv.question}</div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                  <div style={{flex:1,background:"var(--bg2)",borderRadius:4,height:6,overflow:"hidden",marginRight:10}}>
                    <div style={{height:"100%",width:pct+"%",background:"var(--tl)",borderRadius:4}}/>
                  </div>
                  <span style={{fontSize:11,fontWeight:700,color:"var(--tl)"}}>{stats.total||0}/{stats.target||0}名回答</span>
                </div>
              </div>;
            })
        }
      </div>}
    </div>}

    {/* ===== 欠席連絡タブ ===== */}
    {tab==="absence"&&<div>
      {/* 欠席受付フォーム */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>📋 欠席連絡を受け付ける</div>
        <div className="slbl">児童</div>
        <select className="fi" value={absForm.childId} onChange={e=>setAbsForm(p=>({...p,childId:e.target.value}))}>
          <option value="">-- 選択してください --</option>
          {children.map(c=><option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
        <div className="slbl">欠席日</div>
        <input type="date" className="fi" value={absForm.absenceDate} onChange={e=>setAbsForm(p=>({...p,absenceDate:e.target.value}))}/>
        <div className="slbl">連絡方法</div>
        <div style={{display:"flex",gap:6,marginBottom:10}}>
          {["電話","LINE","直接","その他"].map(m=>(
            <button key={m} onClick={()=>setAbsForm(p=>({...p,contactMethod:m}))}
              style={{flex:1,padding:"6px 0",borderRadius:8,border:`1.5px solid ${absForm.contactMethod===m?"var(--tl)":"var(--bd)"}`,background:absForm.contactMethod===m?"var(--tl)":"var(--wh)",color:absForm.contactMethod===m?"#fff":"var(--tx)",fontWeight:absForm.contactMethod===m?700:400,fontSize:12,cursor:"pointer"}}>
              {m}
            </button>
          ))}
        </div>
        <div className="slbl">欠席理由</div>
        <textarea className="fi fta" rows={2} value={absForm.reason} onChange={e=>setAbsForm(p=>({...p,reason:e.target.value}))} placeholder="発熱・体調不良など"/>
        <button className="bsave" style={{width:"100%",marginTop:4}} onClick={submitAbsence}>受け付ける</button>
      </div>

      {/* 今日の欠席一覧 */}
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
        <div style={{fontWeight:700,fontSize:14}}>📅 本日の欠席（{today}）</div>
        <button className="nb" style={{fontSize:11,padding:"5px 10px"}} onClick={printAbsences}>🖨 印刷</button>
      </div>
      {facAbsences.filter(r=>r.absenceDate===today).length===0
        ? <div style={{textAlign:"center",padding:24,color:"var(--tx3)",fontSize:12}}>本日の欠席連絡なし</div>
        : facAbsences.filter(r=>r.absenceDate===today).map(r=>{
            const st = ABS_STATUS_DEF[r.status]||ABS_STATUS_DEF["受付"];
            return <div key={r.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                <span style={{fontWeight:700,fontSize:14}}>{r.childName}</span>
                <span style={{fontSize:11,fontWeight:700,color:st.color,background:st.bg,padding:"3px 10px",borderRadius:20}}>{st.icon} {r.status}</span>
              </div>
              <div style={{fontSize:12,color:"var(--tx3)",marginBottom:6}}>
                連絡方法: {r.contactMethod||"—"} ／ 受付: {r.receivedBy||"—"}
              </div>
              {r.reason&&<div style={{fontSize:12,background:"var(--bg2)",borderRadius:6,padding:"6px 10px",marginBottom:8}}>{r.reason}</div>}
              {r.staffNote&&<div style={{fontSize:12,color:"var(--ac)",marginBottom:8}}>📝 {r.staffNote}</div>}
              {r.status==="受付"&&isMgr&&<button className="nb" style={{fontSize:11,padding:"5px 14px"}} onClick={()=>updAbsenceStatus(r.id,"確認済","")}>✅ 確認済みにする</button>}
            </div>;
          })
      }

      {/* 直近の欠席履歴 */}
      {facAbsences.filter(r=>r.absenceDate!==today).length>0&&<div style={{marginTop:14}}>
        <div style={{fontWeight:700,fontSize:13,marginBottom:8,color:"var(--tx3)"}}>📂 過去の欠席連絡</div>
        {facAbsences.filter(r=>r.absenceDate!==today).slice(0,10).map(r=>{
          const st = ABS_STATUS_DEF[r.status]||ABS_STATUS_DEF["受付"];
          return <div key={r.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 14px",marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div>
              <span style={{fontWeight:600,fontSize:13}}>{r.childName}</span>
              <span style={{fontSize:11,color:"var(--tx3)",marginLeft:8}}>{r.absenceDate}</span>
            </div>
            <span style={{fontSize:11,color:st.color}}>{st.icon} {r.status}</span>
          </div>;
        })}
      </div>}
    </div>}
  </div>;
}

// ==================== 送迎ライブ追跡 ====================
// ルートごとのリアルタイム乗降確認・遅延記録・月次集計

const TRANSPORT_STATUS = {
  pending:   {label:"未乗車",   icon:"⭕",color:"var(--tx3)",  bg:"var(--bg2)"},
  boarded:   {label:"乗車済",   icon:"🟢",color:"var(--gr)",   bg:"rgba(44,170,96,0.1)"},
  absent:    {label:"欠席",     icon:"✖",color:"var(--ro)",    bg:"rgba(224,56,56,0.08)"},
  dropped:   {label:"降車済",   icon:"🏠",color:"var(--tl)",   bg:"rgba(58,160,216,0.1)"},
  late:      {label:"遅延",     icon:"⚠️",color:"var(--ac)",   bg:"rgba(255,160,0,0.08)"},
};

function TransportLiveScreen({user, store, onNav, onBack}) {
  const facilityId = user.selectedFacilityId;
  const today = todayISO();
  const nowYM = today.slice(0,7);
  const [tab, setTab] = useState("live");    // live | summary | stats
  const [dir, setDir] = useState("来所");
  const [selRoute, setSelRoute] = useState(null);
  const [incidentNote, setIncidentNote] = useState("");
  const [incidentChildId, setIncidentChildId] = useState(null);
  const [showIncident, setShowIncident] = useState(false);

  const fac = (store.facilities||FACILITIES).find(f=>f.id===facilityId);
  const routes = (store.routes||[]).filter(r=>r.facilityId===facilityId&&r.direction===dir);
  const children = store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);

  // 今日のルートに含まれる全child（予定表OCRデータまたはルート定義から）
  // ⚠️ BUGFIX: DB保存時は snake_case "log_date"、JS側は camelCase "logDate"
  //    data JSONB に logDate が入っていれば l.logDate、なければ l.log_date にフォールバック
  const todayLogs = store.transportLogs.filter(l=>(l.logDate||l.log_date)===today&&l.facilityId===facilityId&&l.direction===dir);

  // ルートの乗客リストを取得（stops から）
  const getRoutePassengers = route => route.stops||[];

  // 特定childのログを取得
  const getLog = (childId, routeId) =>
    todayLogs.find(l=>l.childId===childId&&l.routeId===routeId);

  // 乗車確認 ワンタップ
  const tapBoard = (child, route) => {
    const log = getLog(child.id, route.id);
    const newStatus = log?.status==="boarded" ? "pending" : "boarded";
    store.saveTransportLog({
      id: log?.id||genId(),
      childId: child.id, childName: child.name,
      facilityId, routeId: route.id, routeName: route.name,
      logDate: today, direction: dir,
      plannedTime: child.estimatedTime||null,
      actualTime: newStatus==="boarded" ? nowHM() : null,
      status: newStatus,
      driver: route.driver||null, vehicle: route.vehicle||null,
    });
    store.showToast(newStatus==="boarded"?`${child.name}：乗車確認`:`${child.name}：確認取消`,"success");
  };

  // 欠席マーク
  const markAbsent = (child, route) => {
    const log = getLog(child.id, route.id);
    store.saveTransportLog({
      id: log?.id||genId(),
      childId: child.id, childName: child.name,
      facilityId, routeId: route.id, routeName: route.name,
      logDate: today, direction: dir,
      status: log?.status==="absent"?"pending":"absent",
      driver: route.driver||null, vehicle: route.vehicle||null,
    });
  };

  // 遅延メモ保存
  const saveIncident = () => {
    if(!incidentNote.trim()||!incidentChildId) return;
    const child = children.find(c=>c.id===incidentChildId);
    const route = selRoute||routes[0];
    if(!route) return;
    const log = getLog(incidentChildId, route.id);
    store.saveTransportLog({
      id: log?.id||genId(),
      childId: incidentChildId, childName: child?.name||"",
      facilityId, routeId: route.id, routeName: route.name,
      logDate: today, direction: dir,
      status: log?.status||"pending",
      incidentNote: incidentNote,
      driver: route.driver||null, vehicle: route.vehicle||null,
    });
    setIncidentNote(""); setIncidentChildId(null); setShowIncident(false);
    store.showToast("メモを保存しました","success");
  };

  // ルート完了率
  const routeProgress = route => {
    const stops = getRoutePassengers(route);
    if(!stops.length) return {done:0,total:0,pct:0};
    const done = stops.filter(s=>{
      const log = getLog(s.userId||s.id, route.id);
      return log?.status==="boarded"||log?.status==="dropped";
    }).length;
    const absent = stops.filter(s=>{
      const log = getLog(s.userId||s.id, route.id);
      return log?.status==="absent";
    }).length;
    const total = stops.length - absent;
    return {done, total, absent, pct: total>0?Math.round(done/total*100):100};
  };

  // 月次統計（当月）
  // logDate または log_date のどちらでも対応
  const monthLogs = store.transportLogs.filter(l=>
    (l.logDate||l.log_date||"").startsWith(nowYM)&&l.facilityId===facilityId
  );
  const monthDays = [...new Set(monthLogs.map(l=>l.logDate))].length;
  const totalRides = monthLogs.filter(l=>l.status==="boarded"||l.status==="dropped").length;
  const absentRides = monthLogs.filter(l=>l.status==="absent").length;
  const incidentRides = monthLogs.filter(l=>l.incidentNote).length;

  // 月次CSV出力
  const exportCSV = () => {
    const hdr = ["日付","方向","ルート名","利用者名","予定時刻","実績時刻","ステータス","メモ"];
    const rows = store.transportLogs
      .filter(l=>(l.logDate||l.log_date||"").startsWith(nowYM)&&l.facilityId===facilityId)
      .sort((a,b)=>(a.logDate||a.log_date||"")>(b.logDate||b.log_date||"")?1:-1)
      .map(l=>[l.logDate||l.log_date||"",l.direction||"",l.routeName||l.route_name||"",l.childName||l.child_id||"",l.plannedTime||l.planned_time||"",l.actualTime||l.actual_time||"",TRANSPORT_STATUS[l.status]?.label||l.status,l.incidentNote||l.incident_note||""]);
    const csv = [hdr,...rows].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a = document.createElement("a");
    a.href = URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download = `送迎記録_${nowYM}.csv`; a.click();
    store.showToast("CSVを出力しました","success");
  };

  // ルート印刷（完了サマリー）
  const printRouteSummary = route => {
    const stops = getRoutePassengers(route);
    const rows = stops.map(s=>{
      const child = children.find(c=>c.id===(s.userId||s.id));
      const log = getLog(s.userId||s.id, route.id);
      const st = TRANSPORT_STATUS[log?.status||"pending"];
      return `<tr>
        <td style="padding:6px 10px;border:1px solid #ccc;font-weight:700;">${s.order||""}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;">${child?.name||s.userName||""}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;">${s.address||""}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;text-align:center;">${s.estimatedTime||""}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;text-align:center;color:${st.color};font-weight:700;">${st.icon} ${st.label}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;text-align:center;">${log?.actualTime||"—"}</td>
        <td style="padding:6px 10px;border:1px solid #ccc;">${log?.incidentNote||""}</td>
      </tr>`;
    }).join("");
    const {done,total,absent} = routeProgress(route);
    const html=`<!DOCTYPE html><html lang="ja"><head><meta charset="UTF-8"/>
    <title>送迎記録 ${route.name}</title>
    <style>@page{size:A4;margin:12mm;}body{font-family:'MS Gothic',sans-serif;font-size:9pt;}h2{font-size:13pt;border-bottom:2px solid #3aa0d8;padding-bottom:5px;}table{border-collapse:collapse;width:100%;font-size:9pt;}th{background:#e8f0ff;padding:6px 8px;border:1px solid #ccc;}</style>
    </head><body>
    <h2>🚌 送迎記録表</h2>
    <div style="display:flex;gap:30px;margin-bottom:10px;font-size:10pt;">
      <span>日付: <b>${today}</b></span><span>ルート: <b>${route.name}</b></span>
      <span>方向: <b>${route.direction}</b></span>
      <span>ドライバー: <b>${route.driver||"未設定"}</b></span>
      <span>車両: <b>${route.vehicle||"未設定"}</b></span>
      <span>確認: <b>${done}/${total}名</b>（欠席${absent}名）</span>
    </div>
    <table><thead><tr><th>順</th><th>氏名</th><th>住所・場所</th><th>予定時刻</th><th>ステータス</th><th>実績時刻</th><th>備考</th></tr></thead>
    <tbody>${rows}</tbody></table>
    <div style="margin-top:16px;display:grid;grid-template-columns:1fr 1fr 1fr;gap:10px;">
      <div style="border:1px solid #aaa;padding:10px;min-height:44px;"><div style="font-size:8pt;color:#666;">出発時刻</div></div>
      <div style="border:1px solid #aaa;padding:10px;min-height:44px;"><div style="font-size:8pt;color:#666;">帰着時刻</div></div>
      <div style="border:1px solid #aaa;padding:10px;min-height:44px;"><div style="font-size:8pt;color:#666;">担当者確認　　　　㊞</div></div>
    </div>
    </body></html>`;
    const w = window.open("","_blank","width=900,height=650");
    if(w){w.document.write(html);w.document.close();setTimeout(()=>w.print(),400);}
  };

  const activeRoute = selRoute||routes[0];

  return <div>
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <h2 style={{margin:0,fontSize:17}}>🚌 送迎ライブ追跡</h2>
      <button className="nb" style={{marginLeft:"auto",fontSize:11,padding:"5px 10px"}} onClick={()=>onNav&&onNav("transport")}>
        ルート管理 →
      </button>
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,margin:"12px 0",overflowX:"auto",paddingBottom:4}}>
      {[["live","🟢 ライブ追跡"],["summary","📋 本日の記録"],["stats","📊 月次統計"]].map(([id,lb])=>(
        <button key={id} onClick={()=>setTab(id)}
          style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${tab===id?"var(--tl)":"var(--bd)"}`,background:tab===id?"var(--tl)":"var(--wh)",color:tab===id?"#fff":"var(--tx)",fontWeight:tab===id?700:400,fontSize:12,whiteSpace:"nowrap",cursor:"pointer"}}>
          {lb}
        </button>
      ))}
    </div>

    {/* ===== ライブ追跡タブ ===== */}
    {tab==="live"&&<div>
      {/* 来所/退所 切替 */}
      <div style={{display:"flex",gap:8,marginBottom:12}}>
        {["来所","退所"].map(d=>(
          <button key={d} onClick={()=>setDir(d)}
            style={{flex:1,padding:"10px 0",borderRadius:10,border:`2px solid ${dir===d?"var(--tl)":"var(--bd)"}`,background:dir===d?"var(--tl)":"var(--wh)",color:dir===d?"#fff":"var(--tx)",fontWeight:700,cursor:"pointer",fontSize:13}}>
            {d==="来所"?"🚌 来所":"🏠 退所"} {d}
          </button>
        ))}
      </div>

      {routes.length===0
        ? <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
            <div style={{fontSize:40,marginBottom:8}}>📍</div>
            <div style={{fontWeight:700}}>ルートが登録されていません</div>
            <div style={{fontSize:12,marginTop:4}}>「送迎管理」からルートを作成してください</div>
            <button className="bsave" style={{marginTop:16}} onClick={()=>onNav&&onNav("transport")}>送迎管理へ →</button>
          </div>
        : <div>
            {/* ルート選択タブ */}
            <div style={{display:"flex",gap:6,marginBottom:12,overflowX:"auto",paddingBottom:4}}>
              {routes.map(r=>{
                const {pct,done,total} = routeProgress(r);
                return <button key={r.id} onClick={()=>setSelRoute(r)}
                  style={{padding:"8px 14px",borderRadius:10,border:`2px solid ${(activeRoute?.id===r.id)?"var(--tl)":"var(--bd)"}`,background:(activeRoute?.id===r.id)?"rgba(58,160,216,0.08)":"var(--wh)",fontWeight:700,fontSize:12,cursor:"pointer",whiteSpace:"nowrap",minWidth:100}}>
                  <div style={{color:activeRoute?.id===r.id?"var(--tl)":"var(--tx)"}}>{r.name}</div>
                  <div style={{fontSize:10,color:"var(--tx3)",marginTop:2}}>{done}/{total}名 {pct}%</div>
                </button>;
              })}
            </div>

            {/* アクティブルートの詳細 */}
            {activeRoute&&<div>
              {/* ルート情報 */}
              <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"10px 14px",marginBottom:10,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                <div>
                  <div style={{fontWeight:700,fontSize:14}}>{activeRoute.name}</div>
                  <div style={{fontSize:11,color:"var(--tx3)"}}>
                    {activeRoute.driver||"ドライバー未設定"} ／ {activeRoute.vehicle||"車両未設定"}
                  </div>
                </div>
                <div style={{display:"flex",gap:6}}>
                  <button className="nb" style={{fontSize:11,padding:"5px 10px"}} onClick={()=>setShowIncident(true)}>
                    📝 メモ
                  </button>
                  <button className="nb" style={{fontSize:11,padding:"5px 10px"}} onClick={()=>printRouteSummary(activeRoute)}>
                    🖨 印刷
                  </button>
                </div>
              </div>

              {/* 進捗バー */}
              {(()=>{const{pct,done,total,absent}=routeProgress(activeRoute);return(
                <div style={{marginBottom:12}}>
                  <div style={{display:"flex",justifyContent:"space-between",fontSize:12,marginBottom:4}}>
                    <span style={{color:"var(--tx3)"}}>完了 {done}/{total}名</span>
                    {absent>0&&<span style={{color:"var(--ro)"}}>欠席 {absent}名</span>}
                    <span style={{fontWeight:700,color:pct===100?"var(--gr)":"var(--tl)"}}>{pct}%</span>
                  </div>
                  <div style={{background:"var(--bg2)",borderRadius:6,height:10,overflow:"hidden"}}>
                    <div style={{height:"100%",width:pct+"%",background:pct===100?"var(--gr)":"var(--tl)",borderRadius:6,transition:"width 0.3s"}}/>
                  </div>
                </div>
              );})()}

              {/* 乗客リスト */}
              <div style={{display:"flex",flexDirection:"column",gap:8}}>
                {getRoutePassengers(activeRoute).map((stop,i)=>{
                  const child = children.find(c=>c.id===(stop.userId||stop.id));
                  const log = getLog(stop.userId||stop.id, activeRoute.id);
                  const st = TRANSPORT_STATUS[log?.status||"pending"];
                  if(!child) return null;
                  return <div key={i} style={{background:"var(--wh)",border:`2px solid ${log?.status==="boarded"||log?.status==="dropped"?"var(--gr)":log?.status==="absent"?"var(--ro)":"var(--bd)"}`,borderRadius:12,padding:"10px 14px",display:"flex",alignItems:"center",gap:10}}>
                    <div style={{fontSize:24,minWidth:30,textAlign:"center"}}>{st.icon}</div>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:700,fontSize:14}}>{child.name}</div>
                      <div style={{fontSize:11,color:"var(--tx3)"}}>
                        {stop.address||"住所未設定"}
                        {stop.estimatedTime?` ／ 予定 ${stop.estimatedTime}`:""}
                        {log?.actualTime?` ／ 実績 ${log.actualTime}`:""}
                      </div>
                      {log?.incidentNote&&<div style={{fontSize:11,color:"var(--ac)",marginTop:2}}>⚠️ {log.incidentNote}</div>}
                    </div>
                    <div style={{display:"flex",gap:6}}>
                      {log?.status!=="absent"&&(
                        <button onClick={()=>tapBoard(child,activeRoute)}
                          style={{padding:"8px 14px",borderRadius:10,border:"none",background:log?.status==="boarded"?"var(--gr)":"var(--tl)",color:"#fff",fontWeight:700,fontSize:13,cursor:"pointer",minWidth:70}}>
                          {log?.status==="boarded"?"✅確認済":"乗車確認"}
                        </button>
                      )}
                      <button onClick={()=>markAbsent(child,activeRoute)}
                        style={{padding:"8px 10px",borderRadius:10,border:`1px solid ${log?.status==="absent"?"var(--ro)":"var(--bd)"}`,background:log?.status==="absent"?"rgba(224,56,56,0.1)":"var(--wh)",color:log?.status==="absent"?"var(--ro)":"var(--tx3)",fontWeight:700,fontSize:12,cursor:"pointer"}}>
                        {log?.status==="absent"?"✖欠席":"欠席"}
                      </button>
                    </div>
                  </div>;
                })}
              </div>
            </div>}
          </div>
      }

      {/* 遅延/事故メモモーダル */}
      {showIncident&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
        <div style={{background:"var(--wh)",borderRadius:14,padding:20,width:"100%",maxWidth:400}}>
          <div style={{fontWeight:700,fontSize:16,marginBottom:12}}>📝 遅延・事故メモ</div>
          <div className="slbl">対象児童</div>
          <select className="fi" value={incidentChildId||""} onChange={e=>setIncidentChildId(e.target.value||null)}>
            <option value="">-- 選択してください --</option>
            {(activeRoute?getRoutePassengers(activeRoute):[]).map(s=>{
              const c = children.find(x=>x.id===(s.userId||s.id));
              return c?<option key={c.id} value={c.id}>{c.name}</option>:null;
            })}
          </select>
          <div className="slbl">メモ内容</div>
          <textarea className="fi fta" rows={3} value={incidentNote} onChange={e=>setIncidentNote(e.target.value)} placeholder="遅延理由・事故・気になる点など"/>
          <div style={{display:"flex",gap:8,marginTop:10}}>
            <button className="bsave" style={{flex:1}} onClick={saveIncident}>保存する</button>
            <button className="nb" style={{flex:1}} onClick={()=>{setShowIncident(false);setIncidentNote("");setIncidentChildId(null);}}>閉じる</button>
          </div>
        </div>
      </div>}
    </div>}

    {/* ===== 本日の記録タブ ===== */}
    {tab==="summary"&&<div>
      <div style={{display:"flex",gap:8,marginBottom:12}}>
        {["来所","退所"].map(d=>(
          <button key={d} onClick={()=>setDir(d)}
            style={{flex:1,padding:"9px 0",borderRadius:10,border:`2px solid ${dir===d?"var(--tl)":"var(--bd)"}`,background:dir===d?"var(--tl)":"var(--wh)",color:dir===d?"#fff":"var(--tx)",fontWeight:700,cursor:"pointer",fontSize:12}}>
            {d==="来所"?"🚌":"🏠"} {d}
          </button>
        ))}
      </div>

      {todayLogs.length===0
        ? <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
            <div style={{fontSize:40,marginBottom:8}}>📭</div>
            <div>本日の記録がありません</div>
            <div style={{fontSize:12,marginTop:4}}>ライブ追跡で乗降確認を行うと記録されます</div>
          </div>
        : <div>
            {/* ルートごとにグループ表示 */}
            {[...new Set(todayLogs.map(l=>l.routeId))].map(routeId=>{
              const routeLogs = todayLogs.filter(l=>l.routeId===routeId);
              const routeName = routeLogs[0]?.routeName||"不明";
              return <div key={routeId} style={{marginBottom:14}}>
                <div style={{fontWeight:700,fontSize:13,marginBottom:8,color:"var(--tl)"}}>📍 {routeName}</div>
                {routeLogs.map(l=>{
                  const st = TRANSPORT_STATUS[l.status||"pending"];
                  return <div key={l.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 14px",marginBottom:6,display:"flex",justifyContent:"space-between",alignItems:"center"}}>
                    <div>
                      <span style={{fontWeight:700,fontSize:13}}>{l.childName}</span>
                      {l.actualTime&&<span style={{fontSize:11,color:"var(--tx3)",marginLeft:8}}>実績: {l.actualTime}</span>}
                      {l.incidentNote&&<div style={{fontSize:11,color:"var(--ac)",marginTop:2}}>⚠️ {l.incidentNote}</div>}
                    </div>
                    <span style={{fontSize:12,fontWeight:700,color:st.color,background:st.bg,padding:"3px 10px",borderRadius:20}}>{st.icon} {st.label}</span>
                  </div>;
                })}
              </div>;
            })}
          </div>
      }
    </div>}

    {/* ===== 月次統計タブ ===== */}
    {tab==="stats"&&<div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:14}}>
        {[
          {icon:"📅",label:"実施日数",val:`${monthDays}日`},
          {icon:"🧒",label:"延べ乗降数",val:`${totalRides}回`},
          {icon:"✖",label:"欠席回数",val:`${absentRides}回`,red:true},
          {icon:"⚠️",label:"メモ件数",val:`${incidentRides}件`,amber:incidentRides>0},
        ].map((c,i)=>(
          <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px 10px",textAlign:"center"}}>
            <div style={{fontSize:24,marginBottom:4}}>{c.icon}</div>
            <div style={{fontSize:22,fontWeight:700,color:c.red?"var(--ro)":c.amber?"var(--ac)":"var(--tl)"}}>{c.val}</div>
            <div style={{fontSize:11,color:"var(--tx3)"}}>{c.label}</div>
          </div>
        ))}
      </div>

      {/* 利用者別集計 */}
      <div style={{fontWeight:700,fontSize:14,marginBottom:8}}>👦 利用者別 当月送迎回数</div>
      <div style={{display:"flex",flexDirection:"column",gap:6}}>
        {children.map(child=>{
          const cLogs = monthLogs.filter(l=>l.childId===child.id);
          if(!cLogs.length) return null;
          const boarded = cLogs.filter(l=>l.status==="boarded"||l.status==="dropped").length;
          const absent = cLogs.filter(l=>l.status==="absent").length;
          return <div key={child.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 14px",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <span style={{fontWeight:600,fontSize:13}}>{child.name}</span>
            <div style={{display:"flex",gap:10,fontSize:12}}>
              <span style={{color:"var(--gr)",fontWeight:700}}>乗降 {boarded}回</span>
              {absent>0&&<span style={{color:"var(--ro)"}}>欠席 {absent}回</span>}
            </div>
          </div>;
        }).filter(Boolean)}
      </div>

      {/* インシデントログ */}
      {incidentRides>0&&<div style={{marginTop:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:8}}>⚠️ メモ一覧（当月）</div>
        {monthLogs.filter(l=>l.incidentNote).sort((a,b)=>b.logDate>a.logDate?1:-1).map(l=>(
          <div key={l.id} style={{background:"rgba(255,160,0,0.06)",border:"1px solid var(--ac)33",borderRadius:10,padding:"10px 14px",marginBottom:6}}>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:3}}>{l.logDate} ／ {l.direction} ／ {l.routeName}</div>
            <div style={{fontWeight:600,fontSize:13}}>{l.childName}</div>
            <div style={{fontSize:12,marginTop:4}}>⚠️ {l.incidentNote}</div>
          </div>
        ))}
      </div>}

      <button className="nb" style={{width:"100%",marginTop:14,padding:"10px 0"}} onClick={exportCSV}>📥 月次送迎記録CSV出力</button>
    </div>}
  </div>;
}

// ==================== 勤怠管理統合ダッシュボード ====================
// 今日の出勤状況・36協定チェック・年5日義務管理・勤怠修正申請

function StaffKintaiDashboardScreen({user, store, onNav, onBack}) {
  const facilityId = user.selectedFacilityId;
  const isMgr = user.role==="admin"||user.role==="manager";
  const [tab, setTab] = useState("today"); // today | overtime | paidleave5 | correction
  const [corrForm, setCorrForm] = useState({targetDate:todayISO(),correctionType:"出勤時刻",requestedTime:"",reason:""});
  const [corrFilter, setCorrFilter] = useState("all"); // all | 申請中 | 承認 | 却下

  const today = todayISO();
  const nowYM = today.slice(0,7);
  const fStaff = store.dynStaff.filter(s=>user.role==="admin"||s.facilityId===facilityId);

  // ── 今日の出勤状況 ──
  const getStaffTodayStatus = staffId => {
    const inRecs  = store.recs.filter(r=>r.type==="staff_in" &&r.staffId===staffId&&(r.time||"").startsWith(today));
    const outRecs = store.recs.filter(r=>r.type==="staff_out"&&r.staffId===staffId&&(r.time||"").startsWith(today));
    const parseT = t => { const m=t.match(/(\d+):(\d+)/); return m?+m[1]*60+ +m[2]:null; };
    const shiftKey = store.getShift ? store.getShift(staffId, today)||"none" : "none";
    if(shiftKey==="off"||shiftKey==="holiday") return {status:"休日/有給",color:"var(--tx3)",icon:"🌴",inTime:null,outTime:null};
    if(shiftKey==="none") return {status:"シフトなし",color:"var(--tx3)",icon:"—",inTime:null,outTime:null};
    if(inRecs.length===0) {
      // 現時刻と比較して遅刻判定（SHIFT_TYPESがあれば）
      const shiftStart = SHIFT_TYPES?.find(s=>s.key===shiftKey)?.time?.split("〜")[0];
      const nowMin = new Date().getHours()*60+new Date().getMinutes();
      const startMin = shiftStart ? (()=>{const[h,m]=shiftStart.split(":").map(Number);return h*60+(m||0);})() : null;
      const isLate = startMin && nowMin > startMin+15;
      return isLate
        ? {status:"遅刻/未出勤",color:"var(--ro)",icon:"⚠️",inTime:null,outTime:null}
        : {status:"出勤前",color:"var(--tx3)",icon:"🕐",inTime:null,outTime:null};
    }
    const inTimes = inRecs.map(r=>parseT(r.time)).filter(t=>t!==null);
    const outTimes = outRecs.map(r=>parseT(r.time)).filter(t=>t!==null);
    const inMin = inTimes.length ? Math.min(...inTimes) : null;
    const outMin = outTimes.length ? Math.max(...outTimes) : null;
    const fmt = m => m===null?"—":`${Math.floor(m/60)}:${String(m%60).padStart(2,"0")}`;
    if(outMin!==null) return {status:"退勤済",color:"var(--tx3)",icon:"✅",inTime:fmt(inMin),outTime:fmt(outMin)};
    return {status:"出勤中",color:"var(--gr)",icon:"🟢",inTime:fmt(inMin),outTime:null};
  };

  // ── 36協定チェック ──
  // 当月の残業時間を各スタッフで計算
  const days = daysInMonth(+nowYM.split("-")[0], +nowYM.split("-")[1]);
  const mk = d => `${nowYM}-${String(d).padStart(2,"0")}`;
  const SHIFT_HOURS_LOCAL = {A:8,B:8,C:8,off:0,holiday:0,P1:5,P2:4,P3:4,none:0};

  const calcMonthOvertime = staffId => {
    let otH = 0, totalH = 0;
    for(let i=1;i<=days;i++){
      const dateStr = mk(i);
      const shiftKey = store.getShift ? store.getShift(staffId,dateStr)||"none" : "none";
      if(shiftKey==="off"||shiftKey==="holiday"||shiftKey==="none") continue;
      const shiftH = SHIFT_HOURS_LOCAL[shiftKey]||8;
      const inRecs = store.recs.filter(r=>r.type==="staff_in"&&r.staffId===staffId&&(r.time||"").startsWith(dateStr));
      const outRecs = store.recs.filter(r=>r.type==="staff_out"&&r.staffId===staffId&&(r.time||"").startsWith(dateStr));
      const parseT = t => {const m=t.match(/(\d+):(\d+)/);return m?+m[1]*60+ +m[2]:null;};
      const inTs = inRecs.map(r=>parseT(r.time)).filter(t=>t!==null);
      const outTs = outRecs.map(r=>parseT(r.time)).filter(t=>t!==null);
      if(inTs.length&&outTs.length){
        const workedH = (Math.max(...outTs)-Math.min(...inTs)-60)/60;
        if(workedH>0){
          totalH += workedH;
          if(workedH>shiftH+0.5) otH += workedH-shiftH;
        }
      }
    }
    return {otH:Math.round(otH*10)/10, totalH:Math.round(totalH*10)/10};
  };

  // 36協定アラートレベル
  const getOTLevel = otH => {
    if(otH>=45) return {level:"danger",  label:"上限超過",   color:"var(--ro)",  bg:"rgba(224,56,56,0.1)"};
    if(otH>=36) return {level:"warn",    label:"要注意",     color:"var(--ac)",  bg:"rgba(255,160,0,0.08)"};
    if(otH>=20) return {level:"caution", label:"注意",       color:"#f59e0b",    bg:"rgba(245,158,11,0.08)"};
    return           {level:"ok",        label:"正常",       color:"var(--gr)",  bg:"rgba(44,170,96,0.06)"};
  };

  // ── 年5日義務チェック ──
  // 各スタッフの年度内有給取得日数（calcGrantedDays / calcUsedDays は既存ヘルパー）
  const check5DayObligation = staffId => {
    const s = fStaff.find(x=>x.id===staffId);
    if(!s) return null;
    const granted = typeof calcGrantedDays==="function" ? calcGrantedDays(s.hireDate, s.workDaysPerWeek||5) : 0;
    const used = typeof calcUsedDays==="function" ? calcUsedDays(staffId, store.paidLeaveReqs) : 0;
    // 年5日義務の対象は付与10日以上の社員
    const isTarget = granted >= 10;
    const remaining5 = Math.max(0, 5-used);
    return {granted, used, remaining5, isTarget};
  };

  // 修正申請の提出
  const submitCorrection = () => {
    if(!corrForm.requestedTime||!corrForm.reason.trim()){
      store.showToast("申請時刻と理由を入力してください","error"); return;
    }
    const myStaff = fStaff.find(s=>s.id===user.staffId);
    store.saveKintaiCorrection({
      id: genId(),
      staffId: user.staffId,
      staffName: user.displayName||myStaff?.name||"",
      facilityId,
      targetDate: corrForm.targetDate,
      correctionType: corrForm.correctionType,
      requestedTime: corrForm.requestedTime,
      reason: corrForm.reason,
      status: "申請中",
      appliedAt: todayISO(),
    });
    setCorrForm({targetDate:todayISO(),correctionType:"出勤時刻",requestedTime:"",reason:""});
    store.showToast("修正申請を提出しました","success");
  };

  // 修正申請の承認・却下
  const approveCorrection = (id, action) => {
    const req = store.kintaiCorrections.find(r=>r.id===id);
    if(!req) return;
    store.saveKintaiCorrection({...req, status:action==="approve"?"承認":"却下", approvedBy:user.displayName, approvedAt:todayISO()});
    store.showToast(action==="approve"?"承認しました":"却下しました","success");
  };

  const myCorrs = store.kintaiCorrections.filter(r=>r.staffId===user.staffId);
  const pendingCorrs = store.kintaiCorrections.filter(r=>r.status==="申請中"&&(user.role==="admin"||r.facilityId===facilityId));
  const filteredCorrs = isMgr
    ? store.kintaiCorrections.filter(r=>(user.role==="admin"||r.facilityId===facilityId)&&(corrFilter==="all"||r.status===corrFilter))
    : myCorrs;

  const CORR_COLORS = {"申請中":["var(--ac)","rgba(255,160,0,0.1)"],"承認":["var(--gr)","rgba(44,170,96,0.1)"],"却下":["var(--ro)","rgba(224,56,56,0.1)"]};

  return <div>
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <h2 style={{margin:0,fontSize:17}}>⏱ 勤怠管理ダッシュボード</h2>
    </div>

    {/* 関連画面へのクイックリンク */}
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
      {[
        {icon:"📅",label:"シフト表",screen:"shift"},
        {icon:"📊",label:"勤務実績",screen:"kintai"},
        {icon:"🌴",label:"有給管理",screen:"paidleave"},
      ].map(btn=>(
        <button key={btn.screen} className="nb" onClick={()=>onNav&&onNav(btn.screen)}
          style={{padding:"10px 6px",borderRadius:10,textAlign:"center",display:"flex",flexDirection:"column",alignItems:"center",gap:4}}>
          <span style={{fontSize:22}}>{btn.icon}</span>
          <span style={{fontSize:11,fontWeight:700}}>{btn.label}</span>
        </button>
      ))}
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,marginBottom:14,overflowX:"auto",paddingBottom:4}}>
      {[
        ["today","🟢 今日の出勤"],
        ["overtime","⚡ 36協定チェック"],
        ["paidleave5","🌴 年5日義務"],
        ["correction",`✏️ 修正申請${pendingCorrs.length>0&&isMgr?` (${pendingCorrs.length})`:""}`,],
      ].map(([id,lb])=>(
        <button key={id} onClick={()=>setTab(id)}
          style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${tab===id?"var(--tl)":"var(--bd)"}`,background:tab===id?"var(--tl)":"var(--wh)",color:tab===id?"#fff":"var(--tx)",fontWeight:tab===id?700:400,fontSize:12,whiteSpace:"nowrap",cursor:"pointer"}}>
          {lb}
        </button>
      ))}
    </div>

    {/* ===== 今日の出勤状況 ===== */}
    {tab==="today"&&<div>
      <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>
        📅 {today.replace(/-/g,"/")} の出勤状況
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {fStaff.map(s=>{
          const st = getStaffTodayStatus(s.id);
          const shiftKey = store.getShift ? store.getShift(s.id,today)||"none" : "none";
          const shiftDef = SHIFT_TYPES?.find(x=>x.key===shiftKey);
          return <div key={s.id} style={{background:"var(--wh)",border:`1.5px solid ${st.status==="出勤中"?"var(--gr)":st.status.includes("遅刻")?"var(--ro)":"var(--bd)"}`,borderRadius:12,padding:"12px 14px",display:"flex",alignItems:"center",gap:12}}>
            <span style={{fontSize:24}}>{st.icon}</span>
            <div style={{flex:1}}>
              <div style={{fontWeight:700,fontSize:14}}>{s.name}</div>
              <div style={{fontSize:11,color:"var(--tx3)"}}>
                {shiftDef?.label||shiftKey}
                {shiftDef?.time?` (${shiftDef.time})`:""}
              </div>
            </div>
            <div style={{textAlign:"right"}}>
              <div style={{fontSize:12,fontWeight:700,color:st.color}}>{st.status}</div>
              {st.inTime&&<div style={{fontSize:11,color:"var(--tx3)"}}>出勤 {st.inTime}</div>}
              {st.outTime&&<div style={{fontSize:11,color:"var(--tx3)"}}>退勤 {st.outTime}</div>}
            </div>
          </div>;
        })}
      </div>

      {/* 今日の集計 */}
      {fStaff.length>0&&(()=>{
        const statuses = fStaff.map(s=>getStaffTodayStatus(s.id));
        const inCnt    = statuses.filter(s=>s.status==="出勤中").length;
        const doneCnt  = statuses.filter(s=>s.status==="退勤済").length;
        const lateCnt  = statuses.filter(s=>s.status.includes("遅刻")).length;
        return <div style={{marginTop:12,display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
          {[
            {label:"出勤中",val:inCnt,color:"var(--gr)"},
            {label:"退勤済",val:doneCnt,color:"var(--tx3)"},
            {label:"遅刻/未",val:lateCnt,color:"var(--ro)"},
          ].map((c,i)=>(
            <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
              <div style={{fontSize:22,fontWeight:700,color:c.color}}>{c.val}</div>
              <div style={{fontSize:10,color:"var(--tx3)"}}>{c.label}</div>
            </div>
          ))}
        </div>;
      })()}
    </div>}

    {/* ===== 36協定チェック ===== */}
    {tab==="overtime"&&<div>
      <div style={{background:"rgba(58,160,216,0.06)",border:"1px solid rgba(58,160,216,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:12,color:"var(--tx3)"}}>
        ⚖️ 36協定：月45時間・年360時間が上限（特別条項なし）。黄色は要注意、赤は超過です。
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {fStaff.map(s=>{
          const {otH, totalH} = calcMonthOvertime(s.id);
          const lv = getOTLevel(otH);
          const pct = Math.min(100, otH/45*100);
          return <div key={s.id} style={{background:"var(--wh)",border:`1.5px solid ${lv.level==="ok"?"var(--bd)":lv.color+"55"}`,borderRadius:12,padding:14}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div>
                <span style={{fontWeight:700,fontSize:14}}>{s.name}</span>
                <span style={{fontSize:11,color:"var(--tx3)",marginLeft:8}}>実働 {totalH}h / 残業 {otH}h</span>
              </div>
              <span style={{fontSize:11,fontWeight:700,color:lv.color,background:lv.bg,padding:"3px 10px",borderRadius:20}}>{lv.label}</span>
            </div>
            {/* 進捗バー */}
            <div style={{background:"var(--bg2)",borderRadius:4,height:8,overflow:"hidden"}}>
              <div style={{height:"100%",width:pct+"%",background:lv.level==="ok"?"var(--gr)":lv.level==="caution"?"#f59e0b":lv.level==="warn"?"var(--ac)":"var(--ro)",borderRadius:4,transition:"width 0.3s"}}/>
            </div>
            <div style={{display:"flex",justifyContent:"space-between",fontSize:10,color:"var(--tx3)",marginTop:4}}>
              <span>0h</span><span style={{color:lv.color,fontWeight:700}}>{otH}h / 45h上限</span>
            </div>
          </div>;
        })}
      </div>
    </div>}

    {/* ===== 年5日義務管理 ===== */}
    {tab==="paidleave5"&&<div>
      <div style={{background:"rgba(44,170,96,0.06)",border:"1px solid rgba(44,170,96,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:12,fontSize:12,color:"var(--tx3)"}}>
        📋 年次有給休暇の年5日取得義務（付与10日以上の社員）。残日数が多い場合は計画的付与を検討してください。
      </div>
      <div style={{display:"flex",flexDirection:"column",gap:8}}>
        {fStaff.map(s=>{
          const chk = check5DayObligation(s.id);
          if(!chk) return null;
          const {granted, used, remaining5, isTarget} = chk;
          const ok = !isTarget || used>=5;
          const pct = isTarget ? Math.min(100, used/5*100) : 100;
          return <div key={s.id} style={{background:"var(--wh)",border:`1.5px solid ${ok?"var(--bd)":"var(--ac)55"}`,borderRadius:12,padding:14,opacity:isTarget?1:0.6}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
              <div>
                <span style={{fontWeight:700,fontSize:14}}>{s.name}</span>
                {!isTarget&&<span style={{fontSize:10,color:"var(--tx3)",marginLeft:8}}>（付与{granted}日・義務対象外）</span>}
              </div>
              <span style={{fontSize:11,fontWeight:700,color:ok?"var(--gr)":"var(--ac)",background:ok?"rgba(44,170,96,0.1)":"rgba(255,160,0,0.1)",padding:"3px 10px",borderRadius:20}}>
                {!isTarget?"対象外":ok?"義務達成":"取得が必要"}
              </span>
            </div>
            {isTarget&&<>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:8,fontSize:12}}>
                {[
                  {lb:"付与日数",val:`${granted}日`},
                  {lb:"取得済み",val:`${used}日`},
                  {lb:"5日まで残",val:`${remaining5}日`,red:remaining5>0},
                ].map((c,i)=>(
                  <div key={i} style={{background:"var(--bg2)",borderRadius:6,padding:"6px 4px",textAlign:"center"}}>
                    <div style={{fontSize:10,color:"var(--tx3)"}}>{c.lb}</div>
                    <div style={{fontSize:13,fontWeight:700,color:c.red?"var(--ac)":"var(--tx)"}}>{c.val}</div>
                  </div>
                ))}
              </div>
              <div style={{background:"var(--bg2)",borderRadius:4,height:8,overflow:"hidden"}}>
                <div style={{height:"100%",width:pct+"%",background:ok?"var(--gr)":"var(--ac)",borderRadius:4,transition:"width 0.3s"}}/>
              </div>
              <div style={{fontSize:10,color:"var(--tx3)",marginTop:4,textAlign:"right"}}>{used}/5日</div>
            </>}
          </div>;
        }).filter(Boolean)}
      </div>
    </div>}

    {/* ===== 勤怠修正申請 ===== */}
    {tab==="correction"&&<div>
      {/* 自分の申請フォーム（スタッフ・管理者共通） */}
      {!isMgr&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>📝 打刻修正を申請する</div>
        <div className="slbl">対象日</div>
        <input type="date" className="fi" value={corrForm.targetDate} onChange={e=>setCorrForm(p=>({...p,targetDate:e.target.value}))}/>
        <div className="slbl">修正種別</div>
        <select className="fi" value={corrForm.correctionType} onChange={e=>setCorrForm(p=>({...p,correctionType:e.target.value}))}>
          {["出勤時刻","退勤時刻","出勤打刻なし","退勤打刻なし"].map(v=><option key={v}>{v}</option>)}
        </select>
        <div className="slbl">修正後の時刻（例: 08:30）</div>
        <input type="time" className="fi" value={corrForm.requestedTime} onChange={e=>setCorrForm(p=>({...p,requestedTime:e.target.value}))}/>
        <div className="slbl">修正理由（必須）</div>
        <textarea className="fi fta" rows={2} value={corrForm.reason} onChange={e=>setCorrForm(p=>({...p,reason:e.target.value}))} placeholder="修正が必要な理由を記入してください"/>
        <button className="bsave" style={{width:"100%",marginTop:6}} onClick={submitCorrection}>申請する</button>
      </div>}

      {/* 管理者：承認管理 */}
      {isMgr&&<div style={{marginBottom:14}}>
        <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap"}}>
          {[["all","全て"],["申請中","申請中"],["承認","承認済"],["却下","却下"]].map(([v,lb])=>(
            <button key={v} onClick={()=>setCorrFilter(v)}
              style={{padding:"6px 14px",borderRadius:20,border:`1.5px solid ${corrFilter===v?"var(--tl)":"var(--bd)"}`,background:corrFilter===v?"var(--tl)":"var(--wh)",color:corrFilter===v?"#fff":"var(--tx)",fontWeight:corrFilter===v?700:400,fontSize:12,cursor:"pointer"}}>
              {lb}{v==="申請中"&&pendingCorrs.length>0?` (${pendingCorrs.length})`:""}
            </button>
          ))}
        </div>
      </div>}

      {/* 申請一覧 */}
      {filteredCorrs.length===0
        ? <div style={{textAlign:"center",padding:40,color:"var(--tx3)"}}>
            <div style={{fontSize:32,marginBottom:8}}>📭</div>
            <div>申請がありません</div>
          </div>
        : filteredCorrs.sort((a,b)=>b.appliedAt>a.appliedAt?1:-1).map(req=>{
            const [col,bg] = CORR_COLORS[req.status]||["var(--tx3)","var(--bg2)"];
            return <div key={req.id} style={{background:"var(--wh)",border:`1px solid var(--bd)`,borderRadius:12,padding:14,marginBottom:8}}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
                <div>
                  <span style={{fontWeight:700,fontSize:13}}>{isMgr?req.staffName:req.correctionType}</span>
                  <span style={{fontSize:11,color:"var(--tx3)",marginLeft:8}}>{req.targetDate}</span>
                </div>
                <span style={{fontSize:11,fontWeight:700,color:col,background:bg,padding:"3px 10px",borderRadius:20}}>{req.status}</span>
              </div>
              <div style={{fontSize:12,color:"var(--tx3)",marginBottom:6}}>
                {isMgr&&<span style={{marginRight:10}}>種別: {req.correctionType}</span>}
                <span>申請時刻: <b>{req.requestedTime||"—"}</b></span>
              </div>
              <div style={{fontSize:12,color:"var(--tx)",background:"var(--bg2)",borderRadius:6,padding:"6px 10px",marginBottom:isMgr&&req.status==="申請中"?8:0}}>
                理由: {req.reason}
              </div>
              {isMgr&&req.status==="申請中"&&<div style={{display:"flex",gap:8,marginTop:6}}>
                <button className="bsave" style={{flex:1,fontSize:12,padding:"7px 0"}} onClick={()=>approveCorrection(req.id,"approve")}>✅ 承認</button>
                <button className="nb" style={{flex:1,fontSize:12,padding:"7px 0",color:"var(--ro)",borderColor:"var(--ro)"}} onClick={()=>approveCorrection(req.id,"reject")}>✗ 却下</button>
              </div>}
            </div>;
          })
      }
    </div>}
  </div>;
}

// ==================== 請求管理・加算管理 ====================
// 国保連請求データ生成・加算管理・月次集計・提出管理

// 基本単位数（放課後等デイサービス・簡易版）
const BASE_UNITS_MAP = {
  afterschool_1: 584,   // 放課後等デイサービス1（一般）
  afterschool_2: 922,   // 放課後等デイサービス2（重症心身障害）
  child_dev: 644,       // 児童発達支援
};
const UNIT_PRICE_YEN = 10.21; // 静岡市・6級地（2024年度）

const ADDITION_DEFS = [
  {id:"transport_in",  label:"送迎加算（来所）",         unit:54,  per:"回"},
  {id:"transport_out", label:"送迎加算（退所）",         unit:54,  per:"回"},
  {id:"meal",          label:"食事提供加算",             unit:30,  per:"日"},
  {id:"absence",       label:"欠席時対応加算",           unit:94,  per:"回"},
  {id:"family",        label:"家庭連携加算",             unit:187, per:"回"},
  {id:"specialist",    label:"専門的支援加算",           unit:135, per:"日"},
  {id:"nurse",         label:"看護職員加算（Ⅰ）",       unit:800, per:"日"},
  {id:"individual",    label:"個別サポート加算（Ⅰ）",   unit:100, per:"日"},
  {id:"severe",        label:"強度行動障害支援加算",     unit:155, per:"日"},
  {id:"medical",       label:"医療連携体制加算（Ⅰ）",   unit:500, per:"日"},
];

const BILLING_STATUS_DEF = {
  draft:     {label:"作成中",  color:"var(--tx3)", bg:"var(--bg2)",            icon:"✏️"},
  confirmed: {label:"確定",    color:"var(--tl)",  bg:"rgba(58,160,216,0.1)", icon:"✅"},
  submitted: {label:"提出済",  color:"var(--gr)",  bg:"rgba(44,170,96,0.1)",  icon:"📤"},
  returned:  {label:"返戻",    color:"var(--ro)",  bg:"rgba(224,56,56,0.1)",  icon:"↩️"},
};

function BillingManagementScreen({user, store, onBack}) {
  const facilityId = user.selectedFacilityId;
  const isMgr = user.role==="admin"||user.role==="manager";
  const nowYM = todayISO().slice(0,7);
  const [selMonth, setSelMonth] = useState(nowYM);
  const [tab, setTab] = useState("list");
  const [selChildId, setSelChildId] = useState(null);
  const [genConfirm, setGenConfirm] = useState(false);

  const fac = store.facilities ? store.facilities.find(f=>f.id===facilityId) : null;
  const children = store.dynUsers.filter(u=>
    u.role==="child"&&(u.facilityId===facilityId||!facilityId)
  );

  // 当月実績（出席のみ）
  const monthRecs = store.serviceRecs.filter(r=>
    (r.visit_date||"").startsWith(selMonth)&&
    (r.facility_id===facilityId||!facilityId)&&
    r.attendance_status==="attended"
  );

  // 当月請求アイテム・加算アイテム
  const monthBilling = store.billingItems.filter(b=>
    b.service_month===selMonth&&(b.facility_id===facilityId||!facilityId)
  );
  const monthAdditions = store.additionItems.filter(a=>
    a.service_month===selMonth&&(a.facility_id===facilityId||!facilityId)
  );

  const getChildDays = cid => monthRecs.filter(r=>r.child_id===cid).length;
  const getChildPickup = cid => monthRecs.filter(r=>r.child_id===cid&&r.pickup_completed).length;
  const getChildDropoff = cid => monthRecs.filter(r=>r.child_id===cid&&r.dropoff_completed).length;
  const getChildAddUnits = cid => monthAdditions.filter(a=>a.child_id===cid).reduce((s,a)=>s+(a.total_units||0),0);
  const getChildTotalUnits = cid => {
    const base = monthBilling.find(b=>b.child_id===cid)?.total_base_units||0;
    return base + getChildAddUnits(cid);
  };

  const facilityTotalUnits = monthBilling.reduce((s,b)=>s+(b.total_base_units||0)+getChildAddUnits(b.child_id),0);
  const facilityTotalYen = Math.floor(facilityTotalUnits * UNIT_PRICE_YEN);

  // 保存ヘルパー
  const upsertBilling = (childId, extra={}) => {
    const child = children.find(c=>c.id===childId);
    const days = getChildDays(childId);
    const baseUnit = BASE_UNITS_MAP[child?.serviceTypeCode||"afterschool_1"]||584;
    const exist = monthBilling.find(b=>b.child_id===childId);
    store.saveBillingItem({
      id: exist?.id||genId(),
      child_id: childId,
      facility_id: facilityId,
      service_month: selMonth,
      service_days: days,
      base_unit: baseUnit,
      total_base_units: baseUnit*days,
      status: exist?.status||"draft",
      child_name: child?.name||"",
      jukyusha_no: child?.jukyushaNo||null,
      max_burden: Number(child?.maxBurden||0),
      ...extra,
    });
  };

  const upsertAddition = (childId, defId, count) => {
    const def = ADDITION_DEFS.find(d=>d.id===defId);
    if(!def) return;
    const exist = monthAdditions.find(a=>a.child_id===childId&&a.addition_type===defId);
    store.saveAddition({
      id: exist?.id||genId(),
      child_id: childId,
      facility_id: facilityId,
      service_month: selMonth,
      addition_type: defId,
      addition_label: def.label,
      unit: def.unit,
      count: count,
      total_units: def.unit*count,
    });
  };

  // 請求データ自動生成
  const generateBilling = () => {
    let cnt = 0;
    children.forEach(child=>{
      if(getChildDays(child.id)===0) return;
      upsertBilling(child.id);
      const pick = getChildPickup(child.id);
      const drop = getChildDropoff(child.id);
      if(pick>0) upsertAddition(child.id,"transport_in",pick);
      if(drop>0) upsertAddition(child.id,"transport_out",drop);
      cnt++;
    });
    store.showToast(`${cnt}名の請求データを生成しました`,"success");
    setGenConfirm(false);
  };

  // 確定・一括提出
  const confirmOne = cid => {
    const b = monthBilling.find(x=>x.child_id===cid);
    if(b) store.saveBillingItem({...b, status:"confirmed"});
    store.showToast("請求を確定しました","success");
  };
  const submitAll = () => {
    const conf = monthBilling.filter(b=>b.status==="confirmed");
    if(conf.length===0){store.showToast("確定済みデータがありません","error");return;}
    conf.forEach(b=>store.saveBillingItem({...b,status:"submitted",submitted_at:new Date().toISOString()}));
    store.showToast(`${conf.length}件を提出済みにしました`,"success");
  };

  // CSV出力
  const exportCSV = () => {
    const hdr = ["氏名","受給者証番号","サービス月","利用日数","基本単位","加算単位","合計単位","概算金額(円)","負担上限(円)","ステータス"];
    const rows = monthBilling.map(b=>{
      const addU = getChildAddUnits(b.child_id);
      const totU = (b.total_base_units||0)+addU;
      const st = BILLING_STATUS_DEF[b.status]?.label||b.status;
      return [b.child_name||"",b.jukyusha_no||"",b.service_month,b.service_days,b.total_base_units||0,addU,totU,Math.floor(totU*UNIT_PRICE_YEN),b.max_burden||0,st];
    });
    const csv = [hdr,...rows].map(r=>r.join(",")).join("\n");
    const a = document.createElement("a");
    a.href = URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download = `請求データ_${selMonth}.csv`; a.click();
    store.showToast("CSVを出力しました","success");
  };

  const moveMonth = dir => {
    const [y,m] = selMonth.split("-").map(Number);
    const d = new Date(y,m-1+dir,1);
    setSelMonth(`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,"0")}`);
  };

  const selChild = children.find(c=>c.id===selChildId);

  return <div>
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <h2 style={{margin:0,fontSize:17}}>💴 請求管理・加算管理</h2>
    </div>

    {/* 月選択 */}
    <div style={{display:"flex",alignItems:"center",gap:8,margin:"12px 0",background:"var(--wh)",padding:"10px 12px",borderRadius:10,border:"1px solid var(--bd)"}}>
      <button className="nb" onClick={()=>moveMonth(-1)} style={{padding:"6px 12px"}}>‹ 前月</button>
      <input type="month" className="fi" style={{flex:1,margin:0,textAlign:"center"}} value={selMonth} onChange={e=>setSelMonth(e.target.value)}/>
      <button className="nb" onClick={()=>moveMonth(1)} style={{padding:"6px 12px"}}>次月 ›</button>
    </div>

    {/* KPIカード */}
    <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
      {[
        {icon:"👦",label:"対象児童",val:`${monthBilling.length}名`},
        {icon:"📊",label:"合計単位",val:facilityTotalUnits.toLocaleString()},
        {icon:"💴",label:"概算請求額",val:`¥${facilityTotalYen.toLocaleString()}`},
      ].map((k,i)=>(
        <div key={i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
          <div style={{fontSize:20,marginBottom:2}}>{k.icon}</div>
          <div style={{fontSize:10,color:"var(--tx3)"}}>{k.label}</div>
          <div style={{fontSize:13,fontWeight:700,color:"var(--tl)"}}>{k.val}</div>
        </div>
      ))}
    </div>

    {/* タブ */}
    <div style={{display:"flex",gap:6,marginBottom:14,overflowX:"auto",paddingBottom:4}}>
      {[["list","📋 請求一覧"],["additions","➕ 加算"],["summary","📊 集計"],["submit","📤 提出"]].map(([id,lb])=>(
        <button key={id} onClick={()=>setTab(id)}
          style={{padding:"7px 14px",borderRadius:20,border:`1.5px solid ${tab===id?"var(--tl)":"var(--bd)"}`,background:tab===id?"var(--tl)":"var(--wh)",color:tab===id?"#fff":"var(--tx)",fontWeight:tab===id?700:400,fontSize:12,whiteSpace:"nowrap",cursor:"pointer"}}>
          {lb}
        </button>
      ))}
    </div>

    {/* ===== 請求一覧タブ ===== */}
    {tab==="list"&&<div>
      <div style={{display:"flex",gap:8,marginBottom:12}}>
        <button className="bsave" style={{flex:1}} onClick={()=>setGenConfirm(true)}>⚙️ 請求データ自動生成</button>
        <button className="nb" onClick={exportCSV} style={{padding:"8px 14px",fontSize:12}}>📥 CSV</button>
      </div>

      {/* 自動生成確認 */}
      {genConfirm&&<div style={{background:"rgba(255,160,0,0.08)",border:"1.5px solid var(--ac)",borderRadius:12,padding:14,marginBottom:12}}>
        <div style={{fontWeight:700,marginBottom:6}}>⚠️ {selMonth} の請求データを自動生成しますか？</div>
        <div style={{fontSize:12,color:"var(--tx3)",marginBottom:10}}>実績（出席）から利用日数・送迎加算を読み込みます。既存データは上書きされます。</div>
        <div style={{display:"flex",gap:8}}>
          <button className="bsave" style={{flex:1}} onClick={generateBilling}>生成する</button>
          <button className="nb" style={{flex:1}} onClick={()=>setGenConfirm(false)}>キャンセル</button>
        </div>
      </div>}

      {monthBilling.length===0
        ? <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
            <div style={{fontSize:40,marginBottom:8}}>📭</div>
            <div style={{fontWeight:700}}>請求データがありません</div>
            <div style={{fontSize:12,marginTop:4}}>「請求データ自動生成」で作成してください</div>
          </div>
        : <div style={{display:"flex",flexDirection:"column",gap:10}}>
            {monthBilling.map(b=>{
              const addU = getChildAddUnits(b.child_id);
              const totU = (b.total_base_units||0)+addU;
              const st = BILLING_STATUS_DEF[b.status]||BILLING_STATUS_DEF.draft;
              return <div key={b.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
                  <span style={{fontWeight:700,fontSize:14}}>{b.child_name||"不明"}</span>
                  <span style={{fontSize:11,fontWeight:700,color:st.color,background:st.bg,padding:"3px 10px",borderRadius:20}}>{st.icon} {st.label}</span>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:10}}>
                  {[
                    {lb:"利用日数",val:`${b.service_days}日`},
                    {lb:"合計単位",val:totU.toLocaleString()},
                    {lb:"概算金額",val:`¥${Math.floor(totU*UNIT_PRICE_YEN).toLocaleString()}`,tl:true},
                  ].map((c,i)=>(
                    <div key={i} style={{background:"var(--bg2)",borderRadius:8,padding:"6px 4px",textAlign:"center"}}>
                      <div style={{fontSize:10,color:"var(--tx3)"}}>{c.lb}</div>
                      <div style={{fontSize:13,fontWeight:700,color:c.tl?"var(--tl)":"var(--tx)"}}>{c.val}</div>
                    </div>
                  ))}
                </div>
                <div style={{fontSize:11,color:"var(--tx3)",marginBottom:b.status==="draft"?8:0}}>
                  基本:{(b.total_base_units||0).toLocaleString()} + 加算:{addU.toLocaleString()} 単位
                  {b.jukyusha_no?` ／ ${b.jukyusha_no}`:""}
                </div>
                {b.status==="draft"&&isMgr&&
                  <button className="bsave" style={{width:"100%",fontSize:12,padding:"7px 0"}} onClick={()=>confirmOne(b.child_id)}>
                    ✅ この児童の請求を確定する
                  </button>}
              </div>;
            })}
          </div>
      }
    </div>}

    {/* ===== 加算管理タブ ===== */}
    {tab==="additions"&&<div>
      <div className="slbl">児童を選択</div>
      <select className="fi" style={{marginBottom:14}} value={selChildId||""} onChange={e=>setSelChildId(e.target.value||null)}>
        <option value="">-- 選択してください --</option>
        {children.filter(c=>monthBilling.find(b=>b.child_id===c.id)).map(c=>(
          <option key={c.id} value={c.id}>{c.name}</option>
        ))}
      </select>

      {selChildId
        ? <div>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12}}>
              {selChild?.name} の加算設定（{selMonth}）
            </div>
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {ADDITION_DEFS.map(def=>{
                const ex = monthAdditions.find(a=>a.child_id===selChildId&&a.addition_type===def.id);
                const cnt = ex?.count||0;
                return <div key={def.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:12}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:8}}>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:600,fontSize:13}}>{def.label}</div>
                      <div style={{fontSize:11,color:"var(--tx3)"}}>{def.unit}単位/{def.per}</div>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:6}}>
                      <button className="nb" style={{width:32,height:32,borderRadius:8,padding:0,fontSize:20,lineHeight:1,fontWeight:700}}
                        onClick={()=>{if(cnt>0)upsertAddition(selChildId,def.id,cnt-1);}}>−</button>
                      <span style={{minWidth:30,textAlign:"center",fontWeight:700,fontSize:18}}>{cnt}</span>
                      <button className="nb s" style={{width:32,height:32,borderRadius:8,padding:0,fontSize:20,lineHeight:1,fontWeight:700}}
                        onClick={()=>upsertAddition(selChildId,def.id,cnt+1)}>＋</button>
                    </div>
                    <div style={{fontSize:11,color:"var(--tl)",minWidth:70,textAlign:"right",fontWeight:cnt>0?700:400}}>
                      {cnt>0?`${(def.unit*cnt).toLocaleString()}単位`:"—"}
                    </div>
                  </div>
                </div>;
              })}
            </div>
            <div style={{marginTop:14,padding:"12px 14px",background:"rgba(58,160,216,0.06)",border:"1.5px solid var(--tl)",borderRadius:10,textAlign:"center"}}>
              <span style={{fontSize:13,fontWeight:700}}>加算合計：{getChildAddUnits(selChildId).toLocaleString()}単位</span>
              <span style={{fontSize:12,color:"var(--tx3)",marginLeft:12}}>≒ ¥{Math.floor(getChildAddUnits(selChildId)*UNIT_PRICE_YEN).toLocaleString()}</span>
            </div>
          </div>
        : <div style={{textAlign:"center",padding:48,color:"var(--tx3)"}}>
            <div style={{fontSize:40,marginBottom:8}}>☝️</div>
            <div>児童を選択してください</div>
            <div style={{fontSize:12,marginTop:4}}>先に「請求一覧」でデータを生成してください</div>
          </div>
      }
    </div>}

    {/* ===== 月次集計タブ ===== */}
    {tab==="summary"&&<div>
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>📊 {selMonth} 月次集計{fac?` — ${fac.name}`:""}</div>
        {[
          {lb:"利用延べ日数", val:`${monthBilling.reduce((s,b)=>s+(b.service_days||0),0)}日`},
          {lb:"基本報酬合計", val:`${monthBilling.reduce((s,b)=>s+(b.total_base_units||0),0).toLocaleString()}単位`},
          {lb:"加算合計", val:`${monthBilling.reduce((s,b)=>s+getChildAddUnits(b.child_id),0).toLocaleString()}単位`},
          {lb:"総請求単位数", val:`${facilityTotalUnits.toLocaleString()}単位`, bold:true, color:"var(--tl)"},
          {lb:"概算請求額", val:`¥${facilityTotalYen.toLocaleString()}`, bold:true, color:"var(--tl)"},
          {lb:"利用者負担上限合計", val:`¥${monthBilling.reduce((s,b)=>s+Number(b.max_burden||0),0).toLocaleString()}`},
        ].map((r,i)=>(
          <div key={i} style={{display:"flex",justifyContent:"space-between",padding:"8px 0",borderBottom:"1px solid var(--bg2)"}}>
            <span style={{fontSize:13,color:"var(--tx3)"}}>{r.lb}</span>
            <span style={{fontSize:14,fontWeight:r.bold?700:400,color:r.color||"var(--tx)"}}>{r.val}</span>
          </div>
        ))}
      </div>

      {/* 加算内訳 */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:12}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>➕ 加算種別内訳</div>
        {ADDITION_DEFS.map(def=>{
          const tot = monthAdditions.filter(a=>a.addition_type===def.id).reduce((s,a)=>s+(a.count||0),0);
          if(!tot) return null;
          return <div key={def.id} style={{display:"flex",justifyContent:"space-between",padding:"7px 0",borderBottom:"1px solid var(--bg2)",fontSize:13}}>
            <span>{def.label}</span>
            <span style={{color:"var(--tx3)"}}>{tot}{def.per} = <b style={{color:"var(--tl)"}}>{(def.unit*tot).toLocaleString()}</b>単位</span>
          </div>;
        }).filter(Boolean)}
        {monthAdditions.length===0&&<div style={{color:"var(--tx3)",fontSize:12,textAlign:"center",padding:10}}>加算なし</div>}
      </div>

      {/* 児童別明細 */}
      <div style={{fontWeight:700,fontSize:14,marginBottom:8}}>👦 児童別明細</div>
      {monthBilling.map(b=>{
        const addU = getChildAddUnits(b.child_id);
        const totU = (b.total_base_units||0)+addU;
        const st = BILLING_STATUS_DEF[b.status]||BILLING_STATUS_DEF.draft;
        return <div key={b.id} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 14px",marginBottom:6}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
            <div>
              <span style={{fontWeight:600,fontSize:13}}>{b.child_name}</span>
              <span style={{fontSize:11,color:st.color,marginLeft:8}}>{st.icon}{st.label}</span>
            </div>
            <span style={{fontWeight:700,color:"var(--tl)",fontSize:13}}>¥{Math.floor(totU*UNIT_PRICE_YEN).toLocaleString()}</span>
          </div>
          <div style={{fontSize:11,color:"var(--tx3)",marginTop:3}}>
            {b.service_days}日×{b.base_unit||584}単位 + 加算{addU}単位 = {totU.toLocaleString()}単位
          </div>
        </div>;
      })}
    </div>}

    {/* ===== 提出管理タブ ===== */}
    {tab==="submit"&&<div>
      {/* ステータス集計 */}
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:8,marginBottom:12}}>
        {Object.entries(BILLING_STATUS_DEF).map(([k,s])=>{
          const cnt = monthBilling.filter(b=>b.status===k).length;
          return <div key={k} style={{background:s.bg,border:`1px solid ${s.color}33`,borderRadius:10,padding:"10px 4px",textAlign:"center"}}>
            <div style={{fontSize:18}}>{s.icon}</div>
            <div style={{fontSize:10,color:s.color,fontWeight:700}}>{s.label}</div>
            <div style={{fontSize:20,fontWeight:700,color:s.color}}>{cnt}</div>
          </div>;
        })}
      </div>

      {isMgr&&<div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
        <button className="bsave" onClick={submitAll}>📤 確定済みをすべて提出済みにする</button>
        <button className="nb" onClick={exportCSV}>📥 請求CSVエクスポート（国保連提出用）</button>
      </div>}

      {/* 提出前チェックリスト */}
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14}}>
        <div style={{fontWeight:700,fontSize:14,marginBottom:10}}>☑️ 提出前チェックリスト</div>
        {[
          {lb:"全件の利用日数を確認した", ok:monthBilling.every(b=>(b.service_days||0)>0)&&monthBilling.length>0},
          {lb:"受給者証番号を全件確認した", ok:monthBilling.length>0&&monthBilling.every(b=>!!b.jukyusha_no)},
          {lb:"加算設定を確認した", ok:monthAdditions.length>0},
          {lb:"全件を確定した", ok:monthBilling.length>0&&monthBilling.every(b=>b.status!=="draft")},
          {lb:"請求前チェック（自動）を実施した", ok:false},
        ].map((item,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:10,padding:"9px 0",borderBottom:"1px solid var(--bg2)",fontSize:13}}>
            <span style={{fontSize:16}}>{item.ok?"✅":"⬜"}</span>
            <span style={{color:item.ok?"var(--gr)":"var(--tx)"}}>{item.lb}</span>
          </div>
        ))}
      </div>
    </div>}
  </div>;
}

// ==================== 個別支援計画 AI統合システム ====================
// 5領域・アセスメント・モニタリング・AI補助文章生成を統合管理
// ※AIは補助のみ。提案は必ず人間が確認・修正してから保存する。

const FIVE_DOMAINS = ["健康・生活","運動・感覚","認知・行動","言語・コミュニケーション","人間関係・社会性"];
const FIVE_DOMAIN_ICONS = ["🏥","🏃","🧠","💬","👫"];
const PLAN_STATUS_DEF = {
  draft:    {label:"下書き",   color:"var(--tx3)", bg:"var(--bg2)"},
  active:   {label:"実施中",   color:"var(--gr)",  bg:"rgba(44,170,96,0.1)"},
  review:   {label:"見直し中", color:"var(--ac)",  bg:"rgba(255,160,0,0.1)"},
  completed:{label:"終了",     color:"var(--tl)",  bg:"rgba(58,160,216,0.08)"},
};
const EMPTY_FIVE_DOMAIN = () => Object.fromEntries(FIVE_DOMAINS.map(d=>[d,{challenge:"",support:"",goal:"",evaluation:""}]));
const EMPTY_PLAN_FORM = () => ({
  plan_type:"放課後等デイサービス", start_date:"", end_date:"",
  long_term_goal:"", short_term_goal:"", support_content:"",
  parent_request:"", school_request:"", monitoring_summary:"",
  five_domain_support: EMPTY_FIVE_DOMAIN(), status:"draft",
});
const EMPTY_ASSESS = () => ({
  home_situation:"", school_situation:"", difficulties:"", strengths:"",
  emotional:"", communication:"", group_participation:"",
  sensory_characteristics:"", behavioral_characteristics:"",
});

function SupportPlanScreen({user, store, onBack}){
  const facilityId = user.selectedFacilityId;
  const myUsers = store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);

  // ── 状態 ──
  const [selChild, setSelChild] = useState(null);
  const [tab, setTab] = useState("list"); // list|plan|assessment|monitoring
  const [editId, setEditId] = useState(null); // 編集中の計画ID
  const [domainTab, setDomainTab] = useState(0); // 5領域の選択インデックス
  const [planForm, setPlanForm] = useState(EMPTY_PLAN_FORM());
  const [assessForm, setAssessForm] = useState(EMPTY_ASSESS());
  const [aiLoading, setAiLoading] = useState(""); // どのフィールドでAI生成中か
  const [aiSugg, setAiSugg] = useState({}); // field → 提案文字列
  const [ocrLoading, setOcrLoading] = useState(false);
  const [ocrResult, setOcrResult] = useState(null);
  const [ocrMode, setOcrMode] = useState("isp_draft");
  const [saving, setSaving] = useState(false);
  const [expandedPlanId, setExpandedPlanId] = useState(null);
  const fileRef = useRef();

  // 選択児童の計画一覧（バージョン降順）
  const childPlans = selChild
    ? (store.supportPlans||[]).filter(p=>p.child_id===selChild.id).sort((a,b)=>(b.version||0)-(a.version||0))
    : [];

  // 計画編集開始
  const startEdit = plan => {
    setEditId(plan.id);
    setPlanForm({
      plan_type:plan.plan_type||"放課後等デイサービス",
      start_date:plan.start_date||"", end_date:plan.end_date||"",
      long_term_goal:plan.long_term_goal||"", short_term_goal:plan.short_term_goal||"",
      support_content:plan.support_content||"", parent_request:plan.parent_request||"",
      school_request:plan.school_request||"", monitoring_summary:plan.monitoring_summary||"",
      five_domain_support:plan.five_domain_support||EMPTY_FIVE_DOMAIN(),
      status:plan.status||"draft",
    });
    setTab("plan");
  };

  // 新規計画
  const startNew = () => {
    setEditId(null);
    setPlanForm(EMPTY_PLAN_FORM());
    setAiSugg({});
    setTab("plan");
  };

  // 計画保存
  const savePlan = () => {
    if(!selChild){alert("利用者を選択してください");return;}
    if(!planForm.long_term_goal.trim()){alert("長期目標を入力してください");return;}
    setSaving(true);
    if(editId){
      store.updSupportPlan(editId,planForm,user.staffId||"",user.displayName||"","計画更新");
    } else {
      const latestVer = Math.max(0,...childPlans.map(p=>p.version||0));
      store.addSupportPlan({
        id:genId(), child_id:selChild.id, child_name:selChild.name,
        facility_id:facilityId, ...planForm,
        version:latestVer+1, created_by:user.displayName||"",
        created_at:new Date().toISOString(), updated_at:new Date().toISOString(),
      });
    }
    setSaving(false);
    setEditId(null);
    setTab("list");
    store.showToast("計画を保存しました","success");
  };

  // ── AI文章生成 ──
  const generateAI = async field => {
    if(!selChild){alert("利用者を選択してください");return;}
    setAiLoading(field);
    try {
      const resp = await fetch("/api/isp-ai",{
        method:"POST", headers:{"Content-Type":"application/json"},
        body:JSON.stringify({
          mode:"generate", field,
          childName:selChild.name, childAge:selChild.age||"",
          assessmentData:assessForm, planForm,
          serviceRecords:(store.serviceRecs||[]).filter(r=>r.child_id===selChild.id).slice(-10),
        })
      });
      const d = await resp.json();
      if(d.success&&d.suggestion) setAiSugg(p=>({...p,[field]:d.suggestion}));
      else alert("AI生成エラー: "+(d.error||"不明"));
    } catch(e){alert("通信エラー: "+e.message);}
    setAiLoading("");
  };

  // AI提案を採用（フォームに反映）
  const applyAI = field => {
    if(!aiSugg[field]) return;
    if(field==="monitoring_summary") setPlanForm(p=>({...p,monitoring_summary:aiSugg[field]}));
    else setPlanForm(p=>({...p,[field]:aiSugg[field]}));
    setAiSugg(p=>({...p,[field]:null}));
    store.showToast("AI提案を反映しました（必ず内容を確認してください）","success");
  };

  // 5領域フィールド更新
  const updDomain = (domain, key, val) => {
    setPlanForm(p=>({...p,five_domain_support:{...p.five_domain_support,[domain]:{...(p.five_domain_support[domain]||{}),[key]:val}}}));
  };

  // ── OCR（紙資料読み取り）──
  const handleOcrFile = async e => {
    const file = e.target.files?.[0];
    if(!file) return;
    // 送信前に縮小するので上限は50MB（旧5MBはiPhone写真を弾いていた）
    if(!checkFileSize(file, COMPRESSED_FILE_SIZE_MB)) { e.target.value=""; return; }
    setOcrLoading(true);
    try {
      // ★ 生の readAsDataURL では原寸base64がそのまま /api/ocr に送られ 413 になる。
      //   maxPx=2000: 計画書・モニタリング記録の細かい文字を残せる解像度。
      const prepared = await _ocrPrepare(file, {maxPx:2000, quality:0.85});
      const resp = await fetch("/api/ocr",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({imageBase64:prepared.base64,mediaType:prepared.mediaType,mode:ocrMode})});
      // ★ resp.json() を直接呼ばない：413(text/plain)等でSafariが不可解な例外を投げる
      const d = await _ocrReadJson(resp);
      if(d.success&&d.data) setOcrResult(d.data);
      else alert("OCR結果の解析: "+(d.error||"読み取れませんでした。もう一度撮影してください。"));
    } catch(e){
      console.warn("[計画書OCR] 失敗:", e?.stage||"", e?.message||e);
      alert(`${e?.stage||"OCR"}: ${e?.message||"エラーが発生しました"}`);
    } finally {
      setOcrLoading(false);
      if(fileRef.current) fileRef.current.value="";
    }
  };

  // OCR結果をフォームに反映（候補表示後に確認してから）
  const applyOcr = () => {
    if(!ocrResult) return;
    const r = ocrResult;
    setPlanForm(p=>({
      ...p,
      long_term_goal:     r.longTermGoal||r.long_term_goal||p.long_term_goal,
      short_term_goal:    r.shortTermGoal||r.short_term_goal||p.short_term_goal,
      support_content:    r.supportPolicy||r.support_content||p.support_content,
      parent_request:     r.parentNeeds||r.parent_request||p.parent_request,
      monitoring_summary: r.monitoringInterval||r.monitoring_summary||p.monitoring_summary,
    }));
    setOcrResult(null);
    store.showToast("OCR内容を反映しました。内容を確認してから保存してください","success");
  };

  // ── モニタリング：出席率計算 ──
  const getAttendRate = plan => {
    if(!selChild||!plan?.start_date) return null;
    const start = new Date(plan.start_date);
    const end = plan.end_date ? new Date(plan.end_date) : new Date();
    let planned=0, attended=0;
    for(let d=new Date(start); d<=end; d.setDate(d.getDate()+1)){
      const ds=d.toISOString().slice(0,10);
      const s=store.getAtt(selChild.id,ds);
      if(s==="予定"||s==="出席") planned++;
      if(s==="出席") attended++;
    }
    return planned>0?Math.round(attended/planned*100):null;
  };

  // ── 印刷 ──
  const printPlan = plan => {
    if(!plan||!selChild) return;
    const dom = plan.five_domain_support||{};
    const html=`<!DOCTYPE html><html><head><meta charset="UTF-8"/><style>
body{font-family:'Noto Sans JP',sans-serif;font-size:9pt;margin:15mm;}
h1{font-size:14pt;text-align:center;border-bottom:2px solid #333;padding-bottom:6px;}
h2{font-size:10pt;background:#e8f0ff;padding:4px 8px;margin:12px 0 6px;}
h3{font-size:9pt;color:#555;margin:8px 0 3px;}
table{width:100%;border-collapse:collapse;margin-bottom:10px;}
th,td{border:1px solid #ccc;padding:4px 6px;font-size:8.5pt;vertical-align:top;}
th{background:#f0f4ff;font-weight:700;width:22%;}
.domain-table th{background:#f5f5f5;width:18%;}
p{margin:0 0 4px;line-height:1.7;}
.meta{color:#666;font-size:8pt;margin-bottom:10px;}
</style></head><body>
<h1>個別支援計画書</h1>
<p class="meta">施設: ${FACILITIES.find(f=>f.id===selChild.facilityId)?.name||""} ／ 利用者: ${selChild.name} ／ バージョン: ${plan.version||1} ／ 作成: ${plan.created_by||""} ／ 作成日: ${(plan.created_at||"").slice(0,10)}</p>
<table><tr><th>計画種別</th><td>${plan.plan_type||""}</td><th>開始日</th><td>${plan.start_date||""}</td></tr>
<tr><th>終了日</th><td>${plan.end_date||""}</td><th>ステータス</th><td>${PLAN_STATUS_DEF[plan.status]?.label||plan.status||""}</td></tr>
</table>
<h2>目標</h2>
<table><tr><th>長期目標</th><td>${plan.long_term_goal||""}</td></tr>
<tr><th>短期目標</th><td>${plan.short_term_goal||""}</td></tr>
<tr><th>支援内容</th><td>${plan.support_content||""}</td></tr></table>
<h2>5領域別支援計画</h2>
${FIVE_DOMAINS.map(d=>{const f=dom[d]||{};return `<h3>■ ${d}</h3>
<table class="domain-table"><tr><th>課題</th><td>${f.challenge||""}</td></tr>
<tr><th>支援内容</th><td>${f.support||""}</td></tr>
<tr><th>目標</th><td>${f.goal||""}</td></tr>
<tr><th>評価</th><td>${f.evaluation||""}</td></tr></table>`;}).join("")}
<h2>保護者・学校要望</h2>
<table><tr><th>保護者要望</th><td>${plan.parent_request||""}</td></tr>
<tr><th>学校要望</th><td>${plan.school_request||""}</td></tr></table>
${plan.monitoring_summary?`<h2>モニタリング要約</h2><p>${plan.monitoring_summary}</p>`:""}
<div style="margin-top:20px;font-size:7.5pt;color:#999">印刷: ${new Date().toLocaleString("ja-JP")} ／ このドキュメントは機密情報です</div>
</body></html>`;
    const w=window.open("","_blank");if(!w){alert("ポップアップがブロックされています。許可してから再実行してください。");return;}w.document.write(html);w.document.close();w.print();
  };

  // ── AI文章フィールド共通UI ──
  const AiField = ({label, field, rows=3, placeholder=""}) => (
    <div style={{marginBottom:14}}>
      <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:4}}>
        <div className="slbl" style={{margin:0,flex:1}}>{label}</div>
        <button style={{fontSize:10,padding:"3px 10px",borderRadius:8,border:"1px solid var(--tl)",background:"rgba(58,160,216,0.1)",color:"var(--tl)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,whiteSpace:"nowrap"}}
          onClick={()=>generateAI(field)} disabled={!!aiLoading}>
          {aiLoading===field?"⏳ 生成中...":"🤖 AI提案"}
        </button>
      </div>
      {/* AI提案プレビュー（確認必須） */}
      {aiSugg[field]&&<div style={{marginBottom:8,padding:"10px 12px",background:"rgba(58,160,216,0.07)",border:"1.5px solid var(--tl)",borderRadius:10}}>
        <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",marginBottom:4}}>🤖 AI提案（確認してから採用してください）</div>
        <div style={{fontSize:12,color:"var(--tx)",lineHeight:1.7,whiteSpace:"pre-wrap",marginBottom:8}}>{aiSugg[field]}</div>
        <div style={{display:"flex",gap:8}}>
          <button style={{flex:1,padding:"6px",borderRadius:8,border:"none",background:"var(--tl)",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>applyAI(field)}>✅ 採用する</button>
          <button style={{flex:1,padding:"6px",borderRadius:8,border:"1px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>setAiSugg(p=>({...p,[field]:null}))}>✕ 破棄</button>
        </div>
      </div>}
      <textarea className="fta" rows={rows} value={planForm[field]||""}
        onChange={e=>setPlanForm(p=>({...p,[field]:e.target.value}))}
        placeholder={placeholder}
        style={{resize:"vertical"}}/>
    </div>
  );

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">📄 個別支援計画</div>
    </div>

    {/* 利用者選択 */}
    <div style={{marginBottom:12}}>
      <div className="slbl">利用者</div>
      <select className="fsm" style={{width:"100%",fontSize:14,padding:"10px 12px"}}
        value={selChild?.id||""} onChange={e=>{
          const u=myUsers.find(x=>x.id===e.target.value)||null;
          setSelChild(u);setTab("list");setEditId(null);
        }}>
        <option value="">-- 利用者を選択してください --</option>
        {myUsers.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
      </select>
    </div>

    {!selChild&&<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
      <div style={{fontSize:32,marginBottom:10}}>📄</div>利用者を選択してください
    </div>}

    {selChild&&<>
      {/* タブ切替 */}
      <div style={{display:"flex",gap:0,marginBottom:14,borderRadius:10,overflow:"hidden",border:"1.5px solid var(--bd)"}}>
        {[{k:"list",l:"📋 計画一覧"},{k:"plan",l:"✏️ 計画作成"},{k:"assessment",l:"📝 アセスメント"},{k:"monitoring",l:"📊 モニタリング"}].map(t=>(
          <button key={t.k} style={{flex:1,padding:"9px 2px",border:"none",background:tab===t.k?"var(--tl)":"var(--wh)",color:tab===t.k?"#fff":"var(--tx3)",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",whiteSpace:"nowrap"}}
            onClick={()=>setTab(t.k)}>{t.l}</button>
        ))}
      </div>

      {/* ══════ 計画一覧タブ ══════ */}
      {tab==="list"&&<>
        <button style={{width:"100%",padding:"12px",borderRadius:10,border:"1.5px dashed var(--tl)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",marginBottom:14}}
          onClick={startNew}>＋ 新しい計画を作成</button>

        {childPlans.length===0&&<div style={{textAlign:"center",padding:"40px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
          まだ計画がありません。「新しい計画を作成」から始めてください。
        </div>}

        {childPlans.map(plan=>{
          const st=PLAN_STATUS_DEF[plan.status]||PLAN_STATUS_DEF.draft;
          const isOpen=expandedPlanId===plan.id;
          const rate=getAttendRate(plan);
          return <div key={plan.id} style={{background:"var(--wh)",border:`1.5px solid ${plan.status==="active"?"var(--gr)":"var(--bd)"}`,borderRadius:12,marginBottom:10,overflow:"hidden"}}>
            <div onClick={()=>setExpandedPlanId(isOpen?null:plan.id)}
              style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",cursor:"pointer",background:st.bg,userSelect:"none"}}>
              <div style={{flex:1}}>
                <div style={{fontWeight:700,fontSize:14,color:"var(--tx)"}}>{plan.plan_type||"個別支援計画"} <span style={{fontSize:11,color:"var(--tx3)"}}>v{plan.version||1}</span></div>
                <div style={{fontSize:11,color:"var(--tx3)",marginTop:2}}>
                  {plan.start_date&&<span style={{marginRight:8}}>{plan.start_date} 〜 {plan.end_date||"未定"}</span>}
                  {rate!==null&&<span style={{color:"var(--tl)",fontWeight:700}}>出席率 {rate}%</span>}
                </div>
              </div>
              <div style={{padding:"4px 10px",borderRadius:20,border:`1.5px solid ${st.color}`,color:st.color,fontSize:11,fontWeight:700,flexShrink:0}}>{st.label}</div>
              <div style={{color:"var(--tx3)",fontSize:14}}>{isOpen?"▲":"▼"}</div>
            </div>
            {isOpen&&<div style={{borderTop:"1px solid var(--bd)",padding:"12px 14px"}}>
              {plan.long_term_goal&&<div style={{marginBottom:8}}><span style={{fontSize:11,color:"var(--tx3)"}}>長期目標：</span><span style={{fontSize:12,color:"var(--tx)"}}>{plan.long_term_goal}</span></div>}
              {plan.short_term_goal&&<div style={{marginBottom:10}}><span style={{fontSize:11,color:"var(--tx3)"}}>短期目標：</span><span style={{fontSize:12,color:"var(--tx)"}}>{plan.short_term_goal}</span></div>}
              <div style={{display:"flex",gap:8}}>
                <button style={{flex:1,padding:"9px",borderRadius:9,border:"1.5px solid var(--tl)",background:"rgba(58,160,216,0.08)",color:"var(--tl)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                  onClick={()=>startEdit(plan)}>✏️ 編集</button>
                <button style={{flex:1,padding:"9px",borderRadius:9,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                  onClick={()=>printPlan(plan)}>🖨️ 印刷</button>
              </div>
            </div>}
          </div>;
        })}
      </>}

      {/* ══════ 計画作成/編集タブ ══════ */}
      {tab==="plan"&&<>
        <div style={{background:"rgba(58,160,216,0.06)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:10,padding:"8px 14px",marginBottom:14,fontSize:11,color:"var(--tx2)",lineHeight:1.7}}>
          📌 AI提案は参考のみです。必ず内容を確認・修正してから保存してください。
        </div>

        {/* 基本情報 */}
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:12}}>📋 基本情報</div>
          <div className="slbl">計画種別</div>
          <select className="fsm" style={{width:"100%",marginBottom:10}} value={planForm.plan_type} onChange={e=>setPlanForm(p=>({...p,plan_type:e.target.value}))}>
            {["放課後等デイサービス","児童発達支援","保育所等訪問支援"].map(s=><option key={s} value={s}>{s}</option>)}
          </select>
          <div style={{display:"flex",gap:8,marginBottom:10}}>
            <div style={{flex:1}}><div className="slbl">開始日</div><input type="date" className="fi" value={planForm.start_date} onChange={e=>setPlanForm(p=>({...p,start_date:e.target.value}))}/></div>
            <div style={{flex:1}}><div className="slbl">終了日</div><input type="date" className="fi" value={planForm.end_date} onChange={e=>setPlanForm(p=>({...p,end_date:e.target.value}))}/></div>
          </div>
          <div className="slbl">ステータス</div>
          <select className="fsm" style={{width:"100%"}} value={planForm.status} onChange={e=>setPlanForm(p=>({...p,status:e.target.value}))}>
            {Object.entries(PLAN_STATUS_DEF).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
          </select>
        </div>

        {/* 目標・支援内容（AI補助） */}
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:12}}>🎯 目標・支援内容</div>
          <AiField label="長期目標 *" field="long_term_goal" rows={3} placeholder="例：地域の中で自分らしく生活できるようになる"/>
          <AiField label="短期目標" field="short_term_goal" rows={3} placeholder="例：友達に自分から挨拶ができるようになる"/>
          <AiField label="支援内容" field="support_content" rows={4} placeholder="具体的な支援方法・手順"/>
        </div>

        {/* 5領域別支援計画 */}
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:12}}>🏗️ 5領域別支援計画</div>
          {/* 領域タブ */}
          <div style={{display:"flex",gap:4,marginBottom:14,overflowX:"auto",paddingBottom:4}}>
            {FIVE_DOMAINS.map((d,i)=>(
              <button key={d} style={{padding:"6px 10px",borderRadius:8,border:`1.5px solid ${domainTab===i?"var(--tl)":"var(--bd)"}`,background:domainTab===i?"rgba(58,160,216,0.1)":"var(--bg)",color:domainTab===i?"var(--tl)":"var(--tx3)",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",whiteSpace:"nowrap",flexShrink:0}}
                onClick={()=>setDomainTab(i)}>
                {FIVE_DOMAIN_ICONS[i]} {d}
              </button>
            ))}
          </div>
          {/* 選択中の領域フォーム */}
          {(()=>{
            const d=FIVE_DOMAINS[domainTab];
            const f=planForm.five_domain_support[d]||{};
            return <div>
              {[{key:"challenge",label:"課題",ph:"この領域での困りごと・課題"},{key:"support",label:"支援内容",ph:"具体的な支援方法"},{key:"goal",label:"目標",ph:"この領域での達成目標"},{key:"evaluation",label:"評価",ph:"評価方法・基準"}].map(item=>(
                <div key={item.key} style={{marginBottom:10}}>
                  <div className="slbl">{item.label}</div>
                  <textarea className="fta" rows={2} value={f[item.key]||""} onChange={e=>updDomain(d,item.key,e.target.value)} placeholder={item.ph} style={{resize:"vertical"}}/>
                </div>
              ))}
            </div>;
          })()}
        </div>

        {/* 保護者・学校要望 */}
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:12}}>🏠 保護者・学校からの要望</div>
          <div className="slbl">保護者の要望</div>
          <textarea className="fta" rows={3} value={planForm.parent_request} onChange={e=>setPlanForm(p=>({...p,parent_request:e.target.value}))} placeholder="保護者からの要望・ニーズ"/>
          <div className="slbl" style={{marginTop:10}}>学校からの情報・要望</div>
          <textarea className="fta" rows={3} value={planForm.school_request} onChange={e=>setPlanForm(p=>({...p,school_request:e.target.value}))} placeholder="学校担任からの情報・連携事項"/>
        </div>

        {/* OCR読み込み */}
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
          <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:10}}>📷 紙資料から読み取り（OCR）</div>
          <div className="slbl">資料の種類</div>
          <select className="fsm" style={{width:"100%",marginBottom:10}} value={ocrMode} onChange={e=>setOcrMode(e.target.value)}>
            <option value="isp_draft">相談支援原案</option>
            <option value="monitoring_memo">モニタリングメモ</option>
            <option value="soudan">相談支援計画書（詳細）</option>
          </select>
          <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleOcrFile}/>
          <button style={{width:"100%",padding:"12px",borderRadius:10,border:"1.5px dashed var(--tl)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>fileRef.current.click()} disabled={ocrLoading}>
            {ocrLoading?"⏳ 読み取り中...":"📷 撮影して読み取る"}
          </button>
          {/* OCR結果プレビュー */}
          {ocrResult&&<div style={{marginTop:12,padding:"12px",background:"rgba(44,170,96,0.07)",border:"1.5px solid var(--gr)",borderRadius:10}}>
            <div style={{fontSize:11,fontWeight:700,color:"var(--gr)",marginBottom:8}}>✅ 読み取り完了（確認してから反映してください）</div>
            {Object.entries(ocrResult).filter(([,v])=>v&&typeof v==="string").slice(0,6).map(([k,v])=>(
              <div key={k} style={{fontSize:11,color:"var(--tx2)",marginBottom:4,lineHeight:1.5}}>
                <span style={{color:"var(--tx3)",marginRight:6}}>{k}：</span>{String(v).slice(0,80)}{String(v).length>80?"...":""}
              </div>
            ))}
            <div style={{display:"flex",gap:8,marginTop:10}}>
              <button style={{flex:1,padding:"8px",borderRadius:8,border:"none",background:"var(--gr)",color:"#fff",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                onClick={applyOcr}>✅ フォームに反映</button>
              <button style={{flex:1,padding:"8px",borderRadius:8,border:"1px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                onClick={()=>setOcrResult(null)}>✕ 破棄</button>
            </div>
          </div>}
        </div>

        {/* 保存 */}
        <button className="bsave" style={{width:"100%",fontSize:15,padding:"14px"}} onClick={savePlan} disabled={saving}>
          {saving?"保存中...":`💾 ${editId?"更新":"計画を保存"}する`}
        </button>
        <div style={{fontSize:11,color:"var(--tx3)",textAlign:"center",marginTop:8}}>保存時に変更履歴が記録されます</div>
      </>}

      {/* ══════ アセスメントタブ ══════ */}
      {tab==="assessment"&&<>
        <div style={{background:"rgba(255,160,0,0.06)",border:"1px solid rgba(255,160,0,0.25)",borderRadius:10,padding:"8px 14px",marginBottom:14,fontSize:11,color:"var(--tx2)"}}>
          📝 アセスメント情報はAI文章生成の参考データとして使われます
        </div>
        <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px"}}>
          {[
            {key:"home_situation",label:"🏠 家庭状況",ph:"家族構成、生活リズム、家庭での様子など"},
            {key:"school_situation",label:"🏫 学校状況",ph:"学校での様子、担任からの情報など"},
            {key:"difficulties",label:"😟 困りごと",ph:"現在の主な困りごと・課題"},
            {key:"strengths",label:"💪 強み・得意なこと",ph:"好きなこと、得意なこと、強みなど"},
            {key:"emotional",label:"💗 感情面",ph:"感情の表現・コントロールの様子"},
            {key:"communication",label:"💬 コミュニケーション",ph:"言語・非言語コミュニケーションの様子"},
            {key:"group_participation",label:"👥 集団参加",ph:"集団での活動・参加の様子"},
            {key:"sensory_characteristics",label:"👁️ 感覚特性",ph:"感覚過敏・鈍麻など感覚面の特性"},
            {key:"behavioral_characteristics",label:"🔄 行動特性",ph:"こだわり・反復行動・その他行動面の特性"},
          ].map(f=>(
            <div key={f.key} style={{marginBottom:12}}>
              <div className="slbl">{f.label}</div>
              <textarea className="fta" rows={2} value={assessForm[f.key]||""} onChange={e=>setAssessForm(p=>({...p,[f.key]:e.target.value}))} placeholder={f.ph} style={{resize:"vertical"}}/>
            </div>
          ))}
          <button className="bsave" style={{width:"100%"}} onClick={()=>{
            // アセスメントをサポートプランに紐づけてSupabaseに保存
            if(!selChild){alert("利用者を選択してください");return;}
            sbSave("assessments",{id:selChild.id+"_assess_"+Date.now(),user_id:selChild.id,facility_id:facilityId,data:assessForm,created_at:new Date().toISOString()});
            store.showToast("アセスメントを保存しました","success");
          }}>💾 アセスメントを保存</button>
        </div>
      </>}

      {/* ══════ モニタリングタブ ══════ */}
      {tab==="monitoring"&&<>
        {(()=>{
          const activePlan=childPlans.find(p=>p.status==="active")||childPlans[0];
          const rate=activePlan?getAttendRate(activePlan):null;
          // 最近の実績記録（活動候補）
          const recentRecs=(store.serviceRecs||[]).filter(r=>r.child_id===selChild.id).slice(-20);
          const legacySvc=store.recs.filter(r=>r.type==="service"&&r.userId===selChild.id).slice(-5);
          return <>
            {/* 出席率カード */}
            {activePlan&&<div style={{background:"var(--wh)",border:`1.5px solid ${rate!==null?(rate>=80?"var(--gr)":rate>=60?"var(--ac)":"var(--ro)"):"var(--bd)"}`,borderRadius:12,padding:"16px",marginBottom:14}}>
              <div style={{display:"flex",alignItems:"center",gap:14}}>
                <div style={{textAlign:"center"}}>
                  <div style={{fontSize:40,fontWeight:800,color:rate!==null?(rate>=80?"var(--gr)":rate>=60?"var(--ac)":"var(--ro)"):"var(--tx3)"}}>{rate!==null?rate+"%":"--"}</div>
                  <div style={{fontSize:11,color:"var(--tx3)"}}>出席率</div>
                </div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:13,color:"var(--tx)"}}>{activePlan.plan_type||"個別支援計画"} v{activePlan.version||1}</div>
                  <div style={{fontSize:11,color:"var(--tx3)",marginTop:3}}>{activePlan.start_date} 〜 {activePlan.end_date||"進行中"}</div>
                  <div style={{fontSize:11,color:"var(--tx2)",marginTop:4,lineHeight:1.5}}>
                    {rate!==null&&(rate>=80?"✅ 良好":"⚠️ 出席率が低下しています")}
                  </div>
                </div>
              </div>
            </div>}

            {/* AI要約生成 */}
            <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
              <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:10}}>📊 モニタリング要約</div>
              <div style={{display:"flex",gap:8,marginBottom:10}}>
                <button style={{flex:1,padding:"10px",borderRadius:9,border:"1.5px solid var(--tl)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                  onClick={()=>generateAI("monitoring_summary")} disabled={!!aiLoading}>
                  {aiLoading==="monitoring_summary"?"⏳ 生成中...":"🤖 AIで要約を生成"}
                </button>
              </div>
              {aiSugg["monitoring_summary"]&&<div style={{marginBottom:10,padding:"10px 12px",background:"rgba(58,160,216,0.07)",border:"1.5px solid var(--tl)",borderRadius:10}}>
                <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",marginBottom:6}}>🤖 AI提案（確認してから採用してください）</div>
                <div style={{fontSize:12,color:"var(--tx)",lineHeight:1.7,whiteSpace:"pre-wrap",marginBottom:8}}>{aiSugg["monitoring_summary"]}</div>
                <div style={{display:"flex",gap:8}}>
                  <button style={{flex:1,padding:"6px",borderRadius:8,border:"none",background:"var(--tl)",color:"#fff",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                    onClick={()=>{applyAI("monitoring_summary");if(activePlan){store.updSupportPlan(activePlan.id,{monitoring_summary:aiSugg["monitoring_summary"]},user.staffId||"",user.displayName||"","モニタリング要約追加");}}}>
                    ✅ 採用して保存</button>
                  <button style={{flex:1,padding:"6px",borderRadius:8,border:"1px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                    onClick={()=>setAiSugg(p=>({...p,monitoring_summary:null}))}>✕ 破棄</button>
                </div>
              </div>}
              {activePlan?.monitoring_summary&&<div>
                <div className="slbl">保存済みのモニタリング要約</div>
                <div style={{fontSize:12,color:"var(--tx)",lineHeight:1.7,padding:"10px 12px",background:"var(--bg2)",borderRadius:8,whiteSpace:"pre-wrap"}}>{activePlan.monitoring_summary}</div>
              </div>}
            </div>

            {/* 最近の活動記録 */}
            {(recentRecs.length>0||legacySvc.length>0)&&<div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
              <div style={{fontWeight:700,fontSize:13,color:"var(--tx)",marginBottom:10}}>📅 最近の活動記録（実績連携）</div>
              {recentRecs.slice(0,8).map((r,i)=>(
                <div key={r.id||i} style={{display:"flex",gap:8,padding:"6px 0",borderBottom:"1px solid var(--bd)",alignItems:"center"}}>
                  <div style={{fontSize:11,color:"var(--tx3)",width:52,flexShrink:0}}>{(r.visit_date||"").slice(5).replace("-","/")}</div>
                  <div style={{flex:1,fontSize:12,color:"var(--tx)"}}>{r.service_type||"放課後等デイサービス"}</div>
                  <div style={{fontSize:11,color:r.attendance_status==="attended"?"var(--gr)":"var(--ro)",fontWeight:700}}>
                    {{attended:"出席",absent:"欠席",cancelled:"キャンセル",late:"遅刻",early_leave:"早退"}[r.attendance_status]||""}
                  </div>
                </div>
              ))}
              {legacySvc.slice(0,3).map((r,i)=>(
                <div key={r.id||i} style={{display:"flex",gap:8,padding:"6px 0",borderBottom:"1px solid var(--bd)",alignItems:"center"}}>
                  <div style={{fontSize:11,color:"var(--tx3)",width:52,flexShrink:0}}>{(r.time||"").slice(0,10).replace(/\//g,"/").slice(5)}</div>
                  <div style={{flex:1,fontSize:12,color:"var(--tx)"}}>{(r.items||[]).join("・")||"活動記録"}</div>
                  <div style={{fontSize:11,color:"var(--gr)",fontWeight:700}}>出席</div>
                </div>
              ))}
            </div>}
          </>;
        })()}
      </>}
    </>}
  </div>;
}

// ==================== 返戻対応・再請求・月次ロック ====================
// 国保連返戻を受けた後の修正・再請求フローと月次ロック・監査ログを管理する
// ※既存データの削除・上書き禁止。すべての変更は履歴として追記する。

const CLAIM_STATUS = {
  submitted:   {label:"提出済み",   color:"var(--tl)",  bg:"rgba(58,160,216,0.1)",  icon:"📤", next:"returned"},
  returned:    {label:"返戻あり",   color:"var(--ro)",  bg:"rgba(224,56,56,0.1)",   icon:"↩️", next:"correcting"},
  correcting:  {label:"修正中",     color:"var(--ac)",  bg:"rgba(255,160,0,0.1)",   icon:"✏️", next:"corrected"},
  corrected:   {label:"修正完了",   color:"#a78bfa",    bg:"rgba(167,139,250,0.1)", icon:"✅", next:"resubmitted"},
  resubmitted: {label:"再請求済み", color:"var(--gr)",  bg:"rgba(44,170,96,0.1)",   icon:"📬", next:"closed"},
  closed:      {label:"完了",       color:"var(--tx3)", bg:"var(--bg2)",             icon:"🔒", next:null},
};
const CLAIM_STATUS_NEXT_LABEL = {
  submitted:"返戻登録する", returned:"修正開始", correcting:"修正完了にする",
  corrected:"再請求する", resubmitted:"完了にする", closed:null
};
const AUDIT_ACTION_LABEL = {
  status_change:"ステータス変更", lock:"月次ロック", unlock:"ロック解除",
  correction:"内容修正", resubmit:"再請求作成"
};

function ReturnsManagementScreen({user, store, onNav, onBack}){
  const now = new Date();
  const [selFacility, setSelFacility] = useState(user.selectedFacilityId||"f1");
  const [selYear,  setSelYear]  = useState(now.getFullYear());
  const [selMonth, setSelMonth] = useState(now.getMonth()+1);
  const [tab, setTab] = useState("returns"); // returns | deadline | audit
  const [expandedId, setExpandedId] = useState(null);
  const [showAddModal, setShowAddModal] = useState(false);
  const [showUnlockModal, setShowUnlockModal] = useState(false);
  const [unlockReason, setUnlockReason] = useState("");
  const [nextStatusReason, setNextStatusReason] = useState(""); // ステータス変更理由
  const [showStatusModal, setShowStatusModal] = useState(null); // {id, nextStatus}
  // 返戻新規登録フォーム
  const emptyForm = {child_id:"",return_reason:"",target_date:"",target_service:"放課後等デイサービス",correction_deadline:"",memo:""};
  const [form, setForm] = useState(emptyForm);

  const monthStr = `${selYear}-${String(selMonth).padStart(2,"0")}`;
  const isAdmin = user.role==="admin";
  const isMgr = user.role==="manager"||user.role==="admin";
  const locked = store.isMonthLocked(selFacility, monthStr);
  const lockInfo = store.monthlyLocks?.[selFacility+"_"+monthStr];

  // 対象ユーザー一覧
  const facUsers = store.dynUsers.filter(u=>u.active!==false&&(selFacility==="all"||u.facilityId===selFacility));

  // 返戻一覧（この施設・月）
  const returns = (store.claimHistory||[]).filter(r=>r.facility_id===selFacility&&r.service_month===monthStr)
    .sort((a,b)=>new Date(b.created_at||0)-new Date(a.created_at||0));

  // 返戻 期限追跡（施設全体の未解決返戻）
  const allOpenReturns=(store.claimHistory||[]).filter(r=>r.facility_id===selFacility&&r.status==="returned"&&r.correction_deadline)
    .sort((a,b)=>(a.correction_deadline||"")>(b.correction_deadline||"")?1:-1);
  const overdueReturns=allOpenReturns.filter(r=>r.correction_deadline<new Date().toISOString().slice(0,10));
  const soonReturns=allOpenReturns.filter(r=>{
    const d=new Date(r.correction_deadline);const diff=Math.floor((d-now)/(1000*60*60*24));
    return diff>=0&&diff<=14;
  });

  // 返戻CSVエクスポート
  const downloadReturnsCSV=()=>{
    const allFacReturns=isAdmin
      ?(store.claimHistory||[])
      :(store.claimHistory||[]).filter(r=>r.facility_id===selFacility);
    const hd=["施設","対象年月","利用者名","返戻理由","対象日","対象サービス","修正期限","ステータス","再請求日","登録者","登録日","備考"];
    const rows=allFacReturns.map(r=>{
      const facName=FACILITIES.find(f=>f.id===r.facility_id)?.name||r.facility_id;
      const userName=facUsers.find(u=>u.id===r.child_id)?.name||r.child_name||r.child_id;
      return [facName,r.service_month||"",userName,r.return_reason||"",r.target_date||"",r.target_service||"",r.correction_deadline||"",r.status||"",r.resubmitted_at?.slice(0,10)||"",r.created_by||"",r.created_at?.slice(0,10)||"",r.memo||""];
    });
    const csv=[hd,...rows].map(r=>r.map(v=>`"${String(v).replace(/"/g,'""')}"`).join(",")).join("\n");
    const a=document.createElement("a");
    a.href=URL.createObjectURL(new Blob(["﻿"+csv],{type:"text/csv;charset=utf-8;"}));
    a.download=`returns_${new Date().toISOString().slice(0,10)}.csv`;a.click();
  };

  // 監査ログ（この施設）
  const logs = (store.auditLogs||[]).filter(l=>l.facility_id===selFacility)
    .sort((a,b)=>new Date(b.created_at||0)-new Date(a.created_at||0))
    .slice(0,50); // 最新50件

  // サマリー
  const smry = {};
  Object.keys(CLAIM_STATUS).forEach(k=>{ smry[k]=returns.filter(r=>r.status===k).length; });

  // ── 月次ロック ──
  const handleLock = () => {
    if(!window.confirm(`${selYear}年${selMonth}月の請求をロックします。\n確定後は修正にロック解除理由が必要になります。\nよろしいですか？`)) return;
    store.lockMonth(selFacility, monthStr, user.staffId||user.id, user.displayName||"");
  };
  const handleUnlock = () => {
    if(!unlockReason.trim()){alert("ロック解除理由を入力してください");return;}
    store.unlockMonth(selFacility, monthStr, user.staffId||user.id, user.displayName||"", unlockReason.trim());
    setUnlockReason("");setShowUnlockModal(false);
  };

  // ── 返戻新規登録 ──
  const handleAdd = () => {
    if(!form.child_id){alert("利用者を選択してください");return;}
    if(!form.return_reason.trim()){alert("返戻理由を入力してください");return;}
    const rec = {
      id:genId(), facility_id:selFacility, child_id:form.child_id,
      child_name:facUsers.find(u=>u.id===form.child_id)?.name||"",
      service_month:monthStr, status:"returned",
      return_reason:form.return_reason, target_date:form.target_date||null,
      target_service:form.target_service||null,
      correction_deadline:form.correction_deadline||null,
      memo:form.memo||null,
      created_by:user.displayName||"", created_at:new Date().toISOString(), updated_at:new Date().toISOString(),
    };
    store.addClaimHistory(rec);
    setForm(emptyForm);setShowAddModal(false);
    // 監査ログ
    store.updClaimHistory(rec.id,{status:"returned"},user.staffId||"",user.displayName||"","返戻登録");
  };

  // ── ステータス変更 ──
  const handleStatusChange = () => {
    if(!showStatusModal) return;
    if(!nextStatusReason.trim()&&showStatusModal.nextStatus!=="closed"){alert("変更理由を入力してください");return;}
    const changes = {status:showStatusModal.nextStatus};
    // 再請求時は再請求日を記録
    if(showStatusModal.nextStatus==="resubmitted") changes.resubmitted_at=new Date().toISOString();
    if(showStatusModal.nextStatus==="closed") changes.closed_at=new Date().toISOString();
    store.updClaimHistory(showStatusModal.id,changes,user.staffId||"",user.displayName||"",nextStatusReason.trim()||"ステータス変更");
    setShowStatusModal(null);setNextStatusReason("");
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">↩️ 返戻・再請求管理</div>
    </div>

    {/* ── 条件選択 ── */}
    <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px",marginBottom:14}}>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12,alignItems:"flex-end"}}>
        {isAdmin&&<div style={{flex:"2 1 120px"}}>
          <div className="slbl">施設</div>
          <select className="fsm" style={{width:"100%"}} value={selFacility} onChange={e=>setSelFacility(e.target.value)}>
            {FACILITIES.filter(f=>isAdmin||f.id===user.selectedFacilityId).map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
          </select>
        </div>}
        <div style={{flex:"1 1 90px"}}>
          <div className="slbl">年</div>
          <select className="fsm" style={{width:"100%"}} value={selYear} onChange={e=>setSelYear(+e.target.value)}>
            {[2024,2025,2026,2027].map(y=><option key={y} value={y}>{y}年</option>)}
          </select>
        </div>
        <div style={{flex:"1 1 70px"}}>
          <div className="slbl">月</div>
          <select className="fsm" style={{width:"100%"}} value={selMonth} onChange={e=>setSelMonth(+e.target.value)}>
            {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
          </select>
        </div>
      </div>

      {/* 月次ロック状態 */}
      <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",borderRadius:10,background:locked?"rgba(220,38,38,0.06)":"rgba(44,170,96,0.08)",border:`1.5px solid ${locked?"var(--ro)":"var(--gr)"}`}}>
        <div style={{fontSize:20}}>{locked?"🔒":"🔓"}</div>
        <div style={{flex:1}}>
          <div style={{fontWeight:700,fontSize:13,color:locked?"var(--ro)":"var(--gr)"}}>
            {locked?`${selYear}/${selMonth} — 月次ロック中（編集不可）`:`${selYear}/${selMonth} — 編集可能`}
          </div>
          {locked&&lockInfo&&<div style={{fontSize:11,color:"var(--tx3)"}}>
            確定: {lockInfo.locked_by} / {lockInfo.locked_at?.slice(0,10)}
          </div>}
        </div>
        {isMgr&&(locked
          ?<button style={{padding:"7px 14px",borderRadius:8,border:"1.5px solid var(--ro)",background:"rgba(224,56,56,0.1)",color:"var(--ro)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>setShowUnlockModal(true)}>🔓 解除</button>
          :<button style={{padding:"7px 14px",borderRadius:8,border:"1.5px solid var(--gr)",background:"rgba(44,170,96,0.1)",color:"var(--gr)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={handleLock}>🔒 ロック確定</button>
        )}
      </div>
    </div>

    {/* タブ切替 */}
    <div style={{display:"flex",gap:0,marginBottom:14,borderRadius:10,overflow:"hidden",border:"1.5px solid var(--bd)"}}>
      {[
        {key:"returns",label:`↩️ 返戻一覧`},
        {key:"deadline",label:`⏰ 期限管理${overdueReturns.length>0?` (${overdueReturns.length}件超過)`:soonReturns.length>0?` (${soonReturns.length}件近迫)`:""}`},
        {key:"audit",label:"📋 監査ログ"},
      ].map(t=>(
        <button key={t.key} style={{flex:1,padding:"10px",border:"none",
          background:tab===t.key?t.key==="deadline"&&overdueReturns.length>0?"var(--ro)":"var(--tl)":"var(--wh)",
          color:tab===t.key?"#fff":"var(--tx3)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",whiteSpace:"nowrap"}}
          onClick={()=>setTab(t.key)}>{t.label}</button>
      ))}
    </div>

    {/* ────── 期限管理タブ ────── */}
    {tab==="deadline"&&<>
      {/* 期限切れアラート */}
      {overdueReturns.length>0&&<div style={{background:"rgba(224,56,56,0.1)",border:"2px solid rgba(224,56,56,0.5)",borderRadius:12,padding:"12px 14px",marginBottom:12}}>
        <div style={{fontSize:13,fontWeight:700,color:"var(--ro)",marginBottom:8}}>🚨 修正期限超過 — {overdueReturns.length}件</div>
        {overdueReturns.map(r=>{
          const daysPast=Math.floor((now-new Date(r.correction_deadline))/(1000*60*60*24));
          const uName=facUsers.find(u=>u.id===r.child_id)?.name||r.child_name||r.child_id;
          return <div key={r.id} style={{background:"rgba(224,56,56,0.06)",border:"1px solid rgba(224,56,56,0.3)",borderRadius:9,padding:"8px 12px",marginBottom:6}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:6}}>
              <div>
                <div style={{fontWeight:700,fontSize:12}}>{uName}</div>
                <div style={{fontSize:11,color:"var(--tx3)"}}>{r.service_month} / {r.return_reason?.slice(0,20)}</div>
              </div>
              <span style={{fontSize:11,fontWeight:700,color:"#fff",background:"var(--ro)",borderRadius:8,padding:"3px 10px",flexShrink:0}}>{daysPast}日超過</span>
            </div>
          </div>;
        })}
      </div>}

      {/* 14日以内期限 */}
      {soonReturns.length>0&&<div style={{background:"rgba(230,160,0,0.08)",border:"1.5px solid rgba(230,160,0,0.4)",borderRadius:12,padding:"12px 14px",marginBottom:12}}>
        <div style={{fontSize:12,fontWeight:700,color:"var(--am)",marginBottom:8}}>⚠️ 修正期限 14日以内 — {soonReturns.length}件</div>
        {soonReturns.map(r=>{
          const daysLeft=Math.floor((new Date(r.correction_deadline)-now)/(1000*60*60*24));
          const uName=facUsers.find(u=>u.id===r.child_id)?.name||r.child_name||r.child_id;
          return <div key={r.id} style={{background:"rgba(230,160,0,0.06)",border:"1px solid rgba(230,160,0,0.3)",borderRadius:9,padding:"8px 12px",marginBottom:6}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",flexWrap:"wrap",gap:6}}>
              <div>
                <div style={{fontWeight:700,fontSize:12}}>{uName}</div>
                <div style={{fontSize:11,color:"var(--tx3)"}}>{r.service_month} / 期限: {r.correction_deadline}</div>
              </div>
              <span style={{fontSize:11,fontWeight:700,color:"var(--am)",background:"rgba(230,160,0,0.2)",borderRadius:8,padding:"3px 10px",flexShrink:0}}>残{daysLeft}日</span>
            </div>
          </div>;
        })}
      </div>}

      {overdueReturns.length===0&&soonReturns.length===0&&<div style={{textAlign:"center",padding:"40px 20px",color:"var(--gr)",background:"rgba(44,170,96,0.06)",borderRadius:12,border:"1px solid rgba(44,170,96,0.25)"}}>
        <div style={{fontSize:32,marginBottom:8}}>✅</div>
        <div style={{fontSize:13,fontWeight:700}}>期限超過・直近期限の返戻はありません</div>
        <div style={{fontSize:11,marginTop:4,color:"var(--tx3)"}}>全{allOpenReturns.length}件の返戻対応が期限内です</div>
      </div>}

      {/* 全未解決返戻一覧 */}
      {allOpenReturns.length>0&&<div style={{marginTop:14}}>
        <div style={{fontWeight:700,fontSize:12,marginBottom:8,color:"var(--tx2)"}}>📋 未解決の返戻 全期限一覧</div>
        <div style={{overflowX:"auto"}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:400}}>
            <thead><tr style={{background:"var(--bg2)"}}>
              {["対象年月","利用者","返戻理由","修正期限","残日数"].map(h=><th key={h} style={{padding:"6px 9px",textAlign:"left",fontSize:10,color:"var(--tx2)",fontWeight:700,borderBottom:"2px solid var(--bd)"}}>{h}</th>)}
            </tr></thead>
            <tbody>{allOpenReturns.map(r=>{
              const dLeft=Math.floor((new Date(r.correction_deadline)-now)/(1000*60*60*24));
              const uName=facUsers.find(u=>u.id===r.child_id)?.name||r.child_name||r.child_id;
              const col=dLeft<0?"var(--ro)":dLeft<=14?"var(--am)":"var(--gr)";
              return <tr key={r.id} style={{borderBottom:"1px solid var(--bd)"}}>
                <td style={{padding:"7px 9px",fontFamily:"'DM Mono',monospace",fontSize:11}}>{r.service_month}</td>
                <td style={{padding:"7px 9px",fontWeight:700}}>{uName}</td>
                <td style={{padding:"7px 9px",color:"var(--tx3)",fontSize:11}}>{r.return_reason?.slice(0,20)}</td>
                <td style={{padding:"7px 9px",fontFamily:"'DM Mono',monospace",fontSize:11}}>{r.correction_deadline||"—"}</td>
                <td style={{padding:"7px 9px",fontWeight:700,color:col}}>{dLeft<0?`${Math.abs(dLeft)}日超過`:dLeft<=14?`残${dLeft}日`:"期限余裕"}</td>
              </tr>;
            })}</tbody>
          </table>
        </div>
      </div>}

      {/* CSV出力 */}
      <button onClick={downloadReturnsCSV}
        style={{width:"100%",marginTop:14,padding:"12px",borderRadius:10,background:"linear-gradient(135deg,#1a4a8a,#2d6ed6)",color:"#fff",fontWeight:700,fontSize:13,border:"none",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>
        📊 返戻一覧 CSVエクスポート
      </button>
    </>}

    {/* ────── 返戻一覧タブ ────── */}
    {tab==="returns"&&<>
      {/* サマリーバー */}
      <div style={{display:"flex",gap:6,marginBottom:14,flexWrap:"wrap"}}>
        {Object.entries(CLAIM_STATUS).map(([key,val])=>smry[key]>0?(
          <div key={key} style={{padding:"5px 12px",borderRadius:20,background:val.bg,border:`1.5px solid ${val.color}`,fontSize:11,fontWeight:700,color:val.color,whiteSpace:"nowrap"}}>
            {val.icon} {val.label} {smry[key]}件
          </div>
        ):null)}
        {returns.length===0&&<div style={{fontSize:12,color:"var(--tx3)"}}>返戻なし — 問題ありません</div>}
      </div>

      {/* CSV出力ボタン */}
      {returns.length>0&&<button onClick={downloadReturnsCSV}
        style={{width:"100%",padding:"10px",borderRadius:10,border:"1.5px solid rgba(58,160,216,0.4)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",marginBottom:10}}>
        📊 この月の返戻 CSVエクスポート
      </button>}

      {/* 返戻登録ボタン */}
      {isMgr&&!locked&&<button style={{width:"100%",padding:"12px",borderRadius:10,border:"1.5px dashed var(--ro)",background:"rgba(224,56,56,0.06)",color:"var(--ro)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",marginBottom:14}}
        onClick={()=>setShowAddModal(true)}>
        ＋ 返戻を登録する
      </button>}
      {locked&&<div style={{textAlign:"center",padding:"10px",fontSize:11,color:"var(--tx3)",marginBottom:10}}>
        🔒 ロック中 — 返戻登録はロック解除後に行えます
      </div>}

      {/* 返戻カード一覧 */}
      {returns.length===0&&<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
        <div style={{fontSize:32,marginBottom:10}}>✅</div>
        {selYear}年{selMonth}月の返戻登録はありません
      </div>}

      {returns.map(rec=>{
        const st=CLAIM_STATUS[rec.status]||CLAIM_STATUS.submitted;
        const isOpen=expandedId===rec.id;
        const nextStatus=st.next;
        const nextLabel=CLAIM_STATUS_NEXT_LABEL[rec.status];
        const userName=facUsers.find(u=>u.id===rec.child_id)?.name||rec.child_name||rec.child_id;
        return <div key={rec.id} style={{background:"var(--wh)",border:`1.5px solid ${st.color}`,borderRadius:12,marginBottom:10,overflow:"hidden"}}>
          {/* ヘッダー */}
          <div onClick={()=>setExpandedId(isOpen?null:rec.id)}
            style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",cursor:"pointer",background:st.bg,userSelect:"none"}}>
            <div style={{fontSize:20,flexShrink:0}}>{st.icon}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:700,fontSize:14,color:"var(--tx)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{userName}</div>
              <div style={{fontSize:11,color:"var(--tx3)",marginTop:1}}>
                {rec.target_date&&<span style={{marginRight:8}}>📅 {rec.target_date}</span>}
                {rec.target_service&&<span>{rec.target_service}</span>}
              </div>
            </div>
            <div style={{padding:"4px 10px",borderRadius:20,border:`1.5px solid ${st.color}`,color:st.color,fontSize:11,fontWeight:700,flexShrink:0,whiteSpace:"nowrap"}}>{st.label}</div>
            <div style={{color:"var(--tx3)",fontSize:14,flexShrink:0}}>{isOpen?"▲":"▼"}</div>
          </div>

          {/* 展開パネル */}
          {isOpen&&<div style={{borderTop:"1px solid var(--bd)"}}>
            <div style={{padding:"12px 14px",borderBottom:"1px solid var(--bd)"}}>
              {[
                {label:"返戻理由",val:rec.return_reason},
                {label:"対象日",  val:rec.target_date},
                {label:"サービス",val:rec.target_service},
                {label:"修正期限",val:rec.correction_deadline},
                {label:"メモ",    val:rec.memo},
                {label:"登録者",  val:rec.created_by},
                {label:"登録日",  val:(rec.created_at||"").slice(0,10)},
                {label:"再請求日",val:rec.resubmitted_at?.slice(0,10)},
              ].filter(f=>f.val).map(f=>(
                <div key={f.label} style={{display:"flex",gap:8,marginBottom:6,fontSize:12}}>
                  <div style={{color:"var(--tx3)",width:64,flexShrink:0}}>{f.label}</div>
                  <div style={{color:"var(--tx)",flex:1,wordBreak:"break-all"}}>{f.val}</div>
                </div>
              ))}
            </div>

            {/* ステータス変更ボタン */}
            {nextStatus&&nextLabel&&isMgr&&<div style={{padding:"10px 14px"}}>
              <button style={{width:"100%",padding:"11px",borderRadius:10,border:"none",background:CLAIM_STATUS[nextStatus]?.color||"var(--tl)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                onClick={()=>{setShowStatusModal({id:rec.id,nextStatus,label:nextLabel});setNextStatusReason("");}}>
                {CLAIM_STATUS[nextStatus]?.icon} {nextLabel} →
              </button>
            </div>}
            {rec.status==="closed"&&<div style={{padding:"10px 14px",textAlign:"center",fontSize:12,color:"var(--tx3)"}}>🔒 この返戻対応は完了しています</div>}
          </div>}
        </div>;
      })}
    </>}

    {/* ────── 監査ログタブ ────── */}
    {tab==="audit"&&<>
      <div style={{fontSize:11,color:"var(--tx3)",marginBottom:10,padding:"8px 12px",background:"var(--bg2)",borderRadius:8}}>
        📋 すべての変更が自動的に記録されています（最新50件表示）
      </div>
      {logs.length===0&&<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
        <div style={{fontSize:32,marginBottom:10}}>📋</div>操作ログがありません
      </div>}
      {logs.map((log,i)=>(
        <div key={log.id||i} style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,marginBottom:8,overflow:"hidden"}}>
          <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px"}}>
            <div style={{fontSize:16,flexShrink:0}}>
              {{lock:"🔒",unlock:"🔓",status_change:"🔄",correction:"✏️",resubmit:"📬"}[log.action_type]||"📝"}
            </div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontSize:12,fontWeight:700,color:"var(--tx)"}}>{AUDIT_ACTION_LABEL[log.action_type]||log.action_type}</div>
              <div style={{fontSize:11,color:"var(--tx3)",marginTop:2}}>
                {log.user_name&&<span style={{marginRight:8}}>👤 {log.user_name}</span>}
                <span>{(log.created_at||"").slice(0,16).replace("T"," ")}</span>
              </div>
              {log.reason&&<div style={{fontSize:11,color:"var(--tx2)",marginTop:2}}>理由：{log.reason}</div>}
            </div>
          </div>
          {/* before/after差分 */}
          {(log.before_data||log.after_data)&&<div style={{padding:"8px 14px",background:"var(--bg2)",borderTop:"1px solid var(--bd)",display:"flex",gap:8,fontSize:10}}>
            {log.before_data&&<div style={{flex:1}}>
              <div style={{color:"var(--ro)",fontWeight:700,marginBottom:2}}>変更前</div>
              <div style={{color:"var(--tx3)",fontFamily:"monospace",wordBreak:"break-all",lineHeight:1.6}}>
                {JSON.stringify(log.before_data,null,0).slice(0,120)}
              </div>
            </div>}
            {log.after_data&&<div style={{flex:1}}>
              <div style={{color:"var(--gr)",fontWeight:700,marginBottom:2}}>変更後</div>
              <div style={{color:"var(--tx3)",fontFamily:"monospace",wordBreak:"break-all",lineHeight:1.6}}>
                {JSON.stringify(log.after_data,null,0).slice(0,120)}
              </div>
            </div>}
          </div>}
        </div>
      ))}
    </>}

    {/* ────── 返戻登録モーダル ────── */}
    {showAddModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"flex-end",justifyContent:"center"}}>
      <div style={{background:"var(--wh)",borderRadius:"18px 18px 0 0",padding:"20px 18px 32px",width:"100%",maxWidth:480,maxHeight:"85vh",overflowY:"auto"}}>
        <div style={{fontWeight:700,fontSize:16,marginBottom:14,color:"var(--tx)"}}>↩️ 返戻を登録する</div>
        <div className="slbl">利用者 *</div>
        <select className="fsm" style={{width:"100%",marginBottom:10}} value={form.child_id} onChange={e=>setForm(p=>({...p,child_id:e.target.value}))}>
          <option value="">-- 選択してください --</option>
          {facUsers.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
        </select>
        <div className="slbl">返戻理由 *</div>
        <textarea className="fta" rows={3} style={{marginBottom:10}} value={form.return_reason} onChange={e=>setForm(p=>({...p,return_reason:e.target.value}))} placeholder="返戻の理由を記入（例：算定誤り、記録不備など）"/>
        <div style={{display:"flex",gap:8,marginBottom:10}}>
          <div style={{flex:1}}>
            <div className="slbl">対象日</div>
            <input type="date" className="fi" value={form.target_date} onChange={e=>setForm(p=>({...p,target_date:e.target.value}))}/>
          </div>
          <div style={{flex:1}}>
            <div className="slbl">修正期限</div>
            <input type="date" className="fi" value={form.correction_deadline} onChange={e=>setForm(p=>({...p,correction_deadline:e.target.value}))}/>
          </div>
        </div>
        <div className="slbl">サービス種別</div>
        <select className="fsm" style={{width:"100%",marginBottom:10}} value={form.target_service} onChange={e=>setForm(p=>({...p,target_service:e.target.value}))}>
          {["放課後等デイサービス","児童発達支援","保育所等訪問支援"].map(s=><option key={s} value={s}>{s}</option>)}
        </select>
        <div className="slbl">メモ</div>
        <textarea className="fta" rows={2} style={{marginBottom:16}} value={form.memo} onChange={e=>setForm(p=>({...p,memo:e.target.value}))} placeholder="備考・経緯など"/>
        <div style={{display:"flex",gap:10}}>
          <button className="bsave" style={{flex:1}} onClick={handleAdd}>登録する</button>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>{setShowAddModal(false);setForm(emptyForm);}}>キャンセル</button>
        </div>
      </div>
    </div>}

    {/* ────── ロック解除モーダル ────── */}
    {showUnlockModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 16px"}}>
      <div style={{background:"var(--wh)",borderRadius:16,padding:"22px 18px",width:"100%",maxWidth:400}}>
        <div style={{fontWeight:700,fontSize:15,marginBottom:6,color:"var(--ro)"}}>🔓 月次ロック解除</div>
        <div style={{fontSize:12,color:"var(--tx2)",marginBottom:14,lineHeight:1.7}}>
          ロック解除は監査ログに記録されます。<br/>解除理由を必ず入力してください。
        </div>
        <div className="slbl">解除理由 *</div>
        <textarea className="fta" rows={3} value={unlockReason} onChange={e=>setUnlockReason(e.target.value)} placeholder="例：返戻対応のため修正が必要、○○の誤り確認のため"/>
        <div style={{display:"flex",gap:10,marginTop:14}}>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"none",background:"var(--ro)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={handleUnlock}>解除する</button>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>{setShowUnlockModal(false);setUnlockReason("");}}>キャンセル</button>
        </div>
      </div>
    </div>}

    {/* ────── ステータス変更モーダル ────── */}
    {showStatusModal&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",zIndex:200,display:"flex",alignItems:"center",justifyContent:"center",padding:"0 16px"}}>
      <div style={{background:"var(--wh)",borderRadius:16,padding:"22px 18px",width:"100%",maxWidth:400}}>
        <div style={{fontWeight:700,fontSize:15,marginBottom:6,color:"var(--tl)"}}>
          {CLAIM_STATUS[showStatusModal.nextStatus]?.icon} {showStatusModal.label}
        </div>
        <div style={{fontSize:12,color:"var(--tx2)",marginBottom:14,lineHeight:1.7}}>
          ステータスを「{CLAIM_STATUS[showStatusModal.nextStatus]?.label}」に変更します。<br/>
          変更理由を入力してください（監査ログに保存されます）。
        </div>
        {showStatusModal.nextStatus!=="closed"&&<>
          <div className="slbl">変更理由 *</div>
          <textarea className="fta" rows={3} value={nextStatusReason} onChange={e=>setNextStatusReason(e.target.value)}
            placeholder="例：国保連に返戻理由を確認、修正後再請求データ送付済み"/>
        </>}
        {showStatusModal.nextStatus==="resubmitted"&&<div style={{marginTop:8,padding:"8px 12px",background:"rgba(44,170,96,0.08)",borderRadius:8,fontSize:11,color:"var(--tx2)",lineHeight:1.7}}>
          📝 再請求データは元の請求と紐づけて保存されます。
        </div>}
        <div style={{display:"flex",gap:10,marginTop:14}}>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"none",background:CLAIM_STATUS[showStatusModal.nextStatus]?.color||"var(--tl)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={handleStatusChange}>確定する</button>
          <button style={{flex:1,padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
            onClick={()=>{setShowStatusModal(null);setNextStatusReason("");}}>キャンセル</button>
        </div>
      </div>
    </div>}
  </div>;
}

// ==================== 請求前チェック・監査チェック ====================
// 請求ミス・漏れ・監査リスクを自動チェックし、エラー理由を記録に残す
// ※自動修正はしない。必ず人間が確認してから確定する。

// チェック種別の日本語ラベル
const CHECK_TYPE_LABELS = {
  no_record_for_planned:  "予定はありますが、実績記録がありません",
  no_planned_for_record:  "実績はありますが、予定が登録されていません",
  missing_time:           "開始・終了時刻が未入力です",
  absent_billed:          "欠席日が請求日数に含まれている可能性があります",
  short_service_time:     "利用時間が30分未満です",
  transport_incomplete:   "送迎記録が未完了です",
  missing_memo:           "キャンセル・遅刻・早退の理由メモが未入力です",
  duplicate_record:       "同じ日に実績が重複して登録されています",
  missing_service_type:   "サービス種別が未設定です",
  missing_service_days:   "サービス提供日数が未入力です",
  no_isp_for_addon:       "加算の根拠となる個別支援計画（ISP）が見つかりません",
  jukyusha_expired:       "受給者証の有効期限が切れています",
  all_ok:                 "全項目チェック済み — 問題なし",
  unknown_error:          "不明なエラーが発生しました",
};

// ステータス表示定義
const CHECK_STATUS_STYLE = {
  ok:       {label:"OK",      color:"var(--gr)", bg:"rgba(44,170,96,0.1)",   icon:"✅"},
  warning:  {label:"要確認",  color:"var(--ac)", bg:"rgba(255,160,0,0.08)", icon:"⚠️"},
  error:    {label:"エラー",  color:"var(--ro)", bg:"rgba(224,56,56,0.08)", icon:"❌"},
  critical: {label:"請求不可",color:"#dc2626",   bg:"rgba(220,38,38,0.1)",  icon:"🚫"},
};
// ステータスの深刻度順（低いほど深刻）
const STATUS_PRIORITY = {critical:0, error:1, warning:2, ok:3};

function BillingCheckScreen({user, store, onNav, onBack}){
  const now = new Date();
  const [selFacility, setSelFacility] = useState(user.selectedFacilityId||"f1");
  const [selYear,  setSelYear]  = useState(now.getFullYear());
  const [selMonth, setSelMonth] = useState(now.getMonth()+1);
  const [checks,   setChecks]   = useState([]); // チェック結果配列
  const [running,  setRunning]  = useState(false);
  const [expanded, setExpanded] = useState({}); // userId → 展開状態

  const isAdmin = user.role==="admin";

  // ── チェック実行 ──
  const runChecks = async () => {
    setRunning(true);
    setChecks([]);
    setExpanded({});
    const monthStr = `${selYear}-${String(selMonth).padStart(2,"0")}`;
    const results = [];
    const addResult = (userId, userName, facilityId, type, status, message, relatedId=null, relatedDate=null) => {
      results.push({
        id: genId(),
        child_id: userId,
        child_name: userName,
        facility_id: facilityId,
        service_month: monthStr,
        check_type: type,
        status,
        message,
        related_record_id: relatedId,
        related_date: relatedDate,
        created_at: new Date().toISOString(),
      });
    };

    // 対象ユーザー（選択施設 or 全施設）
    const targetUsers = store.dynUsers.filter(u => {
      if(u.active===false) return false;
      if(selFacility==="all") return true;
      return u.facilityId===selFacility;
    });

    const daysInM = new Date(selYear, selMonth, 0).getDate();

    for(const u of targetUsers){
      // 月内の日付ごとのatt状態を収集
      const plannedDays=[], attendedDays=[], absentDays=[];
      for(let d=1; d<=daysInM; d++){
        const dateStr=`${monthStr}-${String(d).padStart(2,"0")}`;
        const s = store.getAtt(u.id, dateStr);
        if(s==="予定")  plannedDays.push(dateStr);
        else if(s==="出席") attendedDays.push(dateStr);
        else if(s==="欠席") absentDays.push(dateStr);
      }

      // 実績レコード（新テーブル）
      const svcRecs = (store.serviceRecs||[]).filter(r=>
        r.child_id===u.id && (r.visit_date||"").startsWith(monthStr)
      );
      // レガシー来所記録
      const legacyIn = store.recs.filter(r=>
        r.type==="user_in" && r.userId===u.id && (r.time||"").includes(String(selYear))
        && (r.time||"").includes(`/${selMonth}/`||`-${String(selMonth).padStart(2,"0")}-`)
      );
      // 請求データ
      const billRec = (store.kokuho||[]).find(k=>k.userId===u.id&&k.year===selYear&&k.month===selMonth);

      let hasAnyIssue = false;

      // ── CHECK 1: 予定あり実績なし ──
      plannedDays.forEach(date=>{
        const hasSvc = svcRecs.some(r=>r.visit_date===date&&r.attendance_status==="attended");
        const hasLegacyIn = store.recs.some(r=>r.type==="user_in"&&r.userId===u.id&&(r.time||"").includes(date.replace(/-/g,"/")));
        if(!hasSvc && !hasLegacyIn){
          addResult(u.id,u.name,u.facilityId,"no_record_for_planned","error",
            `${date.slice(5).replace("-","/")} ：来所予定があるが実績・来所記録がありません`,null,date);
          hasAnyIssue=true;
        }
      });

      // ── CHECK 2: 時間未入力 ──
      svcRecs.filter(r=>r.attendance_status==="attended").forEach(r=>{
        if(!r.actual_start||!r.actual_end){
          addResult(u.id,u.name,u.facilityId,"missing_time","warning",
            `${(r.visit_date||"").slice(5).replace("-","/")} ：来所・退所時刻が未入力です`,r.id,r.visit_date);
          hasAnyIssue=true;
        }
      });

      // ── CHECK 3: 欠席日が請求日数に含まれている疑い ──
      if(billRec && billRec.serviceDays>0 && absentDays.length>0){
        // 出席日数 > 請求日数 の場合はOK。逆に少ない場合は欠席混入の疑い
        const actualAttend = attendedDays.length + svcRecs.filter(r=>r.attendance_status==="attended").length;
        if(billRec.serviceDays > actualAttend + plannedDays.length){
          addResult(u.id,u.name,u.facilityId,"absent_billed","error",
            `欠席日(${absentDays.length}日)が請求日数(${billRec.serviceDays}日)に含まれている可能性があります`);
          hasAnyIssue=true;
        }
      }

      // ── CHECK 4: 利用時間30分未満 ──
      svcRecs.forEach(r=>{
        if(r.actual_start&&r.actual_end){
          const [sh,sm]=r.actual_start.split(":").map(Number);
          const [eh,em]=r.actual_end.split(":").map(Number);
          const mins=(eh*60+em)-(sh*60+sm);
          if(mins>0&&mins<30){
            addResult(u.id,u.name,u.facilityId,"short_service_time","warning",
              `${(r.visit_date||"").slice(5).replace("-","/")} ：利用時間が${mins}分（30分未満）です`,r.id,r.visit_date);
            hasAnyIssue=true;
          }
        }
      });

      // ── CHECK 5: 送迎未完了（hasTransportフラグがある利用者） ──
      if(u.hasTransport){
        svcRecs.filter(r=>r.attendance_status==="attended").forEach(r=>{
          if(!r.pickup_completed||!r.dropoff_completed){
            const detail=`迎:${r.pickup_completed?"✓":"未"} 送:${r.dropoff_completed?"✓":"未"}`;
            addResult(u.id,u.name,u.facilityId,"transport_incomplete","warning",
              `${(r.visit_date||"").slice(5).replace("-","/")} ：送迎記録が未完了（${detail}）`,r.id,r.visit_date);
            hasAnyIssue=true;
          }
        });
      }

      // ── CHECK 6: キャンセル/遅刻/早退でメモなし ──
      svcRecs.forEach(r=>{
        if(["cancelled","late","early_leave"].includes(r.attendance_status)&&!r.memo){
          const lbl={cancelled:"キャンセル",late:"遅刻",early_leave:"早退"}[r.attendance_status];
          addResult(u.id,u.name,u.facilityId,"missing_memo","warning",
            `${(r.visit_date||"").slice(5).replace("-","/")} ：${lbl}の理由メモが未入力です（監査対応で必須）`,r.id,r.visit_date);
          hasAnyIssue=true;
        }
      });

      // ── CHECK 7: 同一日に重複実績 ──
      const dateCount={};
      svcRecs.forEach(r=>{ dateCount[r.visit_date]=(dateCount[r.visit_date]||0)+1; });
      Object.entries(dateCount).forEach(([date,cnt])=>{
        if(cnt>1){
          addResult(u.id,u.name,u.facilityId,"duplicate_record","error",
            `${date.slice(5).replace("-","/")} ：同一日に${cnt}件の実績が重複しています`,null,date);
          hasAnyIssue=true;
        }
      });

      // ── CHECK 8: サービス種別未設定 ──
      svcRecs.filter(r=>r.attendance_status==="attended").forEach(r=>{
        if(!r.service_type){
          addResult(u.id,u.name,u.facilityId,"missing_service_type","warning",
            `${(r.visit_date||"").slice(5).replace("-","/")} ：サービス種別が未設定です`,r.id,r.visit_date);
          hasAnyIssue=true;
        }
      });

      // ── CHECK 9: 加算あり・ISP未作成 → 請求不可 ──
      if(billRec&&(billRec.addons||[]).length>0){
        const hasIsp=(store.isps||[]).some(isp=>isp.userId===u.id&&isp.status==="実施中");
        if(!hasIsp){
          addResult(u.id,u.name,u.facilityId,"no_isp_for_addon","critical",
            `加算(${billRec.addons.join("・")})が設定されていますが、有効な個別支援計画(ISP)が見つかりません`);
          hasAnyIssue=true;
        }
      }

      // ── CHECK 10: 受給者証 有効期限切れ ──
      const jukyusha=(store.jukyushaDocs||[]).find(d=>d.userId===u.id&&d.status==="有効");
      if(jukyusha&&jukyusha.expiryDate){
        const expiry=new Date(jukyusha.expiryDate);
        const monthEnd=new Date(selYear,selMonth,0);
        if(expiry<monthEnd){
          addResult(u.id,u.name,u.facilityId,"jukyusha_expired","critical",
            `受給者証の有効期限が ${jukyusha.expiryDate} で、${selYear}年${selMonth}月内に切れています`);
          hasAnyIssue=true;
        }
      }

      // 問題なし → OK記録
      if(!hasAnyIssue&&(attendedDays.length>0||svcRecs.length>0||billRec)){
        addResult(u.id,u.name,u.facilityId,"all_ok","ok","チェック全項目 問題なし");
      }
    }

    setChecks(results);

    // Supabaseにチェック結果を保存（監査ログ）
    results.forEach(r=>{
      sbSave("billing_check_results",{
        id:r.id, facility_id:r.facility_id, child_id:r.child_id,
        service_month:r.service_month, check_type:r.check_type,
        status:r.status, message:r.message,
        related_record_id:r.related_record_id||null,
        created_at:r.created_at, updated_at:r.created_at,
      });
    });

    setRunning(false);
  };

  // ── 結果を利用者ごとにグループ化 ──
  const userResults = {};
  checks.forEach(c=>{
    if(!userResults[c.child_id]) userResults[c.child_id]={name:c.child_name,facilityId:c.facility_id,items:[]};
    userResults[c.child_id].items.push(c);
  });

  const getWorst = items => items.reduce((w,i)=>STATUS_PRIORITY[i.status]<STATUS_PRIORITY[w]?i.status:w,"ok");

  // サマリー集計
  const smry={ok:0,warning:0,error:0,critical:0};
  Object.values(userResults).forEach(u=>{ smry[getWorst(u.items)]++; });
  const totalIssues = smry.warning+smry.error+smry.critical;

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">🔍 請求前チェック</div>
    </div>

    {/* ── 条件選択 ── */}
    <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:"14px 14px 12px",marginBottom:14}}>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12,alignItems:"flex-end"}}>
        {isAdmin&&<div style={{flex:"2 1 120px"}}>
          <div className="slbl">施設</div>
          <select className="fsm" style={{width:"100%"}} value={selFacility} onChange={e=>setSelFacility(e.target.value)}>
            <option value="all">全施設</option>
            {FACILITIES.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}
          </select>
        </div>}
        <div style={{flex:"1 1 90px"}}>
          <div className="slbl">年</div>
          <select className="fsm" style={{width:"100%"}} value={selYear} onChange={e=>setSelYear(+e.target.value)}>
            {[2024,2025,2026,2027].map(y=><option key={y} value={y}>{y}年</option>)}
          </select>
        </div>
        <div style={{flex:"1 1 70px"}}>
          <div className="slbl">月</div>
          <select className="fsm" style={{width:"100%"}} value={selMonth} onChange={e=>setSelMonth(+e.target.value)}>
            {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
          </select>
        </div>
      </div>
      <button className="bsave" onClick={runChecks} disabled={running}
        style={{width:"100%",fontSize:15,padding:"13px"}}>
        {running?"⏳ チェック中...":"🔍 チェック実行（10項目）"}
      </button>
      <div style={{fontSize:11,color:"var(--tx3)",marginTop:8,lineHeight:1.6}}>
        ※ 自動修正はしません。チェック結果はSupabaseに保存されます（監査ログ）。
      </div>
    </div>

    {/* ── サマリーバー ── */}
    {checks.length>0&&<>
      <div style={{display:"flex",gap:8,marginBottom:14}}>
        {Object.entries(CHECK_STATUS_STYLE).map(([key,val])=>(
          <div key={key} style={{flex:1,background:val.bg,border:`1.5px solid ${smry[key]>0?val.color:"var(--bd)"}`,borderRadius:10,padding:"10px 4px",textAlign:"center"}}>
            <div style={{fontSize:15}}>{val.icon}</div>
            <div style={{fontSize:9,color:val.color,fontWeight:700,marginTop:1}}>{val.label}</div>
            <div style={{fontSize:22,fontWeight:800,color:smry[key]>0?val.color:"var(--tx3)"}}>{smry[key]}</div>
            <div style={{fontSize:9,color:"var(--tx3)"}}>名</div>
          </div>
        ))}
      </div>
      {totalIssues>0
        ?<div style={{background:"rgba(224,56,56,0.08)",border:"1px solid rgba(224,56,56,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:14,fontSize:12,color:"var(--ro)",fontWeight:700}}>
          ❌ {totalIssues}名に指摘事項があります。修正してから請求を確定してください。
        </div>
        :<div style={{background:"rgba(44,170,96,0.1)",border:"1px solid rgba(44,170,96,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:14,fontSize:12,color:"var(--gr)",fontWeight:700}}>
          ✅ 全員問題なし。請求確定に進めます。
        </div>
      }
    </>}

    {/* チェック未実行 / 実行中 */}
    {checks.length===0&&(running
      ?<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tl)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
        <div style={{fontSize:36,marginBottom:12,animation:"spin 1.2s linear infinite",display:"inline-block"}}>⏳</div>
        <div style={{fontWeight:700,marginBottom:4}}>チェック中です…</div>
        <div style={{color:"var(--tx3)"}}>利用者データを10項目チェックしています。しばらくお待ちください。</div>
      </div>
      :<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
        <div style={{fontSize:32,marginBottom:10}}>🔍</div>
        「チェック実行」を押すと10項目を自動チェックします
      </div>
    )}

    {/* ── 利用者ごとの結果カード ── */}
    {Object.entries(userResults)
      .sort(([,a],[,b])=>STATUS_PRIORITY[getWorst(a.items)]-STATUS_PRIORITY[getWorst(b.items)])
      .map(([userId,uData])=>{
        const worst=getWorst(uData.items);
        const st=CHECK_STATUS_STYLE[worst];
        const isOpen=!!expanded[userId];
        const issues=uData.items.filter(i=>i.status!=="ok");
        return <div key={userId} style={{background:"var(--wh)",border:`1.5px solid ${worst==="ok"?"var(--bd)":st.color}`,borderRadius:12,marginBottom:10,overflow:"hidden"}}>
          {/* ヘッダー（タップで展開/収納） */}
          <div onClick={()=>setExpanded(p=>({...p,[userId]:!isOpen}))}
            style={{display:"flex",alignItems:"center",gap:10,padding:"12px 14px",cursor:"pointer",background:worst!=="ok"?st.bg:"var(--wh)",userSelect:"none"}}>
            <div style={{fontSize:20,flexShrink:0}}>{st.icon}</div>
            <div style={{flex:1,minWidth:0}}>
              <div style={{fontWeight:700,fontSize:14,color:"var(--tx)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{uData.name}</div>
              <div style={{fontSize:11,color:"var(--tx3)"}}>
                {worst==="ok"?"問題なし — 請求OK":`${issues.length}件の指摘事項`}
              </div>
            </div>
            <div style={{padding:"4px 10px",borderRadius:20,border:`1.5px solid ${st.color}`,color:st.color,fontSize:11,fontWeight:700,flexShrink:0,whiteSpace:"nowrap"}}>{st.label}</div>
            <div style={{color:"var(--tx3)",fontSize:14,flexShrink:0}}>{isOpen?"▲":"▼"}</div>
          </div>

          {/* 展開パネル：指摘一覧 */}
          {isOpen&&<div style={{borderTop:"1px solid var(--bd)"}}>
            {issues.map((item,i)=>{
              const ist=CHECK_STATUS_STYLE[item.status];
              return <div key={i} style={{padding:"10px 14px",borderBottom:"1px solid var(--bd)",background:ist.bg}}>
                <div style={{display:"flex",alignItems:"flex-start",gap:10}}>
                  <div style={{fontSize:16,flexShrink:0,marginTop:1}}>{ist.icon}</div>
                  <div style={{flex:1}}>
                    <div style={{fontSize:11,fontWeight:700,color:ist.color,marginBottom:2}}>
                      {ist.label} — {CHECK_TYPE_LABELS[item.check_type]||item.check_type}
                    </div>
                    <div style={{fontSize:12,color:"var(--tx)",lineHeight:1.6}}>{item.message}</div>
                    {/* 修正ナビボタン */}
                    {item.check_type==="no_record_for_planned"&&onNav&&
                      <button style={{marginTop:6,fontSize:11,padding:"4px 10px",borderRadius:7,border:"1px solid var(--tl)",background:"rgba(58,160,216,0.1)",color:"var(--tl)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700}}
                        onClick={e=>{e.stopPropagation();onNav("jisseki");}}>→ 実績管理で入力</button>}
                    {(item.check_type==="missing_time"||item.check_type==="missing_memo"||item.check_type==="transport_incomplete"||item.check_type==="short_service_time"||item.check_type==="missing_service_type")&&onNav&&
                      <button style={{marginTop:6,fontSize:11,padding:"4px 10px",borderRadius:7,border:"1px solid var(--tl)",background:"rgba(58,160,216,0.1)",color:"var(--tl)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700}}
                        onClick={e=>{e.stopPropagation();onNav("jisseki");}}>→ 実績管理で修正</button>}
                    {item.check_type==="no_isp_for_addon"&&onNav&&
                      <button style={{marginTop:6,fontSize:11,padding:"4px 10px",borderRadius:7,border:"1px solid var(--ro)",background:"rgba(224,56,56,0.08)",color:"var(--ro)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700}}
                        onClick={e=>{e.stopPropagation();onNav("users");}}>→ ISPを作成する</button>}
                    {item.check_type==="jukyusha_expired"&&onNav&&
                      <button style={{marginTop:6,fontSize:11,padding:"4px 10px",borderRadius:7,border:"1px solid var(--ro)",background:"rgba(224,56,56,0.08)",color:"var(--ro)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700}}
                        onClick={e=>{e.stopPropagation();onNav("users");}}>→ 受給者証を更新する</button>}
                  </div>
                </div>
              </div>;
            })}
            {issues.length===0&&<div style={{padding:"10px 14px",fontSize:12,color:"var(--gr)"}}>✅ 問題なし — 請求OKです</div>}
          </div>}
        </div>;
      })}

    {/* 再チェック・請求画面へ */}
    {checks.length>0&&<div style={{display:"flex",gap:10,marginTop:4}}>
      <button style={{flex:1,padding:"13px",borderRadius:10,border:"1.5px solid var(--tl)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
        onClick={runChecks} disabled={running}>
        🔄 再チェック
      </button>
      {totalIssues===0&&onNav&&<button style={{flex:1,padding:"13px",borderRadius:10,border:"none",background:"var(--gr)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
        onClick={()=>onNav("kokuho")}>
        ✅ 請求画面へ →
      </button>}
    </div>}
  </div>;
}

// ==================== 利用実績 管理（当日） ====================
// 予定→実績を自動生成し、カメラ打刻・ステータス変更をワンタップで行う
function JissekiScreen({user, store, onBack}){
  const today = todayISO();
  // selDate: 編集対象日（初期=本日）。過去日の実績も入力・編集できるようにする
  const [selDate,setSelDate]=useState(today);
  const facilityId = user.selectedFacilityId;
  // 自施設の有効ユーザー
  const myUsers = store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);
  // 選択日の来所予定・出席者
  const plannedUsers = myUsers.filter(u=>{
    const s=store.getAtt(u.id,selDate);
    return s==="予定"||s==="出席";
  });
  // 選択日の実績レコード
  const dayRecs = (store.serviceRecs||[]).filter(r=>r.visit_date===selDate&&r.facility_id===facilityId);
  const isToday = selDate===today;

  const [camMode,setCamMode]=useState(null); // {userId,type:"in"|"out"}
  const [editId,setEditId]=useState(null);   // 時間編集展開中の利用者ID
  const fileRef=useRef();

  // ステータス表示定義
  const ST={
    attended:   {label:"出席",    color:"var(--gr)", bg:"rgba(44,170,96,0.12)"},
    absent:     {label:"欠席",    color:"var(--ro)", bg:"rgba(224,56,56,0.1)"},
    cancelled:  {label:"キャンセル",color:"var(--tx3)",bg:"var(--bg2)"},
    late:       {label:"遅刻",    color:"var(--ac)", bg:"rgba(255,160,0,0.1)"},
    early_leave:{label:"早退",    color:"#a78bfa",   bg:"rgba(167,139,250,0.1)"},
  };

  // 実績レコード取得（なければデフォルト生成）
  const getRec=userId=>{
    const ex=dayRecs.find(r=>r.child_id===userId);
    if(ex) return ex;
    const u=myUsers.find(x=>x.id===userId);
    return {
      id:userId+"_"+selDate, child_id:userId, child_name:u?.name||userId,
      facility_id:facilityId, visit_date:selDate,
      planned_start:null, planned_end:null,
      actual_start:null, actual_end:null,
      attendance_status:"attended",
      pickup_completed:false, dropoff_completed:false,
      service_type:"放課後等デイサービス",
      memo:null, staff_id:user.id||user.staffId||"",
      created_at:new Date().toISOString(),
    };
  };

  // 実績保存（att状態にも反映）
  const saveRec=rec=>{
    store.saveServiceRec(rec);
    if(rec.attendance_status==="attended") store.setAtt(rec.child_id,selDate,"出席");
    else if(rec.attendance_status==="absent") store.setAtt(rec.child_id,selDate,"欠席");
  };

  // ステータスワンタップ変更
  const setStatus=(userId,status)=>{
    const rec={...getRec(userId),attendance_status:status,updated_at:nowStr()};
    saveRec(rec);
  };

  // カメラ打刻処理
  const handleCam=e=>{
    if(!camMode) return;
    const file=e.target.files?.[0];
    if(!file) return;
    const now=nowHM();
    const rec=getRec(camMode.userId);
    const updated=camMode.type==="in"
      ? {...rec,actual_start:now,attendance_status:"attended",updated_at:nowStr()}
      : {...rec,actual_end:now,updated_at:nowStr()};
    saveRec(updated);
    setCamMode(null);
    fileRef.current.value="";
  };

  // 自動チェック警告生成
  const warnings=[];
  plannedUsers.forEach(u=>{
    const rec=dayRecs.find(r=>r.child_id===u.id);
    if(!rec||rec.attendance_status==="attended"){
      if(!rec?.actual_start) warnings.push({icon:"📥",text:`${u.name} — 来所打刻 未記録`});
      if(rec?.actual_start&&!rec?.actual_end) warnings.push({icon:"⏰",text:`${u.name} — 退所打刻 未記録`});
    }
    // 送迎漏れチェック（pickup/dropoffが必要なのに未完了）
    if(rec?.attendance_status==="attended"){
      if(!rec.pickup_completed&&!rec.dropoff_completed&&u.hasTransport)
        warnings.push({icon:"🚗",text:`${u.name} — 送迎 未完了`});
    }
  });

  // 在所時間計算（分）
  const calcMin=(start,end)=>{
    if(!start||!end) return null;
    const [sh,sm]=start.split(":").map(Number);
    const [eh,em]=end.split(":").map(Number);
    const m=(eh*60+em)-(sh*60+sm);
    return m>0?m:null;
  };

  // 日付を1日ずらす（YYYY-MM-DD）。未来日は本日まで
  // ※ toISOString()はUTC変換で日付がずれるため、ローカル日付で組み立てる
  const shiftDate=(diff)=>{
    const d=new Date(selDate+"T00:00:00");
    d.setDate(d.getDate()+diff);
    const ns=d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0")+"-"+String(d.getDate()).padStart(2,"0");
    if(ns>today) return; // 本日より先には進めない
    setSelDate(ns);
    setEditId(null);
  };

  return <div className="fl-wrap">
    <div className="fl-hd">
      <button className="bback" onClick={onBack}>← 戻る</button>
      <div className="fl-title">📋 実績管理</div>
    </div>

    {/* ── 日付選択バー（過去日の実績も入力・編集できる）── */}
    <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:12,background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"8px 10px"}}>
      <button onClick={()=>shiftDate(-1)}
        style={{padding:"6px 12px",borderRadius:8,border:"1px solid var(--bd)",background:"var(--bg)",color:"var(--tx2)",fontSize:14,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>‹ 前日</button>
      <input type="date" value={selDate} max={today}
        onChange={e=>{ if(e.target.value){ setSelDate(e.target.value); setEditId(null); } }}
        style={{flex:1,padding:"7px 8px",border:"1px solid var(--bd)",borderRadius:8,fontSize:14,fontWeight:700,textAlign:"center",background:"var(--bg)",color:"var(--tx)",fontFamily:"'Noto Sans JP',sans-serif"}}/>
      <button onClick={()=>shiftDate(1)} disabled={isToday}
        style={{padding:"6px 12px",borderRadius:8,border:"1px solid var(--bd)",background:isToday?"var(--bg2)":"var(--bg)",color:isToday?"var(--tx3)":"var(--tx2)",fontSize:14,fontWeight:700,cursor:isToday?"not-allowed":"pointer",opacity:isToday?0.5:1,fontFamily:"'Noto Sans JP',sans-serif"}}>翌日 ›</button>
    </div>
    {!isToday&&<div style={{margin:"-4px 0 12px",padding:"6px 10px",background:"rgba(255,160,0,0.1)",border:"1px solid rgba(255,160,0,0.3)",borderRadius:8,fontSize:11,fontWeight:700,color:"var(--ac)"}}>
      📅 過去日（{selDate.replace(/-/g,"/")}）の実績を編集中です
    </div>}

    {/* 隠しカメラ入力 */}
    <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleCam}/>

    {/* 自動警告 */}
    {warnings.length>0&&<div style={{margin:"0 0 12px",padding:"10px 14px",background:"rgba(255,160,0,0.1)",border:"1px solid rgba(255,160,0,0.3)",borderRadius:10}}>
      <div style={{fontSize:12,fontWeight:700,color:"var(--ac)",marginBottom:4}}>⚠ 要確認 ({warnings.length}件)</div>
      {warnings.map((w,i)=><div key={i} style={{fontSize:11,color:"var(--tx2)",lineHeight:1.9}}>{w.icon} {w.text}</div>)}
    </div>}

    {/* 今日のサマリー */}
    <div style={{display:"flex",gap:8,marginBottom:14}}>
      {[
        {label:"来所予定",val:plannedUsers.length,color:"var(--tx)"},
        {label:"出席",val:dayRecs.filter(r=>r.attendance_status==="attended").length,color:"var(--gr)"},
        {label:"欠席",val:dayRecs.filter(r=>r.attendance_status==="absent"||r.attendance_status==="cancelled").length,color:"var(--ro)"},
      ].map(s=><div key={s.label} style={{flex:1,background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:10,padding:"10px 6px",textAlign:"center"}}>
        <div style={{fontSize:10,color:"var(--tx3)",marginBottom:2}}>{s.label}</div>
        <div style={{fontSize:22,fontWeight:800,color:s.color}}>{s.val}</div>
      </div>)}
    </div>

    {/* 予定者ゼロ */}
    {plannedUsers.length===0&&<div style={{textAlign:"center",padding:"48px 20px",color:"var(--tx3)",fontSize:13,background:"var(--wh)",borderRadius:12,border:"1px solid var(--bd)"}}>
      {isToday?"本日":selDate.replace(/-/g,"/")}の来所予定者がいません<br/>
      <span style={{fontSize:11}}>予定表読み取りか出欠管理から登録してください</span>
    </div>}

    {/* 実績カード */}
    {plannedUsers.map(u=>{
      const rec=dayRecs.find(r=>r.child_id===u.id)||getRec(u.id);
      const st=ST[rec.attendance_status]||ST.attended;
      const mins=calcMin(rec.actual_start,rec.actual_end);
      return <div key={u.id} style={{background:"var(--wh)",border:"1.5px solid var(--bd)",borderRadius:12,marginBottom:12,overflow:"hidden"}}>

        {/* ── カードヘッダー ── */}
        <div style={{display:"flex",alignItems:"center",gap:10,padding:"11px 14px",background:st.bg,borderBottom:"1px solid var(--bd)"}}>
          <div style={{width:36,height:36,borderRadius:"50%",background:"rgba(58,160,216,0.15)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,flexShrink:0,overflow:"hidden"}}>
            {u.photo?<img src={u.photo} style={{width:36,height:36,borderRadius:"50%",objectFit:"cover"}} alt=""/>:"👤"}
          </div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontWeight:700,fontSize:14,color:"var(--tx)",whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{u.name}</div>
            <div style={{fontSize:10,color:"var(--tx3)"}}>
              {rec.planned_start?`予定 ${rec.planned_start}〜${rec.planned_end||"?"}`:"時間未定"}
              {mins?<span style={{marginLeft:8,color:"var(--tl)",fontWeight:700}}> 在所{Math.floor(mins/60)}h{mins%60}m</span>:null}
            </div>
          </div>
          <div style={{padding:"4px 10px",borderRadius:20,border:`1.5px solid ${st.color}`,color:st.color,fontSize:11,fontWeight:700,whiteSpace:"nowrap"}}>{st.label}</div>
        </div>

        {/* ── 来所・退所打刻 ── */}
        <div style={{display:"flex",gap:8,padding:"10px 14px",borderBottom:"1px solid var(--bd)"}}>
          <div style={{flex:1,textAlign:"center"}}>
            <div style={{fontSize:10,color:"var(--tx3)",marginBottom:4}}>📥 来所打刻</div>
            {rec.actual_start
              ?<div style={{fontWeight:800,color:"var(--gr)",fontSize:16}}>{rec.actual_start} ✓</div>
              :<button style={{width:"100%",padding:"8px 4px",borderRadius:8,border:"1.5px dashed var(--tl)",background:"rgba(58,160,216,0.07)",color:"var(--tl)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                onClick={()=>{setCamMode({userId:u.id,type:"in"});setTimeout(()=>fileRef.current.click(),50);}}>
                📷 打刻する
              </button>
            }
          </div>
          <div style={{flex:1,textAlign:"center"}}>
            <div style={{fontSize:10,color:"var(--tx3)",marginBottom:4}}>🏠 退所打刻</div>
            {rec.actual_end
              ?<div style={{fontWeight:800,color:"var(--gr)",fontSize:16}}>{rec.actual_end} ✓</div>
              :<button style={{width:"100%",padding:"8px 4px",borderRadius:8,border:"1.5px dashed var(--bd)",background:"var(--bg2)",color:"var(--tx2)",fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}
                onClick={()=>{setCamMode({userId:u.id,type:"out"});setTimeout(()=>fileRef.current.click(),50);}}>
                📷 打刻する
              </button>
            }
          </div>
        </div>

        {/* ── ステータス ワンタップ変更 ── */}
        <div style={{display:"flex",gap:5,padding:"9px 14px",flexWrap:"wrap",borderBottom:"1px solid var(--bd)"}}>
          {Object.entries(ST).map(([key,val])=>(
            <button key={key}
              style={{flex:"1 1 50px",padding:"6px 2px",borderRadius:8,border:`1.5px solid ${rec.attendance_status===key?val.color:"var(--bd)"}`,background:rec.attendance_status===key?val.bg:"var(--bg)",color:rec.attendance_status===key?val.color:"var(--tx3)",fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",whiteSpace:"nowrap"}}
              onClick={()=>setStatus(u.id,key)}>
              {val.label}
            </button>
          ))}
        </div>

        {/* ── 送迎 & 時間修正 ── */}
        <div style={{display:"flex",alignItems:"center",gap:12,padding:"8px 14px",flexWrap:"wrap"}}>
          <label style={{display:"flex",alignItems:"center",gap:5,fontSize:12,color:"var(--tx2)",cursor:"pointer",userSelect:"none"}}>
            <input type="checkbox" checked={rec.pickup_completed||false}
              onChange={e=>saveRec({...rec,pickup_completed:e.target.checked,updated_at:nowStr()})}/>
            🚗 迎え完了
          </label>
          <label style={{display:"flex",alignItems:"center",gap:5,fontSize:12,color:"var(--tx2)",cursor:"pointer",userSelect:"none"}}>
            <input type="checkbox" checked={rec.dropoff_completed||false}
              onChange={e=>saveRec({...rec,dropoff_completed:e.target.checked,updated_at:nowStr()})}/>
            🏠 送り完了
          </label>
          <div style={{flex:1}}/>
          <button style={{fontSize:11,color:"var(--tl)",border:"none",background:"none",cursor:"pointer",padding:"3px 6px",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700}}
            onClick={()=>setEditId(editId===u.id?null:u.id)}>
            ✏️ {editId===u.id?"閉じる":"手動修正"}
          </button>
        </div>

        {/* ── 手動時間修正パネル ── */}
        {editId===u.id&&<div style={{padding:"10px 14px 14px",background:"var(--bg2)",borderTop:"1px solid var(--bd)"}}>
          {[
            {label:"来所時刻",key:"actual_start"},
            {label:"退所時刻",key:"actual_end"},
            {label:"予定来所",key:"planned_start"},
            {label:"予定退所",key:"planned_end"},
          ].map(f=><div key={f.key} style={{display:"flex",gap:8,alignItems:"center",marginBottom:8}}>
            <div style={{fontSize:11,color:"var(--tx3)",width:62,flexShrink:0}}>{f.label}</div>
            <input type="time" value={rec[f.key]||""}
              onChange={e=>saveRec({...rec,[f.key]:e.target.value||null,updated_at:nowStr()})}
              style={{flex:1,padding:"6px 8px",border:"1px solid var(--bd)",borderRadius:7,fontSize:13,background:"var(--wh)",color:"var(--tx)",fontFamily:"'Noto Sans JP',sans-serif"}}/>
          </div>)}
          <div style={{display:"flex",gap:8,alignItems:"center"}}>
            <div style={{fontSize:11,color:"var(--tx3)",width:62,flexShrink:0}}>メモ</div>
            <input value={rec.memo||""} onChange={e=>saveRec({...rec,memo:e.target.value,updated_at:nowStr()})}
              placeholder="特記事項など"
              style={{flex:1,padding:"6px 8px",border:"1px solid var(--bd)",borderRadius:7,fontSize:12,background:"var(--wh)",color:"var(--tx)",fontFamily:"'Noto Sans JP',sans-serif"}}/>
          </div>
        </div>}
      </div>;
    })}

    {/* 予定外来所ボタン */}
    <button style={{width:"100%",padding:"13px",borderRadius:10,border:"1.5px dashed var(--bd)",background:"var(--bg)",color:"var(--tx2)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",marginTop:4}}
      onClick={()=>onBack()}>
      ＋ 予定外来所 → 「利用者 来所」から記録
    </button>
  </div>;
}

// ==================== AI運営サポート（予定表チェックエンジン）====================
// OCRで読んだ予定を解析し「人が確認すべき点だけ」を提案する。
// 確定的ルールで即時判定（外部送信なし＝高速・低コスト・児童PII非送信）。
const _hm2m=t=>{ if(!t||!/^\d{1,2}:\d{2}/.test(String(t)))return null; const[h,m]=String(t).split(":").map(Number); return h*60+m; };
const _m2hm=m=>`${String(Math.floor(m/60)).padStart(2,"0")}:${String(m%60).padStart(2,"0")}`;
function analyzeSchedule({visits, selUserId, openMin, closeMin, facVisits}){
  const A=[]; const push=(level,icon,title,detail)=>A.push({level,icon,title,detail});
  const act=(visits||[]).filter(v=>v._checked!==false && v.date);
  const raisho=act.filter(v=>v.status!=="欠席");
  const kesseki=act.filter(v=>v.status==="欠席");
  const list=ds=>ds.slice(0,8).join(",")+(ds.length>8?"…":"");
  // 送迎漏れ
  const noTr=raisho.filter(v=>!v.pickup&&!v.dropoff).map(v=>v.date);
  if(noTr.length) push("warn","⚠","送迎が未設定です",`${noTr.length}日（${list(noTr)}日）に迎え・送りの指定がありません`);
  // 片道送迎
  const one=raisho.filter(v=>(!!v.pickup)!==(!!v.dropoff)).map(v=>v.date);
  if(one.length) push("info","ℹ️","片道送迎の日があります",`${one.length}日（${list(one)}日）は迎え/送りの一方のみ。意図通りか確認`);
  // 時間重複
  const dts=raisho.map(v=>String(v.date));
  const dup=[...new Set(dts.filter((d,i)=>dts.indexOf(d)!==dts.lastIndexOf(d)))];
  if(dup.length) push("warn","⚠","同じ日に予定が重複しています",`${dup.join(",")}日 が複数回登録されています`);
  // 営業時間外
  const out=raisho.filter(v=>{const s=_hm2m(v.startTime),e=_hm2m(v.endTime);return (s!=null&&s<openMin)||(e!=null&&e>closeMin);}).map(v=>v.date);
  if(out.length) push("warn","⚠","営業時間外の予定があります",`${list(out)}日 が営業時間（${_m2hm(openMin)}〜${_m2hm(closeMin)}）外です`);
  // 利用時間 不足/超過
  const durs=raisho.map(v=>{const s=_hm2m(v.startTime),e=_hm2m(v.endTime);return {d:v.date,m:(s!=null&&e!=null&&e>s)?e-s:null};});
  const sh=durs.filter(x=>x.m!=null&&x.m<60).map(x=>x.d);
  const lo=durs.filter(x=>x.m!=null&&x.m>480).map(x=>x.d);
  if(sh.length) push("warn","⚠","利用時間が通常より短いです",`${list(sh)}日 が1時間未満です`);
  if(lo.length) push("warn","⚠","利用時間が長すぎる可能性",`${list(lo)}日 が8時間超。延長支援加算の対象か確認`);
  // 欠席が多い
  if(kesseki.length>=3) push("warn","⚠","欠席が多い利用者です",`今月${kesseki.length}回の欠席予定。連絡状況と欠席時対応加算を確認`);
  // 加算取得漏れの可能性
  const tr=raisho.filter(v=>v.pickup||v.dropoff).length;
  if(tr>0) push("info","💰","送迎加算の対象があります",`${tr}日で送迎あり。送迎加算の算定漏れに注意`);
  if(kesseki.length>0) push("info","💰","欠席時対応加算の可能性",`欠席${kesseki.length}日。事前連絡があれば月4回まで算定可`);
  // 施設横断（同月の他児童データがある時のみ発火＝誤検知防止）
  if(Array.isArray(facVisits)&&facVisits.length){
    const byDate={};
    facVisits.filter(x=>x.child_id!==selUserId).forEach(x=>{ const dd=+(String(x.visit_date||"").slice(8,10)); if(!dd)return; const k=String(dd);
      (byDate[k]=byDate[k]||{kids:new Set(),tr:0}); byDate[k].kids.add(x.child_id); if(x.pickup_required||x.dropoff_required)byDate[k].tr++; });
    raisho.forEach(v=>{ const k=String(v.date); (byDate[k]=byDate[k]||{kids:new Set(),tr:0}); byDate[k].kids.add(selUserId||"_cur"); if(v.pickup||v.dropoff)byDate[k].tr++; });
    const busy=Object.entries(byDate).filter(([,o])=>o.tr>=6).map(([d])=>d);
    if(busy.length) push("warn","⚠","送迎が集中する日があります",`${list(busy)}日 は送迎希望が6件以上。送迎車の配車を確認`);
    const crowd=Object.entries(byDate).filter(([,o])=>o.kids.size>=10).map(([d,o])=>`${d}日(${o.kids.size}名)`);
    if(crowd.length) push("warn","⚠","同時間帯に利用者が集中しています",`${crowd.slice(0,6).join(" / ")}。職員配置基準を確認`);
  }
  return A;
}

// ==================== AI施設運営レポート（共通コンポーネント）====================
// ドメイン非依存の表示カード。report={title,stats[],evaluation,comment,priorities[]} を受け取り描画。
// 予定表以外（送迎表/学校予定表/イベント表/職員シフト）も build◯◯Report() が同形を返せば再利用可能。
function AiReportCard({report}){
  if(!report) return null;
  const {title="AI施設運営レポート", stats=[], evaluation={level:"good",label:"良好"}, comment, priorities=[]}=report;
  const dot=l=>l==="alert"?"🔴":l==="warn"?"🟡":l==="info"?"💰":"🟢";
  const col=l=>l==="alert"?"var(--ro)":l==="warn"?"#c9971f":l==="info"?"var(--ac)":"var(--gr)";
  const evBg={good:"rgba(44,170,96,0.12)",warn:"rgba(201,151,31,0.12)",alert:"rgba(224,56,56,0.1)"}[evaluation.level]||"rgba(44,170,96,0.12)";
  return <div style={{textAlign:"left",width:"100%",maxWidth:520,margin:"16px auto 0",border:"1px solid var(--bd)",borderRadius:14,overflow:"hidden"}}>
    <div style={{background:"var(--bg2)",padding:"9px 12px",fontSize:12.5,fontWeight:900,color:"var(--tl)",letterSpacing:1,textAlign:"center"}}>━━ 🤖 {title} ━━</div>
    <div style={{padding:"12px"}}>
      <div style={{background:evBg,borderRadius:10,padding:"10px 12px",marginBottom:12,textAlign:"center"}}>
        <span style={{fontSize:11,color:"var(--tx3)",fontWeight:700}}>AI総合評価</span>
        <div style={{fontSize:18,fontWeight:900,color:col(evaluation.level),marginTop:2}}>{dot(evaluation.level)} {evaluation.label}</div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:12}}>
        {stats.map((s,i)=><div key={i} style={{background:"var(--bg2)",borderRadius:9,padding:"8px 6px",textAlign:"center"}}>
          <div style={{fontSize:15,fontWeight:900,color:s.level?col(s.level):"var(--tx)"}}>{s.value}</div>
          <div style={{fontSize:9.5,color:"var(--tx3)",marginTop:2,lineHeight:1.3}}>{s.label}</div>
        </div>)}
      </div>
      {comment&&<div style={{background:"rgba(58,160,216,0.07)",border:"1px solid rgba(58,160,216,0.2)",borderRadius:10,padding:"10px 12px",marginBottom:priorities.length?12:0}}>
        <div style={{fontSize:11,fontWeight:800,color:"var(--ac)",marginBottom:4}}>💬 AIコメント</div>
        <div style={{fontSize:12,color:"var(--tx2)",lineHeight:1.7}}>{comment}</div>
      </div>}
      {priorities.length>0&&<div>
        <div style={{fontSize:11,fontWeight:800,color:"var(--tx3)",marginBottom:6}}>優先順位（重要度順）</div>
        <div style={{display:"flex",flexDirection:"column",gap:5}}>
          {priorities.map((p,i)=><div key={i} style={{fontSize:12,fontWeight:700,color:col(p.level),display:"flex",gap:6,alignItems:"center"}}>{dot(p.level)} {p.text}</div>)}
        </div>
      </div>}
    </div>
  </div>;
}

// 予定表ドメイン → AI施設運営レポートのデータ生成（analyzeScheduleを再利用）
function buildScheduleReport({visits, selUserId, facVisits, openMin, closeMin, store, todayStr}){
  const checks=analyzeSchedule({visits, selUserId, openMin, closeMin, facVisits});
  const act=(visits||[]).filter(v=>v._checked!==false && v.date);
  const raisho=act.filter(v=>v.status!=="欠席");
  const kesseki=act.filter(v=>v.status==="欠席");
  const todayDD=+String(todayStr).slice(8,10);
  const fv=Array.isArray(facVisits)?facVisits:[];
  const todayKids=new Set(fv.filter(x=>x.visit_date===todayStr).map(x=>x.child_id));
  const todayTrans=new Set(fv.filter(x=>x.visit_date===todayStr&&(x.pickup_required||x.dropoff_required)).map(x=>x.child_id));
  raisho.forEach(v=>{ if(+v.date===todayDD){ todayKids.add(selUserId||"_cur"); if(v.pickup||v.dropoff) todayTrans.add(selUserId||"_cur"); } });
  let absToday=0;
  try{ if(store&&store.getAtt&&Array.isArray(store.dynUsers)) absToday=store.dynUsers.filter(u=>store.getAtt(u.id,todayStr)==="欠席").length; }catch(_){}
  kesseki.forEach(v=>{ if(+v.date===todayDD) absToday++; });
  const noTr=raisho.filter(v=>!v.pickup&&!v.dropoff).length;
  const dts=raisho.map(v=>String(v.date)); const dupN=new Set(dts.filter((d,i)=>dts.indexOf(d)!==dts.lastIndexOf(d))).size;
  const shortN=raisho.filter(v=>{const s=_hm2m(v.startTime),e=_hm2m(v.endTime);return s!=null&&e!=null&&e>s&&(e-s)<60;}).length;
  const longN=raisho.filter(v=>{const s=_hm2m(v.startTime),e=_hm2m(v.endTime);return s!=null&&e!=null&&(e-s)>480;}).length;
  const outN=raisho.filter(v=>{const s=_hm2m(v.startTime),e=_hm2m(v.endTime);return (s!=null&&s<openMin)||(e!=null&&e>closeMin);}).length;
  const transDays=raisho.filter(v=>v.pickup||v.dropoff).length;
  const staffAlert=checks.some(c=>c.title.includes("配置")||c.title.includes("集中"));
  // ⑩ 総合評価
  let level="good",label="良好";
  if(noTr>0||dupN>0||staffAlert){ level="alert"; label="要確認"; }
  else if(outN>0||shortN>0||longN>0||absToday>=3||kesseki.length>=3){ level="warn"; label="注意"; }
  // 優先順位（重要度順）
  const crit=["送迎が未設定","重複","送迎が集中","利用者が集中"];
  const priorities=checks.map(c=>{ const isCrit=crit.some(k=>c.title.includes(k)); const lv=isCrit?"alert":(c.level==="info"?"good":"warn"); return {level:lv,text:c.title}; })
    .sort((a,b)=>({alert:0,warn:1,good:2}[a.level]-{alert:0,warn:1,good:2}[b.level]));
  // AIコメント（文章要約）
  const p=[]; p.push(`本日の利用予定は${todayKids.size}名、欠席${absToday}名、送迎${todayTrans.size}名です。`);
  if(noTr>0) p.push(`送迎漏れが${noTr}件あります。`);
  if(dupN>0) p.push(`予定の重複が${dupN}件あります。`);
  if(outN>0||shortN>0||longN>0) p.push(`利用時間に確認が必要な予定があります。`);
  p.push(staffAlert?`利用者が集中する日があり、職員配置の確認をおすすめします。`:`職員配置に問題はありません。`);
  if(kesseki.length>0) p.push(`欠席予定者は${kesseki.length}名です。`);
  if(transDays>0) p.push(`送迎加算の対象が${transDays}日あります。`);
  p.push(level==="good"?`全体的に良好です。`:level==="warn"?`いくつか確認事項があります。`:`要確認の項目があります。対応をご検討ください。`);
  return {
    title:"AI施設運営レポート",
    evaluation:{level,label},
    stats:[
      {label:"本日の利用予定", value:`${todayKids.size}名`},
      {label:"本日の欠席予定", value:`${absToday}名`, level:absToday>=3?"warn":null},
      {label:"本日の送迎必要", value:`${todayTrans.size}名`},
      {label:"送迎漏れ", value:`${noTr}件`, level:noTr>0?"alert":"good"},
      {label:"時間重複", value:`${dupN}件`, level:dupN>0?"alert":"good"},
      {label:"利用時間不足", value:`${shortN}件`, level:shortN>0?"warn":"good"},
      {label:"利用時間超過", value:`${longN}件`, level:longN>0?"warn":"good"},
      {label:"加算取得候補", value:`${transDays}日`, level:transDays>0?"info":null},
      {label:"職員配置注意", value:staffAlert?"要確認":"問題なし", level:staffAlert?"warn":"good"},
    ],
    comment:p.join(""), priorities,
  };
}

// ==================== 予定表OCR自動登録 ====================
// カメラで紙の利用予定表を撮影→Claude Vision APIで解析→予定を自動登録
function ScheduleOCRScreen({user, store, onBack}){
  const [step,setStep]=useState("select"); // select|preview|loading|confirm|done
  const [imgB64,setImgB64]=useState("");
  const [imgUrl,setImgUrl]=useState("");
  const [visits,setVisits]=useState([]);
  const [ocrInfo,setOcrInfo]=useState(null); // {childName,facilityName,year,month}
  const [selUserId,setSelUserId]=useState("");
  const [year,setYear]=useState(new Date().getFullYear());
  const [month,setMonth]=useState(new Date().getMonth()+1);
  const [saving,setSaving]=useState(false);
  const [error,setError]=useState("");
  const [progress,setProgress]=useState(0);      // OCR進捗(0-100)
  const [existing,setExisting]=useState([]);      // 既存planned_visits(当該児童・年月)
  const [result,setResult]=useState({ok:0,warn:0,err:0,skip:0,absent:0,transport:0,events:0,unchanged:0}); // 登録結果集計
  const [saveErrors,setSaveErrors]=useState([]);                 // 登録できなかった日と理由
  const [facVisits,setFacVisits]=useState([]);    // 同月・施設内の全予定（施設横断チェック用）
  const [aiChecks,setAiChecks]=useState(null);    // AI運営サポート結果
  const [aiRunning,setAiRunning]=useState(false); // AI解析中フラグ
  const [report,setReport]=useState(null);        // AI施設運営レポート
  const fileRef=useRef();
  const facilityId=user.selectedFacilityId;
  const users=store.dynUsers.filter(u=>u.facilityId===facilityId&&u.active!==false);

  // ── 営業時間（施設設定→未設定なら既定08:00〜19:00）──
  const _facSet=(store.facilityBillingSettings&&store.facilityBillingSettings[facilityId])||{};
  const hmToMin=t=>{ if(!t||!/^\d{1,2}:\d{2}/.test(String(t)))return null; const[h,m]=String(t).split(":").map(Number); return h*60+m; };
  const openMin=hmToMin(_facSet.openTime)??480, closeMin=hmToMin(_facSet.closeTime)??1140;
  const _norm=s=>(s||"").replace(/[\s　]/g,"");
  const dateOf=v=>`${year}-${String(month).padStart(2,"0")}-${String(v.date).padStart(2,"0")}`;

  // ── 名前候補（OCR名→利用者マスタを類似度順）──
  const nameCandidates=(()=>{
    const q=_norm(ocrInfo?.childName); if(!q) return [];
    return users.map(u=>{
      const n=_norm(u.name), k=_norm(_userKana(u));
      let score=0;
      if(n===q) score=100;
      else if(n.includes(q)||q.includes(n)) score=88;
      else if(k&&(k.includes(q)||q.includes(k))) score=74;
      else { const sur=q.slice(0,2); if(sur&&(n.startsWith(sur)||n.includes(sur))) score=62; }
      return {u,score};
    }).filter(x=>x.score>0).sort((a,b)=>b.score-a.score).slice(0,5);
  })();

  // ── 行ごとの検証（エラー/警告）──
  const rowIssues=v=>{
    const errs=[],warns=[];
    if(v.status!=="欠席"){
      const s=hmToMin(v.startTime), e=hmToMin(v.endTime);
      if(s!=null&&e!=null&&s>=e) errs.push("開始≥終了");
      if((s!=null&&s<openMin)||(e!=null&&e>closeMin)) warns.push("営業時間外");
    }
    if(v.date){
      const dd=Math.round((new Date(dateOf(v))-new Date(todayISO()))/86400000);
      if(!isNaN(dd)){ if(dd>180) warns.push("未来日異常"); if(dd<-90) warns.push("過去日異常"); }
    }
    if(visits.filter(x=>String(x.date)===String(v.date)).length>1) warns.push("重複");
    if(existing.some(x=>x.visit_date===dateOf(v))) warns.push("既存あり");
    return {errs,warns};
  };
  // ── 信頼度バッジ ──
  // ── 信頼度の色分け（95%以上=緑 / 85〜94%=黄 / 84%以下=赤）──
  const CONF_HIGH=95, CONF_MID=85, CONF_REVIEW=90;   // REVIEW未満は「要確認」に数える
  const confColor=c=> c==null?"var(--tx3)": c>=CONF_HIGH?"var(--gr)": c>=CONF_MID?"#e0a828":"var(--ro)";
  const confBg   =c=> c==null?"rgba(120,120,120,0.12)": c>=CONF_HIGH?"rgba(44,170,96,0.15)": c>=CONF_MID?"rgba(224,168,40,0.18)":"rgba(224,56,56,0.15)";
  const confText =c=> c==null?"—": c>=CONF_HIGH?`${c}%`: c>=CONF_MID?`${c}% ⚠`:`${c}% ⚠要確認`;
  // 一目で分かるバッジ表示
  const ConfBadge=({c})=><span style={{display:"inline-block",fontSize:11,fontWeight:800,whiteSpace:"nowrap",
    color:confColor(c),background:confBg(c),border:`1px solid ${confColor(c)}55`,
    borderRadius:12,padding:"2px 8px"}}>{confText(c)}</span>;

  // ── AI読取サマリー（読取件数・成功率・要確認件数）──
  const ocrSummary=(()=>{
    const list=visits.filter(v=>v.confidence!=null);
    const total=visits.length;
    if(!total) return null;
    const avg=list.length?Math.round(list.reduce((s,v)=>s+v.confidence,0)/list.length):null;
    const review=visits.filter(v=>v.confidence==null||v.confidence<CONF_REVIEW).length;
    return {total, rate:avg, review};
  })();

  // ── 既存planned_visits読込（当該児童・年月）──
  const loadExisting=async(childId)=>{
    if(!childId){ setExisting([]); return; }
    try{ const all=await sbLoad("planned_visits");
      const ym=`${year}-${String(month).padStart(2,"0")}`;
      const arr=(Array.isArray(all)?all:[]).filter(x=>(x.visit_date||"").startsWith(ym));
      setFacVisits(arr);
      setExisting(arr.filter(x=>x.child_id===childId));
    }catch(_){ setExisting([]); }
  };
  const pickUser=id=>{ setSelUserId(id); loadExisting(id); };

  // ── AI運営サポート: confirm表示後に非同期解析（OCR/入力をブロックしない）──
  useEffect(()=>{
    if(step!=="confirm"){ setAiChecks(null); setAiRunning(false); return; }
    setAiRunning(true);
    const h=setTimeout(()=>{
      setAiChecks(analyzeSchedule({visits, selUserId, openMin, closeMin, facVisits}));
      setAiRunning(false);
    }, 350);
    return ()=>clearTimeout(h);
  },[step, visits, selUserId, facVisits, openMin, closeMin]);

  // 画像選択（カメラ撮影 or ファイル選択）
  // ★ Vercelの4.5MBボディ上限を超えないよう、送信前に必ず縮小＋JPEG再エンコードする。
  //   HEIC/PNG/巨大写真も一律JPEG化されるため mediaType 不一致も同時に解消される。
  const handleFile=async e=>{
    const input=e.target;                  // React18はプールしないが明示的に保持
    const file=input.files?.[0];
    if(!file)return;
    setError("");
    try{
      const dataUrl=await _ocrCompressImage(file);
      const b64=dataUrl.split(",")[1]||"";
      if(!b64) throw new Error("画像データが空です");
      setImgUrl(dataUrl);
      setImgB64(b64);
      setStep("preview");
      if(_OCR_DEV) console.log(`[OCR] 画像圧縮 完了 type=${file.type||"(unknown)"} b64=${(b64.length/1024/1024).toFixed(2)}MB`);
    }catch(err){
      console.error("[OCR] 画像の読み込み・変換に失敗:", err?.message||err);
      setError("画像を読み込めませんでした。もう一度撮影するか、別の写真をお試しください。");
      setStep("select");
    }
    try{ input.value=""; }catch(_){}       // 同じ写真を選び直せるようにする
  };

  // OCR実行
  const runOCR=async()=>{
    setStep("loading");setError("");setProgress(6);
    const timer=setInterval(()=>setProgress(p=>Math.min(92,p+Math.random()*11)),550);
    let stage="画像送信";
    try{
      if(!imgB64) throw _ocrErr(stage,"画像が読み込まれていません。撮影し直してください。");
      if(_OCR_DEV) console.log(`[OCR] stage=${stage} path=/api/ocr mode=yotei b64KB=${Math.round(imgB64.length/1024)}`);
      const resp=await fetch("/api/ocr",{
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body:JSON.stringify({imageBase64:imgB64,mediaType:"image/jpeg",mode:"yotei",year,month})
      });
      // ★ resp.json() を直接呼ばない：413(text/plain)等でSafariが不可解な例外を投げるため
      const d=await _ocrReadJson(resp);
      stage="OCR結果の解析";
      if(_OCR_DEV) console.log(`[OCR] stage=${stage} responseType=${Array.isArray(d?.data?.visits)?"array":typeof d?.data} visits=${d?.data?.visits?.length??0}`);
      clearInterval(timer);setProgress(100);
      if(!(d&&d.success&&d.data)){
        // 失敗時はサーバが返した生テキスト(=JSON.parse前の文字列)をconsoleに出す。
        // 原因(コードブロック/説明文/途中切れ)をこの1行で判別できるようにする。
        if(d?.rawText){
          console.error(`[OCR] サーバ解析失敗 stopReason=${d.stopReason||"-"} rawTextLen=${d.rawText.length}`);
          console.error(`[OCR] JSON.parse前の文字列(先頭500字):\n${String(d.rawText).slice(0,500)}`);
          console.error(`[OCR] JSON.parse前の文字列(末尾300字):\n${String(d.rawText).slice(-300)}`);
        }
        throw _ocrErr(stage, d?.error||"読み取りに失敗しました。もう一度撮影してください。");
      }
      // 応答が途中で切れて修復された場合は、日付が欠けている可能性を警告する
      if(d.truncated){
        console.warn("[OCR] ⚠ 応答が途中で切れたため自動修復しました。日付の抜けがないか確認画面で確認してください。");
        setError("⚠ 読み取り結果が長く、一部が欠けている可能性があります。日付の抜けをご確認ください。");
      }
      {
        const r=d.data;
        stage="日付・時刻の変換";
        const yy=r.year||year, mm=r.month||month;
        setOcrInfo({childName:r.childName,nameConfidence:r.nameConfidence,facilityName:r.facilityName,year:yy,month:mm});
        if(r.year) setYear(r.year);
        if(r.month) setMonth(r.month);
        // ★ OCR値を正規化（空欄・「〜」・丸印・改行・全角数字・不正時刻を安全に処理）。
        //   変換できない値は null にして「未登録／要確認」に倒し、登録処理は止めない。
        const normalized=(Array.isArray(r.visits)?r.visits:[]).map((v,i)=>{
          const st=v.status==="欠席"?"欠席":"来所";
          return {...v,_id:i,_checked:true,_action:"update", status:st,
            date:parseInt(v.date,10),
            startTime: st==="欠席"?null:_ocrTime(v.startTime),
            endTime:   st==="欠席"?null:_ocrTime(v.endTime),
            pickup:    st==="欠席"?false:_ocrFlag(v.pickup),
            dropoff:   st==="欠席"?false:_ocrFlag(v.dropoff),
            memo:_ocrText(v.memo), event:_ocrText(v.event)};
        }).filter(v=>Number.isFinite(v.date)&&v.date>=1&&v.date<=31);
        if(_OCR_DEV) console.log(`[OCR] stage=${stage} 正規化後 ${normalized.length}件（除外 ${(r.visits?.length||0)-normalized.length}件）`);
        setVisits(normalized);
        // 名前からユーザー自動マッチング（一致すれば既存予定も読込）
        let matchedId="";
        if(r.childName){
          const q=_norm(r.childName);
          const found=users.find(u=>_norm(u.name)===q)||users.find(u=>_norm(u.name).includes(q)||q.includes(_norm(u.name)));
          if(found){ matchedId=found.id; setSelUserId(found.id); }
        }
        // 既存planned_visits読込（当該児童＋施設横断チェック用に同月全件）
        try{ const all=await sbLoad("planned_visits");
          const ym=`${yy}-${String(mm).padStart(2,"0")}`;
          const arr=(Array.isArray(all)?all:[]).filter(x=>(x.visit_date||"").startsWith(ym));
          setFacVisits(arr);
          setExisting(arr.filter(x=>x.child_id===matchedId));
        }catch(_){ setExisting([]); setFacVisits([]); }
        setStep("confirm");
      }
    }catch(e){
      clearInterval(timer);
      const st=e?.stage||stage;
      // consoleには段階と詳細（本文は先頭200字まで）。base64・氏名等は出さない。
      console.error(`[OCR] 失敗 stage=${st} msg=${e?.message||e}`, e?.detail||"");
      setError(`${st}に失敗しました: ${e?.message||"不明なエラー"}`);
      setStep("preview");
    }
  };

  // 行の編集
  const updVisit=(idx,key,val)=>setVisits(p=>p.map((v,i)=>i===idx?{...v,[key]:val}:v));
  // 欠席トグル（来所⇄欠席）
  const toggleAbsent=(idx,checked)=>setVisits(p=>p.map((v,i)=>i===idx?{...v,status:checked?"欠席":"来所"}:v));

  // 保存（予定→planned_visits / 欠席→att_data に振り分け・既存はupdate/skip）
  const save=async()=>{
    if(!selUserId){alert("利用者を選択してください");return;}
    setSaving(true);
    const u=users.find(x=>x.id===selUserId);
    let ok=0,warn=0,err=0,skip=0;
    let absent=0,transport=0,events=0,unchanged=0;  // 完了画面の内訳／差分保存の集計
    const failed=[];            // 登録できなかった日と理由（画面＋consoleに出す）
    const seen=new Set();       // 同一日の二重登録を防止

    // ★ 既存行と中身が同じなら書き込まない（変更した行だけ更新する）
    const isSame=(prev,p)=>prev
      && (prev.start_time||null)===p.start_time
      && (prev.end_time||null)===p.end_time
      && !!prev.pickup_required===p.pickup_required
      && !!prev.dropoff_required===p.dropoff_required
      && (prev.memo||null)===p.memo
      && (prev.event_name||null)===p.event_name;
    // ── ログ6: Supabase保存開始 ──
    console.log(`[OCR] 6.Supabase保存開始 対象=${visits.filter(v=>v._checked).length}件 ${year}年${month}月`);
    for(const v of visits){
      if(!v._checked) continue;
      // ★ 1日分の失敗が全31日分を止めないよう、行ごとにtry/catchで隔離する
      try{
        const iss=rowIssues(v);
        if(iss.errs.length){ err++; failed.push(`${v.date}日: ${iss.errs[0]}`); continue; }
        // ★ Invalid Date / NaN を Supabase へ送らない
        const dateStr=_ocrDate(year,month,v.date);
        if(!dateStr){ err++; failed.push(`${v.date}日: 日付を認識できませんでした`); continue; }
        if(seen.has(dateStr)){ skip++; continue; }             // 同日重複はスキップ
        seen.add(dateStr);
        const hasExisting=existing.some(x=>x.visit_date===dateStr);
        if(hasExisting && v._action==="skip"){ skip++; continue; } // 既存ありでスキップ選択

        const MM=dateStr.slice(5,7), DD=dateStr.slice(8,10);
        const st=_ocrTime(v.startTime), et=_ocrTime(v.endTime);

        if(v.status==="欠席"){
          // ── 欠席 → 出欠管理(att_data) ──
          store.setAtt(selUserId,dateStr,"欠席");
          absent++;
        }else{
          // ── 来所予定 → planned_visits（+ schedules / scheduleData / 出欠「予定」）──
          const key=selUserId+"_"+year+"_"+MM+"_"+DD;
          const schedRow={
            id:key, user_id:selUserId, user_name:u?.name||"", facility_id:facilityId,
            date:dateStr, status:"来所予定",
            transport_to:!!v.pickup, transport_from:!!v.dropoff,
            updated_at:new Date().toISOString(),
          };
          // 予約詳細の本命テーブル。既存更新時はcreated_atを保持
          const prev=existing.find(x=>x.visit_date===dateStr);
          const payload={
            id:selUserId+"_"+dateStr,
            child_id:selUserId, facility_id:facilityId, visit_date:dateStr,
            start_time:st, end_time:et,
            pickup_required:!!v.pickup, dropoff_required:!!v.dropoff,
            memo:v.memo||null, event_name:v.event||null,
          };
          // ★ 既存行と完全に同じなら書き込みを省略（変更した行だけ更新）
          if(isSame(prev,payload)){ unchanged++; skip++; continue; }

          if(store.setScheduleData) store.setScheduleData(p=>({...p,[key]:schedRow}));
          if(store.saveScheduleRow) store.saveScheduleRow(schedRow);
          store.setAtt(selUserId,dateStr,"予定");
          // ★ awaitで結果を確認（sbSaveは失敗時にstatus/bodyをconsole.errorへ出力する）
          const saved=await sbSave("planned_visits",{
            ...payload,
            created_at:(prev&&prev.created_at)||new Date().toISOString(),
            updated_at:new Date().toISOString(),
          });
          if(saved===false){ err++; failed.push(`${dateStr}: 予定表の保存に失敗しました`); continue; }
          if(v.pickup||v.dropoff) transport++;
          if(v.event||v.memo)     events++;
        }
        ok++;
        if(iss.warns.length) warn++;
      }catch(rowErr){
        err++;
        failed.push(`${v.date}日: ${rowErr?.message||"不明なエラー"}`);
        console.error(`[OCR保存] 1日分の登録に失敗 date=${v.date}`, rowErr?.message||rowErr);
      }
    }
    // ── ログ7: Supabase保存成功 ──
    console.log(`[OCR] 7.Supabase保存完了 成功=${ok} 警告=${warn} 失敗=${err} スキップ=${skip}（うち変更なし=${unchanged}）`);
    console.log(`[OCR] 内訳 欠席=${absent} 送迎あり=${transport} イベント=${events}`);
    if(failed.length) console.warn(`[OCR] 登録できなかった日 ${failed.length}件`, failed);
    setSaveErrors(failed);
    setResult({ok,warn,err,skip,absent,transport,events,unchanged});
    // AI施設運営レポートを非同期生成（登録処理をブロックしない）
    setTimeout(()=>{ try{ setReport(buildScheduleReport({visits, selUserId, facVisits, openMin, closeMin, store, todayStr:todayISO()})); }catch(_){ setReport(null); } },0);
    setSaving(false);
    setStep("done");
  };

  // ── 完了画面 ──
  if(step==="done") return <div className="succ">
    <div className="si">✅</div>
    <div className="st">予定登録完了</div>
    <div className="sd">{result.ok}件を登録しました</div>

    {/* ── 登録内訳（登録件数・欠席・送迎あり・イベント）── */}
    <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:8,marginTop:14,width:"100%",maxWidth:420}}>
      {[
        {lbl:"登録件数",  val:result.ok,                 col:"var(--gr)", bg:"rgba(44,170,96,0.12)"},
        {lbl:"欠席",      val:result.absent||0,          col:"var(--ro)", bg:"rgba(224,56,56,0.10)"},
        {lbl:"送迎あり",  val:result.transport||0,       col:"var(--tl)", bg:"rgba(58,160,216,0.12)"},
        {lbl:"イベント",  val:result.events||0,          col:"var(--ac)", bg:"rgba(240,110,40,0.12)"},
      ].map(s=>(
        <div key={s.lbl} style={{background:s.bg,border:`1px solid ${s.col}44`,borderRadius:10,padding:"9px 4px",textAlign:"center"}}>
          <div style={{fontSize:9.5,fontWeight:700,color:"var(--tx2)",marginBottom:3}}>{s.lbl}</div>
          <div style={{fontSize:19,fontWeight:900,color:s.col,lineHeight:1.1}}>{s.val}</div>
        </div>
      ))}
    </div>
    {result.unchanged>0&&<div style={{fontSize:11,color:"var(--tx3)",marginTop:8}}>
      💡 {result.unchanged}件は前回と内容が同じだったため、更新をスキップしました
    </div>}

    <div style={{display:"flex",gap:8,marginTop:12,flexWrap:"wrap",justifyContent:"center"}}>
      <span style={{fontSize:12,fontWeight:800,color:"var(--gr)",background:"rgba(44,170,96,0.12)",padding:"5px 12px",borderRadius:20}}>✅ 成功 {result.ok}</span>
      <span style={{fontSize:12,fontWeight:800,color:"#c9971f",background:"rgba(201,151,31,0.12)",padding:"5px 12px",borderRadius:20}}>⚠ 警告 {result.warn}</span>
      <span style={{fontSize:12,fontWeight:800,color:"var(--ro)",background:"rgba(224,56,56,0.1)",padding:"5px 12px",borderRadius:20}}>✕ エラー {result.err}</span>
      <span style={{fontSize:12,fontWeight:800,color:"var(--tx3)",background:"rgba(120,120,120,0.12)",padding:"5px 12px",borderRadius:20}}>⏭ スキップ {result.skip}</span>
    </div>

    {/* 登録できなかった日の内訳（原因を隠さず提示。個人情報は含めない）*/}
    {saveErrors.length>0&&<div style={{marginTop:14,textAlign:"left",background:"rgba(224,56,56,0.08)",
                                       border:"1px solid rgba(224,56,56,0.3)",borderRadius:10,padding:"10px 12px"}}>
      <div style={{fontSize:12,fontWeight:800,color:"var(--ro)",marginBottom:6}}>⚠ 登録できなかった日（{saveErrors.length}件）</div>
      <div style={{fontSize:11,color:"var(--tx2)",lineHeight:1.8,maxHeight:150,overflowY:"auto"}}>
        {saveErrors.map((m,i)=><div key={i}>・{m}</div>)}
      </div>
      <div style={{fontSize:11,color:"var(--tx3)",marginTop:6}}>該当日は「生徒予定表」から手動で登録してください。</div>
    </div>}

    {/* ── AI施設運営レポート（登録完了後・共通コンポーネント）── */}
    <AiReportCard report={report}/>

    <div style={{display:"flex",gap:10,marginTop:16}}>
      <button className="bpri" style={{maxWidth:180}} onClick={()=>{setStep("select");setImgB64("");setImgUrl("");setVisits([]);setOcrInfo(null);setExisting([]);setResult({ok:0,warn:0,err:0,skip:0,absent:0,transport:0,events:0,unchanged:0});setSaveErrors([]);setProgress(0);setReport(null);setError("");}}>続けて登録</button>
      <button className="bpri" style={{maxWidth:150,background:"rgba(255,255,255,0.1)"}} onClick={onBack}>ホームへ</button>
    </div>
  </div>;

  return <div className="fl-wrap">
    <div className="fl-hd"><button className="bback" onClick={step==="preview"||step==="confirm"?()=>setStep("select"):onBack}>← 戻る</button>
      <div className="fl-title">📸 予定表 自動読み取り</div>
    </div>

    {/* ── STEP1: 撮影・選択 ── */}
    {step==="select"&&<div className="fc">
      <div style={{background:"linear-gradient(135deg,rgba(58,160,216,0.1),rgba(44,170,96,0.08))",border:"1px solid rgba(58,160,216,0.25)",borderRadius:14,padding:"16px 18px",marginBottom:16}}>
        <div style={{fontSize:13,fontWeight:700,color:"var(--tl)",marginBottom:6}}>📋 使い方</div>
        <div style={{fontSize:12,color:"var(--tx2)",lineHeight:1.8}}>
          1. 利用予定表を平らに置いて撮影<br/>
          2. AIが来所日・時間・送迎を自動読み取り<br/>
          3. 内容を確認して「登録する」をタップ
        </div>
      </div>
      <div style={{marginBottom:12}}>
        <div className="slbl">対象の年月</div>
        <div style={{display:"flex",gap:8,alignItems:"center"}}>
          <select className="fsm" value={year} onChange={e=>setYear(+e.target.value)}>
            {[2024,2025,2026,2027].map(y=><option key={y} value={y}>{y}年</option>)}
          </select>
          <select className="fsm" value={month} onChange={e=>setMonth(+e.target.value)}>
            {Array.from({length:12},(_,i)=>i+1).map(m=><option key={m} value={m}>{m}月</option>)}
          </select>
        </div>
      </div>
      <input ref={fileRef} type="file" accept="image/*" style={{display:"none"}} onChange={handleFile}/>
      <button className="bsave" style={{marginBottom:10,fontSize:15,padding:"16px"}} onClick={()=>fileRef.current.click()}>
        📷 予定表を撮影する
      </button>
      <button style={{width:"100%",padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx2)",fontSize:13,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>{const i=document.createElement("input");i.type="file";i.accept="image/*";i.onchange=handleFile;i.click();}}>
        🖼️ アルバムから選ぶ
      </button>
    </div>}

    {/* ── STEP2: プレビュー ── */}
    {step==="preview"&&<div className="fc">
      {imgUrl&&<img src={imgUrl} alt="予定表" style={{width:"100%",borderRadius:10,marginBottom:14,border:"1px solid var(--bd)"}}/>}
      {error&&<div style={{color:"var(--ro)",fontSize:12,marginBottom:10,padding:"8px 12px",background:"rgba(224,56,56,0.08)",borderRadius:8}}>{error}</div>}
      <button className="bsave" onClick={runOCR} style={{marginBottom:10}}>🤖 AIで自動読み取り</button>
      <button style={{width:"100%",padding:"10px",borderRadius:9,border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>{setStep("select");setImgUrl("");setImgB64("");}}>撮り直す</button>
    </div>}

    {/* ── STEP3: 読み取り中（Progress表示）── */}
    {step==="loading"&&<div style={{textAlign:"center",padding:"56px 24px"}}>
      <div style={{fontSize:48,marginBottom:16}}>🤖</div>
      <div style={{fontSize:15,fontWeight:800,color:"var(--tl)",marginBottom:10}}>AI解析中...</div>
      <div style={{width:"100%",maxWidth:320,height:10,margin:"0 auto 8px",background:"var(--bg2)",borderRadius:20,overflow:"hidden",border:"1px solid var(--bd)"}}>
        <div style={{width:`${Math.round(progress)}%`,height:"100%",background:"linear-gradient(90deg,var(--ac),var(--gr))",borderRadius:20,transition:"width 0.5s ease"}}/>
      </div>
      <div style={{fontSize:12,fontWeight:700,color:"var(--ac)",marginBottom:4}}>{Math.round(progress)}%</div>
      <div style={{fontSize:12,color:"var(--tx3)"}}>予定表を読み取っています（10〜20秒）</div>
    </div>}

    {/* ── STEP4: 確認・修正 ── */}
    {step==="confirm"&&<div className="fc">
      {ocrInfo&&<div style={{background:"rgba(44,170,96,0.1)",border:"1px solid rgba(44,170,96,0.3)",borderRadius:10,padding:"10px 14px",marginBottom:14}}>
        <div style={{fontSize:12,fontWeight:700,color:"var(--gr)"}}>✅ 読み取り完了</div>
        <div style={{fontSize:12,color:"var(--tx2)",marginTop:4}}>
          {ocrInfo.facilityName&&<span style={{marginRight:10}}>📍 {ocrInfo.facilityName}</span>}
          {ocrInfo.childName&&<span>👤 {ocrInfo.childName}</span>}
        </div>
      </div>}

      {/* ── AI読取サマリー（読取件数・成功率・要確認）── */}
      {ocrSummary&&<div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
        {[
          {lbl:"読取件数", val:`${ocrSummary.total}件`, col:"var(--tl)",  bg:"rgba(58,160,216,0.12)"},
          {lbl:"成功率",   val:ocrSummary.rate==null?"—":`${ocrSummary.rate}%`,
            col:confColor(ocrSummary.rate), bg:confBg(ocrSummary.rate)},
          {lbl:"要確認",   val:`${ocrSummary.review}件`,
            col:ocrSummary.review===0?"var(--gr)":"#e0a828",
            bg:ocrSummary.review===0?"rgba(44,170,96,0.12)":"rgba(224,168,40,0.16)"},
        ].map(s=>(
          <div key={s.lbl} style={{background:s.bg,border:`1px solid ${s.col}44`,borderRadius:10,padding:"9px 6px",textAlign:"center"}}>
            <div style={{fontSize:10,fontWeight:700,color:"var(--tx2)",marginBottom:3}}>{s.lbl}</div>
            <div style={{fontSize:18,fontWeight:900,color:s.col,lineHeight:1.1}}>{s.val}</div>
          </div>
        ))}
      </div>}
      {ocrSummary&&ocrSummary.review>0&&<div style={{fontSize:11,color:"var(--tx3)",marginTop:-8,marginBottom:12}}>
        ⚠ 信頼度{CONF_REVIEW}%未満の{ocrSummary.review}件は、下の表で内容をご確認ください。
      </div>}

      {/* 利用者選択（名前候補＋信頼度） */}
      <div className="slbl">利用者を選択
        {ocrInfo?.childName&&<span style={{marginLeft:6,fontWeight:800,color:confColor(ocrInfo.nameConfidence)}}>（AI読取: {ocrInfo.childName} {confText(ocrInfo.nameConfidence)}）</span>}
      </div>
      <select className="fsm" style={{width:"100%",marginBottom:8,fontSize:14,padding:"10px 12px"}} value={selUserId} onChange={e=>pickUser(e.target.value)}>
        <option value="">-- 選択してください --</option>
        {users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
      </select>
      {nameCandidates.length>0&&<div style={{display:"flex",gap:6,flexWrap:"wrap",alignItems:"center",marginBottom:14}}>
        <span style={{fontSize:10,color:"var(--tx3)"}}>候補:</span>
        {nameCandidates.map(c=><button key={c.u.id} onClick={()=>pickUser(c.u.id)} style={{fontSize:11,fontWeight:700,padding:"4px 10px",borderRadius:16,border:"1px solid "+(selUserId===c.u.id?"var(--ac)":"var(--bd)"),background:selUserId===c.u.id?"rgba(240,110,40,0.12)":"var(--bg)",color:selUserId===c.u.id?"var(--ac)":"var(--tx2)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>{c.u.name} {c.score}%</button>)}
      </div>}

      {/* 読み取り結果テーブル（欠席・信頼度・検証・既存処理を含む） */}
      <div className="slbl">{year}年{month}月 予定 — {visits.filter(v=>v._checked).length}件（チェックを外すと登録しない）</div>
      <div style={{overflowX:"auto",marginBottom:14}}>
        <table style={{width:"100%",borderCollapse:"collapse",fontSize:12,minWidth:560}}>
          <thead><tr style={{background:"var(--bg2)"}}>
            {["✓","日付","欠席","利用時間","送迎","備考/イベント","信頼度"].map(h=><th key={h} style={{padding:"7px 8px",textAlign:"left",color:"var(--tx2)",fontSize:10,fontWeight:700,borderBottom:"2px solid var(--bd)",whiteSpace:"nowrap"}}>{h}</th>)}
          </tr></thead>
          <tbody>{visits.map((v,i)=>{ const iss=rowIssues(v); const absent=v.status==="欠席"; const hasEx=existing.some(x=>x.visit_date===dateOf(v)); return <tr key={i} style={{borderBottom:"1px solid var(--bd)",background:!v._checked?"rgba(0,0,0,0.03)":absent?"rgba(224,56,56,0.05)":"",opacity:v._checked?1:0.5}}>
            <td style={{padding:"6px 8px",verticalAlign:"top"}}><input type="checkbox" checked={v._checked} onChange={e=>updVisit(i,"_checked",e.target.checked)}/></td>
            <td style={{padding:"6px 8px",whiteSpace:"nowrap",verticalAlign:"top"}}>
              <div style={{display:"flex",alignItems:"center",gap:2}}>
                <span style={{color:"var(--tx3)",fontSize:11}}>{month}/</span>
                <input type="number" min={1} max={31} value={v.date||""} onChange={e=>updVisit(i,"date",e.target.value?+e.target.value:"")} style={{width:42,fontSize:12,fontWeight:700,padding:"2px 4px",border:"1px solid var(--bd)",borderRadius:4,background:"var(--bg)",color:"var(--tx)"}}/>
                <span style={{fontSize:10,color:"var(--tx3)"}}>({v.dayOfWeek})</span>
              </div>
              {(iss.errs.length>0||iss.warns.length>0)&&<div style={{display:"flex",gap:3,flexWrap:"wrap",marginTop:3,maxWidth:120}}>
                {iss.errs.map(w=><span key={w} style={{fontSize:9,fontWeight:800,color:"#fff",background:"var(--ro)",padding:"1px 5px",borderRadius:8}}>{w}</span>)}
                {iss.warns.map(w=><span key={w} style={{fontSize:9,fontWeight:800,color:"#8a6d00",background:"rgba(201,151,31,0.22)",padding:"1px 5px",borderRadius:8}}>{w}</span>)}
              </div>}
            </td>
            <td style={{padding:"6px 8px",textAlign:"center",verticalAlign:"top"}}>
              <input type="checkbox" checked={absent} onChange={e=>toggleAbsent(i,e.target.checked)} title="欠席"/>
            </td>
            <td style={{padding:"6px 8px",whiteSpace:"nowrap",verticalAlign:"top",opacity:absent?0.35:1}}>
              <input type="time" disabled={absent} value={v.startTime||""} onChange={e=>updVisit(i,"startTime",e.target.value)} style={{width:76,fontSize:11,padding:"2px 4px",border:"1px solid "+(iss.errs.includes("開始≥終了")?"var(--ro)":"var(--bd)"),borderRadius:4,background:"var(--bg)",color:"var(--tx)"}}/>
              <span style={{margin:"0 3px",color:"var(--tx3)"}}>〜</span>
              <input type="time" disabled={absent} value={v.endTime||""} onChange={e=>updVisit(i,"endTime",e.target.value)} style={{width:76,fontSize:11,padding:"2px 4px",border:"1px solid "+(iss.errs.includes("開始≥終了")?"var(--ro)":"var(--bd)"),borderRadius:4,background:"var(--bg)",color:"var(--tx)"}}/>
            </td>
            <td style={{padding:"6px 8px",whiteSpace:"nowrap",verticalAlign:"top",opacity:absent?0.35:1}}>
              <label style={{fontSize:10,marginRight:6}}><input type="checkbox" disabled={absent} checked={v.pickup||false} onChange={e=>updVisit(i,"pickup",e.target.checked)}/> 迎</label>
              <label style={{fontSize:10}}><input type="checkbox" disabled={absent} checked={v.dropoff||false} onChange={e=>updVisit(i,"dropoff",e.target.checked)}/> 送</label>
            </td>
            <td style={{padding:"6px 8px",verticalAlign:"top"}}>
              <input value={v.memo||v.event||""} onChange={e=>updVisit(i,"memo",e.target.value)} placeholder="備考" style={{width:"100%",minWidth:90,fontSize:11,padding:"2px 6px",border:"1px solid var(--bd)",borderRadius:4,background:"var(--bg)",color:"var(--tx)"}}/>
            </td>
            <td style={{padding:"6px 8px",whiteSpace:"nowrap",verticalAlign:"top"}}>
              <ConfBadge c={v.confidence}/>
              {hasEx&&<div style={{marginTop:4}}>
                <select value={v._action||"update"} onChange={e=>updVisit(i,"_action",e.target.value)} style={{fontSize:10,padding:"1px 3px",border:"1px solid var(--bd)",borderRadius:4,background:"var(--bg)",color:"var(--tx2)"}}>
                  <option value="update">既存を更新</option>
                  <option value="skip">スキップ</option>
                </select>
              </div>}
            </td>
          </tr>;})}</tbody>
        </table>
      </div>

      {/* ── AI運営サポート（確認画面下部・非同期解析）── */}
      <div style={{margin:"2px 0 14px",border:"1px solid var(--bd)",borderRadius:12,overflow:"hidden"}}>
        <div style={{background:"var(--bg2)",padding:"8px 12px",fontSize:12,fontWeight:900,color:"var(--tl)",letterSpacing:1,textAlign:"center"}}>━━ 🤖 AIチェック結果 ━━</div>
        <div style={{padding:"10px 12px"}}>
          {aiRunning&&<div style={{fontSize:12,color:"var(--tx3)",display:"flex",alignItems:"center",gap:8}}><span className="spin" style={{fontSize:15}}>🤖</span> AI運営チェック中...</div>}
          {!aiRunning&&aiChecks&&aiChecks.length===0&&<div style={{fontSize:13,fontWeight:800,color:"var(--gr)"}}>✅ 問題なし（確認が必要な点は見つかりませんでした）</div>}
          {!aiRunning&&aiChecks&&aiChecks.length>0&&<div style={{display:"flex",flexDirection:"column",gap:8}}>
            {aiChecks.map((c,i)=>{ const col=c.level==="warn"?"#c9971f":c.level==="info"?"var(--ac)":"var(--gr)"; const bg=c.level==="warn"?"rgba(201,151,31,0.09)":c.level==="info"?"rgba(240,110,40,0.07)":"rgba(44,170,96,0.08)";
              return <div key={i} style={{background:bg,border:"1px solid "+col+"44",borderRadius:9,padding:"8px 10px"}}>
                <div style={{fontSize:12.5,fontWeight:800,color:col}}>{c.icon} {c.title}</div>
                {c.detail&&<div style={{fontSize:11,color:"var(--tx2)",marginTop:2,lineHeight:1.5}}>{c.detail}</div>}
              </div>; })}
          </div>}
        </div>
      </div>

      {/* Sticky Footerの高さぶんの余白（ボタンが内容に重ならないようにする）*/}
      <div style={{height:96}}/>

      {/* ── 保存ボタンは画面下に固定（スマホでスクロールしても常に押せる）── */}
      <div style={{position:"sticky",bottom:0,left:0,right:0,zIndex:20,
                   margin:"0 -14px -14px",padding:"10px 14px calc(10px + env(safe-area-inset-bottom))",
                   background:"var(--bg)",borderTop:"1px solid var(--bd)",
                   boxShadow:"0 -6px 20px rgba(0,0,0,0.45)"}}>
        <button className="bsave" disabled={!selUserId||saving||visits.filter(v=>v._checked).length===0} onClick={save} style={{marginBottom:8}}>
          {saving?"登録中...":"✅ "+visits.filter(v=>v._checked).length+"件を登録する"}
        </button>
        <button style={{width:"100%",padding:"9px",borderRadius:9,border:"1.5px solid var(--bd)",background:"var(--bg2)",color:"var(--tx3)",fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}} onClick={()=>setStep("preview")}>← 撮り直す</button>
      </div>
    </div>}
  </div>;
}

// ==================== 活動・イベントカレンダー（店舗別管理）====================
// 店舗ごとの活動予定・イベントを登録・管理し、業務日報へ自動反映する
function ActivityCalendarScreen({ user, store, onBack }) {
  const FACILITIES_LIST = [
    { id: "f1", name: "GO HOME" },
    { id: "f2", name: "GO ROOM" },
    { id: "f3", name: "GO TOWN 1ST" },
    { id: "f4", name: "GO TOWN 2ND" },
  ];
  const isAdmin  = user.role === "admin";
  const isMgr    = user.role === "admin" || user.role === "manager";
  // admin は全施設閲覧可、それ以外は所属施設のみ
  const defaultFac = isAdmin ? "all" : (user.selectedFacilityId || "f1");
  const today = todayISO();

  // ── 状態 ──
  const [tab,        setTab]        = useState("calendar"); // calendar | events | notify
  const [selFac,     setSelFac]     = useState(defaultFac);
  const [viewMonth,  setViewMonth]  = useState(() => {
    const d = new Date(); return { y: d.getFullYear(), m: d.getMonth() + 1 };
  });
  const [selDate,    setSelDate]    = useState(today);

  // イベント編集フォーム
  const emptyForm = { title:"", description:"", eventType:"activity", startTime:"",
                      isAllFacilities:false, targetFacilityIds:[] };
  const [showForm,   setShowForm]   = useState(false);
  const [editTarget, setEditTarget] = useState(null); // null=新規, id=編集
  const [form,       setForm]       = useState(emptyForm);
  const [formErr,    setFormErr]    = useState("");
  const [saving,     setSaving]     = useState(false);

  // 一括通知
  const [notifyFac,     setNotifyFac]     = useState(user.selectedFacilityId || "f1");
  const [notifyTitle,   setNotifyTitle]   = useState("");
  const [notifyBody,    setNotifyBody]    = useState("");
  const [notifyConfirm, setNotifyConfirm] = useState(false);
  const [notifyErr,     setNotifyErr]     = useState("");
  const [notifySaving,  setNotifySaving]  = useState(false);

  // ── 表示対象イベントフィルター ──
  const visibleEvents = (store.facilityEvents || []).filter(ev => {
    if (ev.is_deleted) return false;
    // 施設フィルター
    if (selFac === "all") {
      // admin: 全施設
      if (!isAdmin) {
        const myFac = user.selectedFacilityId;
        return ev.facilityId === myFac || ev.isAllFacilities ||
          (ev.targetFacilityIds || []).includes(myFac);
      }
      return true;
    }
    return ev.facilityId === selFac || ev.isAllFacilities ||
      (ev.targetFacilityIds || []).includes(selFac);
  });

  // 月別 / 日別
  const monthKey = `${viewMonth.y}-${String(viewMonth.m).padStart(2,"0")}`;
  const monthEvents = visibleEvents.filter(ev => (ev.eventDate || "").startsWith(monthKey));
  const dateEvents  = visibleEvents.filter(ev => ev.eventDate === selDate);

  // カレンダー日付一覧（当月）
  const daysInMonth = new Date(viewMonth.y, viewMonth.m, 0).getDate();
  const firstDow    = new Date(viewMonth.y, viewMonth.m - 1, 1).getDay();
  const calDays     = [];
  for (let i = 0; i < firstDow; i++) calDays.push(null);
  for (let d = 1; d <= daysInMonth; d++) {
    const ds = `${viewMonth.y}-${String(viewMonth.m).padStart(2,"0")}-${String(d).padStart(2,"0")}`;
    calDays.push(ds);
  }

  // ── 保存 ──
  const saveEvent = async () => {
    setFormErr("");
    if (!form.title.trim()) { setFormErr("タイトルを入力してください"); return; }
    if (!selDate)            { setFormErr("日付を選択してください"); return; }
    if (!form.isAllFacilities && !selFac)
      { setFormErr("施設を選択してください"); return; }
    setSaving(true);
    try {
      const id = editTarget || genId();
      store.saveFacilityEvent({
        id,
        facilityId:          form.isAllFacilities ? null : (selFac === "all" ? null : selFac),
        eventDate:           selDate,
        title:               form.title.trim(),
        description:         form.description.trim(),
        eventType:           form.eventType,
        startTime:           form.startTime,
        isAllFacilities:     form.isAllFacilities,
        targetFacilityIds:   form.isAllFacilities ? FACILITIES_LIST.map(f => f.id) : (form.targetFacilityIds||[]),
        staffId:             user.id || "",
        createdBy:           user.displayName || "",
        createdAt:           editTarget
          ? (visibleEvents.find(x=>x.id===editTarget)?.createdAt || new Date().toISOString())
          : new Date().toISOString(),
      });
      store.showToast(editTarget ? "✅ イベントを更新しました" : "✅ イベントを登録しました");
      setShowForm(false); setEditTarget(null); setForm(emptyForm);
    } catch(e) {
      setFormErr("保存に失敗しました: " + (e.message || e));
    }
    setSaving(false);
  };

  // ── 削除（論理削除）──
  const deleteEvent = (id) => {
    if (!window.confirm("このイベントを削除してもよいですか？")) return;
    store.delFacilityEvent(id, user.displayName);
    store.showToast("🗑 イベントを削除しました");
  };

  // ── 一括通知送信 ──
  const sendNotify = async () => {
    setNotifyErr("");
    if (!notifyTitle.trim() || !notifyBody.trim()) {
      setNotifyErr("タイトルと本文を入力してください"); return;
    }
    setNotifySaving(true);
    try {
      // 対象施設の保護者に向けてお知らせを作成
      const targetFacIds = notifyFac === "all"
        ? FACILITIES_LIST.map(f => f.id)
        : [notifyFac];
      const children = store.dynUsers.filter(u =>
        u.active !== false && targetFacIds.includes(u.facilityId));
      for (const fid of targetFacIds) {
        const facChildren = children.filter(c => c.facilityId === fid);
        if (facChildren.length === 0) continue;
        store.saveAnnouncement({
          id:          genId(),
          facilityId:  fid,
          title:       notifyTitle.trim(),
          body:        notifyBody.trim(),
          category:    "行事予定",
          isUrgent:    false,
          targetIds:   facChildren.map(c => c.id),
          createdBy:   user.displayName,
          createdAt:   todayISO(),
        });
      }
      store.showToast("✅ 一括通知を送信しました");
      setNotifyTitle(""); setNotifyBody(""); setNotifyConfirm(false);
    } catch(e) {
      setNotifyErr("送信に失敗しました: " + (e.message || e));
    }
    setNotifySaving(false);
  };

  // イベントタイプ表示
  const EVENT_TYPE_LABEL = {
    activity: "活動",
    event:    "イベント",
    holiday:  "休業日",
    other:    "その他",
  };
  const EVENT_TYPE_COLOR = {
    activity: "#3aa0d8",
    event:    "#a78bfa",
    holiday:  "#e03838",
    other:    "#888",
  };

  return (
    <div style={{ maxWidth: 800, margin: "0 auto", padding: "0 0 80px 0" }}>
      {/* ヘッダー */}
      <div className="hh">
        <button className="back-btn" onClick={onBack}>←</button>
        <div>
          <div className="ht">活動カレンダー</div>
          <div className="hs">店舗別イベント・活動管理</div>
        </div>
      </div>

      {/* 施設フィルター */}
      <div style={{ display:"flex", gap:6, padding:"10px 12px", flexWrap:"wrap",
                    background:"var(--bg2)", borderBottom:"1px solid var(--bd)" }}>
        {(isAdmin ? [{ id:"all", name:"全施設" }] : []).concat(FACILITIES_LIST).map(f => (
          <button key={f.id}
            onClick={() => setSelFac(f.id)}
            style={{ padding:"4px 12px", borderRadius:20, border:"1px solid var(--tl)",
                     background: selFac===f.id ? "var(--tl)" : "white",
                     color: selFac===f.id ? "white" : "var(--tl)",
                     fontSize:13, cursor:"pointer", fontWeight:selFac===f.id?"bold":"normal" }}>
            {f.name}
          </button>
        ))}
      </div>

      {/* タブ */}
      <div style={{ display:"flex", borderBottom:"2px solid var(--bd)", background:"white" }}>
        {[["calendar","📅 活動カレンダー"],["events","🗓 イベント管理"],["notify","📢 一括通知"]].map(([k,lbl])=>(
          <button key={k} onClick={()=>setTab(k)}
            style={{ flex:1, padding:"10px 4px", border:"none", background:"transparent",
                     color: tab===k ? "var(--tl)" : "var(--tx3)",
                     fontWeight: tab===k ? "bold" : "normal",
                     borderBottom: tab===k ? "3px solid var(--tl)" : "3px solid transparent",
                     fontSize:13, cursor:"pointer" }}>
            {lbl}
          </button>
        ))}
      </div>

      {/* ─── タブ: 活動カレンダー ─── */}
      {tab === "calendar" && (
        <div style={{ padding:12 }}>
          {/* 月ナビ */}
          <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:10 }}>
            <button onClick={()=>setViewMonth(p=>{ const d=new Date(p.y,p.m-2,1); return{y:d.getFullYear(),m:d.getMonth()+1}; })}
              style={{ padding:"4px 14px", borderRadius:8, border:"1px solid var(--bda)", background:"var(--bg3)",
                       color:"var(--tx)", fontSize:15, cursor:"pointer" }}>◀</button>
            <span style={{ fontWeight:"bold", fontSize:16 }}>{viewMonth.y}年{viewMonth.m}月</span>
            <button onClick={()=>setViewMonth(p=>{ const d=new Date(p.y,p.m,1); return{y:d.getFullYear(),m:d.getMonth()+1}; })}
              style={{ padding:"4px 14px", borderRadius:8, border:"1px solid var(--bda)", background:"var(--bg3)",
                       color:"var(--tx)", fontSize:15, cursor:"pointer" }}>▶</button>
          </div>

          {/* カレンダーグリッド */}
          <div style={{ display:"grid", gridTemplateColumns:"repeat(7,1fr)", gap:2, marginBottom:12 }}>
            {["日","月","火","水","木","金","土"].map((d,di)=>(
              <div key={d} style={{ textAlign:"center", fontSize:12, padding:"3px 0", fontWeight:"bold",
                                    color: di===0?"#ff9a9a":di===6?"#8ec9f0":"var(--tx2)" }}>{d}</div>
            ))}
            {calDays.map((ds,i)=>{
              if(!ds) return <div key={"e"+i}/>;
              const evs=monthEvents.filter(ev=>ev.eventDate===ds);
              const isToday=ds===today;
              const isSel=ds===selDate;
              const dow=i%7;   // 0=日曜, 6=土曜
              return (
                <div key={ds} onClick={()=>setSelDate(ds)}
                  style={{ minHeight:52, padding:3, borderRadius:6, cursor:"pointer",
                           background: isSel?"var(--tl)":isToday?"rgba(58,160,216,0.20)":"var(--bg3)",
                           color: isSel?"#fff":"var(--tx)",
                           border: isToday&&!isSel?"2px solid var(--tl)":"1px solid var(--bd)" }}>
                  <div style={{ fontSize:14, textAlign:"right", lineHeight:1.15, paddingRight:2,
                                fontWeight:(isToday||isSel)?800:600,
                                color: isSel?"#fff":isToday?"var(--tl2)"
                                       :dow===0?"#ff9a9a":dow===6?"#8ec9f0":"var(--tx)" }}>
                    {parseInt(ds.split("-")[2])}
                  </div>
                  {evs.slice(0,2).map(ev=>(
                    <div key={ev.id} style={{ fontSize:9, borderRadius:3, padding:"1px 2px", marginTop:1,
                                              background: isSel?"rgba(255,255,255,0.3)":EVENT_TYPE_COLOR[ev.eventType]||"#3aa0d8",
                                              color: isSel?"white":"white",
                                              overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap" }}>
                      {ev.title}
                    </div>
                  ))}
                  {evs.length>2&&<div style={{fontSize:8,color:isSel?"white":"var(--tx3)"}}>+{evs.length-2}</div>}
                </div>
              );
            })}
          </div>

          {/* 選択日のイベント一覧 */}
          <div style={{ background:"var(--bg2)", borderRadius:8, padding:12 }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:8 }}>
              <span style={{ fontWeight:"bold", fontSize:14 }}>{selDate} の予定</span>
              {isMgr && (
                <button onClick={()=>{ setForm(emptyForm); setEditTarget(null); setShowForm(true); }}
                  style={{ padding:"4px 12px", background:"var(--tl)", color:"white",
                           border:"none", borderRadius:6, fontSize:12, cursor:"pointer" }}>
                  ＋ 追加
                </button>
              )}
            </div>
            {dateEvents.length === 0
              ? <div style={{ color:"var(--tx3)", fontSize:13, textAlign:"center", padding:"16px 0" }}>この日の予定はありません</div>
              : dateEvents.map(ev => (
                  <div key={ev.id} style={{ background:"var(--bg3)", color:"var(--tx)", borderRadius:8, padding:10, marginBottom:8,
                                            border:"1px solid var(--bd)",
                                            borderLeft:`4px solid ${EVENT_TYPE_COLOR[ev.eventType]||"#3aa0d8"}` }}>
                    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                      <div>
                        <span style={{ fontSize:11, background:EVENT_TYPE_COLOR[ev.eventType]||"#3aa0d8",
                                       color:"white", borderRadius:4, padding:"1px 6px", marginRight:6 }}>
                          {EVENT_TYPE_LABEL[ev.eventType]||ev.eventType}
                        </span>
                        {ev.isAllFacilities && (
                          <span style={{ fontSize:11, background:"#a78bfa", color:"white",
                                         borderRadius:4, padding:"1px 6px", marginRight:6 }}>全施設</span>
                        )}
                        <span style={{ fontWeight:"bold", fontSize:14 }}>{ev.title}</span>
                        {ev.startTime && <span style={{ color:"var(--tx3)", fontSize:12, marginLeft:6 }}>{ev.startTime}</span>}
                      </div>
                      {isMgr && (
                        <div style={{ display:"flex", gap:4 }}>
                          <button onClick={()=>{
                            setForm({ title:ev.title, description:ev.description||"",
                                      eventType:ev.eventType||"activity", startTime:ev.startTime||"",
                                      isAllFacilities:ev.isAllFacilities||false,
                                      targetFacilityIds:ev.targetFacilityIds||[] });
                            setEditTarget(ev.id); setSelDate(ev.eventDate); setShowForm(true);
                          }} style={{ padding:"2px 8px", fontSize:11, border:"1px solid var(--bd)",
                                      borderRadius:4, cursor:"pointer", background:"white" }}>✏️</button>
                          <button onClick={()=>deleteEvent(ev.id)}
                            style={{ padding:"2px 8px", fontSize:11, border:"1px solid #e03838",
                                     borderRadius:4, cursor:"pointer", background:"white", color:"#e03838" }}>🗑</button>
                        </div>
                      )}
                    </div>
                    {ev.description && (
                      <div style={{ fontSize:12, color:"var(--tx2)", marginTop:4 }}>{ev.description}</div>
                    )}
                    {ev.facilityId && !ev.isAllFacilities && (
                      <div style={{ fontSize:11, color:"var(--tx3)", marginTop:2 }}>
                        📍 {FACILITIES_LIST.find(f=>f.id===ev.facilityId)?.name || ev.facilityId}
                      </div>
                    )}
                  </div>
                ))
            }
          </div>
        </div>
      )}

      {/* ─── タブ: イベント管理 ─── */}
      {tab === "events" && (
        <div style={{ padding:12 }}>
          {isMgr && (
            <button onClick={()=>{ setForm(emptyForm); setEditTarget(null); setShowForm(true); }}
              style={{ width:"100%", padding:"10px", background:"var(--tl)", color:"white",
                       border:"none", borderRadius:8, fontSize:14, cursor:"pointer", marginBottom:12 }}>
              ＋ 新しいイベントを登録
            </button>
          )}
          {visibleEvents.filter(ev=>ev.eventDate>=today).sort((a,b)=>a.eventDate>b.eventDate?1:-1).length === 0
            ? <div style={{ color:"var(--tx3)", textAlign:"center", padding:24 }}>
                登録済みのイベントはありません
              </div>
            : visibleEvents
                .filter(ev => ev.eventDate >= today)
                .sort((a,b) => a.eventDate > b.eventDate ? 1 : -1)
                .map(ev => (
                  <div key={ev.id} style={{ background:"white", border:"1px solid var(--bd)",
                                            borderRadius:8, padding:12, marginBottom:8,
                                            borderLeft:`4px solid ${EVENT_TYPE_COLOR[ev.eventType]||"#3aa0d8"}` }}>
                    <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start" }}>
                      <div>
                        <div style={{ fontWeight:"bold", fontSize:14 }}>{ev.title}</div>
                        <div style={{ fontSize:12, color:"var(--tx3)", marginTop:2 }}>
                          📅 {ev.eventDate}
                          {ev.startTime && <span style={{marginLeft:6}}>⏰ {ev.startTime}</span>}
                          <span style={{ marginLeft:8, background:EVENT_TYPE_COLOR[ev.eventType]||"#3aa0d8",
                                         color:"white", borderRadius:4, padding:"0 5px", fontSize:11 }}>
                            {EVENT_TYPE_LABEL[ev.eventType]||ev.eventType}
                          </span>
                          {ev.isAllFacilities && (
                            <span style={{ marginLeft:4, background:"#a78bfa", color:"white",
                                           borderRadius:4, padding:"0 5px", fontSize:11 }}>全施設</span>
                          )}
                          {!ev.isAllFacilities && ev.facilityId && (
                            <span style={{ marginLeft:4, color:"var(--tx3)", fontSize:11 }}>
                              📍{FACILITIES_LIST.find(f=>f.id===ev.facilityId)?.name||ev.facilityId}
                            </span>
                          )}
                        </div>
                        {ev.description && (
                          <div style={{ fontSize:12, color:"var(--tx2)", marginTop:4 }}>{ev.description}</div>
                        )}
                      </div>
                      {isMgr && (
                        <div style={{ display:"flex", gap:4, flexShrink:0 }}>
                          <button onClick={()=>{
                            setForm({ title:ev.title, description:ev.description||"",
                                      eventType:ev.eventType||"activity", startTime:ev.startTime||"",
                                      isAllFacilities:ev.isAllFacilities||false,
                                      targetFacilityIds:ev.targetFacilityIds||[] });
                            setEditTarget(ev.id); setSelDate(ev.eventDate); setShowForm(true);
                          }} style={{ padding:"4px 10px", fontSize:12, border:"1px solid var(--bd)",
                                      borderRadius:6, cursor:"pointer" }}>✏️ 編集</button>
                          <button onClick={()=>deleteEvent(ev.id)}
                            style={{ padding:"4px 10px", fontSize:12, border:"1px solid #e03838",
                                     borderRadius:6, cursor:"pointer", color:"#e03838" }}>🗑</button>
                        </div>
                      )}
                    </div>
                  </div>
                ))
          }
        </div>
      )}

      {/* ─── タブ: 一括通知 ─── */}
      {tab === "notify" && (
        <div style={{ padding:12 }}>
          {!isMgr
            ? <div style={{ color:"var(--tx3)", textAlign:"center", padding:24 }}>
                一括通知はマネージャー以上が利用できます
              </div>
            : (
              <div style={{ background:"white", border:"1px solid var(--bd)", borderRadius:8, padding:16 }}>
                <div style={{ fontWeight:"bold", fontSize:15, marginBottom:12 }}>保護者への一括通知</div>

                {/* 送信対象施設 */}
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:13, fontWeight:"bold", marginBottom:4 }}>送信対象施設</div>
                  <select value={notifyFac} onChange={e=>setNotifyFac(e.target.value)}
                    style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)", fontSize:14 }}>
                    {isAdmin && <option value="all">全施設</option>}
                    {FACILITIES_LIST.map(f => (
                      <option key={f.id} value={f.id}>{f.name}</option>
                    ))}
                  </select>
                  <div style={{ fontSize:11, color:"var(--tx3)", marginTop:2 }}>
                    対象: {(() => {
                      const facIds = notifyFac === "all" ? FACILITIES_LIST.map(f=>f.id) : [notifyFac];
                      const cnt = store.dynUsers.filter(u=>u.active!==false&&facIds.includes(u.facilityId)).length;
                      return `${cnt}名の保護者`;
                    })()}
                  </div>
                </div>

                {/* タイトル */}
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:13, fontWeight:"bold", marginBottom:4 }}>タイトル</div>
                  <input value={notifyTitle} onChange={e=>setNotifyTitle(e.target.value)}
                    placeholder="例: 5月の行事予定について"
                    style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)",
                             fontSize:14, boxSizing:"border-box" }}/>
                </div>

                {/* 本文 */}
                <div style={{ marginBottom:12 }}>
                  <div style={{ fontSize:13, fontWeight:"bold", marginBottom:4 }}>本文</div>
                  <textarea value={notifyBody} onChange={e=>setNotifyBody(e.target.value)}
                    placeholder="保護者への通知内容を入力してください"
                    rows={5}
                    style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)",
                             fontSize:14, resize:"vertical", boxSizing:"border-box" }}/>
                </div>

                {notifyErr && (
                  <div style={{ background:"#fef2f2", border:"1px solid #fca5a5", borderRadius:6,
                                padding:"8px 12px", color:"#e03838", fontSize:13, marginBottom:10 }}>
                    ⚠ {notifyErr}
                  </div>
                )}

                <button onClick={()=>setNotifyConfirm(true)}
                  disabled={notifySaving}
                  style={{ width:"100%", padding:"12px", background:"var(--tl)", color:"white",
                           border:"none", borderRadius:8, fontSize:15, cursor:"pointer",
                           opacity: notifySaving ? 0.6 : 1 }}>
                  📢 送信内容を確認する
                </button>
              </div>
            )
          }
        </div>
      )}

      {/* ─── イベント編集フォーム（モーダル）─── */}
      {showForm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", zIndex:9000,
                      display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"white", borderRadius:12, padding:20, width:"100%", maxWidth:480,
                        maxHeight:"90vh", overflowY:"auto" }}>
            <div style={{ fontWeight:"bold", fontSize:16, marginBottom:12 }}>
              {editTarget ? "イベントを編集" : "イベントを追加"} ({selDate})
            </div>

            {/* タイトル */}
            <div style={{ marginBottom:10 }}>
              <div style={{ fontSize:13, fontWeight:"bold", marginBottom:3 }}>タイトル <span style={{color:"red"}}>*</span></div>
              <input value={form.title} onChange={e=>setForm(p=>({...p,title:e.target.value}))}
                placeholder="例: 水遊び・工作・遠足"
                style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)",
                         fontSize:14, boxSizing:"border-box" }}/>
            </div>

            {/* 種別 */}
            <div style={{ marginBottom:10 }}>
              <div style={{ fontSize:13, fontWeight:"bold", marginBottom:3 }}>種別</div>
              <select value={form.eventType} onChange={e=>setForm(p=>({...p,eventType:e.target.value}))}
                style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)", fontSize:14 }}>
                <option value="activity">活動</option>
                <option value="event">イベント</option>
                <option value="holiday">休業日</option>
                <option value="other">その他</option>
              </select>
            </div>

            {/* 開始時間 */}
            <div style={{ marginBottom:10 }}>
              <div style={{ fontSize:13, fontWeight:"bold", marginBottom:3 }}>開始時間（任意）</div>
              <input type="time" value={form.startTime}
                onChange={e=>setForm(p=>({...p,startTime:e.target.value}))}
                style={{ padding:"8px", borderRadius:6, border:"1px solid var(--bd)", fontSize:14 }}/>
            </div>

            {/* 全施設共通 */}
            <div style={{ marginBottom:10 }}>
              <label style={{ display:"flex", alignItems:"center", gap:8, cursor:"pointer" }}>
                <input type="checkbox" checked={form.isAllFacilities}
                  onChange={e=>setForm(p=>({...p,isAllFacilities:e.target.checked}))}
                  style={{ width:18, height:18 }}/>
                <span style={{ fontSize:14, fontWeight:"bold" }}>全施設共通イベント</span>
              </label>
              <div style={{ fontSize:11, color:"var(--tx3)", marginTop:2, marginLeft:26 }}>
                チェックすると全施設の日報・カレンダーに表示されます
              </div>
            </div>

            {/* 説明 */}
            <div style={{ marginBottom:12 }}>
              <div style={{ fontSize:13, fontWeight:"bold", marginBottom:3 }}>説明・メモ</div>
              <textarea value={form.description}
                onChange={e=>setForm(p=>({...p,description:e.target.value}))}
                placeholder="活動の内容・注意事項など"
                rows={3}
                style={{ width:"100%", padding:"8px", borderRadius:6, border:"1px solid var(--bd)",
                         fontSize:14, resize:"vertical", boxSizing:"border-box" }}/>
            </div>

            {formErr && (
              <div style={{ background:"#fef2f2", border:"1px solid #fca5a5", borderRadius:6,
                            padding:"8px 12px", color:"#e03838", fontSize:13, marginBottom:10 }}>
                ⚠ {formErr}
              </div>
            )}

            <div style={{ display:"flex", gap:8 }}>
              <button onClick={()=>{ setShowForm(false); setEditTarget(null); setForm(emptyForm); setFormErr(""); }}
                style={{ flex:1, padding:"10px", border:"1px solid var(--bd)", borderRadius:8,
                         background:"white", fontSize:14, cursor:"pointer" }}>
                キャンセル
              </button>
              <button onClick={saveEvent} disabled={saving}
                style={{ flex:2, padding:"10px", background:"var(--tl)", color:"white",
                         border:"none", borderRadius:8, fontSize:14, cursor:"pointer",
                         opacity: saving ? 0.6 : 1 }}>
                {saving ? "保存中..." : (editTarget ? "✏️ 更新する" : "✅ 登録する")}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* ─── 一括通知 確認ダイアログ ─── */}
      {notifyConfirm && (
        <div style={{ position:"fixed", inset:0, background:"rgba(0,0,0,0.5)", zIndex:9001,
                      display:"flex", alignItems:"center", justifyContent:"center", padding:16 }}>
          <div style={{ background:"white", borderRadius:12, padding:20, width:"100%", maxWidth:420 }}>
            <div style={{ fontWeight:"bold", fontSize:16, marginBottom:12, color:"var(--ro)" }}>
              ⚠️ 送信確認
            </div>
            <div style={{ fontSize:14, marginBottom:8 }}>以下の内容を保護者へ送信します。</div>
            <div style={{ background:"var(--bg2)", borderRadius:8, padding:12, marginBottom:12 }}>
              <div style={{ fontWeight:"bold" }}>{notifyTitle}</div>
              <div style={{ fontSize:13, marginTop:4, color:"var(--tx2)", whiteSpace:"pre-wrap" }}>{notifyBody}</div>
              <div style={{ fontSize:12, color:"var(--tx3)", marginTop:8 }}>
                送信先: {notifyFac==="all" ? "全施設" : FACILITIES_LIST.find(f=>f.id===notifyFac)?.name}
              </div>
            </div>
            <div style={{ display:"flex", gap:8 }}>
              <button onClick={()=>setNotifyConfirm(false)}
                style={{ flex:1, padding:"10px", border:"1px solid var(--bd)", borderRadius:8,
                         background:"white", fontSize:14, cursor:"pointer" }}>
                キャンセル
              </button>
              <button onClick={sendNotify} disabled={notifySaving}
                style={{ flex:2, padding:"10px", background:"var(--ro)", color:"white",
                         border:"none", borderRadius:8, fontSize:14, cursor:"pointer",
                         opacity: notifySaving ? 0.6 : 1 }}>
                {notifySaving ? "送信中..." : "📢 送信する"}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function ScheduleScreen({ user, store, onBack }) {
  const today = new Date();
  const [vm, setVm] = useState({ y: today.getFullYear(), m: today.getMonth() + 1 });
  const [selFac, setSelFac] = useState(user.selectedFacilityId || "all");
  const [viewMode, setViewMode] = useState("calendar");
  const [editCell, setEditCell] = useState(null);
  // EditModal用state（内部コンポーネントではなくScheduleScreenで管理することでstateリセット問題を回避）
  const [tmpStatus, setTmpStatus] = useState("");
  const [tmpTo, setTmpTo] = useState(false);
  const [tmpFrom, setTmpFrom] = useState(false);
  const [selDate, setSelDate] = useState(todayISO());
  const [showAddModal, setShowAddModal] = useState(false); // 生徒追加モーダル
  const [addChecked, setAddChecked] = useState([]); // 追加選択中の生徒ID
  // 一括登録モーダル用state
  const [showBulkModal, setShowBulkModal] = useState(false);
  const [bulkUserId, setBulkUserId] = useState("");
  const [bulkDays, setBulkDays] = useState([]);
  const [bulkStatus, setBulkStatus] = useState("来所予定");
  const [bulkTo, setBulkTo] = useState(false);
  const [bulkFrom, setBulkFrom] = useState(false);

  const isAdmin = user.role === "admin";
  const isMgr = user.role === "manager" || user.role === "admin";
  const days = daysInMonth(vm.y, vm.m);

  // ── モーダル表示中は背景スクロールを完全ロック（iOS Safari対応）──
  useEffect(() => {
    const anyOpen = !!(editCell || showBulkModal || showAddModal);
    if (anyOpen) {
      // scrollY を記憶してから fixed にすることでiOSの「スクロール位置リセット」を防ぐ
      const scrollY = window.scrollY;
      document.body.style.overflow  = "hidden";
      document.body.style.position  = "fixed";
      document.body.style.top       = `-${scrollY}px`;
      document.body.style.width     = "100%";
    } else {
      const scrollY = Math.abs(parseInt(document.body.style.top || "0"));
      document.body.style.overflow  = "";
      document.body.style.position  = "";
      document.body.style.top       = "";
      document.body.style.width     = "";
      window.scrollTo(0, scrollY);   // 元のスクロール位置に戻す
    }
    return () => {                   // アンマウント時もリセット
      document.body.style.overflow  = "";
      document.body.style.position  = "";
      document.body.style.top       = "";
      document.body.style.width     = "";
    };
  }, [editCell, showBulkModal, showAddModal]);
  const dayList = Array.from({ length: days }, (_, i) => i + 1);
  const dowLabel = ["日","月","火","水","木","金","土"];

  const facOptions = isAdmin
    ? [{ id: "all", name: "全店舗" }, ...FACILITIES]
    : FACILITIES.filter(f => f.id === user.selectedFacilityId);

  const users = sortUsersByFacilityKana(store.dynUsers.filter(u => {
    if (u.active === false) return false;
    if (selFac === "all") return true;
    return u.facilityId === selFac;
  })); // 店舗別→ふりがな順

  const getKey = (uid, day) =>
    uid + "_" + vm.y + "_" + String(vm.m).padStart(2,"0") + "_" + String(day).padStart(2,"0");

  const getDateStr = (day) =>
    vm.y + "-" + String(vm.m).padStart(2,"0") + "-" + String(day).padStart(2,"0");

  const getRow = (uid, day) => {
    const key = getKey(uid, day);
    if (store.scheduleData && store.scheduleData[key]) return store.scheduleData[key];
    const attStatus = store.getAtt(uid, getDateStr(day));
    if (attStatus === "出席") return { status: "来所", transport_to: false, transport_from: false };
    if (attStatus === "欠席") return { status: "欠席", transport_to: false, transport_from: false };
    if (attStatus === "予定") return { status: "来所予定", transport_to: false, transport_from: false };
    return null;
  };

  const getStatus = (uid, day) => getRow(uid, day)?.status || "";
  const getTransportTo = (uid, day) => getRow(uid, day)?.transport_to || false;
  const getTransportFrom = (uid, day) => getRow(uid, day)?.transport_from || false;

  const setSchedule = (uid, day, status, transportTo, transportFrom) => {
    const key = getKey(uid, day);
    const u = store.dynUsers.find(x => x.id === uid);
    const row = {
      id: key, user_id: uid, user_name: u?.name || "",
      facility_id: u?.facilityId || "", date: getDateStr(day),
      status: status, transport_to: transportTo, transport_from: transportFrom,
      updated_at: nowStr(),
    };
    if (store.setScheduleData) store.setScheduleData(p => ({ ...p, [key]: row }));
    if (store.saveScheduleRow) store.saveScheduleRow(row);
    if (status === "来所" || status === "来所予定") {
      store.setAtt(uid, getDateStr(day), status === "来所" ? "出席" : "予定");
    } else if (status === "欠席") {
      store.setAtt(uid, getDateStr(day), "欠席");
    }
    setEditCell(null);
  };

  const getDow = (day) => new Date(vm.y, vm.m - 1, day).getDay();
  const isWe = (day) => getDow(day) === 0 || getDow(day) === 6;

  const countByDay = (day) => ({
    come: users.filter(u => { const st=getStatus(u.id,day); return st==="来所"||st==="来所予定"; }).length,
    absent: users.filter(u => getStatus(u.id,day)==="欠席").length,
  });

  const countByUser = (uid) => ({
    come: dayList.filter(d => getStatus(uid,d)==="来所"||getStatus(uid,d)==="来所予定").length,
    actual: dayList.filter(d => getStatus(uid,d)==="来所").length,
    absent: dayList.filter(d => getStatus(uid,d)==="欠席").length,
  });

  const selDay = parseInt(selDate.split("-")[2]);
  const selDayUsers = users.map(u => ({
    ...u,
    status: getStatus(u.id, selDay),
    transportTo: getTransportTo(u.id, selDay),
    transportFrom: getTransportFrom(u.id, selDay),
  }));

  const printSchedule = () => {
    const facName = selFac === "all" ? "全店舗" : FACILITIES.find(f => f.id === selFac)?.name || "";
    const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"/><style>body{font-family:'Noto Sans JP',sans-serif;font-size:8pt;margin:10mm;}h2{font-size:13pt;}table{border-collapse:collapse;width:100%;}th,td{border:1px solid #ccc;padding:3px 4px;text-align:center;white-space:nowrap;font-size:7.5pt;}th{background:#e8f0ff;font-weight:700;}.we{background:#f5f5f5;color:#bbb;}.come{background:rgba(44,170,96,0.2);color:var(--gr);font-weight:700;}.plan{background:rgba(58,160,216,0.2);color:var(--tl);}.absent{background:rgba(224,56,56,0.15);color:var(--ro);}.name{text-align:left;font-weight:700;}</style></head><body><h2>生徒予定表 ${facName} ${vm.y}年${vm.m}月</h2><table><thead><tr><th class="name">利用者名</th>${dayList.map(d=>`<th class="${isWe(d)?"we":""}">${d}<br/>${dowLabel[getDow(d)]}</th>`).join("")}<th>予定</th><th>来所</th><th>欠席</th></tr></thead><tbody>${users.map(u=>{const cnt=countByUser(u.id);return `<tr><td class="name">${u.name}</td>${dayList.map(d=>{if(isWe(d))return`<td class="we"></td>`;const st=getStatus(u.id,d);const cls=st==="来所"?"come":st==="来所予定"?"plan":st==="欠席"?"absent":"";const short={"来所":"来","来所予定":"予","欠席":"欠","体調不良":"体","キャンセル":"キャ","休所":"休"}[st]||"";return`<td class="${cls}">${short}</td>`;}).join("")}<td style="background:#eef8f2;font-weight:700">${cnt.come}</td><td style="background:#eef8f2;color:var(--gr);font-weight:700">${cnt.actual}</td><td style="background:rgba(224,56,56,0.08);color:var(--ro);font-weight:700">${cnt.absent}</td></tr>`;}).join("")}</tbody></table><div style="margin-top:8px;font-size:7pt;color:#888">出力: ${new Date().toLocaleString("ja-JP")}</div></body></html>`;
    const win = window.open("","_blank"); if(!win){alert("ポップアップがブロックされています。許可してから再実行してください。");return;} win.document.write(html); win.document.close(); setTimeout(()=>win.print(),400);
  };

  const fw = new Date(vm.y, vm.m - 1, 1).getDay();

  const CalendarView = () => (
    <div>
      <div style={{background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:12,padding:14,marginBottom:14,boxShadow:"var(--sh)"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
          <button className="cn" onClick={()=>setVm(v=>v.m===1?{y:v.y-1,m:12}:{y:v.y,m:v.m-1})}>‹</button>
          <div style={{fontSize:16,fontWeight:900}}>{vm.y}年 {vm.m}月</div>
          <button className="cn" onClick={()=>setVm(v=>v.m===12?{y:v.y+1,m:1}:{y:v.y,m:v.m+1})}>›</button>
        </div>
        <div className="cgrid">
          {["日","月","火","水","木","金","土"].map((d,i)=><div key={d} className={`cdow ${i===0?"su":""} ${i===6?"sa":""}`}>{d}</div>)}
          {Array.from({length:fw}).map((_,i)=><div key={"e"+i} className="cday emp"/>)}
          {dayList.map(d=>{
            const ds=getDateStr(d); const we=isWe(d); const c=countByDay(d);
            const isToday=ds===todayISO(); const isSel=ds===selDate;
            return <div key={d} className={`cday ${isToday?"td":""} ${isSel?"sel":""} ${we?"we":""}`} onClick={()=>!we&&setSelDate(ds)}>
              <span style={{fontSize:16,fontWeight:700}}>{d}</span>
              {!we&&c.come>0&&<div style={{fontSize:13,fontWeight:700,color:"var(--gr)",lineHeight:1}}>{c.come}人</div>}
              {!we&&(c.come>0||c.absent>0)&&<div className="dots">{c.come>0&&<div className="dot dg"/>}{c.absent>0&&<div className="dot dr"/>}</div>}
            </div>;
          })}
        </div>
      </div>
      <div style={{marginBottom:12}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
          <div style={{fontSize:15,fontWeight:900}}>{dlabel(selDate)} の状況</div>
          {isMgr&&<button onClick={()=>{setAddChecked([]);setShowAddModal(true);}} style={{padding:"7px 14px",borderRadius:20,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--ac)",color:"#fff",border:"none",boxShadow:"var(--sh)"}}>＋ 生徒を追加</button>}
        </div>
        {(()=>{const d=parseInt(selDate.split("-")[2]);const c=countByDay(d);const total=users.length;return(
          <div style={{display:"flex",gap:8,marginBottom:12,flexWrap:"wrap"}}>
            <div style={{background:"rgba(44,170,96,0.2)",borderRadius:10,padding:"8px 14px",display:"flex",gap:6,alignItems:"center"}}><span style={{fontSize:20,fontWeight:900,color:"var(--gr)"}}>{c.come}</span><span style={{fontSize:11,color:"var(--gr)"}}>来所予定</span></div>
            <div style={{background:"rgba(224,56,56,0.15)",borderRadius:10,padding:"8px 14px",display:"flex",gap:6,alignItems:"center"}}><span style={{fontSize:20,fontWeight:900,color:"var(--ro)"}}>{c.absent}</span><span style={{fontSize:11,color:"var(--ro)"}}>欠席</span></div>
            <div style={{background:"var(--bg)",borderRadius:10,padding:"8px 14px",display:"flex",gap:6,alignItems:"center"}}><span style={{fontSize:20,fontWeight:900,color:"var(--tx3)"}}>{total-c.come-c.absent}</span><span style={{fontSize:11,color:"var(--tx3)"}}>未定</span></div>
          </div>
        );})()}
        <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(160px,1fr))",gap:8}}>
          {selDayUsers.map(u=>{
            const stObj=SCHEDULE_STATUS[u.status];
            const d=parseInt(selDate.split("-")[2]);
            return <div key={u.id} style={{background:"var(--wh)",border:"2px solid "+(stObj?stObj.color:"var(--bd)"),borderRadius:11,padding:11,boxShadow:"var(--sh)"}}>
              <div style={{fontWeight:700,fontSize:13,marginBottom:4}}>{u.name}</div>
              {selFac==="all"&&<div style={{fontSize:10,color:"var(--tx3)",marginBottom:4}}>{FACILITIES.find(f=>f.id===u.facilityId)?.name}</div>}
              <div style={{padding:"4px 10px",borderRadius:9,fontSize:11,fontWeight:700,background:stObj?stObj.bg:"var(--bg)",color:stObj?stObj.color:"var(--tx3)",marginBottom:8,display:"inline-block"}}>{stObj?stObj.label:"未定"}</div>
              <div style={{display:"flex",gap:5,marginBottom:8}}>
                <span style={{fontSize:10,padding:"2px 7px",borderRadius:7,fontWeight:700,background:u.transportTo?"rgba(58,160,216,0.2)":"var(--bg)",color:u.transportTo?"var(--tl)":"var(--tx3)",border:"1px solid "+(u.transportTo?"rgba(58,160,216,0.4)":"var(--bd)")}}>迎</span>
                <span style={{fontSize:10,padding:"2px 7px",borderRadius:7,fontWeight:700,background:u.transportFrom?"rgba(44,170,96,0.2)":"var(--bg)",color:u.transportFrom?"var(--gr)":"var(--tx3)",border:"1px solid "+(u.transportFrom?"rgba(44,170,96,0.4)":"var(--bd)")}}>送</span>
              </div>
              {isMgr&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:5}}>
                <button onClick={()=>setSchedule(u.id,d,"来所",u.transportTo,u.transportFrom)} style={{padding:"7px 4px",borderRadius:8,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:u.status==="来所"?"var(--gr)":"var(--bd)",background:u.status==="来所"?"rgba(44,170,96,0.2)":"var(--wh)",color:u.status==="来所"?"var(--gr)":"var(--tx2)"}}>✅ 入室</button>
                <button onClick={()=>setSchedule(u.id,d,"欠席",false,false)} style={{padding:"7px 4px",borderRadius:8,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid",borderColor:u.status==="欠席"?"var(--ro)":"var(--bd)",background:u.status==="欠席"?"rgba(224,56,56,0.15)":"var(--wh)",color:u.status==="欠席"?"var(--ro)":"var(--tx2)"}}>❌ 欠席</button>
                <button onClick={()=>{const ec={uid:u.id,day:d,name:u.name,status:u.status,transportTo:u.transportTo,transportFrom:u.transportFrom};setEditCell(ec);setTmpStatus(u.status||"");setTmpTo(u.transportTo||false);setTmpFrom(u.transportFrom||false);}} style={{padding:"6px 4px",borderRadius:8,fontSize:10,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",border:"1.5px solid var(--bd)",background:"var(--bg)",color:"var(--tx3)",gridColumn:"span 2"}}>✏️ 詳細設定</button>
              </div>}
            </div>;
          })}
        </div>
      </div>

      {/* 生徒追加モーダル */}
      {showAddModal&&(()=>{
        const d=parseInt(selDate.split("-")[2]);
        // 全施設の生徒から「未定・欠席」の生徒を選択可能に表示
        const allUsers=store.dynUsers.filter(u=>u.active!==false);
        const toggle=id=>setAddChecked(p=>p.includes(id)?p.filter(x=>x!==id):[...p,id]);
        const confirm=()=>{
          addChecked.forEach(id=>{
            const u=store.dynUsers.find(x=>x.id===id);
            if(u) setSchedule(id,d,"来所予定",false,false);
          });
          setShowAddModal(false);
        };
        return <div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.45)",zIndex:1000,display:"flex",alignItems:"flex-end"}} onClick={()=>setShowAddModal(false)}>
          <div style={{background:"var(--wh)",borderRadius:"18px 18px 0 0",padding:20,width:"100%",maxHeight:"75vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:14}}>
              <div style={{fontSize:15,fontWeight:900}}>📋 {dlabel(selDate)}　生徒を追加</div>
              <button onClick={()=>setShowAddModal(false)} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"var(--tx3)"}}>×</button>
            </div>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:12}}>来所予定にする生徒を選んでください</div>
            {/* 施設ごとにグルーピング */}
            {FACILITIES.map(fac=>{
              const facUsers=allUsers.filter(u=>u.facilityId===fac.id);
              if(facUsers.length===0) return null;
              return <div key={fac.id} style={{marginBottom:14}}>
                <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",marginBottom:6,padding:"3px 8px",background:"var(--bg2)",borderRadius:6}}>{fac.name}</div>
                {facUsers.map(u=>{
                  const st=getStatus(u.id,d);
                  const checked=addChecked.includes(u.id);
                  return <div key={u.id} onClick={()=>toggle(u.id)} style={{display:"flex",alignItems:"center",gap:10,padding:"10px 8px",borderRadius:9,marginBottom:4,background:checked?"#e8f4fd":"var(--bg)",border:"1.5px solid "+(checked?"var(--tl)":"var(--bd)"),cursor:"pointer"}}>
                    <div style={{width:20,height:20,borderRadius:5,border:"2px solid "+(checked?"var(--tl)":"var(--bd)"),background:checked?"var(--tl)":"#fff",display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0}}>
                      {checked&&<span style={{color:"#fff",fontSize:13,fontWeight:900}}>✓</span>}
                    </div>
                    <div style={{flex:1}}>
                      <div style={{fontWeight:700,fontSize:13}}>{u.name}</div>
                      {st&&<div style={{fontSize:10,color:SCHEDULE_STATUS[st]?.color||"var(--tx3)"}}>{SCHEDULE_STATUS[st]?.label||st}</div>}
                    </div>
                  </div>;
                })}
              </div>;
            })}
            <div style={{display:"flex",gap:10,paddingTop:10}}>
              <button onClick={()=>setShowAddModal(false)} style={{flex:1,padding:"12px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,fontSize:13,cursor:"pointer"}}>キャンセル</button>
              <button onClick={confirm} disabled={addChecked.length===0} style={{flex:2,padding:"12px",borderRadius:10,border:"none",background:addChecked.length>0?"var(--ac)":"var(--bd)",color:"#fff",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,fontSize:13,cursor:addChecked.length>0?"pointer":"default"}}>
                {addChecked.length>0?`✅ ${addChecked.length}名を来所予定に追加`:"生徒を選んでください"}
              </button>
            </div>
          </div>
        </div>;
      })()}
    </div>
  );

  const TableView = () => (
    <div style={{overflowX:"auto",WebkitOverflowScrolling:"touch"}}>
      <div style={{display:"flex",alignItems:"center",gap:9,marginBottom:12}}>
        <button className="cn" onClick={()=>setVm(v=>v.m===1?{y:v.y-1,m:12}:{y:v.y,m:v.m-1})}>‹</button>
        <div style={{fontSize:15,fontWeight:900}}>{vm.y}年 {vm.m}月</div>
        <button className="cn" onClick={()=>setVm(v=>v.m===12?{y:v.y+1,m:1}:{y:v.y,m:v.m+1})}>›</button>
      </div>
      <table style={{borderCollapse:"collapse",fontSize:11,minWidth:"max-content"}}>
        <thead>
          <tr>
            <th style={{border:"1px solid var(--bd)",padding:"6px 10px",background:"var(--bg2)",textAlign:"left",minWidth:90,position:"sticky",left:0,zIndex:2,boxShadow:"2px 0 4px rgba(0,0,0,0.08)"}}>利用者名</th>
            {dayList.map(d=><th key={d} style={{border:"1px solid var(--bd)",padding:"4px 2px",background:isWe(d)?"#f5f5f5":getDateStr(d)===todayISO()?"rgba(58,160,216,0.2)":"var(--bg2)",color:isWe(d)?"#aaa":getDow(d)===0?"var(--ro)":getDow(d)===6?"var(--tl)":"var(--tx2)",minWidth:34,textAlign:"center",fontSize:9}}>{d}<br/>{dowLabel[getDow(d)]}</th>)}
            <th style={{border:"1px solid var(--bd)",padding:"4px 5px",background:"var(--bg2)",minWidth:36,fontSize:9}}>予定</th>
            <th style={{border:"1px solid var(--bd)",padding:"4px 5px",background:"rgba(44,170,96,0.2)",minWidth:36,fontSize:9}}>来所</th>
            <th style={{border:"1px solid var(--bd)",padding:"4px 5px",background:"rgba(224,56,56,0.15)",minWidth:36,fontSize:9}}>欠席</th>
          </tr>
        </thead>
        <tbody>
          {users.map(u=>{
            const cnt=countByUser(u.id);
            return <tr key={u.id}>
              <td style={{border:"1px solid var(--bd)",padding:"5px 8px",fontWeight:700,fontSize:12,background:"var(--wh)",position:"sticky",left:0,zIndex:1,whiteSpace:"nowrap",boxShadow:"2px 0 4px rgba(0,0,0,0.08)"}}>
                {u.name}
                {selFac==="all"&&<div style={{fontSize:9,color:"var(--tx3)",fontWeight:400}}>{FACILITIES.find(f=>f.id===u.facilityId)?.name}</div>}
              </td>
              {dayList.map(d=>{
                const st=getStatus(u.id,d); const stObj=SCHEDULE_STATUS[st];
                const tr_to=getTransportTo(u.id,d); const tr_fr=getTransportFrom(u.id,d);
                return <td key={d} onClick={()=>isMgr&&(setEditCell({uid:u.id,day:d,name:u.name,status:st,transportTo:tr_to,transportFrom:tr_fr}),setTmpStatus(st||""),setTmpTo(tr_to||false),setTmpFrom(tr_fr||false))}
                  style={{border:"1px solid var(--bd)",padding:"2px 1px",textAlign:"center",background:stObj?stObj.bg:isWe(d)?"#fafafa":"var(--wh)",cursor:isMgr?"pointer":"default",minWidth:34}}>
                  {stObj&&<div style={{fontSize:10,fontWeight:700,color:stObj.color,lineHeight:1.2}}>{stObj.short}</div>}
                  {(tr_to||tr_fr)&&<div style={{fontSize:8,color:"#555",lineHeight:1}}>{tr_to?"迎":""}{tr_fr?"送":""}</div>}
                </td>;
              })}
              <td style={{border:"1px solid var(--bd)",padding:"4px 5px",textAlign:"center",fontWeight:700,color:"var(--tl)",background:"var(--bg)"}}>{cnt.come}</td>
              <td style={{border:"1px solid var(--bd)",padding:"4px 5px",textAlign:"center",fontWeight:700,color:"var(--gr)",background:"#eef8f2"}}>{cnt.actual}</td>
              <td style={{border:"1px solid var(--bd)",padding:"4px 5px",textAlign:"center",fontWeight:700,color:"var(--ro)",background:"rgba(224,56,56,0.08)"}}>{cnt.absent}</td>
            </tr>;
          })}
          <tr style={{background:"#f0f5ff",borderTop:"2px solid var(--bd)"}}>
            <td style={{padding:"6px 8px",fontWeight:700,fontSize:11,position:"sticky",left:0,background:"#f0f5ff",border:"1px solid var(--bd)",boxShadow:"2px 0 4px rgba(0,0,0,0.08)"}}>日別来所数</td>
            {dayList.map(d=>{
              if(isWe(d)) return <td key={d} style={{border:"1px solid var(--bd)",background:"#f5f5f5"}}></td>;
              const c=countByDay(d);
              return <td key={d} style={{border:"1px solid var(--bd)",padding:"3px 1px",textAlign:"center"}}>
                <div style={{fontSize:9,fontWeight:700,color:"var(--gr)"}}>{c.come}</div>
                {c.absent>0&&<div style={{fontSize:8,color:"var(--ro)"}}>欠{c.absent}</div>}
              </td>;
            })}
            <td colSpan={3} style={{border:"1px solid var(--bd)"}}></td>
          </tr>
        </tbody>
      </table>
    </div>
  );

  // EditModal は内部コンポーネントではなくインラインJSXで描画（useStateリセット問題を回避）
  // ※ zIndex:400 → bottom-nav(250)・sidebar(300)より上に表示されるよう修正

  return (
    <div className="fl-wrap">
      <div className="fl-hd" style={{flexWrap:"wrap",rowGap:6}}>
        <button className="bback" onClick={onBack}>← 戻る</button>
        <div className="fl-title">📅 生徒予定表</div>
        {/* ヘッダーボタン群：小画面でも1行に収まるよう marginLeft:auto でまとめて右寄せ */}
        <div style={{marginLeft:"auto",display:"flex",gap:6,alignItems:"center",flexShrink:0}}>
          {isMgr&&<button onClick={()=>{setBulkUserId(users.length>0?users[0].id:"");setBulkDays([]);setBulkStatus("来所予定");setBulkTo(false);setBulkFrom(false);setShowBulkModal(true);}} style={{padding:"7px 11px",borderRadius:16,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--tl)",color:"#fff",border:"none",boxShadow:"var(--sh)",whiteSpace:"nowrap"}}>📅 一括登録</button>}
          <button style={{padding:"7px 11px",borderRadius:16,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"#fff8f0",border:"1.5px solid var(--ac)",color:"var(--ac)",whiteSpace:"nowrap"}} onClick={printSchedule}>🖨️ 印刷</button>
        </div>
      </div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:12,alignItems:"center"}}>
        {isAdmin&&<select className="fsm" value={selFac} onChange={e=>setSelFac(e.target.value)}>{facOptions.map(f=><option key={f.id} value={f.id}>{f.name}</option>)}</select>}
        <div style={{display:"flex",gap:5}}>
          <button onClick={()=>setViewMode("calendar")} style={{padding:"7px 14px",borderRadius:16,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:viewMode==="calendar"?"var(--tl)":"var(--wh)",color:viewMode==="calendar"?"#fff":"var(--tx3)",border:viewMode==="calendar"?"none":"1.5px solid var(--bd)"}}>📅 カレンダー</button>
          <button onClick={()=>setViewMode("table")} style={{padding:"7px 14px",borderRadius:16,fontSize:12,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:viewMode==="table"?"var(--tl)":"var(--wh)",color:viewMode==="table"?"#fff":"var(--tx3)",border:viewMode==="table"?"none":"1.5px solid var(--bd)"}}>📊 表形式</button>
        </div>
      </div>
      <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:12}}>
        {Object.entries(SCHEDULE_STATUS).map(([k,v])=>(
          <span key={k} style={{padding:"3px 9px",borderRadius:8,background:v.bg,color:v.color,fontSize:10,fontWeight:700}}>{v.label}</span>
        ))}
      </div>
      {users.length===0
        ? <div style={{textAlign:"center",color:"var(--tx3)",padding:32,background:"var(--wh)",border:"1px solid var(--bd)",borderRadius:11}}>利用者が登録されていません</div>
        : viewMode==="calendar" ? <CalendarView /> : <TableView />
      }
      {/* ==================== 編集モーダル（インラインJSX） ==================== */}
      {/* maxHeight:80dvh + 内部スクロール + 固定フッターで保存ボタンが常に見える */}
      {editCell&&<div style={{position:"fixed",top:0,right:0,bottom:0,left:0,background:"rgba(0,0,0,0.55)",zIndex:400,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={e=>e.target===e.currentTarget&&setEditCell(null)}>
        <div style={{background:"var(--wh)",borderRadius:"16px 16px 0 0",width:"100%",maxWidth:480,boxShadow:"0 -4px 24px rgba(0,0,0,0.22)",display:"flex",flexDirection:"column",maxHeight:"80dvh"}}>
          {/* ── スクロール可能なフォーム部分 ── */}
          <div style={{overflowY:"auto",flex:1,padding:"20px 18px 12px",WebkitOverflowScrolling:"touch"}}>
            <div style={{fontWeight:900,fontSize:16,marginBottom:2}}>{editCell.name}</div>
            <div style={{fontSize:12,color:"var(--tx3)",marginBottom:14}}>{vm.y}年{vm.m}月{editCell.day}日（{dowLabel[getDow(editCell.day)]}）</div>
            <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:8}}>状態を選択</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:6,marginBottom:14}}>
              {Object.entries(SCHEDULE_STATUS).map(([k,v])=>(
                <button key={k} onClick={()=>setTmpStatus(k)} style={{padding:"10px 5px",borderRadius:10,background:tmpStatus===k?v.bg:"var(--bg)",color:tmpStatus===k?v.color:"var(--tx3)",border:"2px solid "+(tmpStatus===k?v.color:"var(--bd)"),fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>{v.label}</button>
              ))}
              <button onClick={()=>setTmpStatus("")} style={{padding:"10px 5px",borderRadius:10,background:tmpStatus===""?"#e8e8e8":"var(--bg)",color:"var(--tx3)",border:"2px solid "+(tmpStatus===""?"#aaa":"var(--bd)"),fontWeight:700,fontSize:11,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>クリア</button>
            </div>
            <div style={{fontSize:10,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:8}}>送迎設定</div>
            <div style={{display:"flex",gap:10,marginBottom:4}}>
              <button onClick={()=>setTmpTo(p=>!p)} style={{flex:1,padding:"10px",borderRadius:10,background:tmpTo?"rgba(58,160,216,0.2)":"var(--bg)",color:tmpTo?"var(--tl)":"var(--tx3)",border:"2px solid "+(tmpTo?"var(--tl)":"var(--bd)"),fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🚌 迎（来所時）</button>
              <button onClick={()=>setTmpFrom(p=>!p)} style={{flex:1,padding:"10px",borderRadius:10,background:tmpFrom?"rgba(44,170,96,0.2)":"var(--bg)",color:tmpFrom?"var(--gr)":"var(--tx3)",border:"2px solid "+(tmpFrom?"var(--gr)":"var(--bd)"),fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🚌 送（帰り）</button>
            </div>
          </div>
          {/* ── 固定フッター：保存ボタン（safe-area + bottom-nav分の余白） ── */}
          <div style={{flexShrink:0,borderTop:"1px solid var(--bd)",padding:"12px 18px",paddingBottom:"calc(env(safe-area-inset-bottom,0px) + 72px)",background:"var(--wh)"}}>
            <button onClick={()=>setSchedule(editCell.uid,editCell.day,tmpStatus,tmpTo,tmpFrom)} style={{width:"100%",padding:"13px",borderRadius:12,background:"var(--tl)",border:"none",color:"#fff",fontWeight:900,fontSize:14,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>保存する</button>
          </div>
        </div>
      </div>}

      {/* ==================== 一括登録モーダル ==================== */}
      {showBulkModal&&(()=>{
        const fw2 = new Date(vm.y, vm.m-1, 1).getDay();
        const toggleDay = (d) => setBulkDays(p=>p.includes(d)?p.filter(x=>x!==d):[...p,d]);
        const applyPattern = (pat) => {
          setBulkDays(dayList.filter(d=>{
            if(isWe(d)) return false;
            const dow=getDow(d);
            if(pat==="all") return true;
            if(pat==="mwf") return dow===1||dow===3||dow===5;
            if(pat==="tt")  return dow===2||dow===4;
            if(pat==="mon") return dow===1;
            if(pat==="tue") return dow===2;
            if(pat==="wed") return dow===3;
            if(pat==="thu") return dow===4;
            if(pat==="fri") return dow===5;
            return false;
          }));
        };
        const confirmBulk = () => {
          if(!bulkUserId||bulkDays.length===0) return;
          bulkDays.forEach(d=>setSchedule(bulkUserId,d,bulkStatus,bulkTo,bulkFrom));
          setShowBulkModal(false);
        };
        const patterns=[
          {k:"all",l:"毎日（平日）"},{k:"mwf",l:"月・水・金"},
          {k:"tt",l:"火・木"},{k:"mon",l:"毎週月"},
          {k:"tue",l:"毎週火"},{k:"wed",l:"毎週水"},
          {k:"thu",l:"毎週木"},{k:"fri",l:"毎週金"},
        ];
        return <div style={{position:"fixed",top:0,left:0,right:0,bottom:0,background:"rgba(0,0,0,0.5)",zIndex:1000,display:"flex",alignItems:"flex-end"}} onClick={()=>setShowBulkModal(false)}>
          <div style={{background:"var(--wh)",borderRadius:"18px 18px 0 0",padding:"20px 16px 32px",width:"100%",maxHeight:"90vh",overflowY:"auto"}} onClick={e=>e.stopPropagation()}>

            {/* ヘッダー */}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:16}}>
              <div style={{fontSize:15,fontWeight:900}}>📅 今月の利用日を一括登録</div>
              <button onClick={()=>setShowBulkModal(false)} style={{background:"none",border:"none",fontSize:22,cursor:"pointer",color:"var(--tx3)"}}>×</button>
            </div>
            <div style={{fontSize:11,color:"var(--tx3)",marginBottom:14}}>{vm.y}年{vm.m}月 — カレンダーで来所日をまとめてチェックして登録できます</div>

            {/* ① 生徒選択 */}
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:6}}>① 生徒を選択</div>
              <select value={bulkUserId} onChange={e=>setBulkUserId(e.target.value)} className="fi" style={{fontSize:13}}>
                <option value="">-- 生徒を選んでください --</option>
                {users.map(u=><option key={u.id} value={u.id}>{u.name}{selFac==="all"?" ("+FACILITIES.find(f=>f.id===u.facilityId)?.name+")":""}</option>)}
              </select>
            </div>

            {/* ② ステータス */}
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:6}}>② 登録する状態</div>
              <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
                {["来所予定","来所","欠席","休所"].map(s=>{
                  const v=SCHEDULE_STATUS[s];
                  return <button key={s} onClick={()=>setBulkStatus(s)} style={{padding:"7px 12px",borderRadius:9,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:bulkStatus===s?v.bg:"var(--bg)",color:bulkStatus===s?v.color:"var(--tx3)",border:"2px solid "+(bulkStatus===s?v.color:"var(--bd)")}}>
                    {v.label}
                  </button>;
                })}
              </div>
            </div>

            {/* ③ 日付選択 */}
            <div style={{marginBottom:14}}>
              <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:6}}>③ 日付を選択</div>
              {/* クイック選択 */}
              <div style={{fontSize:10,color:"var(--tx3)",marginBottom:5}}>クイック選択：</div>
              <div style={{display:"flex",gap:5,flexWrap:"wrap",marginBottom:10}}>
                {patterns.map(p=>(
                  <button key={p.k} onClick={()=>applyPattern(p.k)} style={{padding:"5px 10px",borderRadius:14,fontSize:11,fontWeight:700,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg2)",color:"var(--tl)",border:"1.5px solid var(--tl)"}}>
                    {p.l}
                  </button>
                ))}
                <button onClick={()=>setBulkDays([])} style={{padding:"5px 10px",borderRadius:14,fontSize:11,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",background:"var(--bg)",color:"var(--tx3)",border:"1.5px solid var(--bd)",fontWeight:700}}>
                  クリア
                </button>
              </div>
              {/* カレンダーグリッド */}
              <div style={{background:"var(--bg2)",borderRadius:12,padding:10}}>
                <div style={{textAlign:"center",fontSize:13,fontWeight:900,marginBottom:8}}>{vm.y}年 {vm.m}月</div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3,marginBottom:4}}>
                  {["日","月","火","水","木","金","土"].map((d,i)=>(
                    <div key={d} style={{textAlign:"center",fontSize:10,fontWeight:700,color:i===0?"var(--ro)":i===6?"var(--tl)":"var(--tx3)",padding:"2px 0"}}>{d}</div>
                  ))}
                </div>
                <div style={{display:"grid",gridTemplateColumns:"repeat(7,1fr)",gap:3}}>
                  {Array.from({length:fw2}).map((_,i)=><div key={"e"+i}/>)}
                  {dayList.map(d=>{
                    const we=isWe(d); const sel=bulkDays.includes(d); const dow=getDow(d);
                    const isTd=getDateStr(d)===todayISO();
                    return <div key={d} onClick={()=>!we&&toggleDay(d)} style={{
                      aspectRatio:"1",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",
                      borderRadius:7,border:"2px solid "+(sel?"var(--tl)":we?"transparent":"var(--bd)"),
                      background:sel?"rgba(58,160,216,0.25)":we?"rgba(0,0,0,0.04)":isTd?"rgba(58,160,216,0.08)":"var(--wh)",
                      cursor:we?"default":"pointer",opacity:we?0.35:1,
                      transition:"all .1s",
                    }}>
                      <span style={{fontSize:12,fontWeight:900,color:sel?"var(--tl)":dow===0?"var(--ro)":dow===6?"#2196F3":"var(--tx)"}}>{d}</span>
                      {sel&&<span style={{fontSize:7,color:"var(--tl)",lineHeight:1}}>✓</span>}
                    </div>;
                  })}
                </div>
              </div>
              <div style={{marginTop:8,fontSize:12,fontWeight:700,color:bulkDays.length>0?"var(--tl)":"var(--tx3)",textAlign:"center"}}>
                {bulkDays.length>0?`✅ ${bulkDays.length}日選択中`:"日付をタップして選択（土日は除外）"}
              </div>
            </div>

            {/* ④ 送迎 */}
            <div style={{marginBottom:18}}>
              <div style={{fontSize:11,fontWeight:700,color:"var(--tl)",letterSpacing:1,marginBottom:6}}>④ 送迎設定（任意）</div>
              <div style={{display:"flex",gap:10}}>
                <button onClick={()=>setBulkTo(!bulkTo)} style={{flex:1,padding:"9px",borderRadius:9,background:bulkTo?"rgba(58,160,216,0.2)":"var(--bg)",color:bulkTo?"var(--tl)":"var(--tx3)",border:"2px solid "+(bulkTo?"var(--tl)":"var(--bd)"),fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🚌 迎（来所）</button>
                <button onClick={()=>setBulkFrom(!bulkFrom)} style={{flex:1,padding:"9px",borderRadius:9,background:bulkFrom?"rgba(44,170,96,0.2)":"var(--bg)",color:bulkFrom?"var(--gr)":"var(--tx3)",border:"2px solid "+(bulkFrom?"var(--gr)":"var(--bd)"),fontWeight:700,fontSize:12,cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif"}}>🚌 送（帰り）</button>
              </div>
            </div>

            {/* 確定ボタン */}
            <div style={{display:"flex",gap:10}}>
              <button onClick={()=>setShowBulkModal(false)} style={{flex:1,padding:"13px",borderRadius:10,border:"1.5px solid var(--bd)",background:"var(--bg)",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,fontSize:13,cursor:"pointer",color:"var(--tx)"}}>キャンセル</button>
              <button onClick={confirmBulk} disabled={!bulkUserId||bulkDays.length===0}
                style={{flex:2,padding:"13px",borderRadius:10,border:"none",fontFamily:"'Noto Sans JP',sans-serif",fontWeight:700,fontSize:13,
                  background:bulkUserId&&bulkDays.length>0?"var(--tl)":"var(--bd)",
                  color:"#fff",cursor:bulkUserId&&bulkDays.length>0?"pointer":"default"}}>
                {bulkDays.length>0&&bulkUserId?`✅ ${bulkDays.length}日分を一括登録する`:"生徒と日付を選んでください"}
              </button>
            </div>
          </div>
        </div>;
      })()}
    </div>
  );
}
// ==================== SIDEBAR ====================
function Sidebar({user,screen,onNav,onLogout,unreadCount,open,onClose,onChangeFacility}){
  const isMgr=user.role==="manager"||user.role==="admin";
  const fac=FACILITIES.find(f=>f.id===user.selectedFacilityId);
  const [facOpen,setFacOpen]=useState(false);
  const roleLabel={staff:"支援員",specialist:"専門職員",cdsm:"児発管責任者",manager:"管理者",part_qual:"パート(指導員)",part_noqual:"パート",consultant:"相談支援員",admin:"本部管理者"}[user.role]||user.role;

  // 現在の施設が保育所等訪問支援を持つか判定
  const facSvcTypes = getFacilityServiceTypes(user.selectedFacilityId||"f1");
  const hasVisitNav = facSvcTypes.some(s=>s.id==="hoikuvisit");

  const nav=[
    {id:"home",icon:"🏠",label:"ダッシュボード"},
    {sec:"今日の記録"},
    {id:"clock_in",icon:"🟢",label:"職員 出勤"},
    {id:"clock_out",icon:"🟡",label:"職員 退勤"},
    {id:"user_arrive",icon:"🌟",label:"利用者 来所"},
    {id:"user_depart",icon:"🏠",label:"利用者 退所"},
    {sec:"支援・記録"},
    {id:"service",icon:"📋",label:"サービス記録"},
    {id:"photo",icon:"📸",label:"写真記録"},
    {id:"messages",icon:"💬",label:"保護者連絡",badge:unreadCount>0?unreadCount:null},
    {id:"daily",icon:"📓",label:"業務日報"},
    {id:"isp",icon:"📝",label:"個別支援計画"},
    ...(hasVisitNav?[{id:"visit",icon:"🚌",label:"保育所等訪問支援"}]:[]),
    {sec:"管理"},
    {id:"schedule",icon:"📅",label:"生徒予定表"},
    {id:"users",icon:"👤",label:"利用者管理"},
    {id:"shift",icon:"📆",label:"シフト管理"},
    {id:"kintai",icon:"⏱",label:"勤務実績"},
    {id:"records_list",icon:"📊",label:"実績一覧"},
    {id:"paidleave",icon:"🌴",label:"有給管理"},
    ...(isMgr?[
      {sec:"管理者専用"},
      {id:"attendance",icon:"📋",label:"出欠管理"},
      {id:"transport",icon:"🚗",label:"送迎管理"},
      {id:"kokuho",icon:"💴",label:"国保連請求"},
      {id:"staffmgmt",icon:"👥",label:"スタッフ管理"},
      {id:"admin",icon:"📊",label:"管理画面"},
      {id:"audit",icon:"🔍",label:"監査モード"},
    ]:[]),
  ];

  const go=(id)=>{onNav(id);onClose();};

  return <>
    <div className={`sb-overlay${open?" open":""}`} onClick={onClose}/>
    <div className={`sidebar${open?" open":""}`}>
      {/* ロゴ */}
      <div className="sb-brand">
        <div className="sb-logo">GO GROUP</div>
        <div className="sb-logo-sub">{facSvcTypes.map(s=>s.short).join(" / ")} 管理システム</div>
      </div>
      {/* 施設切替 */}
      <div style={{margin:"10px 12px 4px",position:"relative"}}>
        <button onClick={()=>setFacOpen(o=>!o)} style={{width:"100%",background:"var(--bg3)",border:"1px solid var(--bd)",borderRadius:8,padding:"8px 11px",textAlign:"left",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",display:"flex",alignItems:"center",justifyContent:"space-between"}}>
          <div>
            <div style={{fontSize:10,color:"var(--tx3)",marginBottom:2}}>📍 現在の施設</div>
            <div style={{fontSize:13,fontWeight:700,color:"var(--tx)"}}>{fac?.name||"未選択"}</div>
          </div>
          <span style={{fontSize:12,color:"var(--tx3)",marginLeft:6}}>{facOpen?"▲":"▼"}</span>
        </button>
        {facOpen&&<div style={{position:"absolute",top:"100%",left:0,right:0,zIndex:999,background:"var(--bg2)",border:"1px solid var(--tl)",borderRadius:8,marginTop:4,overflow:"hidden",boxShadow:"0 4px 16px rgba(0,0,0,0.3)"}}>
          {FACILITIES.map(f=>(
            <button key={f.id} onClick={()=>{onChangeFacility(f.id);setFacOpen(false);}}
              style={{width:"100%",padding:"10px 14px",textAlign:"left",background:f.id===user.selectedFacilityId?"rgba(58,160,216,0.2)":"transparent",border:"none",borderBottom:"1px solid var(--bd)",cursor:"pointer",fontFamily:"'Noto Sans JP',sans-serif",fontSize:13,fontWeight:f.id===user.selectedFacilityId?700:400,color:f.id===user.selectedFacilityId?"var(--tl)":"var(--tx)",display:"flex",alignItems:"center",gap:8}}>
              {f.id===user.selectedFacilityId&&<span style={{color:"var(--tl)"}}>✓</span>}
              {f.name}
            </button>
          ))}
        </div>}
      </div>
      {/* ナビゲーション */}
      <div style={{flex:1,overflowY:"auto",padding:"6px 0",scrollbarWidth:"none"}}>
        {nav.map((item,i)=>{
          if(item.sec!==undefined){
            return <div key={i} className="sb-section">{item.sec}</div>;
          }
          return <div key={item.id} className={`sb-item${screen===item.id?" active":""}`} onClick={()=>go(item.id)}>
            <span className="sb-icon">{item.icon}</span>
            <span style={{flex:1}}>{item.label}</span>
            {item.badge&&<span className="sb-badge">{item.badge}</span>}
          </div>;
        })}
      </div>
      {/* ユーザー情報 */}
      <div className="sb-bottom">
        <div className="sb-user">
          <div className="sb-avatar">👤</div>
          <div className="sb-user-info">
            <div className="sb-user-name">{user.displayName}</div>
            <div className="sb-user-role">{roleLabel}</div>
          </div>
          <button className="sb-logout" onClick={onLogout}>退出</button>
        </div>
        {/* Produce By バッジ */}
        <div style={{margin:"8px 12px 4px",display:"flex",alignItems:"center",justifyContent:"center",gap:8,background:"rgba(255,255,255,0.05)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:8,padding:"7px 10px"}}>
          <span style={{fontSize:9,color:"rgba(255,255,255,0.4)",letterSpacing:1,fontWeight:500,whiteSpace:"nowrap"}}>Produce By</span>
          <div style={{background:"#fff",borderRadius:6,padding:"2px 6px",display:"flex",alignItems:"center"}}>
            <img src="/bells-logo.jpg" alt="株式会社BELLSインターナショナル" style={{height:24,width:"auto",display:"block"}}/>
          </div>
        </div>
      </div>
    </div>
  </>;
}

// ==================== セッションタイムアウト定数 ====================
const SESSION_TIMEOUT_MIN = 60;   // 自動ログアウトまでの時間（分）
const SESSION_WARN_MIN    = 55;   // 警告を出す時間（分）
const SESSION_KEY = 'gogroup_last_activity';

// ==================== APP ROOT ====================
export default function App(){
  const [user,setUser]=useState(()=>{
    try{const s=localStorage.getItem('gogroup_user');return s?JSON.parse(s):null;}catch(e){return null;}
  });
  const [screen,setScreen]=useState("home");
  const [sbOpen,setSbOpen]=useState(false);
  const [sessionWarn,setSessionWarn]=useState(false); // 55分警告モーダル
  const [navParams,setNavParams]=useState({}); // 画面遷移時に追加パラメータ（ids等）を渡す
  const store=useStore();

  // onNav: 画面IDと追加パラメータ（{ids:[...]}等）を受け取って遷移する
  const handleNav=(screenId,params={})=>{
    setNavParams(params||{});
    setScreen(screenId);
  };

  // ネットワークエラーをトーストで通知できるよう、モジュール変数に登録
  useEffect(()=>{ _sbErrCb=(m,t)=>store.showToast(m,t); },[]);

  // ── オフライン状態管理 ──
  // navigator.onLine を監視して、通信状態バナーをリアルタイム表示する
  const [isOnline, setIsOnline] = useState(
    typeof navigator !== "undefined" ? navigator.onLine : true
  );
  useEffect(() => {
    const onOnline  = () => setIsOnline(true);
    const onOffline = () => setIsOnline(false);
    window.addEventListener("online",  onOnline);
    window.addEventListener("offline", onOffline);
    return () => {
      window.removeEventListener("online",  onOnline);
      window.removeEventListener("offline", onOffline);
    };
  }, []);

  const logout=()=>{
    localStorage.removeItem('gogroup_user');
    localStorage.removeItem(SESSION_KEY);
    ggAuthSignOut();               // Supabase Auth トークンも破棄（anonへ戻す）
    setUser(null);setScreen("home");setSessionWarn(false);
  };

  // ─── JWT先行リフレッシュ（Phase1）───
  // access_token は約1時間で失効するため、稼働中セッションが RLS で弾かれないよう
  // 45分ごとに先行更新する。アイドル60分で自動ログアウトするため過剰更新にはならない。
  useEffect(()=>{
    if(!user) return;
    const t=setInterval(()=>{ ggAuthRefresh(); }, 45*60*1000);
    return ()=>clearInterval(t);
  },[user]);

  // ─── セッションタイムアウト監視 ───
  useEffect(()=>{
    if(!user) return;

    // アクティビティ更新（クリック・キー・スクロール・タッチ）
    const updateActivity=()=>{ try{localStorage.setItem(SESSION_KEY,Date.now().toString());}catch(e){} };
    const events=["click","keydown","mousemove","touchstart","scroll"];
    events.forEach(ev=>document.addEventListener(ev,updateActivity,{passive:true}));
    updateActivity(); // 初期化

    // 1分ごとにセッション期限をチェック
    const timer=setInterval(()=>{
      try{
        const last=parseInt(localStorage.getItem(SESSION_KEY)||"0",10);
        const idleMin=(Date.now()-last)/60000;
        if(idleMin>=SESSION_TIMEOUT_MIN){
          // 60分経過 → 自動ログアウト
          clearInterval(timer);
          alert("セッションがタイムアウトしました。\n再度ログインしてください。");
          logout();
        } else if(idleMin>=SESSION_WARN_MIN){
          // 55分経過 → 警告表示
          setSessionWarn(true);
        } else {
          setSessionWarn(false);
        }
      }catch(e){}
    },60000); // 1分ごと

    return ()=>{
      events.forEach(ev=>document.removeEventListener(ev,updateActivity));
      clearInterval(timer);
    };
  },[user]); // eslint-disable-line

  if(!user)return <><style>{CSS}</style><div className="app"><LoginScreen store={store} onLogin={u=>{
    try{
      localStorage.setItem('gogroup_user',JSON.stringify(u));
      localStorage.setItem(SESSION_KEY,Date.now().toString());
    }catch(e){}
    setUser(u);setScreen("home");
  }}/></div></>;

  const unreadCount=store.msgs.filter(m=>(user.role==="admin"||m.facilityId===user.selectedFacilityId)&&!m.read).length;

  const screenTitles={
    home:"ダッシュボード",clock_in:"職員 出勤打刻",clock_out:"職員 退勤打刻",
    user_arrive:"利用者 来所",user_depart:"利用者 退所",photo:"写真記録",
    service:"サービス提供記録",messages:"保護者連絡",schedule:"生徒予定表",
    daily:"業務日報",paidleave:"有給管理",users:"利用者管理",
    shift:"シフト管理",kintai:"勤務実績",attendance:"出欠管理",transport:"送迎管理",
    kokuho:"国保連請求",staffmgmt:"スタッフ管理",admin:"管理画面",audit:"監査モード",
    isp:"個別支援計画",visit:"保育所等訪問支援",records_list:"実績一覧",
    billing_mgmt:"請求管理・加算管理",
    kintai_dash:"勤怠管理ダッシュボード",
    transport_live:"送迎ライブ追跡",
    parent_connect:"保護者連絡センター",
    data_analytics:"データ分析・帳票出力",
    billing_check:"請求前チェック",
    returns:"返戻管理",
    support_plan:"個別支援計画・モニタリング",
    jisseki:"実績管理（当日）",
    schedule_ocr:"予定表 OCR読み取り",
    parent_contacts:"保護者連絡",
    staff_monitor:"スタッフ管理",
    activity_ai:"AI活動記録生成",
    management_dash:"経営ダッシュボード",
    audit_mode:"監査ログ",
    staff_documents:"職員書類管理",
    photo_album:"写真アルバム",
    parent_portal:"保護者ポータル",
  };

  // ─── ルーティング権限ガード ───
  // allowedRoles に user.role が含まれない場合はアクセス拒否画面を返す
  const guard = (allowedRoles, component) => {
    if (!allowedRoles.includes(user.role)) {
      return (
        <div style={{display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",
          minHeight:300,padding:32,textAlign:"center"}}>
          <div style={{fontSize:48,marginBottom:12}}>🔒</div>
          <div style={{fontSize:17,fontWeight:700,color:"#c0392b",marginBottom:8}}>
            アクセス権限がありません
          </div>
          <div style={{fontSize:13,color:"#666",marginBottom:24,lineHeight:1.7}}>
            このページは <strong>{allowedRoles.join(" / ")}</strong> のみアクセスできます。<br/>
            権限が必要な場合は管理者にお問い合わせください。
          </div>
          <button onClick={()=>setScreen("home")}
            style={{padding:"10px 28px",borderRadius:8,background:"#2563eb",color:"#fff",
              border:"none",fontSize:14,fontWeight:700,cursor:"pointer"}}>
            ← ホームに戻る
          </button>
        </div>
      );
    }
    return component;
  };

  // ロール定数（可読性のため）
  // viewer: 閲覧専用（編集・削除・請求不可）
  const ROLE_ALL           = ["admin","manager","staff","viewer"];
  const ROLE_ADMIN         = ["admin"];
  const ROLE_ADMIN_MGR     = ["admin","manager"];
  const ROLE_ADMIN_MGR_STF = ["admin","manager","staff"];

  const render=()=>{switch(screen){
    // ── 全員アクセス可 ──
    case "home":return user.role==="parent"?<ParentPortalScreen user={user} store={store} onBack={()=>{}}/>:<HomeScreen user={user} onNav={handleNav} store={store}/>;
    case "parent_portal":return <ParentPortalScreen user={user} store={store} onBack={()=>setScreen("home")}/>;

    // ── staff以上（保護者除外）──
    case "clock_in":         return guard(ROLE_ADMIN_MGR_STF,<StaffClockIn user={user} onBack={()=>setScreen("home")} store={store}/>);
    case "clock_out":        return guard(ROLE_ADMIN_MGR_STF,<StaffClockOut user={user} onBack={()=>setScreen("home")} store={store}/>);
    case "user_arrive":      return guard(ROLE_ADMIN_MGR_STF,<UserArrive user={user} onBack={()=>{setNavParams({});setScreen("home");}} store={store} filterIds={navParams.ids||null}/>);
    case "user_depart":      return guard(ROLE_ADMIN_MGR_STF,<UserDepart user={user} onBack={()=>setScreen("home")} store={store}/>);
    case "photo":            return guard(ROLE_ADMIN_MGR_STF,<PhotoRecord user={user} onBack={()=>setScreen("home")} store={store}/>);
    case "service":          return guard(ROLE_ADMIN_MGR_STF,<ServiceRecord user={user} onBack={()=>setScreen("home")} store={store}/>);
    case "messages":         return guard(ROLE_ADMIN_MGR_STF,<ParentMessages user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "daily":            return guard(ROLE_ADMIN_MGR_STF,<DailyReport user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "schedule":         return guard(ROLE_ADMIN_MGR_STF,<ScheduleScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "activity_calendar":return guard(ROLE_ADMIN_MGR_STF,<ActivityCalendarScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "jisseki":          return guard(ROLE_ADMIN_MGR_STF,<JissekiScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "transport":        return guard(ROLE_ADMIN_MGR_STF,<TransportScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "transport_live":   return guard(ROLE_ADMIN_MGR_STF,<TransportLiveScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "isp":              return guard(ROLE_ADMIN_MGR_STF,<IspScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "visit":            return guard(ROLE_ADMIN_MGR_STF,<VisitManagementScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "records_list":     return guard(ROLE_ADMIN_MGR_STF,<RecordListScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "parent_connect":   return guard(ROLE_ADMIN_MGR_STF,<ParentConnectScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "parent_contacts":  return guard(ROLE_ADMIN_MGR_STF,<ParentContactsScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "activity_ai":      return guard(ROLE_ADMIN_MGR_STF,<ActivityAIScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "photo_album":      return guard(ROLE_ADMIN_MGR_STF,<PhotoAlbumScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "schedule_ocr":     return guard(ROLE_ADMIN_MGR_STF,<ScheduleOCRScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "support_plan":     return guard(ROLE_ADMIN_MGR_STF,<SupportPlanScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "paidleave":        return guard(ROLE_ADMIN_MGR_STF,<PaidLeaveScreen user={user} store={store} onBack={()=>setScreen("home")}/>);

    // ── admin / manager のみ ──
    case "attendance":       return guard(ROLE_ADMIN_MGR,<AttendanceScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "shift":            return guard(ROLE_ADMIN_MGR,<ShiftScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "kintai":           return guard(ROLE_ADMIN_MGR,<WorkRecordScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "users":            return guard(ROLE_ADMIN_MGR,<UserManagement user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "staffmgmt":        return guard(ROLE_ADMIN_MGR,<StaffManagement user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "staff_monitor":    return guard(ROLE_ADMIN_MGR,<StaffMonitorScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "kokuho":           return guard(ROLE_ADMIN_MGR,<KokuhoScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "billing_check":    return guard(ROLE_ADMIN_MGR,<BillingCheckScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "returns":          return guard(ROLE_ADMIN_MGR,<ReturnsManagementScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "billing_mgmt":     return guard(ROLE_ADMIN_MGR,<BillingManagementScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "kintai_dash":      return guard(ROLE_ADMIN_MGR,<StaffKintaiDashboardScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "data_analytics":   return guard(ROLE_ADMIN_MGR,<DataAnalyticsScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "staff_documents":  return guard(ROLE_ADMIN_MGR,<StaffDocumentScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "management_dash":  return guard(ROLE_ADMIN_MGR,<ManagementDashboardScreen user={user} store={store} onNav={setScreen} onBack={()=>setScreen("home")}/>);
    case "audit":            return guard(ROLE_ADMIN_MGR,<AuditScreen user={user} store={store} onBack={()=>setScreen("home")}/>);
    case "audit_mode":       return guard(ROLE_ADMIN_MGR,<AuditModeScreen user={user} store={store} onBack={()=>setScreen("home")}/>);

    // ── admin のみ ──
    case "admin":            return guard(ROLE_ADMIN,<AdminScreen user={user} store={store} onBack={()=>setScreen("home")}/>);

    default:return <HomeScreen user={user} onNav={setScreen} store={store}/>;
  }};

  // モバイル ボトムナビ
  const bnItems=[
    {id:"home",icon:"🏠",label:"ホーム"},
    {id:"clock_in",icon:"🟢",label:"出勤"},
    {id:"user_arrive",icon:"🌟",label:"来所"},
    {id:"messages",icon:"💬",label:"連絡",badge:unreadCount>0?unreadCount:null},
    {id:"schedule",icon:"📅",label:"予定表"},
  ];

  return <>
    <style>{CSS}</style>
    <div className="app">

      {/* ── オフラインバナー ──
          通信が切れた場合に画面最上部に固定表示する。
          _isOnline (グローバル) と isOnline (state) の両方が false の時のみ表示。 */}
      {!isOnline && (
        <div style={{
          position:"fixed", top:0, left:0, right:0, zIndex:99999,
          background:"rgba(220,38,38,0.97)", color:"#fff",
          textAlign:"center", padding:"9px 16px",
          fontSize:12, fontWeight:700, letterSpacing:0.3,
          boxShadow:"0 2px 8px rgba(0,0,0,0.25)",
        }}>
          📡 オフラインです — 通信環境を確認してください。データの保存は通信回復後に再試行してください。
        </div>
      )}

      <div className="app-shell" style={!isOnline ? {marginTop:38} : {}}>
        <Sidebar user={user} screen={screen} onNav={setScreen} onLogout={logout}
          unreadCount={unreadCount} open={sbOpen} onClose={()=>setSbOpen(false)}
          onChangeFacility={fid=>{const u2={...user,selectedFacilityId:fid};setUser(u2);try{localStorage.setItem('gogroup_user',JSON.stringify(u2));}catch(e){}setScreen("home");setSbOpen(false);}}/>
        <div className="main-wrap">
          {/* トップバー */}
          <div className="top-bar">
            <div className="top-bar-left">
              <button className="hmb" onClick={()=>setSbOpen(o=>!o)}>☰</button>
              <div className="top-bar-title">{screenTitles[screen]||"GO GROUP"}</div>
            </div>
            <div className="top-bar-right">
              <div className="top-bar-date">{todayDisplay()}</div>
            </div>
          </div>
          {/* メインコンテンツ — ErrorBoundaryでレンダリングエラーを補足 */}
          <div className="main-content">
            <div className="wrap">
              <ErrorBoundary>
                {render()}
              </ErrorBoundary>
            </div>
          </div>
        </div>
      </div>
      {/* モバイル ボトムナビ */}
      <div className="bottom-nav">
        <div className="bn-row">
          {bnItems.map(item=>(
            <div key={item.id} className={`bn-item${screen===item.id?" active":""}`} onClick={()=>setScreen(item.id)}>
              <span className="bn-icon">{item.icon}</span>
              <span>{item.label}</span>
              {item.badge&&<span className="bn-badge">{item.badge}</span>}
            </div>
          ))}
        </div>
      </div>
      {/* グローバルトースト */}
      <Toast msg={store.toastMsg} type={store.toastType}/>
      {/* セッションタイムアウト警告モーダル */}
      {sessionWarn&&<div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.7)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center"}}>
        <div style={{background:"#1e1e2a",border:"2px solid #e0a828",borderRadius:16,padding:"28px 32px",maxWidth:340,width:"90%",textAlign:"center",boxShadow:"0 8px 32px rgba(0,0,0,0.8)"}}>
          <div style={{fontSize:40,marginBottom:12}}>⏰</div>
          <div style={{fontSize:16,fontWeight:700,color:"#e0a828",marginBottom:8}}>セッションまもなく終了</div>
          <div style={{fontSize:13,color:"#ccc",marginBottom:20,lineHeight:1.7}}>
            操作がない状態が続いています。<br/>
            あと約<strong style={{color:"#fff"}}>{SESSION_TIMEOUT_MIN-SESSION_WARN_MIN}分</strong>で自動的にログアウトします。
          </div>
          <button onClick={()=>{
            try{localStorage.setItem(SESSION_KEY,Date.now().toString());}catch(e){}
            setSessionWarn(false);
          }} style={{width:"100%",padding:"12px",borderRadius:10,background:"#e0a828",color:"#000",border:"none",fontSize:14,fontWeight:700,cursor:"pointer"}}>
            ✅ ログインを継続する
          </button>
        </div>
      </div>}
    </div>
  </>;
}

// エントリーポイント（Vite HMRで多重createRootしないよう対策）
const _rootEl = document.getElementById("root");
if (_rootEl) {
  // HMRリロード時は既存ルートを再利用する
  let _appRoot = import.meta.hot?.data?.root;
  if (!_appRoot) {
    _appRoot = createRoot(_rootEl);
    if (import.meta.hot) import.meta.hot.data.root = _appRoot;
  }
  _appRoot.render(<ErrorBoundary><App /></ErrorBoundary>);
}
